-- Name: surfaces_as_geojson_fkb50(text[], integer, integer); Type: FUNCTION; Schema: topo_ar5ngis; Owner: lop
--

CREATE FUNCTION topo_ar5ngis.surfaces_as_geojson_fkb50(surfaceids text[], outsrid integer DEFAULT NULL::integer, maxdecimaldigits integer DEFAULT 9) RETURNS jsonb
    LANGUAGE plpgsql
    AS $$  --}{
BEGIN

	-- Produce the GeoJSON for new or modified surfaces
	RETURN topo_update.surfaces_as_geojson(
		'topo_ar5ngis.face_attributes_export_fkb50',	-- surfaceLayerView
		'omrade',				-- surfaceLayerTopoGeomColumn
		'identifikasjon_lokal_id',		-- surfaceLayerIDColumn
