		-- that we want to include in the GeoJSON
		surfaceIds,

		-- JSON feature modifier
		'topo_ar5ngis.surfaces_as_geojson_featureJsonModifier_fkb50',

		-- Parameter passed to JSON feature modifier
		NULL::int,

		outSRID,

		maxdecimaldigits

		);

END;
$$;



--
-- Name: update_feature_attribute_java(text, text); Type: FUNCTION; Schema: topo_ar5ngis; Owner: lop
--

CREATE FUNCTION topo_ar5ngis.update_feature_attribute_java(feature_properties text, opphav text DEFAULT NULL::text) RETURNS text
    LANGUAGE plpgsql
    AS $_$ -- {
DECLARE
	feature JSONB := feature_properties::jsonb;
BEGIN

	-- TODO should also be wrapper function
	-- Set default kvalitet

	--   kartstandard AR5,

	feature := jsonb_set(
		feature,
		'{properties, "registreringsversjon" }',
		to_jsonb('2022-01-01'::TEXT)
	);

	feature := jsonb_set(
		feature,
		'{properties, "identifikasjon_versjon_id" }',
		to_jsonb(now())
	);

	-- Get value from server side
	IF opphav IS NOT NULL THEN
		feature := jsonb_set(
			feature,
			'{properties, opphav}',
			to_jsonb(opphav)
		);
	END IF;

	-- fails with topo_ar5ngis.colMapForFaceAttributes() -- layerColMap
	-- +ERROR:  query returned more than one row
	-- +ERROR:  current transaction is aborted, commands ignored until end of transaction block


	RETURN topo_update.update_feature_attribute(
	feature::JSONB,
	'topo_ar5ngis.face_attributes'::regclass,
	'identifikasjon_lokal_id',
	$$
	{
		"identifikasjon_lokal_id": [
			"id"
		],
		"identifikasjon_versjon_id": [
			"identifikasjon_versjon_id"
		],
		"kvalitet": [
			"kvalitet"
		],
		"registreringsversjon": [
			"registreringsversjon"
		],
		"informasjon": [
			"informasjon"
		],
		"opphav": [
			"opphav"
		],
		"arealtype": [
			"arealtype"
		],
		"treslag": [
			"treslag"
		],
		"skogbonitet": [
			"skogbonitet"
		],
		"grunnforhold": [
			"grunnforhold"
		],
		"datafangstdato": [
			"datafangstdato"
		],
		"verifiseringsdato": [
			"verifiseringsdato"
		],
		"klassifiseringsmetode": [ "klassifiseringsmetode" ],

		"oppdateringsdato": [
			"oppdateringsdato"
		]
	}
	$$ -- layerColMap

);
END;
$_$;



