--
-- Name: __insert_to_update_identifier_syntax(text); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.__insert_to_update_identifier_syntax(id text) RETURNS text
    LANGUAGE plpgsql
    AS $$ --{
DECLARE
	parent_id TEXT;
	comps TEXT[];
	len INTEGER;
	ret TEXT;
BEGIN

	-- with x as ( select regexp_split_to_array('a.b.c.d', '\.') as a) select
	-- repeat('(', array_upper(a,1)-1) || '"' || array_to_string(a, '")."')
	-- || '"' from x;

	comps = string_to_array(id, '.');
	len := array_upper(comps, 1);
-- STRIP -- 	RAISE DEBUG 'Comps: %, len: %', comps, len;

	IF len = 1
	THEN
		RETURN format('%I', comps[1]);
	END IF;
	parent_id = topo_update.__insert_to_update_identifier_syntax(
		array_to_string(comps[1:len-1], '.') -- TODO: avoid this back and forth
	);
-- STRIP -- 	RAISE DEBUG 'Parent id: %, comps[len]: %', parent_id, comps[len];

	ret := format('(%s).%I', parent_id, comps[len]);
-- STRIP -- 	RAISE DEBUG 'Returning: %', ret;

	RETURN ret;
END;
$$;



--
-- Name: _add_border_split_surface_get_map_from_array(jsonb[], character, character); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._add_border_split_surface_get_map_from_array(usr jsonb[], typ character, act character) RETURNS jsonb
    LANGUAGE plpgsql
    AS $$
DECLARE
	procName TEXT := 'topo_update._add_border_split_surface_get_map_from_array';
BEGIN
	IF typ = 'B' AND act IN ( 'M', 'C', 'S' )
	THEN
		RETURN usr[1];
	ELSIF typ = 'S' AND act IN ( 'M', 'C', 'S' )
	THEN
		RETURN usr[2];
	ELSE
		RAISE EXCEPTION '%: unsupported typ/act combination: %/%',
			procName, typ, act;
	END IF;
END;
$$;



--
-- Name: _add_border_split_surface_mergeable_faces(topology.topology, topology.layer, integer[]); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._add_border_split_surface_mergeable_faces(topo topology.topology, borderlayer topology.layer, face_ids integer[]) RETURNS SETOF topology.topoelementarray
    LANGUAGE plpgsql
    AS $_$ --}{
DECLARE
	id INT;
	sql TEXT;
	mergeable_ids INT[];
	teary topology.TopoElementArray;
BEGIN

	LOOP --{
		id := face_ids[1];
		IF id IS NULL THEN
			EXIT;
		END IF;

		face_ids := array_remove(face_ids, id);

		IF cardinality(face_ids) = 0 THEN
			-- Shortcut (TODO: drop?)
-- STRIP -- 			RAISE DEBUG 'No more faces to find!';

			RETURN NEXT ARRAY[ARRAY[id, 3]];
			EXIT;
		END IF;

-- STRIP -- 		RAISE DEBUG 'More than a face to evaluate for merge';


		CREATE TEMPORARY TABLE face_set(fid INT unique, checked BOOL DEFAULT FALSE);
		INSERT INTO pg_temp.face_set(fid, checked) VALUES (id, true);

		LOOP --{

			sql := format(
				$$
SELECT
	array_agg(
		DISTINCT
		CASE WHEN $1 = e.left_face THEN
			e.right_face
		ELSE
			e.left_face
		END
	)
FROM %1$I.edge e
WHERE ( e.left_face = $1 OR e.right_face = $1 )
  AND e.left_face != e.right_face
  -- TODO: this part should be optimized
  AND e.edge_id NOT IN (
	SELECT abs(r.element_id)
	FROM %1$I.relation r
	WHERE r.layer_id = %2$L
  )
				$$,
				topo.name, -- %1
				borderLayer.layer_id -- %2
			);
-- STRIP -- 			RAISE DEBUG 'SQL: %', sql;

			EXECUTE sql
			INTO mergeable_ids
			USING id;

-- STRIP -- 			RAISE DEBUG 'Faces mergeable with %: %', id, mergeable_ids;


			INSERT INTO pg_temp.face_set(fid)
			SELECT unnest(mergeable_ids)
			ON CONFLICT DO NOTHING;

			SELECT fid FROM pg_temp.face_set
			WHERE NOT checked
			ORDER BY fid LIMIT 1
			INTO id;

			IF id IS NULL THEN
				EXIT;
			END IF;

			UPDATE pg_temp.face_set
			SET checked = true
			WHERE fid = id;

		END LOOP; --}

		-- Remove each of the mergeable faces from face_ids
		SELECT array_agg(x) FROM (
			SELECT unnest(face_ids) x
				EXCEPT
			SELECT fid FROM pg_temp.face_set
		) foo
		INTO face_ids;

		-- Build a TopoElementArray with all
		-- all mergeable ids
		SELECT array_agg(ARRAY[fid,3])
		FROM pg_temp.face_set
		INTO teary;
		RETURN NEXT teary;

		DROP TABLE pg_temp.face_set;

	END LOOP; --}

END;
$_$;



--
-- Name: _app_check_border_layer(jsonb, jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_check_border_layer(appconfig jsonb, cfg_tables jsonb) RETURNS void
    LANGUAGE plpgsql
    AS $$ --{
DECLARE
	cfg_border_layer JSONB;
BEGIN
	-- Check border_layer
	cfg_border_layer := appconfig -> 'border_layer';
	IF cfg_border_layer IS NULL THEN
		RAISE EXCEPTION 'Missing "border_layer" element in appconfig';
	END IF;
	IF jsonb_typeof(cfg_border_layer) != 'object' THEN
		RAISE EXCEPTION 'Invalid "border_layer" element in appconfig (must be object, not %)', jsonb_typeof(cfg_border_layer);
	END IF;
	PERFORM topo_update._app_validate_layer_config('border_layer', cfg_tables, cfg_border_layer, 'lineal');

END;
$$;



--
-- Name: _app_check_getfeaturesastopojson_config(jsonb, jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_check_getfeaturesastopojson_config(appconfig jsonb, cfg_op jsonb) RETURNS void
    LANGUAGE plpgsql
    AS $$ --{
DECLARE
	roles_supported TEXT[] := topo_update._app_do_GetFeaturesAsTopoJSON_SupportedRoles(appconfig, cfg_op);
	roles_default TEXT[] := topo_update._app_do_GetFeaturesAsTopoJSON_DefaultRoles(cfg_op);
	missing_roles TEXT[];
BEGIN

	IF cfg_op ? 'default_roles' THEN
		SELECT array_agg(x) FROM (
			SELECT unnest( roles_default ) x
				EXCEPT
			SELECT unnest( roles_supported )
		) foo
		INTO missing_roles;
		IF missing_roles IS NOT NULL THEN
			RAISE EXCEPTION 'The following GetFeaturesAsTopoJSON default_roles are not supported: %', array_to_string(missing_roles, ', ');
		END IF;
	ELSE
		-- By default we get what we can
		SELECT array_agg(x) FROM (
			SELECT unnest( roles_default ) x
				INTERSECT
			SELECT unnest( roles_supported )
		) foo
		INTO missing_roles;
		IF missing_roles IS NULL THEN
			RAISE EXCEPTION 'None of the required layers for GetFeaturesAsTopoJSON are available: %', array_to_string(roles_default, ', ');
		END IF;
	END IF;


END;
$$;



