-- Name: _app_createschema_domain(name, jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_createschema_domain(appname name, domconfig jsonb) RETURNS void
    LANGUAGE plpgsql
    AS $_$ --{
DECLARE
	domname NAME;
	sql TEXT;
	sql_att TEXT;
	sql_attlist TEXT[];
	rec RECORD;
	attsql TEXT[];
	pkey NAME;
BEGIN

	domname := domconfig ->> 'name';
	IF domname IS NULL THEN
		RAISE EXCEPTION 'Missing "name" in domain config %', domconfig;
	END IF;

-- STRIP -- 	RAISE DEBUG 'Should create domain %', domname;


	sql_att := topo_update._app_CreateSchema_table_attribute(domconfig);

	sql := format('CREATE DOMAIN %1$s', sql_att);

-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;

	EXECUTE sql;


END;
$_$;



--
-- Name: _app_createschema_table(name, jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_createschema_table(appname name, tabconfig jsonb) RETURNS regclass
    LANGUAGE plpgsql
    AS $_$ --{
DECLARE
	tabname NAME;
	sql TEXT;
	sql_att TEXT;
	sql_attlist TEXT[];
	rec RECORD;
	attsql TEXT[];
	pkey NAME;
BEGIN

	tabname := tabconfig ->> 'name';
	IF tabname IS NULL THEN
		RAISE EXCEPTION 'Missing "name" in table config %', tabconfig;
	END IF;

-- STRIP -- 	RAISE DEBUG 'Should create table %', tabname;


	sql := format('CREATE TABLE %1$I (', tabname);
	FOR rec IN SELECT jsonb_array_elements( tabconfig -> 'attributes' ) cfg
	LOOP --{
		sql_att := topo_update._app_CreateSchema_table_attribute(rec.cfg);
		sql_attlist := array_append(sql_attlist, sql_att);
	END LOOP; --}
	sql := format('%1$s %2$s',
		sql,
		array_to_string(sql_attlist, ', ')
	);

	-- Add primary key
	pkey := tabconfig ->> 'primary_key';
	IF pkey IS NOT NULL THEN --{
		sql := format('%s, PRIMARY KEY(%I)',
			sql,
			pkey
		);
	END IF; --}

	sql := sql || ')';

	-- TODO: add table constraints ?

-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;

	EXECUTE sql;


	-- Create TopoGeometry columns
	FOR rec IN SELECT jsonb_array_elements( tabconfig -> 'topogeom_columns' ) cfg
	LOOP --{
		sql := format('SELECT topology.AddTopoGeometryColumn(%L, %L, %L, %L, %L)',
			appname || '_sysdata_webclient',
			appname,
			tabname,
			rec.cfg ->> 'name',
			rec.cfg ->> 'type'
		);
-- STRIP -- 		RAISE DEBUG 'SQL: %', sql;

		EXECUTE sql;

		-- Add unique index on the topogeometry identifier
		-- See https://gitlab.com/nibioopensource/pgtopo_update_sql/-/issues/299
		sql := format('CREATE UNIQUE INDEX ON %I.%I ( id(%I) )',
			appname,
			tabname,
			rec.cfg ->> 'name'
		);
-- STRIP -- 		RAISE DEBUG 'SQL: %', sql;

		EXECUTE sql;

		IF NOT COALESCE( (rec.cfg -> 'allow_overlaps')::boolean, true)
		THEN --{
			PERFORM topo_update.add_unique_topo_primitive_constraint(
				tabname::regclass,
				rec.cfg ->> 'name',
				pkey
			);
		END IF; --}

		IF NOT COALESCE( (rec.cfg ->> 'allow_multi')::boolean, true)
		THEN --{
			RAISE WARNING 'Disallowing multi for % layer %.% not implemented yet',
				rec.cfg ->> 'type', tabname, rec.cfg ->> 'name';
		END IF; --}

		IF NOT COALESCE( (rec.cfg ->> 'allow_crossings')::boolean, true)
		THEN --{
			IF rec.cfg ->> 'type' != 'lineal' THEN --{
				RAISE EXCEPTION 'Disallowing crossings is not supported for % layers (%.%)',
					rec.cfg ->> 'type', tabname, rec.cfg ->> 'name';
			END IF; --}
			RAISE WARNING 'Disallowing crossings for % layer %.% not implemented yet',
				rec.cfg ->> 'type', tabname, rec.cfg ->> 'name';
		END IF; --}

		IF NOT COALESCE( (rec.cfg ->> 'allow_gaps')::boolean, true)
		THEN --{
			PERFORM topo_update.add_all_topo_primitive_used_constraint(
				tabname::regclass,
				rec.cfg ->> 'name'
			);
		END IF; --}

	END LOOP; --}



	RETURN tabname::regclass;

END;
$_$;



--
-- Name: _app_createschema_table_attribute(jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_createschema_table_attribute(attconfig jsonb) RETURNS text
    LANGUAGE plpgsql
    AS $$ --{
DECLARE
	attname NAME;
	atttype NAME;
	sql TEXT;
	def_json JSONB;
	def_type TEXT;
	rec RECORD;
BEGIN

	-- atttype := format('%s', (attconfig ->> 'type')::regtype);
	atttype := attconfig ->> 'type';
	IF atttype = 'integer' THEN
		atttype = 'int4'; -- or quoting it will fail
	ELSIF atttype = 'smallint' THEN
		atttype = 'int2'; -- or quoting it will fail
	ELSIF atttype ilike 'geometry(%' THEN
		atttype = 'geometry'; -- or quoting it will fail
	END IF;

	sql := format('%I %I',
		attconfig ->> 'name',
		atttype
	);

	-- Attribute modifiers
	IF attconfig ? 'modifiers' THEN --{
		sql := format('%s (%s)',
			sql,
			(SELECT array_to_string(array_agg(quote_literal(x)), ',')
				FROM jsonb_array_elements_text(attconfig -> 'modifiers') x )
		);
	END IF; --}

	-- Attribute default
	def_json := attconfig -> 'default';
	IF def_json IS NOT NULL THEN --{
		IF jsonb_typeof(def_json) = 'object'
		THEN --{{
			-- Array of literal values
			def_type := def_json ->> 'type';
			IF def_type IS NULL THEN
				RAISE EXCEPTION 'Missing "type" from attribute default object %', def_json;
			END IF;
			IF def_type = 'function' THEN --{
				IF NOT def_json ? 'name' THEN
					RAISE EXCEPTION 'Missing "name" from attribute default function object %', def_json;
				END IF;
				sql := format('%s DEFAULT %I()',
					sql,
					def_json ->> 'name'
				);
			END IF; --}
		ELSIF jsonb_typeof(def_json) = 'array' THEN --}{
			-- Array of literal values
			sql := format('%s DEFAULT ( %s )',
				sql,
				(SELECT array_to_string(array_agg(quote_literal(x)), ',')
					FROM jsonb_array_elements_text(def_json) x )
			);
		ELSE --}{
			-- Literal value
			sql := format('%s DEFAULT %L',
				sql,
				def_json #>> '{}'
			);
		END IF; --}}
	END IF; --}

-- STRIP -- 	RAISE DEBUG 'ATT: %', sql;


	RETURN sql;
END;
$$;



--
-- Name: _app_createschema_view(name, jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_createschema_view(appname name, viewconfig jsonb) RETURNS regclass
    LANGUAGE plpgsql
    AS $_$ --{
DECLARE
	viewname NAME;
	viewdef TEXT;
	sql TEXT;
	sql_att TEXT;
	sql_attlist TEXT[];
	rec RECORD;
	attsql TEXT[];
	pkey NAME;
BEGIN

	viewname := viewconfig ->> 'name';
	IF viewname IS NULL THEN
		RAISE EXCEPTION 'Missing "name" in view config %', viewconfig;
	END IF;

	viewdef := viewconfig ->> 'definition';
	IF viewdef IS NULL THEN
		RAISE EXCEPTION 'Missing "definition" in view config %', viewconfig;
	END IF;

-- STRIP -- 	RAISE DEBUG 'Should create view %', viewname;


	sql := format('CREATE VIEW %1$I AS %2$s', viewname, viewdef);

-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;

	EXECUTE sql;

	RETURN viewname::regclass;

END;
$_$;



--
-- Name: _app_do_addborder_dynamic(name, jsonb, jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_addborder_dynamic(appname name, appconfig jsonb, border jsonb) RETURNS text
    LANGUAGE plpgsql
    AS $$ --{
DECLARE
	cfg_borderLayer JSONB;
	cfg_borderLayerTable JSONB;
	cfg_op JSONB;
	cfg_op_params JSONB;
	cfg JSONB;
	borderLayerTable REGCLASS;
	borderLayerGeomColumn NAME;
	borderLayerIdColumn NAME;
	snapTolerance FLOAT8;
	border_geom GEOMETRY;
	border_is_multiline BOOLEAN;
	rec RECORD;
	colMap JSONB;
	borderID TEXT;
BEGIN

	RAISE NOTICE 'AddBorder operation is deprecated, consider using AddPath';

	-- Check if the operation is enabled
	IF NOT appconfig -> 'operations' ? 'AddBorder' THEN
		RAISE EXCEPTION 'AddBorder operation not enabled for application %', appname;
	END IF;

	cfg_borderLayer := appconfig -> 'border_layer';

-- STRIP -- 	--RAISE DEBUG 'borderLayer: %', cfg_borderLayer;


	FOR rec IN SELECT jsonb_array_elements( appconfig -> 'tables' ) cfg
	LOOP --{
		IF rec.cfg ->> 'name' = cfg_borderlayer ->> 'table_name' THEN
			cfg_borderLayerTable := rec.cfg;
			EXIT;
		END IF;
	END LOOP; --}

-- STRIP -- 	--RAISE DEBUG 'borderLayerTable: %', cfg_borderLayerTable;


	borderLayerTable := ( appname || '.' || ( cfg_borderlayer ->> 'table_name' ) );
	borderLayerGeomColumn := cfg_borderlayer ->> 'geo_column';
	borderLayerIdColumn := cfg_borderlayerTable ->> 'primary_key';

	-- Set parameters defaults
	snapTolerance := 0;

	-- Read parameters defaults from appconfig
	cfg_op_params := appconfig -> 'operations' -> 'AddBorder' -> 'parameters';
	IF cfg_op_params IS NOT NULL THEN --{

		-- Read snapTolerance from config, if found
		cfg := cfg_op_params -> 'snapTolerance';
		IF cfg ? 'units' THEN
			snapTolerance := cfg -> 'units';
			IF cfg -> 'unitsAreMeters' THEN
				RAISE EXCEPTION 'Specifying snapTolerance in meters is unsupported';
			END IF;
		END IF;

	END IF; --}

-- STRIP --     RAISE DEBUG 'snapTolerance: %', snapTolerance;



	-- Validate border geometry,
    border_geom := ST_GeomFromGeoJSON(border -> 'geometry');
	IF border_geom IS NULL THEN
		RAISE EXCEPTION 'Missing geometry in border';
	END IF;

	IF ST_GeometryType(border_geom) = 'ST_MultiLineString' THEN
		IF ST_NumGeometries(border_geom) > 1 THEN
			border_is_multiline := true;
		END IF;
	ELSIF ST_GeometryType(border_geom) = 'ST_LineString' THEN
		border_is_multiline := false;
	ELSE
		RAISE EXCEPTION 'Border must be either LineString or MultiLineString, is % instead', ST_GeometryType(border_geom);
	END IF;

-- STRIP -- 	--RAISE DEBUG 'Border is multiline ? %', border_is_multiline;

-- STRIP -- 	--RAISE DEBUG 'Border geom is %', ST_AsEWKT(border_geom);


	-- TODO: get colmap
	--colMap := ...

	SELECT id FROM topo_update.insert_feature(
		border_geom,
		border -> 'properties',

		borderLayerTable,
		borderLayerGeomColumn,
		borderLayerIdColumn,

		colMap,

		snapTolerance
	)
	INTO borderID;

	return borderID;

END;
$$;



--
-- Name: _app_do_addborderssplitsurface_colmapprovider(character, character, jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_addborderssplitsurface_colmapprovider(typ character, act character, usr jsonb) RETURNS jsonb
    LANGUAGE plpgsql
    AS $$ --{
DECLARE
	map JSONB;
	typData JSONB;
    typmap JSONB := '{"S": "Surface", "B": "Border"}';
    actmap JSONB := '{"M": "modified", "S": "split", "C": "new"}';
	props JSONB := usr -> 'properties';
	jsk TEXT[];
	rec RECORD;
BEGIN

	IF typ = 'S' THEN
		typData := usr -> 'surface';
	ELSE
		typData := usr -> 'border';
	END IF;

	map := topo_update.json_col_map_from_pg(
		typData ->> 'table',
		ARRAY[
			typData ->> 'idcol',
			typData ->> 'geomcol'
		]
	);
-- STRIP -- 	--RAISE DEBUG '-map for % %: %', actmap ->> act, typmap ->> typ, jsonb_pretty(map);


	-- For each element of map, prepend to the json array
	-- the (type,act) array
	FOR rec IN SELECT jsonb_object_keys(map) k
	LOOP --{

		jsk := array_agg(x) FROM jsonb_array_elements_text(map -> rec.k) x;

-- STRIP -- 		--RAISE DEBUG 'XXX- map k:% = %', rec.k, jsk;

		jsk := ARRAY[
				typmap ->> typ,
				actmap ->> act
			] || jsk;
-- STRIP -- 		--RAISE DEBUG 'XXX+ map k:% = %', rec.k, jsk;


		IF props #> jsk IS NULL THEN
-- STRIP -- 			--RAISE DEBUG 'props do not contain % element, dropping mapping for it', jsk;

			map := map - rec.k;
		ELSE
			map := jsonb_set(map, ARRAY[rec.k], to_jsonb(jsk));
		END IF;
	END LOOP; --}

-- STRIP -- 	--RAISE DEBUG '+map for % %: %', actmap ->> act, typmap ->> typ, jsonb_pretty(map);


	RETURN map;
END;
$$;



--
-- Name: _app_do_addborderssplitsurface_minareameterstotopounits(name, jsonb, jsonb, double precision); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_addborderssplitsurface_minareameterstotopounits(appname name, appconfig jsonb, borderset jsonb, aream2 double precision) RETURNS double precision
    LANGUAGE plpgsql
    AS $$ --{
DECLARE
	area FLOAT8;
	geom geometry;
	geog geography;
	topoSRID INT;
	topoProj4Text TEXT;
	topoUnits TEXT;
	topoToMeter TEXT;
	topoProj TEXT;
BEGIN

	-- Find topo units
	topoSRID := appconfig -> 'topology' ->> 'srid';
	IF topoSRID IS NULL THEN
		-- should we fetch from actual topology otherwise ?
		RAISE EXCEPTION 'Topology SRID must be defined in appconfig';
	END IF;

	-- Find topo proj4text
	SELECT proj4text
	FROM spatial_ref_sys
	WHERE srid = topoSRID
	INTO topoProj4Text;

	topoUnits := (regexp_match(topoProj4Text, '\+units=([^ ]*) '))[1];
	IF topoUnits IS NOT NULL THEN --{

		-- If topo units are already meters we can return immediately
		IF topoUnits = 'm' THEN
			RETURN areaM2;
		END IF;

		-- If topo units have known conversion to meters,
		-- we will be able to convert directly
		IF topoUnits = 'us-ft' THEN
			topoToMeter := '0.3048006096';
		ELSIF topoUnits = 'ft' THEN
			topoToMeter := '0.3048';
		ELSE
			RAISE EXCEPTION 'Unsupported conversion from square meters to % units, used by topology', topoUnits;
		END IF;

	ELSE --}{

		-- Check if the projection defines an explicit conversion to meters
		topoToMeter := (regexp_match(topoProj4Text, '\+to_meter=([^ ]*) '))[1];

	END IF; --}

	-- If we found a known conversion to meters, we go for it
	IF topoToMeter IS NOT NULL THEN
		RETURN areaM2 * topoToMeter * topoToMeter;
	END IF;


	-- Being there no direct conversion, we should be
	-- using a latlong projection, let's check

	topoProj := (regexp_match(topoProj4Text, '\+proj=([^ ]*) '))[1];
	IF topoProj != 'longlat' THEN
		RAISE EXCEPTION 'Unsupported topology projection for using square meters: %', topoProj;
	END IF;

	-- As topology is using latlong we'll need to
	-- return an area (in square degrees) which may
	-- be different based on the latitude of the
	-- area we are dealing with.
	--

    -- Extract input geometry
    geom := ST_GeomFromGeoJSON(borderset -> 'geometry');

	-- Pick point with highest latitude/longitude values
	geom := ST_PointN(
		ST_BoundingDiagonal(
			geom
		),
		1
	);
	-- Make sure we're in latlon projection, which
	-- is required for _ST_BestSRID to work
	geom := ST_Transform(geom, topoSRID);
	-- Switch to metrical units projection
	geom := ST_Transform(geom, _ST_BestSRID(geom));
	-- Build a rectangle of ~200 square meters around the geometry's highest lat/lon value
	--geom := ST_Buffer(geom, sqrt(200/PI()), 16);
	geom := ST_Expand(geom, sqrt(areaM2)/2.0);
	-- TODO: densify the geometry to have less distortion upon projecting ?
	RAISE NOTICE 'Built geom area in square meters: % (% targeted)', ST_Area(geom), areaM2;
	-- Switch back to latlon (topology) CRS (shall we query it rather than hardcoding it?)
	geom := ST_Transform(geom, topoSRID);
	-- Compute area in target topology SRID
	RETURN ST_Area(geom);

END;
$$;



--
-- Name: _app_do_addborderssplitsurfaces_dynamic(name, jsonb, jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_addborderssplitsurfaces_dynamic(appname name, appconfig jsonb, borderset jsonb) RETURNS TABLE(fid text, typ character, act character, frm text)
    LANGUAGE plpgsql
    AS $$ --{
DECLARE
	cfg_surfaceLayer JSONB;
	cfg_surfaceLayerTable JSONB;
	cfg_borderLayer JSONB;
	cfg_borderLayerTable JSONB;
	cfg_op JSONB;
	cfg_op_params JSONB;
	cfg JSONB;
	surfaceLayerTable REGCLASS;
	surfaceLayerGeomColumn NAME;
	surfaceLayerIdColumn NAME;
	borderLayerTable REGCLASS;
	borderLayerGeomColumn NAME;
	borderLayerIdColumn NAME;
	snapTolerance FLOAT8;
	minToleratedFaceArea FLOAT8;
	maxAllowedSplitSurfaceCount INT;
	maxAllowedNewSurfaceCount INT;
	rec RECORD;
	borderset_geom GEOMETRY;
	borderset_polygonal GEOMETRY;
	borderset_is_multiline BOOL;
	behaviourType TEXT;
BEGIN

	-- Check if the operation is enabled
	IF NOT appconfig -> 'operations' ? 'AddBordersSplitSurfaces' THEN
		RAISE EXCEPTION 'AddBordersSplitSurfaces operation not enabled for application %', appname;
	END IF;

	cfg_surfaceLayer := appconfig -> 'surface_layer';
	cfg_borderLayer := appconfig -> 'border_layer';

-- STRIP -- 	--RAISE DEBUG 'surfacelayer: %', cfg_surfaceLayer;

-- STRIP -- 	--RAISE DEBUG 'borderLayer: %', cfg_borderLayer;


	FOR rec IN SELECT jsonb_array_elements( appconfig -> 'tables' ) cfg
	LOOP --{
		IF rec.cfg ->> 'name' = cfg_surfacelayer ->> 'table_name' THEN
			cfg_surfaceLayerTable := rec.cfg;
		ELSIF rec.cfg ->> 'name' = cfg_borderlayer ->> 'table_name' THEN
			cfg_borderLayerTable := rec.cfg;
		END IF;
		IF cfg_borderLayerTable IS NOT NULL AND
		   cfg_surfaceLayerTable IS NOT NULL
		THEN
			EXIT;
		END IF;
	END LOOP; --}

-- STRIP -- 	--RAISE DEBUG 'surfaceLayerTable: %', cfg_surfaceLayerTable;

-- STRIP -- 	--RAISE DEBUG 'borderLayerTable: %', cfg_borderLayerTable;


	surfaceLayerTable := ( appname || '.' || ( cfg_surfaceLayer ->> 'table_name' ) );
	surfaceLayerGeomColumn := cfg_surfacelayer ->> 'geo_column';
	surfaceLayerIdColumn := cfg_surfacelayerTable ->> 'primary_key';

	borderLayerTable := ( appname || '.' || ( cfg_borderlayer ->> 'table_name' ) );
	borderLayerGeomColumn := cfg_borderlayer ->> 'geo_column';
	borderLayerIdColumn := cfg_borderlayerTable ->> 'primary_key';

	-- Set parameters defaults
	snapTolerance := 0;
	minToleratedFaceArea := 0;
	maxAllowedSplitSurfaceCount := 5;

	-- Validate borderset geometry,
    borderset_geom := ST_GeomFromGeoJSON(borderset -> 'geometry');
	IF borderset_geom IS NULL THEN
		RAISE EXCEPTION 'Missing geometry in borderset';
	END IF;

	IF ST_GeometryType(borderset_geom) = 'ST_MultiLineString' THEN
		IF ST_NumGeometries(borderset_geom) > 1 THEN
			borderset_is_multiline := true;
		END IF;
	ELSIF ST_GeometryType(borderset_geom) = 'ST_LineString' THEN
		borderset_is_multiline := false;
	ELSE
		RAISE EXCEPTION 'Borderset must be either LineString or MultiLineString, is % instead', ST_GeometryType(borderset_geom);
	END IF;

-- STRIP -- 	--RAISE DEBUG 'Borderset is multiline ? %', borderset_is_multiline;


-- STRIP -- 	--RAISE DEBUG 'Borderset geom is %', ST_AsText(borderset_geom);


	-- Analyze borderset geometry to determine behaviour
	borderset_polygonal := ST_BuildArea(ST_UnaryUnion(borderset_geom));
	IF borderset_polygonal IS NULL THEN
-- STRIP -- 		-- RAISE DEBUG 'Borderset does NOT form rings';

		-- Lines do not form a ring
		behaviourType := 'forOpenLines';
	ELSE
-- STRIP -- 		-- RAISE DEBUG 'Borderset form rings';

		IF borderset_is_multiline THEN
			RAISE EXCEPTION 'Invalid borderset: multiple lines cannot form rings, use single line for that';
		END IF;
		behaviourType := 'forClosedLines';
		-- TODO: rewrite borderset with just the boundary of the found area ?
	END IF;

	cfg_op := appconfig -> 'operations' -> 'AddBordersSplitSurfaces' -> 'parameters';
-- STRIP -- 	--RAISE DEBUG 'XXX behaviourType:%, params:%', behaviourType, jsonb_pretty(cfg_op);

	IF cfg_op IS NOT NULL THEN --{

		-- Read parameters from appconfig
		cfg_op_params :=
			COALESCE(cfg_op -> 'default', '{}')
			||
			COALESCE(cfg_op -> behaviourType, '{}')
		;
	END IF; --}

-- STRIP -- 	--RAISE DEBUG 'XXX Operation configuration (behavior %): %', behaviourType, jsonb_pretty(cfg_op_params);


	-- Read parameters defaults from appconfig
	IF cfg_op_params IS NOT NULL THEN --{
		-- Read minAllowedNewSurfaceArea from config, if found
		cfg := cfg_op_params -> 'minAllowedNewSurfacesArea';
		IF cfg ? 'units' THEN
			minToleratedFaceArea := cfg -> 'units';
			IF cfg -> 'unitsAreMeters' THEN
				minToleratedFaceArea = topo_update._app_do_AddBordersSplitSurface_minAreaMetersToTopoUnits(appname, appconfig, borderset, minToleratedFaceArea);
			END IF;
		END IF;

		-- Read snapTolerance from config, if found
		cfg := cfg_op_params -> 'snapTolerance';
		IF cfg ? 'units' THEN
			snapTolerance := cfg -> 'units';
			IF cfg -> 'unitsAreMeters' THEN
				RAISE EXCEPTION 'Specifying snapTolerance in meters is unsupported';
			END IF;
		END IF;

		-- Read maxAllowedSplitSurfaceCount from config, if found
		cfg := cfg_op_params;
		IF cfg ? 'maxAllowedSplitSurfacesCount' THEN
			maxAllowedSplitSurfaceCount = cfg ->> 'maxAllowedSplitSurfacesCount';
		END IF;

		-- Read maxAllowedNewSurfaceCount from config, if found
		cfg := cfg_op_params;
		IF cfg ? 'maxAllowedNewSurfacesCount' THEN
			maxAllowedNewSurfaceCount = cfg ->> 'maxAllowedNewSurfacesCount';
		END IF;
	END IF; --}

-- STRIP -- 	RAISE DEBUG 'snapTolerance: %', snapTolerance;

-- STRIP -- 	RAISE DEBUG 'minToleratedFaceArea: %', minToleratedFaceArea;

-- STRIP -- 	RAISE DEBUG 'maxAllowedSplitSurfaceCount: %', maxAllowedSplitSurfaceCount;



	RETURN QUERY
	SELECT * FROM topo_update.add_border_split_surface(
		borderset,
		surfaceLayerTable,
		surfaceLayerGeomColumn,
		surfaceLayerIdColumn,
		borderLayerTable,
		borderLayerGeomColumn,
		borderLayerIdColumn,
		snapTolerance,
		'topo_update._app_do_AddBordersSplitSurface_ColMapProvider'::regproc,
		jsonb_build_object(
			'properties', borderset -> 'properties',
			'surface', jsonb_build_object(
				'table', surfaceLayerTable,
				'geomcol', surfaceLayerGeomColumn,
				'idcol', surfaceLayerIdColumn
			),
			'border', jsonb_build_object(
				'table', borderLayerTable,
				'geomcol', borderLayerGeomColumn,
				'idcol', borderLayerIdColumn
			)
		),
		minToleratedFaceArea,
		maxAllowedSplitSurfaceCount,
		maxAllowedNewSurfaceCount
	);

END;
$$;



--
-- Name: _app_do_addpath_colmapprovider(character, jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

