		]
	);
-- STRIP -- 	--RAISE DEBUG '-map for %: %', actmap ->> act, jsonb_pretty(map);


	-- For each element of map, prepend to the json array
	-- the (type,act) array
	FOR rec IN SELECT jsonb_object_keys(map) k
	LOOP --{

		jsk := array_agg(x) FROM jsonb_array_elements_text(map -> rec.k) x;

-- STRIP -- 		--RAISE DEBUG 'XXX- map k:% = %', rec.k, jsk;

		jsk := ARRAY[
				actmap ->> act
			] || jsk;
-- STRIP -- 		--RAISE DEBUG 'XXX+ map k:% = %', rec.k, jsk;


		IF props #> jsk IS NULL THEN
-- STRIP -- 			--RAISE DEBUG 'props do not contain % element, dropping mapping for it', jsk;

			map := map - rec.k;
		ELSE
			map := jsonb_set(map, ARRAY[rec.k], to_jsonb(jsk));
		END IF;
