--
-- Name: _app_do_addpath_dynamic(name, jsonb, jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_addpath_dynamic(appname name, appconfig jsonb, path jsonb) RETURNS TABLE(fid text, act character, frm text)
    LANGUAGE plpgsql
    AS $$ --{
DECLARE
	cfg_pathLayer JSONB;
	cfg_pathLayerTable JSONB;
	cfg_op JSONB;
	cfg_op_params JSONB;
	cfg JSONB;
	pathLayerTable REGCLASS;
	pathLayerGeomColumn NAME;
	pathLayerIdColumn NAME;
	snapTolerance FLOAT8;
	minAllowedPathLength FLOAT8;
	path_geom GEOMETRY;
	path_is_multiline BOOLEAN;
	rec RECORD;
	colMap JSONB;
	pathID TEXT;
BEGIN

	-- Check if the operation is enabled
	IF NOT appconfig -> 'operations' ? 'AddPath' THEN
		RAISE EXCEPTION 'AddPath operation not enabled for application %', appname;
	END IF;

	cfg_pathLayer := appconfig -> 'path_layer';

-- STRIP -- 	--RAISE DEBUG 'pathLayer: %', cfg_pathLayer;


	FOR rec IN SELECT jsonb_array_elements( appconfig -> 'tables' ) cfg
	LOOP --{
		IF rec.cfg ->> 'name' = cfg_pathlayer ->> 'table_name' THEN
			cfg_pathLayerTable := rec.cfg;
			EXIT;
		END IF;
	END LOOP; --}

-- STRIP -- 	--RAISE DEBUG 'pathLayerTable: %', cfg_pathLayerTable;


	pathLayerTable := ( appname || '.' || ( cfg_pathlayer ->> 'table_name' ) );
	pathLayerGeomColumn := cfg_pathlayer ->> 'geo_column';
	pathLayerIdColumn := cfg_pathlayerTable ->> 'primary_key';

	-- Set parameters defaults
	snapTolerance := 0;
	minAllowedPathLength := 0;

	-- Read parameters defaults from appconfig
	cfg_op_params := appconfig -> 'operations' -> 'AddPath' -> 'parameters';
	IF cfg_op_params IS NOT NULL THEN --{

		-- Read snapTolerance from config, if found
		cfg := cfg_op_params -> 'snapTolerance';
		IF cfg ? 'units' THEN
			snapTolerance := cfg -> 'units';
			IF cfg -> 'unitsAreMeters' THEN
				RAISE EXCEPTION 'Specifying snapTolerance in meters is unsupported';
			END IF;
		END IF;

		-- Read minAllowedPathLength from config, if found
		cfg := cfg_op_params -> 'minAllowedPathLength';
		IF cfg ? 'units' THEN
			minAllowedPathLength := cfg -> 'units';
			IF cfg -> 'unitsAreMeters' THEN
				minAllowedPathLength = topo_update._app_do_AddPath_minLengthMetersToTopoUnits(appname, appconfig, path, minAllowedPathLength);
			END IF;
		END IF;

	END IF; --}

-- STRIP --     RAISE DEBUG 'snapTolerance: %', snapTolerance;

-- STRIP --     RAISE DEBUG 'minAllowedPathLength: %', minAllowedPathLength;


	RETURN QUERY
	SELECT * FROM topo_update.add_path(
		path,

		pathLayerTable,
		pathLayerGeomColumn,
		pathLayerIdColumn,

		'topo_update._app_do_AddPath_ColMapProvider'::regproc,
		jsonb_build_object(
			'properties', path -> 'properties',
			'path', jsonb_build_object(
				'table', pathLayerTable,
				'geomcol', pathLayerGeomColumn,
				'idcol', pathLayerIdColumn
			)
		),

		snapTolerance,
		minAllowedPathLength
	);

END;
$$;



--
-- Name: _app_do_addpath_minlengthmeterstotopounits(name, jsonb, jsonb, double precision); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_addpath_minlengthmeterstotopounits(appname name, appconfig jsonb, pathset jsonb, lenm double precision) RETURNS double precision
    LANGUAGE plpgsql
    AS $$ --{
DECLARE
	area FLOAT8;
	geom geometry;
	geog geography;
	topoSRID INT;
	topoProj4Text TEXT;
	topoUnits TEXT;
	topoToMeter TEXT;
	topoProj TEXT;
BEGIN

	-- Find topo units
	topoSRID := appconfig -> 'topology' ->> 'srid';
	IF topoSRID IS NULL THEN
		-- should we fetch from actual topology otherwise ?
		RAISE EXCEPTION 'Topology SRID must be defined in appconfig';
	END IF;

	-- Find topo proj4text
	SELECT proj4text
	FROM spatial_ref_sys
	WHERE srid = topoSRID
	INTO topoProj4Text;

	topoUnits := (regexp_match(topoProj4Text, '\+units=([^ ]*) '))[1];
	IF topoUnits IS NOT NULL THEN --{

		-- If topo units are already meters we can return immediately
		IF topoUnits = 'm' THEN
			RETURN lenM;
		END IF;

		-- If topo units have known conversion to meters,
		-- we will be able to convert directly
		IF topoUnits = 'us-ft' THEN
			topoToMeter := '0.3048006096';
		ELSIF topoUnits = 'ft' THEN
			topoToMeter := '0.3048';
		ELSE
			RAISE EXCEPTION 'Unsupported conversion from meters to % units, used by topology', topoUnits;
		END IF;

	ELSE --}{

		-- Check if the projection defines an explicit conversion to meters
		topoToMeter := (regexp_match(topoProj4Text, '\+to_meter=([^ ]*) '))[1];

	END IF; --}

	-- If we found a known conversion to meters, we go for it
	IF topoToMeter IS NOT NULL THEN
		RETURN lenM * topoToMeter;
	END IF;


	-- Being there no direct conversion, we should be
	-- using a latlong projection, let's check

	topoProj := (regexp_match(topoProj4Text, '\+proj=([^ ]*) '))[1];
	IF topoProj != 'longlat' THEN
		RAISE EXCEPTION 'Unsupported topology projection for using square meters: %', topoProj;
	END IF;

	-- As topology is using latlong we'll need to
	-- return an area (in square degrees) which may
	-- be different based on the latitude of the
	-- area we are dealing with.
	--

    -- Extract input geometry
    geom := ST_GeomFromGeoJSON(pathset -> 'geometry');

	-- Pick point with highest latitude/longitude values
	geom := ST_PointN(
		ST_BoundingDiagonal(
			geom
		),
		1
	);
	-- Make sure we're in latlon projection, which
	-- is required for _ST_BestSRID to work
	geom := ST_Transform(geom, topoSRID);
	-- Switch to metrical units projection
	geom := ST_Transform(geom, _ST_BestSRID(geom));
	-- Build a line of lenM meters around the geometry's highest lat/lon value
	--geom := ST_Buffer(geom, sqrt(200/PI()), 16);
	geom := ST_MakeLine(geom, ST_Translate(geom, lenM, 0));
	-- TODO: densify the geometry to have less distortion upon projecting ?
	RAISE NOTICE 'Built geom length in meters: % (% targeted)', ST_Length(geom), lenM;
	-- Switch back to latlon (topology) CRS (shall we query it rather than hardcoding it?)
	geom := ST_Transform(geom, topoSRID);
	-- Compute area in target topology SRID
	RETURN ST_Length(geom);

END;
$$;



--
-- Name: _app_do_addpoint_dynamic(name, jsonb, jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_addpoint_dynamic(appname name, appconfig jsonb, point jsonb) RETURNS text
    LANGUAGE plpgsql
    AS $$ --{
DECLARE
	cfg_pointLayer JSONB;
	cfg_pointLayerTable JSONB;
	cfg_op JSONB;
	cfg_op_params JSONB;
	cfg JSONB;
	pointLayerTable REGCLASS;
	pointLayerGeomColumn NAME;
	pointLayerIdColumn NAME;
	snapTolerance FLOAT8;
	point_geom GEOMETRY;
	rec RECORD;
	colMap JSONB;
	pointID TEXT;
BEGIN

	-- Check if the operation is enabled
	IF NOT appconfig -> 'operations' ? 'AddPoint' THEN
		RAISE EXCEPTION 'AddPoint operation not enabled for application %', appname;
	END IF;

	cfg_pointLayer := appconfig -> 'point_layer';

-- STRIP -- 	--RAISE DEBUG 'pointLayer: %', cfg_pointLayer;


	FOR rec IN SELECT jsonb_array_elements( appconfig -> 'tables' ) cfg
	LOOP --{
		IF rec.cfg ->> 'name' = cfg_pointlayer ->> 'table_name' THEN
			cfg_pointLayerTable := rec.cfg;
			EXIT;
		END IF;
	END LOOP; --}

-- STRIP -- 	--RAISE DEBUG 'pointLayerTable: %', cfg_pointLayerTable;


	pointLayerTable := ( appname || '.' || ( cfg_pointlayer ->> 'table_name' ) );
	pointLayerGeomColumn := cfg_pointlayer ->> 'geo_column';
	pointLayerIdColumn := cfg_pointlayerTable ->> 'primary_key';

	-- Set parameters defaults
	snapTolerance := 0;

	-- Read parameters defaults from appconfig
	cfg_op_params := appconfig -> 'operations' -> 'AddPoint';
	IF cfg_op_params IS NOT NULL THEN --{

		-- Read snapTolerance from config, if found
		cfg := cfg_op_params -> 'snapTolerance';
		IF cfg ? 'units' THEN
			snapTolerance := cfg -> 'units';
			IF cfg -> 'unitsAreMeters' THEN
				RAISE EXCEPTION 'Specifying snapTolerance in meters is unsupported';
			END IF;
		END IF;

	END IF; --}

-- STRIP --     RAISE DEBUG 'snapTolerance: %', snapTolerance;



	-- Validate point geometry,
	point_geom := ST_GeomFromGeoJSON(point -> 'geometry');
	IF point_geom IS NULL THEN
		RAISE EXCEPTION 'Missing geometry in point';
	END IF;

	IF ST_GeometryType(point_geom) != 'ST_Point' THEN
		RAISE EXCEPTION 'Point must be Point, is % instead', ST_GeometryType(point_geom);
	END IF;

	-- Build colmap
	colMap := topo_update.json_col_map_from_pg(
		pointLayerTable,
		ARRAY[
			pointLayerIdColumn::text,
			pointLayerGeomColumn
		]
	);
-- STRIP -- 	-- RAISE DEBUG 'Col map: %', jsonb_pretty(colMap);


	SELECT id FROM topo_update.insert_feature(
		point_geom,
		point -> 'properties',

		pointLayerTable,
		pointLayerGeomColumn,
		pointLayerIdColumn,

		colMap,

		snapTolerance
	)
	INTO pointID;

	return pointID;

END;
$$;



--
-- Name: _app_do_addsurface_dynamic(name, jsonb, jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_addsurface_dynamic(appname name, appconfig jsonb, surface jsonb) RETURNS text
    LANGUAGE plpgsql
    AS $$ --{
DECLARE
	cfg_surfaceLayer JSONB;
	cfg_surfaceLayerTable JSONB;
	cfg_op JSONB;
	cfg_op_params JSONB;
	cfg JSONB;
	surfaceLayerTable REGCLASS;
	surfaceLayerGeomColumn NAME;
	surfaceLayerIdColumn NAME;
	snapTolerance FLOAT8;
	surface_geom GEOMETRY;
	surface_is_multi BOOLEAN;
	rec RECORD;
	colMap JSONB;
	surfaceID TEXT;
BEGIN

	-- Check if the operation is enabled
	IF NOT appconfig -> 'operations' ? 'AddSurface' THEN
		RAISE EXCEPTION 'AddSurface operation not enabled for application %', appname;
	END IF;

	cfg_surfaceLayer := appconfig -> 'surface_layer';

-- STRIP -- 	--RAISE DEBUG 'surfaceLayer: %', cfg_surfaceLayer;


	FOR rec IN SELECT jsonb_array_elements( appconfig -> 'tables' ) cfg
	LOOP --{
		IF rec.cfg ->> 'name' = cfg_surfacelayer ->> 'table_name' THEN
			cfg_surfaceLayerTable := rec.cfg;
			EXIT;
		END IF;
	END LOOP; --}

-- STRIP -- 	--RAISE DEBUG 'surfaceLayerTable: %', cfg_surfaceLayerTable;


	surfaceLayerTable := ( appname || '.' || ( cfg_surfacelayer ->> 'table_name' ) );
	surfaceLayerGeomColumn := cfg_surfacelayer ->> 'geo_column';
	surfaceLayerIdColumn := cfg_surfacelayerTable ->> 'primary_key';

	-- Set parameters defaults
	snapTolerance := 0;

	-- Read parameters defaults from appconfig
	cfg_op_params := appconfig -> 'operations' -> 'AddSurface' -> 'parameters';
	IF cfg_op_params IS NOT NULL THEN --{

		-- Read snapTolerance from config, if found
		cfg := cfg_op_params -> 'snapTolerance';
		IF cfg ? 'units' THEN
			snapTolerance := cfg -> 'units';
			IF cfg -> 'unitsAreMeters' THEN
				RAISE EXCEPTION 'Specifying snapTolerance in meters is unsupported';
			END IF;
		END IF;

	END IF; --}

-- STRIP --     RAISE DEBUG 'snapTolerance: %', snapTolerance;



	-- Validate surface geometry,
    surface_geom := ST_GeomFromGeoJSON(surface -> 'geometry');
	IF surface_geom IS NULL THEN
		RAISE EXCEPTION 'Missing geometry in surface';
	END IF;

	IF ST_GeometryType(surface_geom) = 'ST_MultiPolygon' THEN
		IF ST_NumGeometries(surface_geom) > 1 THEN
			surface_is_multi := true;
		END IF;
	ELSIF ST_GeometryType(surface_geom) = 'ST_Polygon' THEN
		surface_is_multi := false;
	ELSE
		RAISE EXCEPTION 'Surface must be either Polygon or MultiPolygon, is % instead', ST_GeometryType(surface_geom);
	END IF;

-- STRIP -- 	--RAISE DEBUG 'Surface is multi ? %', surface_is_multi;

-- STRIP -- 	--RAISE DEBUG 'Surface geom is %', ST_AsEWKT(surface_geom);


	-- TODO: get colmap
	--colMap := ...

	SELECT id FROM topo_update.insert_feature(
		surface_geom,
		surface -> 'properties',

		surfaceLayerTable,
		surfaceLayerGeomColumn,
		surfaceLayerIdColumn,

		colMap,

		snapTolerance
	)
	INTO surfaceID;

	return surfaceID;

END;
$$;



--
-- Name: _app_do_getfeaturesastopojson_defaultroles(jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_getfeaturesastopojson_defaultroles(cfg_operation jsonb) RETURNS text[]
    LANGUAGE plpgsql
    AS $$
DECLARE
	roles_supported TEXT[];
	roles_default TEXT[];
BEGIN

	IF cfg_Operation -> 'default_roles' IS NOT NULL THEN
		roles_default := array_agg(x) FROM (
			SELECT
			jsonb_array_elements_text(cfg_Operation -> 'default_roles') x
		) foo;
	ELSE
		roles_default := ARRAY[ 'border_layer', 'surface_layer', 'path_layer', 'point_layer' ];
	END IF;

	return roles_default;
END;
$$;



--
-- Name: _app_do_getfeaturesastopojson_dynamic(name, jsonb, public.geometry); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_getfeaturesastopojson_dynamic(appname name, appconfig jsonb, bbox public.geometry) RETURNS jsonb
    LANGUAGE sql
    AS $_$
	SELECT topo_update._app_do_GetFeaturesAsTopoJSON_Dynamic($1,$2,$3,0,9,NULL);
$_$;



--
-- Name: _app_do_getfeaturesastopojson_dynamic(name, jsonb, public.geometry, integer, integer, text[]); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_getfeaturesastopojson_dynamic(appname name, appconfig jsonb, bbox public.geometry, out_srid integer, max_decimal_digits integer, roles_requested text[] DEFAULT NULL::text[]) RETURNS jsonb
    LANGUAGE plpgsql
    AS $_$ --{
DECLARE
	rec RECORD;
	cfg_Operation JSONB;
	cfg_Operation_CustomRoles JSONB;
	cfg_tables JSONB;
	cfg_table JSONB;
	cfg_layer JSONB;

	ident_quoted_attnames TEXT[];
	geoms_json JSONB[];
	arcs_json JSONB[];
	nodes_json JSONB;

	srid INT;

	--attributes_json JSONB;

	role TEXT;

	sql TEXT;

	ret JSONB;

	v_cnt int;

BEGIN

	-- Check if the operation is enabled
	cfg_Operation := appconfig -> 'operations' -> 'GetFeaturesAsTopoJSON';
	IF cfg_Operation IS NULL THEN
		RAISE EXCEPTION 'GetFeaturesAsTopoJSON operation not enabled for application %', appname;
	END IF;

	cfg_Operation_CustomRoles = cfg_Operation -> 'custom_roles';

	-- Get topology info
	srid := appconfig #>> ARRAY[ 'topology', 'srid' ];

	-- Create edgemap table
	CREATE TEMP TABLE topo_update_topology_topojson_edgemap (
		arc_id serial primary key,
		edge_id int
	);
	CREATE INDEX ON topo_update_topology_topojson_edgemap(edge_id);

	cfg_tables := appconfig -> 'tables';
	IF cfg_tables IS NULL THEN
		RAISE EXCEPTION 'Config of application % is broken: missing "tables" element', appname;
	END IF;

	IF roles_requested IS NULL THEN
		roles_requested := topo_update._app_do_GetFeaturesAsTopoJSON_DefaultRoles(cfg_Operation);
-- STRIP -- 		-- RAISE DEBUG 'No roles requested explicitly, using default_roles: %', roles_requested;

	END IF;

	-- Dump intersecting features from requested layers
	-- NOTE: 'nodes' needs to be handled LAST
	FOR role IN SELECT x FROM unnest( roles_requested ) x ORDER BY x = 'nodes'
	LOOP --{
-- STRIP -- 		RAISE DEBUG 'Looking for %', role;


		--  1. Handle custom roles first, so they can override built-ins
		cfg_layer = cfg_Operation_CustomRoles -> role;
		IF cfg_layer IS NOT NULL THEN

			RAISE Debug 'Handling custom "%" role', role;

			IF NOT cfg_layer ? 'relation' THEN
				RAISE EXCEPTION 'Malformed custom role "%" in appconfig for app "%": missing "relation" attribute', role, appname;
			END IF;

			IF NOT cfg_layer ? 'primary_key' THEN
				RAISE EXCEPTION 'Malformed custom role "%" in appconfig for app "%": missing "primary_key" attribute', role, appname;
			END IF;

			IF NOT cfg_layer ? 'geo_column' THEN
				RAISE EXCEPTION 'Malformed custom role "%" in appconfig for app "%": missing "geo_column" attribute', role, appname;
			END IF;

			geoms_json = geoms_json || topo_update._app_do_GetFeaturesAsTopoJSON_getGeomsJSON_fromRelation(
				relation => format('%I.%I', appname, cfg_layer ->> 'relation'),
				pkey_column => cfg_layer ->> 'primary_key',
				geo_column => cfg_layer ->> 'geo_column',
				bbox => bbox,
				edgemap_table => 'pg_temp.topo_update_topology_topojson_edgemap',
				out_srid => out_srid,
				max_decimal_digits => max_decimal_digits,
				srid => srid
			);

			CONTINUE;
		END IF;

		--  2. Handle built-in roles
		IF role = 'nodes' THEN --{

			sql := format(
				$$
SELECT
	jsonb_concat(
		ST_AsGeoJSON(
			ST_Union(
				%3$s
				ORDER BY n.node_id
			),
			%2$s
		)::jsonb,
		jsonb_build_object(
			'properties',
			jsonb_build_object('role', 'snap-nodes')
		)
	)
FROM %1$I.node n
WHERE n.node_id = ANY (
	SELECT unnest(ARRAY[e.start_node,e.end_node])
	FROM %1$I.edge e
	JOIN pg_temp.topo_update_topology_topojson_edgemap m ON ( m.edge_id = e.edge_id )
)
				$$,
				format('%s_sysdata_webclient', appname),
				16, -- since this is used for snapping we can not limit number of decimals here to have snapping to work,
				CASE WHEN srid != out_srid THEN
					format('ST_Transform(n.geom, %s)', out_srid)
				ELSE
					'n.geom'
				END

			);

-- STRIP -- 			RAISE DEBUG 'sql: %', sql;


			EXECUTE sql INTO nodes_json;

-- STRIP -- 		--	RAISE DEBUG 'nodes: %', jsonb_pretty(nodes_json);


			IF nodes_json IS NOT NULL THEN
				geoms_json := array_append(geoms_json, nodes_json);
			END IF;


			CONTINUE;
		END IF; --}


		--  3. Handler layers
		cfg_layer = appconfig -> role;
		IF cfg_layer IS NULL THEN
			RAISE EXCEPTION 'GetFeaturesAsTopoJSON: role % is not defined in app % config', role, appname;
			CONTINUE;
		END IF;

		-- Find tables corresponding to layer
		FOR rec IN SELECT jsonb_array_elements( cfg_tables ) cfg
		LOOP
			IF rec.cfg ->> 'name' = cfg_layer ->> 'table_name' THEN
				cfg_table := rec.cfg;
				EXIT;
			END IF;
		END LOOP;

		IF cfg_table IS NULL THEN
			RAISE EXCEPTION 'App % config is broken: table "%" referenced in % not found in "tables"',
				appname,
				cfg_layer ->> 'table_name',
				role;
		END IF;

-- STRIP -- 		RAISE DEBUG 'Should dump table %.% (for layer %)',
-- STRIP -- 			cfg_table ->> 'name',
-- STRIP -- 			cfg_layer ->> 'geo_column',
-- STRIP -- 			role
-- STRIP -- 		

		-- Build array of quoted attribute names
		SELECT array_agg( quote_ident(a ->> 'name') )
		FROM (
			SELECT jsonb_array_elements( cfg_table -> 'attributes' ) a
		) foo
		INTO ident_quoted_attnames;

-- STRIP -- 		RAISE DEBUG 'Quoted att names: %', array_to_string(ident_quoted_attnames, ', ');


		geoms_json = geoms_json || topo_update._app_do_GetFeaturesAsTopoJSON_getGeomsJSON_fromRelation(
			relation => format('%I.%I', appname, cfg_table ->> 'name'),
			pkey_column => cfg_table ->> 'primary_key',
			geo_column => cfg_layer ->> 'geo_column',
			bbox => bbox,
			edgemap_table => 'pg_temp.topo_update_topology_topojson_edgemap',
			out_srid => out_srid,
			max_decimal_digits => max_decimal_digits,
			ident_quoted_attnames => ident_quoted_attnames,
			is_puntual => role = 'point_layer',
			srid => srid
		);


-- STRIP -- 		RAISE DEBUG 'geometries after %: %', role, jsonb_pretty(to_jsonb(geoms_json));


	END LOOP; --}

	-- Add arcs

	IF out_srid = 0 THEN
		out_srid = srid;
	END IF;

	sql := format(
		$$
			SELECT
					array_agg(
						ST_AsGeoJSON(%3$s, %2$s, 0)::jsonb -> 'coordinates'
						ORDER BY em.arc_id
					)
			FROM pg_temp.topo_update_topology_topojson_edgemap em
			JOIN %1$I.edge_data e ON (em.edge_id = e.edge_id)
		$$,
		format('%s_sysdata_webclient', appname), --------- %1
		max_decimal_digits, ------------------------------ %2
		CASE WHEN srid != out_srid THEN
			format('ST_Transform(e.geom, %s)', out_srid)
		ELSE
			'e.geom'
		END ---------------------------------------------- %3
	);
-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;


	EXECUTE sql INTO arcs_json;

-- STRIP -- --	RAISE DEBUG 'arcs: %', jsonb_pretty(arcs_json);


	DROP TABLE topo_update_topology_topojson_edgemap;

	-- TODO: reduce output if there are no objects ?

	ret := jsonb_build_object(
		'type', 'Topology',
		'crs', topo_update.srid_to_json_crs(out_srid),
		'objects', jsonb_build_object(
			'collection', jsonb_build_object(
				'type', 'GeometryCollection',
				'geometries', to_jsonb(geoms_json)
			)
		),
		'arcs', to_jsonb(arcs_json)
	);

	RETURN jsonb_strip_nulls(ret);

END;
$_$;



--
-- Name: _app_do_getfeaturesastopojson_getgeomsjson_fromrelation(regclass, name, name, regclass, public.geometry, integer, integer, name[], boolean, integer); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_getfeaturesastopojson_getgeomsjson_fromrelation(relation regclass, pkey_column name, geo_column name, edgemap_table regclass, bbox public.geometry, out_srid integer, max_decimal_digits integer, ident_quoted_attnames name[] DEFAULT NULL::name[], is_puntual boolean DEFAULT NULL::boolean, srid integer DEFAULT NULL::integer) RETURNS jsonb[]
    LANGUAGE plpgsql
    AS $_$ --{
DECLARE
	sql TEXT;
	geoms_json JSONB[];
BEGIN

	IF ident_quoted_attnames IS NULL THEN
		SELECT array_agg(format('%I', a.attname))
			FROM pg_catalog.pg_attribute a
			JOIN pg_catalog.pg_class c ON (a.attrelid = c.oid)
			WHERE c.oid = relation
			AND a.attnum > 0
			AND NOT a.attisdropped
			AND a.attname NOT IN ( geo_column )
		INTO ident_quoted_attnames;
-- STRIP -- 		RAISE DEBUG 'Extracted quoted attribute names from "%": %', relation, ident_quoted_attnames;

	END IF;

	IF is_puntual IS NULL THEN
		sql := format(
			'SELECT ST_Dimension(%I) = 0 FROM %s LIMIT 1',
			geo_column,
			relation
		);
		EXECUTE sql INTO is_puntual;
-- STRIP -- 		RAISE DEBUG 'Extracted puntual info from "%": %', relation, is_puntual;

	END IF;

	IF srid IS NULL THEN
		RAISE EXCEPTION 'Extracting srid from relation/geomcolumn not implemented yet';
	END IF;

	sql := format(
		$$
			SELECT
				array_agg(
					jsonb_concat(
						%2$s::jsonb,
						jsonb_build_object(
							'properties',
							to_jsonb( l )
						)
					)
					ORDER BY t.%5$I
				)
			FROM %4$s t, lateral ( SELECT %3$s ) l
			WHERE ST_Intersects(
				%1$I, $1
			)
		$$,
		geo_column, ----------------------- %1
		CASE ------------------------------ %2 {
		WHEN NOT is_puntual THEN
			format(
				'topology.AsTopoJSON(t.%1$I, %2$L)',
				geo_column,
				edgemap_table
			)
		WHEN srid != out_srid AND out_srid != 0 THEN
			format(
				'ST_AsGeoJSON(ST_Transform(t.%1$I::geometry, %2$s), %3$s, 0)',
				geo_column,
				out_srid,
				max_decimal_digits
			)
		ELSE
			format(
				'ST_AsGeoJSON(t.%1$I::geometry, %2$s, 0)',
				geo_column,
				max_decimal_digits
			)
		END, ---------------------------------------------- %2 }
		array_to_string(ident_quoted_attnames, ','), ------ %3
		relation, ----------------------------------------- %4
		pkey_column --------------------------------------- %5
	);

-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;


	EXECUTE sql USING bbox INTO geoms_json;

-- STRIP -- 	RAISE DEBUG 'geoms_json: %', geoms_json;


	RETURN geoms_json;
END;
$_$;



--
-- Name: _app_do_getfeaturesastopojson_supportedroles(jsonb, jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_getfeaturesastopojson_supportedroles(appconfig jsonb, cfg_operation jsonb) RETURNS text[]
    LANGUAGE plpgsql
    AS $$ --{
DECLARE
	known_layer_kinds TEXT[] := ARRAY[ 'border_layer', 'surface_layer', 'path_layer', 'point_layer' ];
	roles_supported TEXT[] := ARRAY[ 'nodes' ];
	cfg_Operation_CustomRoles JSONB;
BEGIN

	cfg_Operation_CustomRoles = cfg_Operation -> 'custom_roles';

	-- Add custom roles to supported roles
	roles_supported := array_agg(x) FROM (
			SELECT jsonb_object_keys(cfg_Operation_CustomRoles) x
				UNION
			SELECT unnest(roles_supported)
		) foo;

	-- Add defined layers to supported roles
	roles_supported := array_agg(x) FROM (
		SELECT jsonb_object_keys(appconfig) x
			INTERSECT
		SELECT unnest(known_layer_kinds)
	) foo;

	-- Add built-in roless
	roles_supported := roles_supported || ARRAY[ 'nodes' ];

	RETURN roles_supported;
END;
$$;



--
-- Name: _app_do_getmergeablesurfaceborders_dynamic(name, jsonb, public.geometry); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_getmergeablesurfaceborders_dynamic(appname name, appconfig jsonb, bbox public.geometry) RETURNS TABLE(border_ids text[], side_surfaces text[])
    LANGUAGE plpgsql
    AS $_$ --{
DECLARE
	cfg_surfaceLayer JSONB;
	cfg_surfaceLayerTable JSONB;
	cfg_borderLayer JSONB;
	cfg_borderLayerTable JSONB;
	cfg_op JSONB;
	cfg JSONB;
	surfaceLayerTableName NAME;
	surfaceLayerTableRegclass REGCLASS;
	surfaceLayerGeomColumn NAME;
	surfaceLayerIdColumn NAME;
	borderLayerTableName NAME;
	borderLayerTableRegclass REGCLASS;
	borderLayerGeomColumn NAME;
	borderLayerIdColumn NAME;
	rec RECORD;
	sql TEXT;
BEGIN

	-- Check if the operation is enabled
	IF NOT appconfig -> 'operations' ? 'SurfaceMerge' THEN
		RAISE EXCEPTION 'SurfaceMerge operation not enabled for application %', appname;
	END IF;

	cfg_surfaceLayer := appconfig -> 'surface_layer';
	IF cfg_surfaceLayer IS NULL THEN
		RAISE EXCEPTION 'GetMergeableSurfaceBorders operations requires missing "surface_layer" in appconfig';
	END IF;
	cfg_borderLayer := appconfig -> 'border_layer';
	IF cfg_borderLayer IS NULL THEN
		RAISE EXCEPTION 'GetMergeableSurfaceBorders operations requires missing "border_layer" in appconfig';
	END IF;
	cfg_op := appconfig -> 'operations' -> 'SurfaceMerge';

-- STRIP -- 	--RAISE DEBUG 'cfg_surfacelayer: %', cfg_surfaceLayer;

-- STRIP -- 	--RAISE DEBUG 'cfg_borderLayer: %', cfg_borderLayer;


	FOR rec IN SELECT jsonb_array_elements( appconfig -> 'tables' ) cfg
	LOOP --{
		IF rec.cfg ->> 'name' = cfg_surfacelayer ->> 'table_name' THEN
			cfg_surfaceLayerTable := rec.cfg;
		ELSIF rec.cfg ->> 'name' = cfg_borderlayer ->> 'table_name' THEN
			cfg_borderLayerTable := rec.cfg;
		END IF;
		IF cfg_borderLayerTable IS NOT NULL AND
		   cfg_surfaceLayerTable IS NOT NULL
		THEN
			EXIT;
		END IF;
	END LOOP; --}

-- STRIP -- 	--RAISE DEBUG 'cfg_surfaceLayerTable: %', cfg_surfaceLayerTable;

-- STRIP -- 	--RAISE DEBUG 'cfg_borderLayerTable: %', cfg_borderLayerTable;


	surfaceLayerTableName := cfg_surfaceLayer ->> 'table_name';
	surfaceLayerTableRegclass := appname || '.' || surfaceLayerTableName;
	surfaceLayerGeomColumn := cfg_surfacelayer ->> 'geo_column';
	surfaceLayerIdColumn := cfg_surfacelayerTable ->> 'primary_key';

	borderLayerTableName := cfg_borderlayer ->> 'table_name';
	borderLayerTableRegclass := appname || '.' || borderLayerTableName;
	borderLayerGeomColumn := cfg_borderlayer ->> 'geo_column';
	borderLayerIdColumn := cfg_borderlayerTable ->> 'primary_key';


	sql := topo_update._GetMergeableSurfaceBorders_Query(
		appname,
		cfg_op,
		borderLayerIdColumn,
		borderLayerTableName,
		borderLayerGeomColumn,
		surfaceLayerTableName,
		surfaceLayerGeomColumn,
		surfaceLayerIdColumn,
		bbox
	);

	sql := format('SELECT border_ids, side_faces FROM ( %1$s ) foo', sql);

-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;


	RETURN QUERY EXECUTE sql USING bbox;

END;
$_$;



--
-- Name: _app_do_getmergeablesurfacebordersasgeojson_dynamic(name, jsonb, public.geometry, integer, integer); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_getmergeablesurfacebordersasgeojson_dynamic(appname name, appconfig jsonb, bbox public.geometry, out_srid integer, max_decimal_digits integer) RETURNS jsonb
    LANGUAGE plpgsql
    AS $_$ --{
DECLARE
	cfg_borderLayer JSONB;
	cfg_borderLayerTable JSONB;
	cfg_surfaceLayer JSONB;
	cfg_surfaceLayerTable JSONB;
	cfg_op JSONB;
	cfg_op_params JSONB;
	cfg JSONB;
	surfaceLayerTableName NAME;
	surfaceLayerTableRegclass REGCLASS;
	surfaceLayerGeomColumn NAME;
	surfaceLayerIdColumn NAME;
	borderLayerTableName NAME;
	borderLayerTableRegclass REGCLASS;
	borderLayerGeomColumn NAME;
	borderLayerIdColumn NAME;
	rec RECORD;
	sql TEXT;
	geojsonFeatures JSONB;
	out JSONB;
	borderIds TEXT[];
	procName TEXT := 'app_do_GetMergeableSurfaceBordersAsGeoJSON_Dynamic';
	crsSRID INT;
	crs TEXT;
BEGIN

	-- Check if the operation is enabled
	IF NOT appconfig -> 'operations' ? 'SurfaceMerge' THEN
		RAISE EXCEPTION 'SurfaceMerge operation not enabled for application %', appname;
	END IF;

	cfg_surfaceLayer := appconfig -> 'surface_layer';
	IF cfg_surfaceLayer IS NULL THEN
		RAISE EXCEPTION 'GetMergeableSurfaceBordersAsGeoJSON operations requires missing "surface_layer" in appconfig';
	END IF;
	cfg_borderLayer := appconfig -> 'border_layer';
	IF cfg_borderLayer IS NULL THEN
		RAISE EXCEPTION 'GetMergeableSurfaceBordersAsGeoJSON operations requires missing "border_layer" in appconfig';
	END IF;
	cfg_op := appconfig -> 'operations' -> 'SurfaceMerge';

-- STRIP -- 	--RAISE DEBUG 'cfg_surfacelayer: %', cfg_surfaceLayer;

-- STRIP -- 	--RAISE DEBUG 'cfg_borderLayer: %', cfg_borderLayer;


	FOR rec IN SELECT jsonb_array_elements( appconfig -> 'tables' ) cfg
	LOOP --{
		IF rec.cfg ->> 'name' = cfg_surfacelayer ->> 'table_name' THEN
			cfg_surfaceLayerTable := rec.cfg;
		ELSIF rec.cfg ->> 'name' = cfg_borderlayer ->> 'table_name' THEN
			cfg_borderLayerTable := rec.cfg;
		END IF;
		IF cfg_borderLayerTable IS NOT NULL AND
		   cfg_surfaceLayerTable IS NOT NULL
		THEN
			EXIT;
		END IF;
	END LOOP; --}

-- STRIP -- 	--RAISE DEBUG 'cfg_surfaceLayerTable: %', cfg_surfaceLayerTable;

-- STRIP -- 	--RAISE DEBUG 'cfg_borderLayerTable: %', cfg_borderLayerTable;


	surfaceLayerTableName := cfg_surfaceLayer ->> 'table_name';
	surfaceLayerTableRegclass := appname || '.' || surfaceLayerTableName;
	surfaceLayerGeomColumn := cfg_surfacelayer ->> 'geo_column';
	surfaceLayerIdColumn := cfg_surfacelayerTable ->> 'primary_key';

	borderLayerTableName := cfg_borderlayer ->> 'table_name';
	borderLayerTableRegclass := appname || '.' || borderLayerTableName;
	borderLayerGeomColumn := cfg_borderlayer ->> 'geo_column';
	borderLayerIdColumn := cfg_borderlayerTable ->> 'primary_key';

	IF out_srid IS NOT NULL
	THEN
		IF out_srid = 0 THEN
			RAISE EXCEPTION 'If an output SRID is given, it cannot be 0';
		END IF;
		crsSRID = out_srid;
	ELSE
		crsSRID = COALESCE( ( appconfig -> 'topology' -> 'srid' )::int, 0 );
	END IF;

-- STRIP -- 	RAISE DEBUG '%: GeoJSON header: %', procName, out;


	sql := topo_update._GetMergeableSurfaceBorders_Query(
		appname,
		cfg_op,
		borderLayerIdColumn,
		borderLayerTableName,
		borderLayerGeomColumn,
		surfaceLayerTableName,
		surfaceLayerGeomColumn,
		surfaceLayerIdColumn,
		bbox
	);

	sql := format(
		$$
			SELECT to_jsonb(array_agg(ST_AsGeoJSON(bar, 'geom', %1$L)::jsonb))
			FROM (
				SELECT
					ST_Transform(
						border_visible_geom,
						COALESCE(
							%2$L,
							ST_Srid(border_visible_geom)
						)
					) geom,
					border_ids,
					side_faces
				FROM ( %3$s ) foo
				ORDER BY border_ids -- make predictable
			) bar
		$$,
		max_decimal_digits,    -- %1
		out_srid,              -- %2
		sql                    -- %3
	);

-- STRIP -- 	-- RAISE DEBUG 'SQL: %', sql;


	EXECUTE sql USING bbox INTO geojsonFeatures;

	IF geojsonFeatures IS NULL THEN
		RETURN NULL; -- TODO: return something nicer here, maybe
	END IF;

	-- Initialize geojson with CRS member
	IF crsSRID = 0 THEN
		out := jsonb_build_object();
	ELSE
		SELECT auth_name || ':' || auth_srid
		FROM public.spatial_ref_sys
		WHERE srid = crsSRID
		INTO crs;

		IF NOT FOUND THEN
			RAISE EXCEPTION 'Could not found spatial_ref_sys entry for SRID %', out_srid;
		END IF;

		-- Initialize geojson with CRS member, if SRID is known
		out := jsonb_build_object(
			'crs', jsonb_build_object(
				'properties', jsonb_build_object('name', crs),
				'type', 'name'
			)
		);
	END IF;

	-- Add features and type to the GsoJSON
	out := out || jsonb_build_object(
		'type', 'FeatureCollection',
		'features', geojsonFeatures
	);

	RETURN out;

END;
$_$;



--
-- Name: _app_do_mergemergeablesurfaces_dynamic(name, jsonb, public.geometry); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_mergemergeablesurfaces_dynamic(appname name, appconfig jsonb, bbox public.geometry) RETURNS TABLE(fid text, typ character, act character, frm text[])
    LANGUAGE plpgsql
    AS $$ --{
DECLARE
	rec RECORD;
BEGIN
	CREATE TEMPORARY TABLE _mergeable_surface_borders AS
		SELECT DISTINCT border_ids[1] bid
		FROM topo_update._app_do_GetMergeableSurfaceBorders_Dynamic(
			appname,
			appconfig,
			bbox
		)
		ORDER BY 1;

	LOOP
		SELECT * FROM pg_temp._mergeable_surface_borders LIMIT 1
		INTO rec;

		IF rec IS NULL THEN
			EXIT;
		END IF;

-- STRIP -- 		RAISE DEBUG 'Getting rid of Border %', rec.bid;


		CREATE TEMPORARY TABLE _merged_surface_borders AS
			SELECT * FROM topo_update._app_do_RemoveBordersMergeSurfaces_Dynamic(
				appname,
				appconfig,
				rec.bid
			);


		RETURN QUERY SELECT * FROM pg_temp._merged_surface_borders;

		-- Remove ANY border found in _merged_surface_borders
		DELETE FROM pg_temp._mergeable_surface_borders
		WHERE bid IN (
			SELECT m.fid
			FROM pg_temp._merged_surface_borders m
			WHERE m.typ = 'B'
			AND m.act = 'D'
		);

		DROP TABLE pg_temp._merged_surface_borders;

	END LOOP;

	DROP TABLE pg_temp._mergeable_surface_borders;
END;
$$;



--
-- Name: _app_do_movepoint_dynamic(name, jsonb, text, jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_movepoint_dynamic(appname name, appconfig jsonb, point_id text, point jsonb) RETURNS void
    LANGUAGE plpgsql
    AS $_$ --{
DECLARE
	cfg_pointLayer JSONB;
	cfg_pointLayerTable JSONB;
	cfg_op JSONB;
	cfg_op_params JSONB;
	cfg JSONB;
	pointLayerTable REGCLASS;
	pointLayerGeomColumn NAME;
	pointLayerIdColumn NAME;
	pointNewProps JSONB;
	snapTolerance FLOAT8;
	point_geom GEOMETRY;
	rec RECORD;
	sql TEXT;
	removePrimitives BOOLEAN := true;
	procName TEXT := 'topo_update._app_do_MovePoint_Dynamic';
	topo_srid INT;
BEGIN

	-- Check if the operation is enabled
	IF NOT appconfig -> 'operations' ? 'MovePoint' THEN
		RAISE EXCEPTION 'MovePoint operation not enabled for application %', appname;
	END IF;

	cfg_pointLayer := appconfig -> 'point_layer';

-- STRIP -- 	--RAISE DEBUG 'pointLayer: %', cfg_pointLayer;


	FOR rec IN SELECT jsonb_array_elements( appconfig -> 'tables' ) cfg
	LOOP --{
		IF rec.cfg ->> 'name' = cfg_pointlayer ->> 'table_name' THEN
			cfg_pointLayerTable := rec.cfg;
			EXIT;
		END IF;
	END LOOP; --}

-- STRIP -- 	--RAISE DEBUG 'pointLayerTable: %', cfg_pointLayerTable;


	pointLayerTable := ( appname || '.' || ( cfg_pointlayer ->> 'table_name' ) );
	pointLayerGeomColumn := cfg_pointlayer ->> 'geo_column';
	pointLayerIdColumn := cfg_pointlayerTable ->> 'primary_key';

	-- Validate point geometry,
	point_geom := ST_GeomFromGeoJSON(point -> 'geometry');
	IF point_geom IS NULL THEN
		RAISE EXCEPTION 'Missing geometry in point';
	END IF;

	IF ST_GeometryType(point_geom) != 'ST_Point' THEN
		RAISE EXCEPTION 'Point must be Point, is % instead', ST_GeometryType(point_geom);
	END IF;

	topo_srid := appconfig -> 'topology' ->> 'srid';
	IF ST_Srid(point_geom) != topo_srid
	THEN
-- STRIP -- 		RAISE DEBUG '%: point srid (%) does not match topology srid (%), reprojecting',
-- STRIP -- 			procName,
-- STRIP -- 			ST_Srid(point_geom),
-- STRIP -- 			topo_srid
		point_geom := ST_Transform(point_geom, topo_srid);
	END IF;

	snapTolerance := 0; -- TODO: read from config ?

	-- update topogeometry of record with new point

	-- TODO: cast user argument to id type
	sql := format(
		$$
			UPDATE %1$s SET %2$I = topology.toTopoGeom($1, topology.clearTopoGeom(%2$I), $2)
			WHERE %3$I::text = $3
			RETURNING %3$I::text id
		$$,
		pointLayerTable,      -- %1
		pointLayerGeomColumn, -- %2
		pointLayerIdColumn    -- %3
	);

-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;


	EXECUTE sql USING point_geom, snapTolerance, point_id
	INTO rec;

	IF rec IS NULL THEN
		RAISE EXCEPTION 'No Point with id % in table %', point_id, pointLayerTable;
	END IF;

	-- Cleanup old node if not needed anymore
	IF removePrimitives THEN
		-- TODO: pass the bounding box of the removed point ?
		PERFORM topo_update.cleanup_topology(
			( SELECT t FROM topology.topology t
			  WHERE name = appname || '_sysdata_webclient' )
		);
	END IF;

	-- Update attributes if properties are found in the input point
	pointNewProps = ( point -> 'properties' )
		- pointLayerIdColumn
		- pointLayerGeomColumn;
	IF pointNewProps <> '{}'::jsonb
	THEN
-- STRIP -- 		RAISE DEBUG 'Updating props';

		PERFORM topo_update._app_do_UpdateAttributes_Dynamic(
			appname,
			appconfig,
			( cfg_pointlayer ->> 'table_name' ),
			point_id,
			pointNewProps
		);
	END IF;


END;
$_$;



--
-- Name: _app_do_removebordersmergesurfaces_dynamic(name, jsonb, text); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_removebordersmergesurfaces_dynamic(appname name, appconfig jsonb, border_id text) RETURNS TABLE(fid text, typ character, act character, frm text[])
    LANGUAGE plpgsql
    AS $$ --{
DECLARE
	cfg_surfaceLayer JSONB;
	cfg_surfaceLayerTable JSONB;
	cfg_borderLayer JSONB;
	cfg_borderLayerTable JSONB;
	cfg_op JSONB;
	cfg_op_params JSONB;
	cfg JSONB;
	surfaceLayerTable REGCLASS;
	surfaceLayerGeomColumn NAME;
	surfaceLayerIdColumn NAME;
	borderLayerTable REGCLASS;
	borderLayerGeomColumn NAME;
	borderLayerIdColumn NAME;
	rec RECORD;
BEGIN

	-- Check if the operation is enabled
	IF NOT appconfig -> 'operations' ? 'SurfaceMerge' THEN
		RAISE EXCEPTION 'SurfaceMerge operation not enabled for application %', appname;
	END IF;

	cfg_surfaceLayer := appconfig -> 'surface_layer';
	cfg_borderLayer := appconfig -> 'border_layer';
	cfg_op := appconfig -> 'operations' -> 'SurfaceMerge';

-- STRIP -- 	--RAISE DEBUG 'surfacelayer: %', cfg_surfaceLayer;

-- STRIP -- 	--RAISE DEBUG 'borderLayer: %', cfg_borderLayer;


	FOR rec IN SELECT jsonb_array_elements( appconfig -> 'tables' ) cfg
	LOOP --{
		IF rec.cfg ->> 'name' = cfg_surfacelayer ->> 'table_name' THEN
			cfg_surfaceLayerTable := rec.cfg;
		ELSIF rec.cfg ->> 'name' = cfg_borderlayer ->> 'table_name' THEN
			cfg_borderLayerTable := rec.cfg;
		END IF;
		IF cfg_borderLayerTable IS NOT NULL AND
		   cfg_surfaceLayerTable IS NOT NULL
		THEN
			EXIT;
		END IF;
	END LOOP; --}

-- STRIP -- 	--RAISE DEBUG 'surfaceLayerTable: %', cfg_surfaceLayerTable;

-- STRIP -- 	--RAISE DEBUG 'borderLayerTable: %', cfg_borderLayerTable;


	surfaceLayerTable := ( appname || '.' || ( cfg_surfaceLayer ->> 'table_name' ) );
	surfaceLayerGeomColumn := cfg_surfacelayer ->> 'geo_column';
	surfaceLayerIdColumn := cfg_surfacelayerTable ->> 'primary_key';

	borderLayerTable := ( appname || '.' || ( cfg_borderlayer ->> 'table_name' ) );
	borderLayerGeomColumn := cfg_borderlayer ->> 'geo_column';
	borderLayerIdColumn := cfg_borderlayerTable ->> 'primary_key';

	-- TODO: check if border_id is removable according to cfg_op
	-- HINT: use topo_update._GetMergeableSurfaceBorders_Query


	RETURN QUERY
	SELECT * FROM topo_update.remove_border_merge_surfaces(
		borderLayerTable,
		borderLayerGeomColumn,
		borderLayerIdColumn,
		border_id,
		surfaceLayerTable,
		surfaceLayerGeomColumn,
		surfaceLayerIdColumn,
		'topo_update._app_do_RemoveBordersMergeSurfaces_PolicyProvider'::regproc,
		cfg_op, -- mergePolicyProviderParam
		removePrimitives => true,
		removeDanglingBorders => true
	);

END;
$$;



--
-- Name: _app_do_removebordersmergesurfaces_policyprovider(text, topology.topogeometry, jsonb, text, topology.topogeometry, jsonb, jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_removebordersmergesurfaces_policyprovider(surfaceleftid text, surfacelefttopogeom topology.topogeometry, surfaceleftprops jsonb, surfacerightid text, surfacerighttopogeom topology.topogeometry, surfacerightprops jsonb, usr jsonb) RETURNS jsonb
    LANGUAGE plpgsql
    AS $_$
DECLARE
	procName TEXT := 'topo_update._app_do_RemoveBordersMergeSurfaces_PolicyProvider';
	props JSONB;
	orderBy TEXT;
	sql TEXT;
BEGIN

-- STRIP -- 	RAISE DEBUG 'USR: %', usr;


	orderBy := usr ->> 'surfaceSQLOrderBy';
	IF orderBy IS NULL THEN
		-- By default
		orderBy := 'ST_Area(tg::geometry) DESC, ST_NPoints(tg::geometry) DESC, id ASC';
	END IF;

	sql := format(
		$$
SELECT pr FROM (
	SELECT $1 id, $2 tg, $3 pr
	UNION ALL
	SELECT $4 id, $5 tg, $6 pr
) foo
ORDER BY %s
LIMIT 1
		$$,
		orderBy
	);

-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;


	EXECUTE sql
	USING
		surfaceLeftId, surfaceLeftTopoGeom, surfaceLeftProps,
		surfaceRightId, surfaceRightTopoGeom, surfaceRightProps
	INTO props;
	RETURN props;

END;
$_$;



--
-- Name: _app_do_removepath_dynamic(name, jsonb, text); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_removepath_dynamic(appname name, appconfig jsonb, path_id text) RETURNS void
    LANGUAGE plpgsql
    AS $_$ --{
DECLARE
	cfg_pathLayer JSONB;
	cfg_pathLayerTable JSONB;
	cfg_op JSONB;
	cfg_op_params JSONB;
	cfg JSONB;
	pathLayerTable REGCLASS;
	pathLayerGeomColumn NAME;
	pathLayerIdColumn NAME;
	rec RECORD;
	sql TEXT;
	removedPath RECORD;
	removePrimitives BOOLEAN := true;
BEGIN

	-- Check if the operation is enabled
	IF NOT appconfig -> 'operations' ? 'RemovePath' THEN
		RAISE EXCEPTION 'RemovePath operation not enabled for application %', appname;
	END IF;

	cfg_pathLayer := appconfig -> 'path_layer';
	cfg_op := appconfig -> 'operations' -> 'RemovePath';

-- STRIP -- 	--RAISE DEBUG 'pathLayer: %', cfg_pathLayer;


	FOR rec IN SELECT jsonb_array_elements( appconfig -> 'tables' ) cfg
	LOOP --{
		IF rec.cfg ->> 'name' = cfg_pathlayer ->> 'table_name' THEN
			cfg_pathLayerTable := rec.cfg;
		END IF;
		IF cfg_pathLayerTable IS NOT NULL
		THEN
			EXIT;
		END IF;
	END LOOP; --}

-- STRIP -- 	--RAISE DEBUG 'pathLayerTable: %', cfg_pathLayerTable;


	pathLayerTable := ( appname || '.' || ( cfg_pathlayer ->> 'table_name' ) );
	pathLayerGeomColumn := cfg_pathlayer ->> 'geo_column';
	pathLayerIdColumn := cfg_pathlayerTable ->> 'primary_key';

	-- TODO: cast the parameter into the type of the primary key, not
	--       vice-versa
	sql := format(
		$$
			WITH deleted AS (
				DELETE FROM %1$s
				WHERE %2$I::text = $1
				RETURNING %3$I as tg
			) SELECT topology.clearTopoGeom(tg) FROM deleted
		$$,
		pathLayerTable,      -- %1
		pathLayerIdColumn,   -- %2
		pathLayerGeomColumn  -- %3
	);

	EXECUTE sql
	USING path_id
	INTO removedPath
	;

	IF removedPath IS NULL THEN
		RAISE EXCEPTION 'No Path with id % in table %', path_id, pathLayerTable;
	END IF;

	IF removePrimitives THEN
		-- TODO: pass the bounding box of the removed path ?
		PERFORM topo_update.cleanup_topology(
			( SELECT t FROM topology.topology t
			  WHERE name = appname || '_sysdata_webclient' )
		);
	END IF;


END;
$_$;



