--
-- Name: _app_do_removesmallsurfaces_dynamic(name, jsonb, double precision, public.geometry); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_removesmallsurfaces_dynamic(appname name, appconfig jsonb, minarea double precision, bbox public.geometry) RETURNS TABLE(fid text, typ character, act character, frm text[])
    LANGUAGE plpgsql
    AS $_$ --{
DECLARE
	cfg_surfaceLayer JSONB;
	cfg_surfaceLayerTable JSONB;
	cfg_borderLayer JSONB;
	cfg_borderLayerTable JSONB;
	cfg_op JSONB;
	cfg_op_params JSONB;
	cfg JSONB;
	topo topology.topology;
	surfaceLayer topology.layer;
	surfaceLayerTableName NAME;
	surfaceLayerTable REGCLASS;
	surfaceLayerGeomColumn NAME;
	surfaceLayerIdColumn NAME;
	borderLayer topology.layer;
	borderLayerTableName NAME;
	borderLayerTable REGCLASS;
	borderLayerGeomColumn NAME;
	borderLayerIdColumn NAME;
	rec RECORD;
	sql TEXT;
	numassigned INT;
	topoProj4Text TEXT;
	topoUnits TEXT;
	topoProj TEXT;
	geographyCast TEXT := '';
BEGIN

	-- TODO: Check if the operation is enabled ?
	--IF NOT appconfig -> 'operations' ? 'RemoveSmallSurfaces' THEN
	--	RAISE EXCEPTION 'RemoveSmallSurfaces operation not enabled for application %', appname;
	--END IF;

	cfg_surfaceLayer := appconfig -> 'surface_layer';
	cfg_borderLayer := appconfig -> 'border_layer';
	cfg_op := appconfig -> 'operations' -> 'AddBordersNewSurface';

-- STRIP -- 	--RAISE DEBUG 'surfacelayer: %', cfg_surfaceLayer;

-- STRIP -- 	--RAISE DEBUG 'borderLayer: %', cfg_borderLayer;


	FOR rec IN SELECT jsonb_array_elements( appconfig -> 'tables' ) cfg
	LOOP --{
		IF rec.cfg ->> 'name' = cfg_surfacelayer ->> 'table_name' THEN
			cfg_surfaceLayerTable := rec.cfg;
		ELSIF rec.cfg ->> 'name' = cfg_borderlayer ->> 'table_name' THEN
			cfg_borderLayerTable := rec.cfg;
		END IF;
		IF cfg_borderLayerTable IS NOT NULL AND
		   cfg_surfaceLayerTable IS NOT NULL
		THEN
			EXIT;
		END IF;
	END LOOP; --}

-- STRIP -- 	--RAISE DEBUG 'surfaceLayerTable: %', cfg_surfaceLayerTable;

-- STRIP -- 	--RAISE DEBUG 'borderLayerTable: %', cfg_borderLayerTable;


	surfaceLayerTableName := cfg_surfaceLayer ->> 'table_name';
	surfaceLayerGeomColumn := cfg_surfacelayer ->> 'geo_column';
	surfaceLayerIdColumn := cfg_surfacelayerTable ->> 'primary_key';
	surfaceLayerTable := format('%I.%I', appname, surfaceLayerTableName);

	borderLayerTableName := cfg_borderlayer ->> 'table_name';
	borderLayerGeomColumn := cfg_borderlayer ->> 'geo_column';
	borderLayerIdColumn := cfg_borderlayerTable ->> 'primary_key';
	borderLayerTable := format('%I.%I', appname, borderLayerTableName);

	SELECT * FROM topology.topology
	WHERE name = format('%I', appname || '_sysdata_webclient')
	INTO topo;
	IF topo.id IS NULL THEN
		RAISE EXCEPTION 'Cannot find topology associated with appname %', appname;
	END IF;

	-- Check if the topology srid corresponds to a latlon
	-- Find topo proj4text
	SELECT proj4text
	FROM spatial_ref_sys
	WHERE srid = topo.srid
	INTO topoProj4Text;

	topoUnits := (regexp_match(topoProj4Text, '\+units=([^ ]*) '))[1];
	IF topoUnits IS NOT NULL THEN
		IF topoUnits = 'm' THEN
-- STRIP -- 			RAISE DEBUG 'Units of topo SRID % are meters', topo.srid;

		ELSE
			RAISE EXCEPTION 'Unsupported units % in topology', topoUnits;
		END IF;
	ELSE
		-- TODO: handle ft, us-ft and to_meter ?
		topoProj := (regexp_match(topoProj4Text, '\+proj=([^ ]*) '))[1];
		IF topoProj = 'longlat' THEN
-- STRIP -- 			RAISE DEBUG 'Units of topo SRID % are degrees, will cast to geography', topo.srid;

			geographyCast = '::geography';
		ELSE
			RAISE EXCEPTION 'Unsupported topology projection for using square meters: %', topoProj;
		END IF;
	END IF;

	SELECT * FROM topology.layer
	WHERE schema_name = appname
	AND table_name = surfaceLayerTableName
	INTO surfaceLayer;
	IF surfaceLayer.layer_id IS NULL THEN
		RAISE EXCEPTION 'Cannot find layer associated with table % in app %', surfaceLayerTableName, appname;
	END IF;

	SELECT * FROM topology.layer
	WHERE schema_name = appname
	AND table_name = borderLayerTableName
	INTO borderLayer;
	IF borderLayer.layer_id IS NULL THEN
		RAISE EXCEPTION 'Cannot find layer associated with table % in app %', borderLayerTableName, appname;
	END IF;

-- STRIP -- 	RAISE DEBUG 'min allowed new surface area: %', minArea;


	sql := format(
		$$
	CREATE TEMPORARY TABLE _removed_surfaces AS
	WITH deleted AS (
		DELETE FROM %1$s
		WHERE
		-- TODO: optimize limiting to bbox this
		( $1 IS NULL OR ST_Intersects($1, %2$I) )
		AND
		-- TODO: compute in meters ?
		ST_Area(%2$I::geometry%5$s) < %3$s
		RETURNING %4$I as id, %2$I as tg, ST_BoundingDiagonal(%2$I) as diagonal
	)
	SELECT * FROM deleted
		$$,
		surfaceLayerTable,      -- %1
		surfaceLayerGeomColumn, -- %2
		minArea,                -- %3
		surfaceLayerIdColumn,   -- %4
		geographyCast           -- %5
	);

-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;


	RAISE NOTICE 'Deleting small surfaces';
	EXECUTE sql USING bbox;

	-- Report removed surfaces
	RETURN QUERY SELECT id::text, 'S'::char, 'D'::char, null::text[] FROM pg_temp._removed_surfaces;

	sql := format(
		$$
	CREATE TEMPORARY TABLE _orphaned_faces AS
	WITH deleted AS (
		DELETE FROM %1$I.relation
		WHERE layer_id = %2$L
		AND topogeo_id IN (
			SELECT id(tg)
			FROM pg_temp._removed_surfaces
		)
		RETURNING topogeo_id, element_id face_id
	)
	SELECT *, null::int as assigned, null::int[] merge_edges, false processed FROM deleted
		$$,
		appname || '_sysdata_webclient',
		surfaceLayer.layer_id
	);

-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;


	RAISE NOTICE 'Extracting orphaned faces';
	EXECUTE sql;

	-- Iteratively assign each deleted Surface composing faces
	--       to the largest adjacent Surface, if any
	LOOP --{

		RAISE NOTICE 'Assigning orphaned faces';

		sql := format(
			$$
WITH adjacent_surfaces AS (
	SELECT o.face_id, array_agg(e.edge_id) edges, r.topogeo_id other_tgid
	FROM
		pg_temp._orphaned_faces o,
		%1$I.edge e,
		%1$I.relation r
	WHERE o.assigned IS NULL
	AND e.left_face != e.right_face
	AND ( e.left_face = o.face_id OR e.right_face = o.face_id )
	AND ( e.left_face = r.element_id OR e.right_face = r.element_id )
	AND r.layer_id = %2$L
	-- exclude other TopoGeometries already having this face
	-- in their composition (TODO: verify this is to be done)
	AND r.element_id != o.face_id
	GROUP BY o.face_id, r.topogeo_id
), surface_areas AS (
    SELECT other_tgid tgid, ST_Area(
		(%3$L,%2$L,other_tgid, 3)::topology.topogeometry
		::geometry%4$s
    ) area
    FROM ( SELECT DISTINCT other_tgid FROM adjacent_surfaces ) foo
),
candidates AS (
    SELECT row_number() over ( partition by face_id) rn, s.*
	FROM adjacent_surfaces s
    JOIN surface_areas a ON ( a.tgid = s.other_tgid )
    ORDER by area DESC, other_tgid ASC
)
UPDATE pg_temp._orphaned_faces o
	SET assigned = rec.other_tgid,
		merge_edges = rec.edges
FROM candidates rec
WHERE o.face_id = rec.face_id
			$$,
			topo.name,             -- %1
			surfaceLayer.layer_id, -- %2
			topo.id,               -- %3
			geographyCast          -- %4
		);
-- STRIP -- 		RAISE DEBUG 'SQL: %', sql;


		EXECUTE sql;
		GET DIAGNOSTICS numassigned := ROW_COUNT;

		IF numassigned = 0 THEN
			RAISE NOTICE 'No face assigned, nothing to process';
			EXIT;
		END IF;

		RAISE NOTICE 'Processing % orphaned faces', numassigned;
		--
		-- Process face assignments (make TopoGeometry actually grow)
		--

		sql := format(
			$$
WITH toprocess AS (
	SELECT o.* FROM pg_temp._orphaned_faces o WHERE o.assigned IS NOT NULL
	AND NOT o.processed
), updated AS (
	UPDATE pg_temp._orphaned_faces o SET processed = true
	FROM toprocess tp
	WHERE o.face_id = tp.face_id
	RETURNING o.*
)
INSERT INTO %1$I.relation (topogeo_id, layer_id, element_type, element_id)
SELECT u.assigned,%2$L,3,u.face_id
FROM updated u
-- do nothing if the same face is already used by another surface
-- (should not happen in a valid starting state)
ON CONFLICT DO NOTHING
			$$,
			topo.name,
			surfaceLayer.layer_id
		);

-- STRIP -- 		RAISE DEBUG 'SQL: %', sql;


		EXECUTE sql;

	END LOOP; --}

	--
	-- Report modified surfaces activity
	--

	sql := format(
		$$
SELECT lto.%1$I::text fid, 'S'::char typ, 'M'::char act, array_agg(lfrm.id order by lfrm.id)::text[] frm
FROM
	pg_temp._orphaned_faces o,
	pg_temp._removed_surfaces lfrm,
	%2$s lto
WHERE id ( tg ) = o.topogeo_id
AND id ( lto.%3$I ) = o.assigned
GROUP BY 1,2,3 -- lto.%1$I
ORDER BY 1
		$$,
		surfaceLayerIdColumn,
		surfaceLayerTable,
		surfaceLayerGeomColumn
	);

-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;


	RAISE NOTICE 'Reporting modified surfaces';
	RETURN QUERY EXECUTE sql;

	--
	-- remove Border objects defined by merge edges
	--

	sql := format(
		$$
WITH deleted_compositions AS (
	DELETE FROM %3$I.relation
	WHERE layer_id = %4$L AND element_type = 2 AND element_id IN
		( SELECT unnest(merge_edges) FROM pg_temp._orphaned_faces UNION ALL
		  SELECT -unnest(merge_edges) FROM pg_temp._orphaned_faces )
	RETURNING topogeo_id
)
DELETE FROM %1$s WHERE id(%2$I) IN (
	SELECT topogeo_id FROM deleted_compositions
)
RETURNING %5$I::text id, 'B'::char, 'D'::char, null::text[] frm
		$$,
		borderLayerTable,      -- %1
		borderLayerGeomColumn, -- %2
		topo.name,             -- %3
		borderLayer.layer_id,  -- %4
		borderLayerIdColumn    -- %5
	);

-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;


	RAISE NOTICE 'Removing borders defined by merged edges';
	RETURN QUERY EXECUTE sql;

	--
	-- remove Border objects defined by edges of unassigned orphaned
	-- faces
	--
	sql := format(
		$$
WITH unassigned_face_edges AS (
	SELECT e.edge_id
	FROM
		%3$I.edge e,
		pg_temp._orphaned_faces o
	WHERE o.assigned IS NULL
	AND ( e.left_face = o.face_id OR e.right_face = o.face_id )
), deleted_compositions AS (
	DELETE FROM %3$I.relation
	WHERE layer_id = %4$L AND element_type = 2 AND element_id IN
		( SELECT edge_id FROM unassigned_face_edges UNION
		  SELECT -edge_id FROM unassigned_face_edges )
	RETURNING topogeo_id
)
DELETE FROM %1$s WHERE id(%2$I) IN (
	SELECT topogeo_id FROM deleted_compositions
)
RETURNING %5$I::text id, 'B'::char, 'D'::char, null::text[] frm
		$$,
		borderLayerTable,      -- %1
		borderLayerGeomColumn, -- %2
		topo.name,             -- %3
		borderLayer.layer_id,  -- %4
		borderLayerIdColumn    -- %5
	);

-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;


	RAISE NOTICE 'Removing borders defined by edges of unassigned faces';
	RETURN QUERY EXECUTE sql;

	--
	-- Remove orphaned primitives
	--

	RAISE NOTICE 'Removing orphaned primitives';
	PERFORM topo_update.cleanup_topology(topo,
		-- Expand bbox to cover extent of all removed surfaces
		( SELECT ST_Union(diagonal) FROM pg_temp._removed_surfaces )
	);

	DROP TABLE pg_temp._removed_surfaces;
	DROP TABLE pg_temp._orphaned_faces;


END;
$_$;



--
-- Name: _app_do_removesurfaces_dynamic(name, jsonb, text[]); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_removesurfaces_dynamic(appname name, appconfig jsonb, surface_ids text[]) RETURNS TABLE(fid text, typ character)
    LANGUAGE plpgsql
    AS $_$ --{
DECLARE
	cfg_surfaceLayer JSONB;
	cfg_surfaceLayerTable JSONB;
	cfg_borderLayer JSONB;
	cfg_borderLayerTable JSONB;
	cfg_op JSONB;
	cfg_op_params JSONB;
	cfg JSONB;
	surfaceLayer topology.layer;
	surfaceLayerTable REGCLASS;
	surfaceLayerGeomColumn NAME;
	surfaceLayerIdColumn NAME;
	borderLayer topology.layer;
	borderLayerTable REGCLASS;
	borderLayerGeomColumn NAME;
	borderLayerIdColumn NAME;
	rec RECORD;
	sql TEXT;
	removedSurface RECORD;
	removedSurfaceFaces INT[];
	removePrimitives BOOLEAN := true;
	dangling_border_ids TEXT[];
BEGIN

	-- -- Check if the operation is enabled
	-- IF NOT appconfig -> 'operations' ? 'RemoveSurface' THEN
	--	RAISE EXCEPTION 'RemoveSurface operation not enabled for application %', appname;
	--END IF;
	--cfg_op := appconfig -> 'operations' -> 'RemoveSurface';

	cfg_surfaceLayer := appconfig -> 'surface_layer';
-- STRIP -- 	RAISE DEBUG 'cfg_surfaceLayer: %', cfg_surfaceLayer;


	FOR rec IN SELECT jsonb_array_elements( appconfig -> 'tables' ) cfg
	LOOP --{
		IF rec.cfg ->> 'name' = cfg_surfacelayer ->> 'table_name' THEN
			cfg_surfaceLayerTable := rec.cfg;
		END IF;
		IF cfg_surfaceLayerTable IS NOT NULL
		THEN
			EXIT;
		END IF;
	END LOOP; --}

-- STRIP -- 	RAISE DEBUG 'cfg_surfaceLayerTable: %', cfg_surfaceLayerTable;


	surfaceLayerTable := ( appname || '.' || ( cfg_surfacelayer ->> 'table_name' ) );
	surfaceLayerGeomColumn := cfg_surfacelayer ->> 'geo_column';
	surfaceLayerIdColumn := cfg_surfacelayerTable ->> 'primary_key';

	SELECT l.*
	FROM topology.layer l
	WHERE l.schema_name = appname
	AND l.table_name =  ( cfg_surfaceLayer ->> 'table_name' )
	AND l.feature_column = surfaceLayerGeomColumn
	INTO surfaceLayer;

	IF surfaceLayer.layer_id IS NULL THEN
		RAISE EXCEPTION 'Cannot find Surface layer in topology.layer table';
	END IF;


	-- TODO: cast the parameter into the type of the primary key, not
	--       vice-versa
	sql := format(
		$$
			DELETE FROM %1$s
			WHERE %2$I::text = ANY( $1 )
			RETURNING %2$I as id, %3$I as tg
		$$,
		surfaceLayerTable,      -- %1
		surfaceLayerIdColumn,   -- %2
		surfaceLayerGeomColumn  -- %3
	);

-- STRIP -- 	RAISE DEBUG 'SQL (delete): %', sql;


	FOR rec IN EXECUTE sql USING surface_ids
	LOOP

		-- Log faces defining this Surface
		sql := format(
			$$
SELECT array_cat($1, array_agg(element_id))
FROM %1$I.relation
WHERE layer_id = %2$L
AND topogeo_id = %3$L
			$$,
			appname || '_sysdata_webclient',
			surfaceLayer.layer_id,
			id(rec.tg)
		);

-- STRIP -- 		RAISE DEBUG 'SQL (array_cat): %', sql;


		EXECUTE sql USING removedSurfaceFaces
		INTO removedSurfaceFaces;

-- STRIP -- 		RAISE DEBUG 'RemovedSurfaceFaces: %', removedSurfaceFaces;


		PERFORM topology.clearTopoGeom(rec.tg);

		fid := rec.id;
		typ := 'S';
		RETURN NEXT;

	END LOOP;

	-- remove Borders left dangling, if defined in appconfig
	cfg_borderLayer := appconfig -> 'border_layer';
-- STRIP -- 	RAISE DEBUG 'cfg_borderLayer: %', cfg_borderLayer;

	IF cfg_borderLayer IS NOT NULL THEN
	--{

		RAISE NOTICE 'Checking for dangling borders';
		FOR rec IN SELECT jsonb_array_elements( appconfig -> 'tables' ) cfg
		LOOP --{
			IF rec.cfg ->> 'name' = cfg_borderlayer ->> 'table_name' THEN
				cfg_borderLayerTable := rec.cfg;
			END IF;
			IF cfg_borderLayerTable IS NOT NULL
			THEN
				EXIT;
			END IF;
		END LOOP; --}
-- STRIP -- 		RAISE DEBUG 'cfg_borderLayerTable: %', cfg_borderLayerTable;


		borderLayerTable := ( appname || '.' || ( cfg_borderlayer ->> 'table_name' ) );
		borderLayerGeomColumn := cfg_borderlayer ->> 'geo_column';
		borderLayerIdColumn := cfg_borderlayerTable ->> 'primary_key';

		SELECT l.*
		FROM topology.layer l
		WHERE l.schema_name = appname
		AND l.table_name =  ( cfg_borderLayer ->> 'table_name' )
		AND l.feature_column = borderLayerGeomColumn
		INTO borderLayer;

		IF borderLayer.layer_id IS NULL THEN
			RAISE EXCEPTION 'Cannot find Border layer in topology.layer table';
		END IF;

		-- Find borders defined by edges having any of the removed
		-- surface faces on their sides
		sql := format(
			$$
				WITH dangling AS (
					SELECT
					  rb.topogeo_id tgid,
					  e.edge_id eid,
					  e.left_face fl,
					  e.right_face fr,
					  rsl.topogeo_id sl,
					  rsr.topogeo_id sr
					FROM %1$I.relation rb
					JOIN %1$I.edge_data e
						ON ( e.edge_id in ( rb.element_id, -rb.element_id ) )
					LEFT JOIN %1$I.relation rsl
						ON ( rsl.layer_id = %2$L AND rsl.element_id = e.left_face )
					LEFT OUTER JOIN %1$I.relation rsr
						ON ( rsr.layer_id = %2$L AND rsr.element_id = e.right_face )
					WHERE rb.layer_id = %3$L
					AND (
						e.left_face = ANY ( %4$L )
						OR
						e.right_face = ANY ( %4$L )
					)
					AND rsl.topogeo_id IS NOT DISTINCT FROM rsr.topogeo_id
				)
				SELECT array_agg(%5$I::text)
				FROM %6$s
				WHERE id(%7$I) IN (
					SELECT tgid FROM dangling
				)
			$$,
			appname || '_sysdata_webclient',             -- %1
			surfaceLayer.layer_id, -- %2
			borderLayer.layer_id,  -- %3
			removedSurfaceFaces,   -- %4
			borderLayerIdColumn,   -- %5
			borderLayerTable,      -- %6
			borderLayerGeomColumn  -- %7
		);

-- STRIP -- 		RAISE DEBUG 'SQL: %', sql;


		EXECUTE sql
		INTO dangling_border_ids;

		RAISE NOTICE 'Dangling border ids: %', dangling_border_ids;

		IF dangling_border_ids IS NOT NULL THEN

			-- TODO: cast the parameter into the type of the primary key, not
			--       vice-versa
			sql := format(
				$$
					DELETE FROM %1$s
					WHERE %2$I::text = ANY( $1 )
					RETURNING %2$I as id, %3$I as tg
				$$,
				borderLayerTable,      -- %1
				borderLayerIdColumn,   -- %2
				borderLayerGeomColumn  -- %3
			);

			FOR rec IN EXECUTE sql USING dangling_border_ids
			LOOP
				PERFORM topology.clearTopoGeom(rec.tg);

				fid := rec.id;
				typ := 'B';
				RETURN NEXT;

			END LOOP;

		END IF;

	END IF; --}

	IF removePrimitives THEN
		-- TODO: pass the bounding box of the removed surface ?
		PERFORM topo_update.cleanup_topology(
			( SELECT t FROM topology.topology t
			  WHERE name = appname || '_sysdata_webclient' )
		);
	END IF;


END;
$_$;



--
-- Name: _app_do_splitmultiedgeborders_dynamic(name, jsonb, public.geometry); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_splitmultiedgeborders_dynamic(appname name, appconfig jsonb, bbox public.geometry DEFAULT NULL::public.geometry) RETURNS TABLE(bid text, act character, frm text)
    LANGUAGE plpgsql
    AS $_$
DECLARE
	cfg_borderLayer JSONB;
	rec RECORD;
	cfg_borderLayerTable JSONB;
	topo topology.topology;
	borderLayer topology.layer;
	sql TEXT;
BEGIN
	cfg_borderLayer := appconfig -> 'border_layer';
	IF cfg_borderLayer IS NULL THEN
		RAISE EXCEPTION 'App config defines no border_layer';
	END IF;

	FOR rec IN SELECT jsonb_array_elements( appconfig -> 'tables' ) cfg
	LOOP --{
		IF rec.cfg ->> 'name' = cfg_borderLayer ->> 'table_name' THEN
			cfg_borderLayerTable := rec.cfg;
		END IF;
		IF cfg_borderLayerTable IS NOT NULL
		THEN
			EXIT;
		END IF;
	END LOOP; --}

	sql := format(
		$$
SELECT * FROM topo_update.split_multiedge_borders(
	%1$L,
	%2$L,
	%3$L,
	$1
)
		$$,
		format('%I.%I', appname, ( cfg_borderLayer ->> 'table_name'))::regclass,
		( cfg_borderLayer ->> 'geo_column' ),
		( cfg_borderlayerTable ->> 'primary_key' )
	);

	RETURN QUERY EXECUTE sql USING (bbox);
END;
$_$;



--
-- Name: _app_do_splitpaths_dynamic(name, jsonb, jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_splitpaths_dynamic(appname name, appconfig jsonb, pathset jsonb) RETURNS TABLE(fid text, act character, frm text)
    LANGUAGE plpgsql
    AS $$ --{
DECLARE
	cfg_pathLayer JSONB;
	cfg_pathLayerTable JSONB;
	cfg_op JSONB;
	cfg_op_params JSONB;
	cfg JSONB;
	pathLayerTable REGCLASS;
	pathLayerGeomColumn NAME;
	pathLayerIdColumn NAME;
	rec RECORD;
	sql TEXT;
	maxSplits INT;
BEGIN

	-- Check if the operation is enabled
	IF NOT appconfig -> 'operations' ? 'SplitPaths' THEN
		RAISE EXCEPTION 'SplitPaths operation not enabled for application %', appname;
	END IF;

	cfg_pathLayer := appconfig -> 'path_layer';
	cfg_op := appconfig -> 'operations' -> 'SplitPaths';

-- STRIP -- 	--RAISE DEBUG 'pathLayer: %', cfg_pathLayer;


	FOR rec IN SELECT jsonb_array_elements( appconfig -> 'tables' ) cfg
	LOOP --{
		IF rec.cfg ->> 'name' = cfg_pathlayer ->> 'table_name' THEN
			cfg_pathLayerTable := rec.cfg;
		END IF;
		IF cfg_pathLayerTable IS NOT NULL
		THEN
			EXIT;
		END IF;
	END LOOP; --}

-- STRIP -- 	--RAISE DEBUG 'pathLayerTable: %', cfg_pathLayerTable;


	pathLayerTable := ( appname || '.' || ( cfg_pathlayer ->> 'table_name' ) );
	pathLayerGeomColumn := cfg_pathlayer ->> 'geo_column';
	pathLayerIdColumn := cfg_pathlayerTable ->> 'primary_key';

	-- Set parameters defaults
	maxSplits := 0;

	-- Read parameters defaults from appconfig
	cfg_op_params := appconfig -> 'operations' -> 'SplitPaths';
	IF cfg_op_params IS NOT NULL THEN --{

		-- Read maxSplits from config, if found
		cfg := cfg_op_params -> 'maxSplits';
		maxSplits := cfg ->> 'units';

	END IF; --}

-- STRIP -- 	RAISE DEBUG 'maxSplits: %', maxSplits;


	RETURN QUERY
	SELECT * FROM topo_update.split_paths(
		pathset,

		pathLayerTable,
		pathLayerGeomColumn,
		pathLayerIdColumn,

		'topo_update._app_do_AddPath_ColMapProvider'::regproc,
		jsonb_build_object(
			'properties', pathset -> 'properties',
			'path', jsonb_build_object(
				'table', pathLayerTable,
				'geomcol', pathLayerGeomColumn,
				'idcol', pathLayerIdColumn
			)
		),

		maxSplits => maxSplits
	);

END;
$$;



--
-- Name: _app_do_updateattributes_dynamic(name, jsonb, text, text, jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_updateattributes_dynamic(appname name, appconfig jsonb, tablename text, id text, properties jsonb) RETURNS boolean
    LANGUAGE plpgsql
    AS $_$ --{
DECLARE
	cfg_table JSONB;
	tgt_table REGCLASS;
	id_column NAME;
	map JSONB;

	colnames TEXT[];
	colvals TEXT[];
	col_updates TEXT[];
	col_upd TEXT;
	sql TEXT;

	v_cnt int;

	rec RECORD;
BEGIN

	-- Check if the operation is enabled
	IF NOT appconfig -> 'operations' ? 'UpdateAttributes' THEN
		RAISE EXCEPTION 'UpdateAttributes operation not enabled for application %', appname;
	END IF;

-- STRIP -- 	--RAISE DEBUG 'borderLayer: %', cfg_borderLayer;


	FOR rec IN SELECT jsonb_array_elements( appconfig -> 'tables' ) cfg
	LOOP --{
		IF rec.cfg ->> 'name' = tablename THEN
			cfg_table := rec.cfg;
			EXIT;
		END IF;
	END LOOP; --}

-- STRIP -- 	--RAISE DEBUG 'table: %', cfg_table;


	IF cfg_table IS NULL THEN
		RAISE EXCEPTION
			$$Table '%' is not defined in configuration of app '%'$$,
			tablename, appname;
	END IF;

	id_column := cfg_table ->> 'primary_key';

	IF id_column IS NULL THEN
		RAISE EXCEPTION
			$$Table '%' in app '%' does not have a primary key defined, cannot update$$,
			tablename, appname;
	END IF;

	-- Get the table's regclass

	SELECT c.oid::regclass
	FROM
		pg_catalog.pg_class c,
		pg_catalog.pg_namespace n
	WHERE
		n.nspname = appname AND
		c.relnamespace = n.oid AND
		c.relname = tablename
	INTO tgt_table;

	IF tgt_table IS NULL THEN
		RAISE EXCEPTION
			$$Table '%.%' does not exist: app '%' is broken$$,
			appname, tablename, appname;
	END IF;

	-- TODO: perform the update

	map := topo_update.json_col_map_from_pg( tgt_table );

	--RAISE WARNING 'COMPUTED: map: %', map;

	SELECT c.colnames, c.colvals
	FROM topo_update.json_props_to_pg_cols(properties, map) c
	INTO colnames, colvals;

	--RAISE WARNING 'COMPUTED: colnames: %', colnames;
	--RAISE WARNING 'COMPUTED: colvals: %', colvals;

	IF colnames IS NULL THEN
		-- Should this be an error instead ?
-- STRIP -- 		RAISE DEBUG 'No properties passed to app_do_UpdateAttributes, nothing to do';

		RETURN false;
	END IF;

	-- Naive approach: always UPDATE, no matter what

	FOR i IN 1 .. array_upper(colnames, 1)
	LOOP
		-- TODO: check the target column is ALLOWED to be changed
		--       by the operation, in appconfig
		col_upd := format('%s = %s', colnames[i], colvals[i]);
-- STRIP -- 		RAISE DEBUG 'col_upd: %', col_upd;

		col_updates := array_append(col_updates, col_upd);
	END LOOP;

-- STRIP -- 	RAISE DEBUG 'col_updates: %', col_updates;


	sql := format(
		$$
			UPDATE %1$s t
			SET %2$s
			FROM %1$s ot
			WHERE ot.%3$I = t.%3$I
			  AND ot.%3$I = %4$L
		$$,
		tgt_table,
		array_to_string(col_updates, ', '),
		id_column,
		id
	);

	-- TODO: ADD more WHERE clauses to skip setting values which did not
	--			 change ?
	--RAISE WARNING 'SQL: %', sql;

	EXECUTE sql;

	GET DIAGNOSTICS v_cnt = row_count;

	IF v_cnt = 0 THEN
		RETURN false;
	ELSE
		RETURN true;
	END IF;

END;
$_$;



--
-- Name: _app_do_validatebordersurfacemodel_dynamic(name, jsonb, public.geometry); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_do_validatebordersurfacemodel_dynamic(appname name, appconfig jsonb, bbox public.geometry DEFAULT NULL::public.geometry) RETURNS TABLE(err text, loc public.geometry)
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
	cfg_surfaceLayer JSONB;
	cfg_borderLayer JSONB;
	sql TEXT;
	topo topology.topology;
	borderLayer topology.layer;
	surfaceLayer topology.layer;
	rec RECORD;
BEGIN

	cfg_surfaceLayer := appconfig -> 'surface_layer';
	cfg_borderLayer := appconfig -> 'border_layer';

	IF cfg_surfaceLayer IS NULL OR cfg_borderLayer IS NULL THEN
		RETURN;
	END IF;

	-- Fetch topology and layer info from border layer references
	SELECT t topo, l layer
		FROM topology.layer l, topology.topology t, pg_class c, pg_namespace n
		WHERE l.schema_name = n.nspname
		AND l.table_name = c.relname
		AND c.oid = format('%I.%I', appname, ( cfg_borderLayer ->> 'table_name' ) )::regclass
		AND c.relnamespace = n.oid
		AND l.feature_column = ( cfg_borderLayer ->> 'geo_column' )
		AND l.topology_id = t.id
		INTO rec;
	topo := rec.topo;
	borderLayer := rec.layer;

	-- Fetch topology and layer info from surface layer references
	SELECT t topo, l layer
		FROM topology.layer l, topology.topology t, pg_class c, pg_namespace n
		WHERE l.schema_name = n.nspname
		AND l.table_name = c.relname
		AND c.oid = format('%I.%I', appname, ( cfg_surfaceLayer ->> 'table_name' ) )::regclass
		AND c.relnamespace = n.oid
		AND l.feature_column = ( cfg_surfaceLayer ->> 'geo_column' )
		AND l.topology_id = t.id
		INTO rec;

	IF id(topo) != id(rec.topo) THEN
		RAISE EXCEPTION 'Surface and Border layers need to be in same topology';
	END IF;
	surfaceLayer := rec.layer;

	-- Surface gaps are not invalid per Border/Surface model
	--RETURN QUERY SELECT * FROM topo_update.find_surface_gaps(topo, surfaceLayer, bbox);

	RETURN QUERY SELECT * FROM topo_update.find_surface_overlaps(topo, surfaceLayer, bbox);

	RETURN QUERY SELECT * FROM topo_update.validate_surface_borders(topo, surfaceLayer, borderLayer, bbox);

END;
$$;



--
-- Name: _app_validate_config(jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_validate_config(appconfig jsonb) RETURNS void
    LANGUAGE plpgsql
    AS $$ --{
DECLARE
	appconfig_version TEXT;
	cfg_tables JSONB;
	cfg_domains JSONB;
	rec RECORD;
	op_count INT := 0;
	cfg JSONB;
BEGIN

	-- Check version
	appconfig_version := appconfig ->> 'version';
	IF appconfig_version IS NULL THEN
		RAISE EXCEPTION 'Missing version in appconfig';
	END IF;
	IF appconfig_version != '1.0' THEN
		RAISE EXCEPTION 'Unsupported appconfig version %', appconfig -> 'version';
	END IF;

	-- Check domains
	cfg_domains := appconfig -> 'domains';
	IF cfg_tables IS NULL THEN
		IF jsonb_typeof(cfg_tables) != 'array' THEN
			RAISE EXCEPTION 'Invalid "domains" element in appconfig (must be array, not %)', jsonb_typeof(cfg_domains);
		END IF;
	END IF;

	-- Check tables
	cfg_tables := appconfig -> 'tables';
	IF cfg_tables IS NULL THEN
		RAISE EXCEPTION 'Missing "tables" element in appconfig';
	END IF;
	IF jsonb_typeof(cfg_tables) != 'array' THEN
		RAISE EXCEPTION 'Invalid "tables" element in appconfig (must be array, not %)', jsonb_typeof(cfg_tables);
	END IF;

	-- Validate "operations"
	-- TODO: avoid duplicated checks when multiple operations require
	--       the same status
	FOR rec IN SELECT * FROM jsonb_each(appconfig -> 'operations')
	LOOP --{
		cfg := rec.value;
		CASE rec.key
			WHEN 'AddBordersSplitSurfaces' THEN
				-- AddBorderSplitSurface always avoids:
				--   o Surfaces overlap
				--   o Surfaces gaps
				--   o Surfaces forming multi-polygons
				--   o Borders overlap
				--   o Borders cross
				--   o Borders dangling
				--   o Borders forming multi-linestrings
				-- TODO: shall it be made incompatible with
				--       those characteristics being allowed ?
				PERFORM topo_update._app_check_surface_layer(appconfig, cfg_tables);
				PERFORM topo_update._app_check_border_layer(appconfig, cfg_tables);
			WHEN 'SurfaceMerge' THEN
				-- SurfaceMerge operations require definition
				-- of Border and Surface layers
				PERFORM topo_update._app_check_surface_layer(appconfig, cfg_tables);
				PERFORM topo_update._app_check_border_layer(appconfig, cfg_tables);
			WHEN 'AddBorder' THEN
				-- AddBorder delegates allowing or not following
				-- situation based on APP_CONFIG:
				--   o Borders overlap
				--   o Borders cross
				--   o Borders dangling
				--   o Borders forming multi-linestrings
				PERFORM topo_update._app_check_border_layer(appconfig, cfg_tables);
			WHEN 'AddSurface' THEN
				-- AddSurface delegates allowing or not following
				-- situation based on APP_CONFIG:
				--   o Surfaces overlap
				--   o Surfaces gaps
				--   o Surfaces forming multi-polygons
				-- TODO: shall it be made incompatible with
				--       those characteristics being allowed ?
				PERFORM topo_update._app_check_surface_layer(appconfig, cfg_tables);
			WHEN 'UpdateAttributes' THEN
				-- TODO: check at least a table exists with primary key
			WHEN 'GetFeaturesAsTopoJSON' THEN
				PERFORM topo_update._app_check_GetFeaturesAsTopoJSON_config(appconfig, cfg);
			WHEN 'AddPath' THEN
				PERFORM topo_update._app_check_path_layer(appconfig, cfg_tables);
			WHEN 'RemovePath' THEN
				PERFORM topo_update._app_check_path_layer(appconfig, cfg_tables);
			WHEN 'SplitPaths' THEN
				PERFORM topo_update._app_check_path_layer(appconfig, cfg_tables);
			WHEN 'AddPoint' THEN
				PERFORM topo_update._app_check_point_layer(appconfig, cfg_tables);
			WHEN 'RemovePoint' THEN
				PERFORM topo_update._app_check_point_layer(appconfig, cfg_tables);
			WHEN 'MovePoint' THEN
				PERFORM topo_update._app_check_point_layer(appconfig, cfg_tables);
			ELSE
				RAISE EXCEPTION 'Unsupported operation %', rec.key;
		END CASE;
		op_count := op_count + 1;
	END LOOP; --}
	IF op_count < 1 THEN
		RAISE EXCEPTION 'Invalid appconfig: no operation defined';
	END IF;

END;
$$;



--
-- Name: _app_validate_layer_config(text, jsonb, jsonb, text); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._app_validate_layer_config(layer_element_name text, cfg_tables jsonb, cfg_layer jsonb, layertype text) RETURNS void
    LANGUAGE plpgsql
    AS $$ --{
DECLARE
	rec RECORD;
	cfg_layer_table JSONB;
	cfg_layer_geo_col JSONB;
	cfg_layer_id_col JSONB;
	cfg_layer_version_col JSONB;
BEGIN
	IF NOT cfg_layer ? 'table_name' THEN
		RAISE EXCEPTION 'Missing "table_name" in "%" element of appconfig',
			layer_element_name;
	END IF;
	IF NOT cfg_layer ? 'geo_column' THEN
		RAISE EXCEPTION 'Missing "geo_column" in "%" element of appconfig',
			layer_element_name;
	END IF;

	-- Find tables corresponding to surface layer
	FOR rec IN SELECT jsonb_array_elements( cfg_tables ) cfg
	LOOP
		IF rec.cfg ->> 'name' = cfg_layer ->> 'table_name' THEN
			cfg_layer_table := rec.cfg;
			EXIT;
		END IF;
	END LOOP;

	IF cfg_layer_table IS NULL THEN
		RAISE EXCEPTION '% table "%" not found in "tables" element',
			layer_element_name,
			cfg_layer ->> 'table_name';
	END IF;
	-- Find and check defined surface geocolumn
	FOR rec IN SELECT jsonb_array_elements( cfg_layer_table -> 'topogeom_columns' ) cfg
	LOOP --{
		IF rec.cfg ->> 'name' = cfg_layer ->> 'geo_column' THEN
			cfg_layer_geo_col := rec.cfg;
			EXIT;
		END IF;
	END LOOP; --}
	IF cfg_layer_geo_col IS NULL THEN
		RAISE EXCEPTION 'Table "%" does not have a "%" column (used as geo_column) defined in "topogeom_columns" array',
			cfg_layer_table ->> 'name',
			cfg_layer ->> 'geo_column';
	END IF;
	IF cfg_layer_geo_col ->> 'type' != layertype THEN
		RAISE EXCEPTION 'TopoGeom column % of layer table "%" must be have type "%", not "%"',
			cfg_layer_geo_col ->> 'name',
			cfg_layer_table ->> 'name',
			layertype,
			cfg_layer_geo_col ->> 'type'
		;
	END IF;
	-- Ensure layer table has a primary key defined
	IF NOT cfg_layer_table ? 'primary_key' THEN
		RAISE EXCEPTION '% table "%" lacks a "primary_key" element',
			layer_element_name, cfg_layer_table ->> 'name'
		;
	END IF;
	-- Find version and primary_key columns
	FOR rec IN SELECT jsonb_array_elements( cfg_layer_table -> 'attributes' ) cfg
	LOOP --{
		IF rec.cfg ->> 'name' = cfg_layer ->> 'version_column' THEN
			cfg_layer_version_col := rec.cfg;
		END IF;
-- STRIP -- 		--RAISE DEBUG 'Attribue %, we are looking for %', rec.cfg ->> 'name' , cfg_layer_table ->> 'primary_key' ;

		IF rec.cfg ->> 'name' = cfg_layer_table ->> 'primary_key' THEN
			cfg_layer_id_col := rec.cfg;
		END IF;
	END LOOP; --}
	-- Verify primary key column is found in table
	IF cfg_layer_id_col IS NULL THEN
		RAISE EXCEPTION '% table "%" primary key attribute "%" not found',
			layer_element_name,
			cfg_layer_table ->> 'name',
			cfg_layer_table ->> 'primary_key'
		;
	END IF;
END;
$$;



--
-- Name: _getmergeablesurfaceborders_query(name, jsonb, name, name, name, name, name, name, public.geometry); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._getmergeablesurfaceborders_query(appname name, cfg_op jsonb, borderlayeridcolumn name, borderlayertablename name, borderlayergeomcolumn name, surfacelayertablename name, surfacelayergeomcolumn name, surfacelayeridcolumn name, bbox public.geometry) RETURNS text
    LANGUAGE plpgsql
    AS $_$ --{
DECLARE
	filter TEXT := '';
	sql TEXT;
	rec RECORD;

BEGIN

	sql := format(
		$$
SELECT
	ST_Union(distinct b.%5$I) border_visible_geom,
	array_agg(distinct b.%1$I::text) border_ids,
	ARRAY[
		least(sl.%8$I::text, sr.%8$I::text),
		greatest(sl.%8$I::text, sr.%8$I::text)
	] side_faces
FROM
	%2$I.edge e,
	%2$I.face fl,
	%2$I.face fr,
	%2$I.relation ebr,
	topology.layer blayer,
	%3$I.%4$I b,

	%2$I.relation flsr,
	%2$I.relation frsr,
	topology.layer slayer,
	%3$I.%6$I sl,
	%3$I.%6$I sr
WHERE

	-- edges selection
	( $1 IS NULL OR ST_Intersects(e.geom, $1) )

	-- border layer selection
	AND blayer.schema_name = %3$L
	AND blayer.table_name = %4$L
	AND blayer.feature_column = %5$L

	-- border layer relation join
	AND ebr.layer_id = blayer.layer_id
	AND ebr.element_id = e.edge_id
	AND ebr.topogeo_id = id(b.%5$I)

	-- left face selection
	AND e.left_face = fl.face_id

	-- right face selection
	AND e.right_face = fr.face_id

	-- surface layer selection
	AND slayer.schema_name = %3$L
	AND slayer.table_name = %6$L
	AND slayer.feature_column = %7$L

	-- left surface / surface layer relation join
	AND flsr.layer_id = slayer.layer_id
	AND flsr.element_id = e.left_face
	AND flsr.topogeo_id = id(sl.%7$I)

	-- right surface / surface layer relation join
	AND frsr.layer_id = slayer.layer_id
	AND frsr.element_id = e.right_face
	AND frsr.topogeo_id = id(sr.%7$I)

		$$,
		borderLayerIdColumn, ----------------------- %1: border id column
		format('%s_sysdata_webclient', appname), --- %2: topology schema
		appname, ----------------------------------- %3: appname
		borderLayerTableName, ---------------------- %4: border table name
		borderLayerGeomColumn, --------------------- %5: border geom column
		surfaceLayerTableName, --------------------- %6: surface table name
		surfaceLayerGeomColumn, -------------------- %7: surface geom name
		surfaceLayerIdColumn  ---------------------- %8: surface id column
	);

-- STRIP -- 	--RAISE DEBUG 'Op config: %', cfg_op;


	-- Add sharedSurfaceAttributes condition
	FOR rec IN SELECT
		jsonb_array_elements_text(cfg_op -> 'sharedSurfaceAttributes') a
	LOOP
-- STRIP -- 		--RAISE DEBUG 'Adding condition about same value for attribute %', rec.a;

		-- NOTE: we use IS DISTINCT FROM so that nulls are considered equal
		sql := format(E'%1$s\nAND NOT sl.%2$I IS DISTINCT FROM sr.%2$I', sql, rec.a);
	END LOOP;

	-- Add max area condition
	IF cfg_op ? 'maxSurfaceArea' THEN
		sql := format(
			E'%1$s\nAND ( ST_Area(sl.%2$I::%4$s) <= %3$s OR ST_Area(sr.%2$I::%4$s) <= %3$s )',
			sql,
			surfaceLayerGeomColumn,
			cfg_op -> 'maxSurfaceArea' ->> 'units',
			CASE WHEN
				(cfg_op -> 'maxSurfaceArea' -> 'unitsAreMeters')::bool
			THEN
				'geometry::geography'
			ELSE
				'geometry'
			END
		);
	END IF;

	-- Add arbitrary sql filter
	IF cfg_op ? 'surfaceSQLFilter' THEN
		filter = cfg_op ->> 'surfaceSQLFilter';
		-- minimal sanification
		IF position(';' in filter) > 0 THEN
			RAISE EXCEPTION 'Semicolon character is forbidden in surfaceSQLFilter';
		END IF;
		-- TODO: check quotes are balanced ?
		-- TODO: check parens are balanced ?
		filter = REPLACE (filter, ':S1', 'sl');
		filter = REPLACE (filter, ':S2', 'sr');

		sql := format(E'%1$s\nAND ( %2$s )', sql, filter);

	END IF;


	sql := format(E'%1$s\nGROUP BY 3', sql);

	-- RAISE WARNING 'SQL: %', sql;

	RETURN sql;
END;
$_$;



--
-- Name: _json_col_map_override(jsonb[]); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._json_col_map_override(maps jsonb[]) RETURNS jsonb
    LANGUAGE plpgsql
    AS $$
DECLARE
	rec RECORD;
	map JSONB;
BEGIN

	IF array_upper(maps, 1) != 2 THEN
		RAISE EXCEPTION '_json_col_map_override only supports 2 maps at the moment';
	END IF;

	map := '{}';
	FOR rec IN SELECT jsonb_object_keys(maps[1]) k
	LOOP
		-- Find right-most map containing the key

		map := jsonb_set(
			map,
			ARRAY[rec.k], -- pg col name (check composite!)
			CASE WHEN maps[2] ? rec.k THEN
				-- Take col value from payload
				to_jsonb(ARRAY['p' || 1]) || (
					maps[2] -> rec.k
				)
			ELSE
				-- Take col value from exiting Surface
				to_jsonb(ARRAY['p' || 0]) || (
					maps[1] -> rec.k
				)
			END
		);
	END LOOP;
	return map;
END;
$$;



--
-- Name: _most_adjacent_surface(topology.topology, integer[], topology.layer, name); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._most_adjacent_surface(topo topology.topology, faces integer[], surfacelayer topology.layer, surfacelayeridcolumn name, OUT bestsurfaceid text, OUT bestsurfaceprops jsonb) RETURNS record
    LANGUAGE plpgsql
    AS $_$
DECLARE
	--adjFaces INT[];
	rec RECORD;
	sql TEXT;
	procName TEXT := 'topo_update._most_adjacent_surface';
BEGIN
	--
	-- Find Surface TopoGeometry object containing any
	-- adjacent faces and pick the one with the longest
	-- shared boundary
	--
	sql := format(
		$$
WITH adjacentFaces AS (
	-- Find adjacent faces
	SELECT face_id, sum(len) len
	FROM (
		SELECT
			CASE WHEN left_face = ANY($1) THEN right_face
			ELSE left_face END face_id,
			ST_Length(geom) len
		FROM %1$s.edge
		WHERE ( left_face = ANY($1) ) <> ( right_face = ANY($1) )
		AND left_face > 0
		AND right_face > 0
	) foo
	GROUP BY face_id
), adjacentSurfaces AS (
	SELECT
		surface.%2$I surface_id,
		sum(adjFace.len) len,
		surface surface_record
	FROM
		%3$I.%4$I surface,
		adjacentFaces adjFace,
		%1$I.relation
	WHERE
		-- TopoGeometry contains any of the
		-- adjacentFaces
		relation.topogeo_id = id(%5$I)
		AND relation.layer_id = layer_id(%5$I)
		AND relation.element_id = adjFace.face_id
	GROUP BY surface_id, surface_record
)
SELECT surface_id, to_jsonb(surface_record) surface_record_jsonb, len border_len
FROM adjacentSurfaces
ORDER BY
	len DESC,
	-- in case of same shared-edges len, pick Surface with highest id
	surface_id DESC
LIMIT 1
		$$,
		topo.name,
		surfaceLayerIdColumn,
		surfaceLayer.schema_name,
		surfaceLayer.table_name,
		surfaceLayer.feature_column
	);
-- STRIP -- 	RAISE DEBUG '%: SQL %', procName, sql;

	EXECUTE sql USING faces INTO rec;
	IF rec.surface_id IS NULL THEN
		RETURN;
	END IF;

-- STRIP -- 	RAISE DEBUG '%: Surface % has shared border length %',
-- STRIP -- 		procName, rec.surface_id, rec.border_len

	-- Extract id of best surface
	bestSurfaceId = rec.surface_id;

	-- Extract properties of best surface
	bestSurfaceProps := rec.surface_record_jsonb
		- surfaceLayer.feature_column -- drop TopoGeometry column from props
		- surfaceLayerIdColumn -- drop ID column from props
	;
-- STRIP -- 	RAISE DEBUG '%: best Surface props: %', procName, bestSurfaceProps;


END;
$_$;



--
-- Name: _pg_col_names(regclass); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._pg_col_names(targettable regclass) RETURNS text[]
    LANGUAGE plpgsql STABLE
    AS $$ --{
DECLARE
	rec RECORD;
	subrec RECORD;
	keys TEXT[];
BEGIN

	FOR rec IN
		SELECT
			a.attname,
			t.typtype,
			t.typrelid
		FROM pg_attribute a
		JOIN pg_type t ON (a.atttypid = t.oid)
		WHERE a.attrelid = targetTable
		AND NOT a.attisdropped
		AND a.attnum > 0
		ORDER BY a.attnum
	LOOP
		IF rec.typtype = 'b' OR rec.typtype = 'd' THEN
			keys := keys || rec.attname::text;
		ELSIF rec.typtype = 'c' THEN
			-- Type is composite
			FOR subrec IN SELECT unnest(topo_update._pg_col_names(rec.typrelid)) k
			LOOP
				keys := keys || format('%s.%s', rec.attname, subrec.k);
			END LOOP;
		ELSE
			RAISE EXCEPTION 'topo_update._pg_col_names does not support attributes of type %', rec.typtype;
		END IF;
	END LOOP;

	RETURN keys;
END;
$$;



--
-- Name: _point_on_face(text, integer); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._point_on_face(topo_name text, face_id integer) RETURNS public.geometry
    LANGUAGE plpgsql
    AS $_$ --{
DECLARE
	mbr GEOMETRY;
BEGIN
	IF face_id = 0 THEN
		EXECUTE format($$
			SELECT mbr FROM %1$I.face WHERE face_id = 0
		$$, topo_name) INTO mbr;
		IF mbr IS NOT NULL THEN
			RAISE EXCEPTION 'topo_update._point_on_face: topology % is corrupted: universal face has not-null MBR', topo_name;
		ELSE
			-- universal face has no geometry...
			RAISE EXCEPTION 'topo_update._point_on_face should not be called with face_id=0';
		END IF;
		--RETURN NULL;
	END IF;

	-- TODO: rather than building the face's
	-- Geometry we could  take a point on its
	-- surface using some optimized function
	-- to do that. See
	-- https://trac.osgeo.org/postgis/ticket/4861
	RETURN ST_PointOnSurface(topology.ST_GetFaceGeometry(topo_name, face_id));
END;
$_$;



--
-- Name: _select_split_component(public.geometry, topology.topology, boolean, double precision); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._select_split_component(geom_in public.geometry, topo topology.topology, longestonly boolean DEFAULT true, snaptolerance double precision DEFAULT 0) RETURNS public.geometry
    LANGUAGE plpgsql
    AS $_$ --{
DECLARE
	sql TEXT;
	geom_out GEOMETRY;
	intersecting_edges GEOMETRY;
	proc_name TEXT = 'topo_update._select_split_component';
	rec RECORD;
	split_components GEOMETRY[];
	endpoint GEOMETRY;
	tol FLOAT8;
	-- We can increase this a lot becuase we now use the number of faces generated as test.
	-- We also have checks on min area this means that we avoid all those small surfaces.
	max_geometries_intersects INT = 20;
BEGIN

	tol := snapTolerance;
	IF tol = 0 THEN
		tol := topo.precision;
	END IF;
	IF tol = 0 THEN
		tol := topology._st_mintolerance(geom_in);
	END IF;

-- STRIP -- 	RAISE DEBUG '%: working tolerance: %', proc_name, tol;


	-- Collect the edges intersecting
	-- the input geometry
	sql := format(
		$$
SELECT ST_Collect(e.geom) as geom
FROM %1$I.edge e
WHERE ST_DWithin(e.geom, $1, $2)
		$$,
		topo.name
	);
	EXECUTE sql
	USING geom_in, tol
	INTO intersecting_edges;

-- STRIP -- 	RAISE DEBUG '%: % edges intersect input line, collected as: %',
-- STRIP -- 		proc_name, ST_NumGeometries(intersecting_edges), ST_AsEWKT(intersecting_edges)

	-- TODO: check intersection exists with at least 1 edge ?
	-- TODO: check there are at least 2 intersections with the edges ?
	-- TODO: exclude dangling edges from the check ?

	-- Snap the input geometry to the intersecting edges
	geom_in := ST_Snap(geom_in, intersecting_edges, tol);
-- STRIP -- 	RAISE DEBUG '%: input line (of type %) snapped to intersecting edges: %',
-- STRIP -- 		proc_name, ST_GeometryType(geom_in), ST_AsEWKT(geom_in)

	-- Split the input geometry by
	-- snapped edges
	geom_out := ST_Split(geom_in, intersecting_edges);

-- STRIP -- 	RAISE DEBUG '%: snapped input line split by intersecting edges into % components, collected as: %',
-- STRIP -- 		proc_name, ST_NumGeometries(geom_out), ST_AsEWKT(geom_out)

	-- We need to accept
	IF ST_GeometryType(geom_in) = 'ST_MultiLineString' THEN
		max_geometries_intersects := max_geometries_intersects * 4;
	END IF;

	IF ST_NumGeometries(geom_out) > max_geometries_intersects THEN
		RAISE EXCEPTION 'Non closed linestring of type % intersects more than % (% times) with existing edges',
			ST_GeometryType(geom_in), max_geometries_intersects-1, ST_NumGeometries(geom_out)-1;
	END IF;

	-- Select, among all components of the splitted input geometry,
	-- the component touching existing edges on both sides.
	FOR rec IN
		SELECT (ST_Dump(geom_out)).geom
	LOOP
-- STRIP -- 		RAISE DEBUG '%: split component:  %', proc_name, ST_AsEWKT(rec.geom);


		-- Skip component if it does not touch intersecting
		-- edges on both sides

		endpoint := ST_StartPoint(rec.geom);

		IF NOT ST_DWithin(
			endpoint,
			intersecting_edges,
			tol)
		THEN
-- STRIP -- 			RAISE DEBUG '%: component start point not within min tolerance from edges',
-- STRIP -- 				proc_name
			CONTINUE;
		END IF;

		endpoint := ST_EndPoint(rec.geom);

		IF NOT ST_DWithin(
			endpoint,
			intersecting_edges,
			tol)
		THEN
-- STRIP -- 			RAISE DEBUG '%: component end point not within min tolerance from edges',
-- STRIP -- 				proc_name
			CONTINUE;
		END IF;

		split_components := array_append(split_components, rec.geom);
	END LOOP;

	IF longestOnly THEN
		SELECT geom
		FROM unnest(split_components) geom
		ORDER BY ST_Length(geom)
		LIMIT 1
		INTO rec;
		RETURN rec.geom;
	ELSE
		RETURN ST_Collect(split_components);
	END IF;
END;
$_$;



--
-- Name: _surface_as_geojson_features(topology.topology, topology.layer, text, topology.topogeometry, jsonb, regclass, name, name, jsonb, regclass, regproc, anyelement, integer, integer); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._surface_as_geojson_features(topo topology.topology, surfacelayer topology.layer, surfaceid text, surfacetopogeom topology.topogeometry, surfaceprops jsonb, borderlayertable regclass, borderlayertopogeomcolumn name, borderlayeridcolumn name, borderlayercolmap jsonb, visitedborders regclass, featurejsonmodifier regproc DEFAULT NULL::regproc, featurejsonmodifierarg anyelement DEFAULT NULL::integer, outsrid integer DEFAULT NULL::integer, maxdecimaldigits integer DEFAULT 9) RETURNS SETOF jsonb
    LANGUAGE plpgsql
    AS $_$ -- {
DECLARE
	sql TEXT;
	borderRewriteSQL TEXT;
	surfaceRewriteSQL TEXT;
	rec RECORD;
	surfaceBorders TEXT[];
	feature JSONB;
	surfaceGeom GEOMETRY;
	borderGeom GEOMETRY;
	surfacePosition GEOMETRY;
	exteriorRing JSONB;
	exteriorRingGeom GEOMETRY;
	interiorRings JSONB[];
	interiorRingGeoms GEOMETRY[];
	procName TEXT := 'topo_update._surface_as_geojson_features';
	borderProps JSONB;
	prec FLOAT8 := pow(10, -maxdecimaldigits);
BEGIN


	--------------------------------------------------------
	-- Find the Surface's exterior and interior rings
	--------------------------------------------------------

	-- Create a temporary "surface_borders" table
	FOR rec IN
		SELECT * FROM topo_update.get_surface_borders(
			topo,
			surfaceTopoGeom,
			borderLayerTable,
			borderLayerTopoGeomColumn,
			borderLayerIdColumn
		)
	LOOP

		IF exteriorRing IS NULL
		THEN
			exteriorRing := to_jsonb(rec.signedRingBorders);
			exteriorRingGeom := ST_LineMerge(ST_Collect(rec.ringBorderGeoms));
		ELSE
			interiorRings := array_append(interiorRings, to_jsonb(rec.signedRingBorders));
			interiorRingGeoms := array_append(interiorRingGeoms, ST_LineMerge(ST_Collect(rec.ringBorderGeoms)));
		END IF;

		surfaceBorders := surfaceBorders || rec.ringBorders;

	END LOOP;


-- STRIP -- 	RAISE DEBUG '%: Surface % exteriorRing: %', procName, surfaceID, exteriorRing;

-- STRIP -- 	RAISE DEBUG '%: Surface % interiorRings: %', procName, surfaceID, interiorRings;


	-------------------------------------------------
	-- Write and return the unvisited Border objects
	-------------------------------------------------

	-- Query to:
	--   - extract unvisited Borders data
	--   - mark unvisited Borders as visited
	--
	-- Parameters:
	--   $1 - Surface Border identifiers as a TEXT[]
	sql := format(
		$$
			WITH unvisitedBorders AS (
				INSERT INTO %4$s
				SELECT b FROM unnest($1) b
				WHERE b NOT IN ( SELECT fid FROM %4$s )
				RETURNING fid
			)
			SELECT
				b border_record,
				b.%1$I::text border_id,
				b.%2$I border_topogeom
			FROM %3s b, unvisitedBorders ub
			WHERE b.%1$I::TEXT = ub.fid
			ORDER BY b.%1$I
		$$,
		borderLayerIdColumn,        -- %1
		borderLayerTopoGeomColumn,  -- %2
		borderLayerTable,           -- %3
		visitedBorders              -- %4
	);
-- STRIP -- 	RAISE DEBUG '%: SQL: %', procName, sql;


	-- Write and return each unvisited Border
	FOR rec IN EXECUTE sql USING surfaceBorders
	LOOP --{

		-- Build properties of the Border
		borderProps := topo_update.record_to_jsonb(
			rec.border_record,
			borderLayerColMap
		);

		IF borderProps IS NULL THEN
			RAISE EXCEPTION 'Properties for border % as extracted by colMap % are NULL',
				to_jsonb(rec.border_record), borderLayerColMap;
		END IF;

		-- Write and return the unvisited Border Feature object

		borderGeom = ST_CollectionHomogenize(
			rec.border_topogeom::geometry
		);

		IF outSRID IS NOT NULL
		THEN
			borderGeom := ST_Transform(borderGeom, outSRID);
		END IF;

		-- Remove points that will be seen as repeated
		-- when precision is reduced due to number of
		-- decimal digits
		borderGeom := ST_RemoveRepeatedPoints(borderGeom, prec);

		feature := jsonb_build_object(
			'type', 'Feature',
			'geometry', ST_AsGeoJSON(
				borderGeom,
				maxdecimaldigits => maxdecimaldigits,
				options => 0
			)::jsonb,
			'properties', borderProps
		);

		IF featureJsonModifier IS NOT NULL
		THEN
			-- TODO: take borderRewriteSQL as parameter
			IF borderRewriteSQL IS NULL
			THEN
				IF featureJsonModifierArg IS NULL
				THEN
					borderRewriteSQL := format(
						$$
							SELECT * FROM %s(feat => $1, role => 'B')
						$$,
						featureJsonModifier::text
					);
				ELSE
					borderRewriteSQL := format(
						$$
							SELECT * FROM %s(feat => $1, role => 'B', usr => $2)
						$$,
						featureJsonModifier::text
					);
				END IF;
-- STRIP -- 				RAISE DEBUG 'Border JSON Modifier SQL: %', borderRewriteSQL;

			END IF;
			-- invoke borderRewriteSQL
			EXECUTE borderRewriteSQL
				USING feature, featureJsonModifierArg
				INTO feature;
		END IF;

		RETURN NEXT feature;

	END LOOP; -- }

	-----------------------------------------------
	-- Write and return the Surface Feature object
	-----------------------------------------------

	-- Build the Surface geometry, to be used
	-- for writing the "geometry" GeoJSON Feature
	-- attribute
	--
	IF interiorRingGeoms IS NULL
	THEN
		surfaceGeom := ST_MakePolygon(
			exteriorRingGeom
		);
	ELSE
		surfaceGeom := ST_MakePolygon(
			exteriorRingGeom,
			interiorRingGeoms
		);
	END IF;

	-- Reproject to output SRID, if requested
	IF outSRID IS NOT NULL
	THEN
		-- TODO: drop this, ensure borders are transformed first
		surfaceGeom := ST_Transform(surfaceGeom, outSRID);
	END IF;

	-- Remove points that will be seen as repeated
	-- when precision is reduced due to number of
	-- decimal digits
	-- TODO: do this at the border level, no need to do it again
	surfaceGeom := ST_RemoveRepeatedPoints(surfaceGeom, prec);

	-- Sanity check
	IF ST_NumGeometries(surfaceGeom) > 1 THEN
		RAISE EXCEPTION '%: Surface % is unexpectedly a multi-geometry: %',
			procName, surfaceID, ST_Summary(surfaceGeom);
	END IF;

	-- Find a point on the Surface
	-- TODO: get point on surface directly from the TopoGeometry
	--       see https://trac.osgeo.org/postgis/ticket/4865
	surfacePosition := ST_PointOnSurface(surfaceGeom);

	feature := jsonb_build_object(
		'type', 'Feature',
		'geometry', ST_AsGeoJSON(
			surfaceGeom,
			maxdecimaldigits => maxdecimaldigits,
			options => 0
		)::jsonb,
		'properties', surfaceProps,
		'geometry_properties', jsonb_build_object(
			'position', jsonb_build_array(
				round(ST_X(surfacePosition)::numeric, maxdecimaldigits),
				round(ST_Y(surfacePosition)::numeric, maxdecimaldigits)
			),
			'exterior', exteriorRing
		)
	);

	IF interiorRings IS NOT NULL THEN
		feature := jsonb_set(
			feature,
			'{geometry_properties,interiors}',
			to_jsonb(interiorRings)
		);
	END IF;

	IF featureJsonModifier IS NOT NULL
	THEN
		-- TODO: take surfaceRewriteSQL as parameter
		IF surfaceRewriteSQL IS NULL
		THEN
			IF featureJsonModifierArg IS NULL
			THEN
				surfaceRewriteSQL := format(
					$$
						SELECT * FROM %s(feat => $1, role => 'S')
					$$,
					featureJsonModifier::text
				);
			ELSE
				surfaceRewriteSQL := format(
					$$
						SELECT * FROM %s(feat => $1, role => 'S', usr => $2)
					$$,
					featureJsonModifier::text
				);
			END IF;
-- STRIP -- 			RAISE DEBUG 'Surface JSON Modifier SQL: %', surfaceRewriteSQL;

		END IF;
		-- invoke surfaceRewriteSQL
		EXECUTE surfaceRewriteSQL
			USING feature, featureJsonModifierArg
			INTO feature;
	END IF;

	RETURN NEXT feature;

END;
$_$;



--
-- Name: _update_features_def_extractor(jsonb, integer, integer); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update._update_features_def_extractor(feature jsonb, feat_srid integer, topo_srid integer, OUT role character, OUT prop jsonb) RETURNS record
    LANGUAGE plpgsql
    AS $$ -- {
DECLARE
	proc_name TEXT := 'topo_update._update_features_def_extractor';
	feat_type TEXT;
BEGIN

	-- Determine role
	feat_type := feature -> 'geometry' ->> 'type';
	IF feat_type = 'LineString' OR feat_type = 'MultiLineString'
	THEN
		role := 'B';
	ELSIF feat_type = 'Polygon' OR feat_type = 'MultiPolygon'
	THEN
		role := 'S';
	ELSE
		RAISE EXCEPTION '%: unsupported feature type %', proc_name, feat_type;
	END IF;

	-- Extract properties role
	prop := feature -> 'properties';
END;
$$;



--
-- Name: add_all_topo_primitive_used_constraint(regclass, name, text); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.add_all_topo_primitive_used_constraint(layertable regclass, layertopogeomcolumn name, filtersql text DEFAULT NULL::text) RETURNS text
    LANGUAGE plpgsql
    AS $_$
DECLARE
	sql TEXT;
	rec RECORD;
	topo topology.topology;
	layer topology.layer;
	trigname TEXT;
BEGIN

	-- Fetch topology and layer info from layer references
	SELECT t topo, l layer
		FROM topology.layer l, topology.topology t, pg_class c, pg_namespace n
		WHERE l.schema_name = n.nspname
		AND l.table_name = c.relname
		AND c.oid = layerTable
		AND c.relnamespace = n.oid
		AND l.feature_column = layerTopoGeomColumn
		AND l.topology_id = t.id
	INTO rec;
	topo := rec.topo;
	layer := rec.layer;

	-- Check consistency upfront
	FOR rec IN SELECT * FROM topo_update.find_gaps(
			layerTable,
			layerTopoGeomColumn,
			filterSQL
		)
	LOOP
		RAISE EXCEPTION 'No feature in layer % (%) uses % %',
				layerTable,
				layerTopoGeomColumn,
				CASE rec.etyp
				WHEN 1 THEN
					'node'
				WHEN 2 THEN
					'edge'
				WHEN 3 THEN
					'face'
				END,
				rec.eid;
	END LOOP;

	trigName := format('primitives_all_used_in_layer_%s', layer.layer_id);

	sql := format(
		$$
CREATE TRIGGER %1$I
AFTER DELETE OR UPDATE
ON %2$s
FOR EACH STATEMENT
EXECUTE PROCEDURE
topo_update.check_topo_primitives_all_used(%3$L, %4$L)
		$$,
		trigName,              -- %1
		layerTable,            -- %2
		layerTopoGeomColumn,   -- %3
		COALESCE(filterSQL,'') -- %4
	);

-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;


	EXECUTE sql;

	RETURN trigName;

END;
$_$;



--
-- Name: add_border_split_surface(jsonb, regclass, name, name, jsonb, regclass, name, name, jsonb, double precision); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.add_border_split_surface(feature jsonb, surfacelayertable regclass, surfacelayergeomcolumn name, surfacelayeridcolumn name, surfacelayercolmap jsonb, borderlayertable regclass, borderlayergeomcolumn name, borderlayeridcolumn name, borderlayercolmap jsonb, tolerance double precision) RETURNS TABLE(fid text, typ character, act character)
    LANGUAGE plpgsql
    AS $$
BEGIN
	RAISE WARNING 'add_border_split_surface with colMap params is deprecated';
	RETURN QUERY
	SELECT o.fid, o.typ, o.act FROM topo_update.add_border_split_surface(
		feature,
		surfaceLayerTable,
		surfaceLayerGeomColumn,
		surfaceLayerIdColumn,
		borderLayerTable,
		borderLayerGeomColumn,
		borderLayerIdColumn,
		tolerance,
		'topo_update._add_border_split_surface_get_map_from_array',
		ARRAY[borderLayerColMap, surfaceLayerColMap]
	) o;

END;
$$;



--
-- Name: add_border_split_surface(jsonb, regclass, name, name, regclass, name, name, double precision, regproc, anyelement, double precision, integer, integer, boolean); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.add_border_split_surface(feature jsonb, surfacelayertable regclass, surfacelayergeomcolumn name, surfacelayeridcolumn name, borderlayertable regclass, borderlayergeomcolumn name, borderlayeridcolumn name, tolerance double precision, colmapproviderfunc regproc, colmapproviderparam anyelement, mintoleratedfacearea double precision DEFAULT NULL::double precision, maxallowedsurfacesplitcount integer DEFAULT 5, maxnewsurfacesorchangedareasurfaces integer DEFAULT 10, keepmodifiedsurface boolean DEFAULT true) RETURNS TABLE(fid text, typ character, act character, frm text)
    LANGUAGE plpgsql
    AS $_$
DECLARE

	rec RECORD;
	rec2 RECORD;

	featureGeom JSONB;

	payloadProps JSONB;

	newBorder topology.topogeometry;
	modBorderGeom GEOMETRY;
	newBorderId text;
	oldBorderProps JSONB;
	newBorderProps JSONB;

	newSurface topology.topogeometry;
	newSurfaceId text;
	oldSurfaceProps JSONB;
	newSurfaceProps JSONB;

	-- holds dynamic sql
	sql text;

	proc_name text = 'topo_update.add_border_split_surface';

	inputLine GEOMETRY;
	overlapPoints GEOMETRY;

	topo topology.topology;

	candidateInputLines GEOMETRY;
	dropInputLines INT[];

	inputLineEdgeIds INT[];
	inputLineNodeIds INT[];

	maxFaceBefore INT;
	newFacesCount INT;
	newFaces INT[];

	coveredNewFaces INT[];
	uncoveredNewFaces INT[];

	borderLayer topology.layer;
	surfaceLayer topology.layer;

	-- Holds dynamic sql to execute
	-- by passing $1=colMapProviderParam,
	-- $2=typ, $3=act to extract the
	-- appropriate column mapping
	colMapExtractSQL TEXT;

	-- Column mapping file for modified surfaces
	-- as provided by colMapProvider
	colMapForModSurface JSONB;

	-- Column mapping file for independent surfaces
	-- as provided by colMapProvider
	colMapForNewSurface JSONB;

	-- Column mapping file for surfaces replacing
	-- space previously covered by existing surfaces
	-- as provided by colMapProvider
	colMapForSplitSurface JSONB;

	-- Column mapping file for independent surfaces
	-- inheriting attributes from adjacent Surface
	inhNewSurfaceColMap JSONB;

	-- Column mapping file for split surfaces
	-- inheriting attributes from adjacent Surface
	inhSplitSurfaceColMap JSONB;

	-- Column mapping used for new surfaces
	-- (pointer to one of the *SurfaceColMap above)
	surfaceColMap JSONB;

	-- Column mapping file for modified borders
	-- as provided by colMapProvider
	colMapForModBorder JSONB;

	-- Column mapping file for borders
	-- as provided by colMapProvider
	colMapForNewBorder JSONB;

	-- Column mapping file for borders
	-- replacing space previously covered
	-- by existing borders as provided by
	-- colMapProvider
	colMapForSplitBorder JSONB;

	-- Column mapping file for split borders
	-- inheriting attributes from existing Border
	inhSplitBorderColMap JSONB;

	-- Border as split by incoming line
	splitBorderGeom GEOMETRY;
	splitBorderGeomComp GEOMETRY;
	splitBorderStartPoint GEOMETRY;
	splitBorderStartPointNodeDegree INT;
	splitBorderMergeOnStartPoint BOOLEAN;

	-- Number of elements a border was split into
	splitBorderCount INT;

	-- Number of surfaces being split
	splitSurfaceCount INT := 0;

	i INT;

	tea topology.TopoElementArray;

BEGIN

	-- Fetch topology and layer info from border layer references
	SELECT t topo, l layer
		FROM topology.layer l, topology.topology t, pg_class c, pg_namespace n
		WHERE l.schema_name = n.nspname
		AND l.table_name = c.relname
		AND c.oid = borderLayerTable
		AND c.relnamespace = n.oid
		AND l.feature_column = borderLayerGeomColumn
		AND l.topology_id = t.id
	--	FOR UPDATE, 2 problems, user needs SUPERUSER (can be fixed),
	--  ms used from 8601 -> 113606 for ((14.355156130507279 67.27980828078813, 14.354976710179235 67.28648792270606, 14.395077865039152 67.28664388346324, 14.395246132501715 67.27996419068565, 14.355156130507279 67.27980828078813))
		INTO rec;
	topo := rec.topo;
	borderLayer := rec.layer;

	IF topo.id IS NULL THEN
		RAISE EXCEPTION 'Could not find topology from input';
	END IF;

	--	RAISE NOTICE 'Lock on topology % obtained', topo.name;

	-- Fetch topology and layer info from surface layer references
	SELECT t topo, l layer
		FROM topology.layer l, topology.topology t, pg_class c, pg_namespace n
		WHERE l.schema_name = n.nspname
		AND l.table_name = c.relname
		AND c.oid = surfaceLayerTable
		AND c.relnamespace = n.oid
		AND l.feature_column = surfaceLayerGeomColumn
		AND l.topology_id = t.id
		INTO rec;

	IF id(topo) != id(rec.topo) THEN
		RAISE EXCEPTION 'Surface and Border layers need to be in same topology';
	END IF;
	surfaceLayer := rec.layer;

	featureGeom = feature->'geometry';
	IF featureGeom IS NULL
	THEN
		RAISE EXCEPTION 'Input feature lacks a "geometry" element: %',
			feature;
	END IF;

	IF NOT featureGeom ? 'crs'
	THEN
		RAISE EXCEPTION 'Input feature geometry lacks a "crs" element: %',
			featureGeom;
	END IF;

	-- Read input line geometry from GeoJSON
	inputLine := ST_GeomFromGeoJSON(featureGeom);

	IF topo.srid != ST_Srid(inputLine) THEN
		inputLine := ST_Transform(inputLine, topo.srid);
-- STRIP -- 		--RAISE DEBUG 'REPROJECTED GEOM: %', ST_AsEWKT(inputLine);

	END IF;

	-- "Massage" input line
-- STRIP -- 	RAISE DEBUG 'Input line: %', ST_AsText(inputLine);

	inputLine := topo_update.prepare_split_border(
		inputLine,
		topo,
		tolerance
	);
-- STRIP -- 	RAISE DEBUG 'Prepared input line: %', ST_AsText(inputLine);


	-- Keep track of max face id in the topology
	sql := format('SELECT max(face_id) FROM %I.face', topo.name);
-- STRIP -- 	RAISE DEBUG '%: sql: %', proc_name, sql;

	EXECUTE sql INTO maxFaceBefore;
-- STRIP -- 	RAISE DEBUG '%: max face_id before inserting border: %', proc_name, maxFaceBefore;


	-- Write SQL to extract colMaps
	-- $1: usr
	-- $2: typ
	-- $3: act
	colMapExtractSQL := format(
		'SELECT * FROM %s(usr => $1, typ => $2, act => $3)',
		colMapProviderFunc
	);

	payloadProps := feature -> 'properties';

	candidateInputLines := ST_ForceCollection(inputLine);

	-- We only tolerate faces having an area of at least
	-- the given amoun of square topology units
	RAISE NOTICE 'Minimum tolerated face area: %', minToleratedFaceArea;

	-- Insert candidate input lines and iterate if any of
	-- them has to be refused
	LOOP --{

-- STRIP -- 		--RAISE DEBUG 'Candidate input lines: %', ST_AsText(candidateInputLines);


		BEGIN --{

			-- Insert the inputLine to the topology
			-- and gather list of edges forming it
			SELECT array_agg(DISTINCT e)
			FROM ST_Dump(candidateInputLines) d,
			LATERAL topology.TopoGeo_addLineString(
					topo.name,
					d.geom,
					tolerance
				) e
			INTO inputLineEdgeIds;
-- STRIP -- 			RAISE DEBUG '%: input line edges: %',
-- STRIP -- 				proc_name, array_to_string(inputLineEdgeIds, ',')

			-- Remove any edge already used by existing borders
			-- from the the list of edges forming the new line
			sql := format(
				$$
		SELECT array_agg(x)
		FROM (
			SELECT x FROM (
				SELECT unnest($1) x
			) foo
			WHERE abs(x) NOT IN (
				SELECT abs(element_id)
				FROM %1$I.relation
				WHERE layer_id = %2$L
				AND element_type = 2 -- edge
			)
		) foo
				$$,
				topo.name,           -- %1
				borderLayer.layer_id -- %2
			);
-- STRIP -- 			RAISE DEBUG '%: sql: %', proc_name, sql;

			EXECUTE sql
			USING inputLineEdgeIds
			INTO inputLineEdgeIds;

-- STRIP -- 			RAISE DEBUG '%: input line edges not already used by existing borders: %',
-- STRIP -- 				proc_name, array_to_string(inputLineEdgeIds, ',')

			-- Check which new edges should be dropped
			dropInputLines := NULL;

			-- Remove dangling edge
			-- See https://gitlab.com/nibioopensource/pgtopo_update_sql/-/issues/261
			sql := format(
				$$
					SELECT array_agg(edge_id)
					FROM %1$I.edge_data
					WHERE edge_id = ANY($1)
					AND left_face = right_face
				$$,
				topo.name
			);
			EXECUTE sql USING inputLineEdgeIds
			INTO dropInputLines;
			IF dropInputLines IS NOT NULL THEN
				RAISE NOTICE 'New edges % are dangling, dropping', dropInputLines;
			END IF;

			-- Remove any edge binding faces having an area
			-- below given optional area tolerance
			-- See https://gitlab.com/nibioopensource/pgtopo_update_sql/-/issues/157
			IF minToleratedFaceArea IS NOT NULL
			THEN --{

				sql := format(
					$$
			WITH newEdges AS (
				SELECT edge_id, left_face, right_face
				FROM %1$I.edge_data
				WHERE edge_id = ANY($1)
			), newBoundFaces AS (
				SELECT face_id, ST_Area(topology.ST_GetFaceGeometry(%1$L, f.face_id)) face_area
				FROM %1$I.face f
				WHERE face_id > 0
				AND face_id IN (
					SELECT left_face FROM newEdges
					UNION
					SELECT right_face FROM newEdges
				)
			)
			SELECT array_agg(DISTINCT e.edge_id) edge_ids, f.face_id, f.face_area
			FROM newBoundFaces f, newEdges e
			WHERE ( f.face_id = e.left_face OR f.face_id = e.right_face )
			AND face_area < $2
			GROUP BY f.face_id, f.face_area
					$$,
					topo.name
				);
				FOR rec IN EXECUTE sql USING inputLineEdgeIds, minToleratedFaceArea
				LOOP
					-- Collect IDs of edges to be dropped
					RAISE NOTICE 'New edges % binding too small face % (area %), dropping',
						rec.edge_ids, rec.face_id, rec.face_area;
					dropInputLines := array_cat(dropInputLines, rec.edge_ids);
				END LOOP;

			END IF; --}

			IF dropInputLines IS NOT NULL
			THEN --{
				RAISE NOTICE 'All input lines edges: %', inputLineEdgeIds;
				RAISE NOTICE 'Dropped input lines edges: %', dropInputLines;
				SELECT array_agg(x) FROM (
					SELECT abs(unnest(inputLineEdgeIds)) x
						EXCEPT
					SELECT unnest(dropInputLines)
				) foo
				INTO inputLineEdgeIds;
				-- Re-write candidate input lines as the list
				-- of edges we keep
				sql := format(
					$$
						SELECT ST_Collect(e.geom ORDER BY e.edge_id)
						FROM
							%1$I.edge e
						WHERE edge_id = ANY($1)
					$$,
					topo.name
				);
				EXECUTE sql USING inputLineEdgeIds
				INTO candidateInputLines;
-- STRIP -- 				--RAISE DEBUG 'New candidate input lines num: %', ST_NumGeometries(candidateInputLines);


				IF candidateInputLines IS NULL THEN
				    IF minToleratedFaceArea IS NOT NULL THEN
					    RAISE EXCEPTION 'No usable input lines found with minimum tolerated face area: % for inputline % where isClosed = %' ,
					    minToleratedFaceArea , ST_AsText(inputLine),  ST_IsClosed(inputLine) ;
				    ELSE
					    RAISE EXCEPTION 'No usable input lines found for inputline % where isClosed = %' , ST_AsText(inputLine),  ST_IsClosed(inputLine) ;
				    END IF;
				END IF;

				-- Some input lines were refused,
				-- rollback the subtransaction
				RAISE USING ERRCODE = '22901'; -- custom error code
			END IF; --}

			EXIT; -- Exits the loop, no input lines were drop

		EXCEPTION WHEN SQLSTATE '22901' THEN --}{
			NULL; -- continue the loop
		END; --} exception handling transaction

	END LOOP; --}

	-- Collect all nodes covered by the inputLineEdgeIds
	-- Param $1 is the input line edge ids
	sql := format(
		$$
			WITH coveredNodes AS (
				SELECT start_node node_id
				FROM %1$I.edge_data
				WHERE edge_id = ANY($1)
					UNION
				SELECT end_node
				FROM %1$I.edge_data
				WHERE edge_id = ANY($1)
			)
			SELECT array_agg(node_id)
			FROM coveredNodes
		$$,
		topo.name
	);
-- STRIP -- 	RAISE DEBUG '%: sql: %', proc_name, sql;

	EXECUTE sql
		USING inputLineEdgeIds
		INTO inputLineNodeIds
	;
-- STRIP -- 	RAISE DEBUG '%: input line covers nodes %',
-- STRIP -- 		proc_name,
-- STRIP -- 		array_to_string(inputLineNodeIds, ',')
-- STRIP -- 	

	-- Query to extract Borders split by nodes
	-- covering edges forming the input line
	--
	-- Param $1 is the list of inputLineNodeIds
	--
	sql := format(
		$$
WITH borderSplit AS (
		SELECT
			DISTINCT
			b border_record,
			b.%1$I::text border_id,
			b.%4$I border_tg,
			n.node_id,
			e.edge_id,
			n.geom node_geom
		FROM
			%3$s b,
			%2$I.relation r,
			%2$I.edge_data e,
			%2$I.node n
		WHERE
			r.topogeo_id = id(b.%4$I)
			AND r.layer_id = layer_id(b.%4$I)
			AND r.element_type = 2 -- edge
			AND r.element_id IN ( e.edge_id, -e.edge_id )
			AND
			(
				(
					e.start_node = ANY($1)
					AND
					e.start_node = n.node_id
				)
				OR
				(
					e.end_node = ANY($1)
					AND
					e.end_node = n.node_id
				)
			)
)
SELECT
	to_jsonb(border_record) border_record_jsonb,
	border_id,
	ST_CollectionHomogenize(
			border_tg::geometry
	) border_geom,
	ST_Collect(node_geom) node_geoms,
	array_agg(node_id) node_ids
FROM borderSplit
GROUP BY border_record, border_id, border_tg
HAVING count(edge_id) > 1
		$$,
		borderLayerIdColumn,  -- %1
		topo.name,            -- %2
		borderLayerTable,     -- %3
		borderLayerGeomColumn -- %4
	);
-- STRIP -- 	RAISE DEBUG '%: sql: %', proc_name, sql;

	FOR rec IN
		EXECUTE sql
		USING inputLineNodeIds
	LOOP --{
-- STRIP -- 		RAISE DEBUG 'Border % was split on nodes %',
-- STRIP -- 			rec.border_id,
-- STRIP -- 			array_to_string(rec.node_ids, ',')
-- STRIP -- 		

-- STRIP -- 		RAISE DEBUG 'Border geom was: %',
-- STRIP -- 			ST_AsText(rec.border_geom)
-- STRIP -- 		

		splitBorderStartPoint := ST_StartPoint(rec.border_geom);
		-- If the border is a closed border
		-- and its start/end point is not
		-- one of the "splitting nodes",
		-- then we will want to merge components
		-- of the split border that end on such
		-- point.
		splitBorderMergeOnStartPoint := FALSE;
		IF ST_IsClosed(rec.border_geom)
		AND NOT ST_Intersects(
				splitBorderStartPoint,
				rec.node_geoms
			)
		THEN
-- STRIP -- 			RAISE DEBUG 'Border is closed and its endpoint % is not a split node',
-- STRIP -- 				ST_AsText(splitBorderStartPoint)
			-- Check if the node has degree > 2
			-- in which case we cannot merge back on it.
			-- TODO: only count edges taking part of the definition of
			--       other TopoGeometries in the Border layer
			-- See https://gitlab.com/nibioopensource/pgtopo_update_sql/-/issues/275
			sql := format(
				$SQL$
					SELECT count(e.edge_id)
					FROM %1$I.edge e, %1$I.node n
					WHERE ST_Equals(n.geom, $1)
					AND ( e.start_node = n.node_id OR e.end_node = n.node_id )
				$SQL$,
				topo.name
			);
			EXECUTE sql USING splitBorderStartPoint INTO splitBorderStartPointNodeDegree;
-- STRIP -- 			RAISE DEBUG 'Border endpoint node degree=%', splitBorderStartPointNodeDegree;

			IF splitBorderStartPointNodeDegree < 3 THEN
				splitBorderMergeOnStartPoint := TRUE;
			END IF;
		END IF;

		-- Split the border geometry
		splitBorderGeom := ST_Split(
			rec.border_geom,
			rec.node_geoms
		);
-- STRIP -- 		RAISE DEBUG 'Border was split to: %', ST_AsText(splitBorderGeom);


		splitBorderCount := ST_NumGeometries(splitBorderGeom);

		-- (Sanity check: split border must have been split in at least 2 components.)
		-- The above is not true when we use snapTo because then we get the nodes from the server
		-- TODO do we need another sanity check her, or do we need this check at all ?
		IF splitBorderCount < 1
		THEN
			RAISE EXCEPTION 'Border % (%) split by nodes % (%) is still a single geometry',
				ST_AsText(rec.border_geom),
				rec.border_id,
				ST_AsText(rec.node_geoms),
				array_to_string(rec.node_ids, ',')
			;
		END IF;

		-- Get column map for modified Borders
		IF colMapForModBorder IS NULL
		THEN
			EXECUTE colMapExtractSQL
				USING colMapProviderParam, 'B', 'M'
				INTO colMapForModBorder;
			IF colMapForModBorder IS NULL
			THEN
				RAISE EXCEPTION '%: colMapProvider did not provide a map for modified border typ=% and act=%',
					proc_name, 'B', 'M';
			END IF;
-- STRIP -- 			RAISE DEBUG 'colMapForModBorder: %', colMapForModBorder;

		END IF;

		-- Get column map for split Borders
		IF colMapForSplitBorder IS NULL
		THEN
			EXECUTE colMapExtractSQL
				USING colMapProviderParam, 'B', 'S'
				INTO colMapForSplitBorder;
			IF colMapForSplitBorder IS NULL
			THEN
				RAISE EXCEPTION '%: colMapProvider did not provide a map for split border typ=% and act=%',
					proc_name, 'B', 'S';
			END IF;
-- STRIP -- 			RAISE DEBUG 'colMapForSplitBorder: %', colMapForSplitBorder;


			-- Build a column map for attributes-inheriting split Border objects
			-- Write new border mapping taking properties
			-- from payload when specified or from old border
			-- when not specified
			inhSplitBorderColMap := topo_update._json_col_map_override(
				ARRAY[
					topo_update.json_col_map_from_pg(
						borderLayerTable,
						ARRAY[
							-- omit TopoGeometry column from mapping
							borderLayerGeomColumn::text,
							-- omit ID column from props
							borderLayerIdColumn::text
						]
					),
					colMapForSplitBorder
				]
			);
-- STRIP -- 			RAISE DEBUG '%: inheriting split Border ColMap: %', proc_name, inhSplitBorderColMap;

		END IF;

		-- Create split borders for subsequent
		-- components of the splitted geometry

		-- Extract properties of old border
		oldBorderProps := rec.border_record_jsonb
			- borderLayerGeomColumn -- drop TopoGeometry column from props
			- borderLayerIdColumn   -- drop ID column from props
		;
-- STRIP -- 		RAISE DEBUG 'Old Border props: %', oldBorderProps;


		-- Create new border props with
		-- old attributes in an 'old'-keyed field
		-- and payload attributes in a 'new'-keyed field
		newBorderProps := jsonb_build_object(
			'p0', oldBorderProps,
			'p1', payloadProps
		);
-- STRIP -- 		RAISE DEBUG 'New Border props: %', newBorderProps;


		modBorderGeom := NULL;
		FOR i IN 1 .. splitBorderCount
		LOOP -- {
			splitBorderGeomComp = ST_GeometryN(splitBorderGeom, i);
-- STRIP -- 			RAISE DEBUG 'Split border geom component: %',
-- STRIP -- 				ST_AsText(splitBorderGeomComp)

			IF NOT splitBorderMergeOnStartPoint
			THEN --{

				-- If we don't need to merge components
				-- then we take component having the
				-- same start point as the original
				-- border as the one which will retain
				-- its border id
				IF modBorderGeom IS NULL
				THEN
					IF ST_Equals(
						ST_StartPoint(splitBorderGeomComp),
						splitBorderStartPoint
					)
					THEN
-- STRIP -- 						RAISE DEBUG 'Component starts from  original border start point';

						modBorderGeom := splitBorderGeomComp;
						CONTINUE;
					END IF;
				END IF;

			ELSE -- }{

				-- If we do need to merge components
				-- then we take all components (2 expected)
				-- ending on the splitBorderMergeOnStartPoint
				-- to build the new versino of the border
				-- which will retain its id
				IF ST_Equals(
						ST_StartPoint(splitBorderGeomComp),
						splitBorderStartPoint
					) OR
					ST_Equals(
						ST_EndPoint(splitBorderGeomComp),
						splitBorderStartPoint
					)
				THEN --{
-- STRIP -- 					RAISE DEBUG 'Component ends on original border endpoint';

					IF modBorderGeom IS NULL
					THEN
						modBorderGeom := splitBorderGeomComp;
					ELSE
						modBorderGeom := ST_LineMerge(
							ST_Collect(
								modBorderGeom,
								splitBorderGeomComp
							)
						);
					END IF;
					CONTINUE;

				END IF; --}

			END IF; --}

			rec2 := topo_update.insert_feature(
				splitBorderGeomComp,
				newBorderProps,
				borderLayerTable,
				borderLayerGeomColumn,
				borderLayerIdColumn,
				inhSplitBorderColMap,
				-- use 0 tolerance as we're only using
				-- existing topological elements
				0.0 -- tolerance
			);

			fid := rec2.id;
			typ := 'B';
			act := 'S';
			frm := rec.border_id;
-- STRIP -- 			RAISE DEBUG 'Border % split from % - returning %|%|%|%',
-- STRIP -- 				fid, frm, fid,typ,act,frm
			RETURN NEXT;

		END LOOP; --}

		-- Update the modified border to only be composed
		-- by the first geometry returned by the split
-- STRIP -- 		RAISE DEBUG 'Modified border geom: %', ST_AsText(modBorderGeom);


		fid := rec.border_id;
		typ := 'B';
		act := 'M';
		frm := null;
-- STRIP -- 		RAISE DEBUG 'Border % modified - returning %|%|%|%',
-- STRIP -- 			fid, fid,typ,act,frm
		RETURN NEXT;

		rec2 := topo_update.update_feature(
			modBorderGeom,
			payloadProps,
			borderLayerTable,
			borderLayerGeomColumn,
			borderLayerIdColumn,
			fid,
			colMapForModBorder,
			-- use 0 tolerance as we're only using
			-- existing topological elements
			0.0, -- tolerance
			true -- modify existing TopoGeometry
		);

		-- Sanity check
		IF NOT (
			id(rec2.old_topogeom) = newBorder.id
		) THEN
			RAISE EXCEPTION 'topo_update.update_feature'
				' unexpectedly found the old TopoGeometry'
				' to be different from the new one (border)';
		END IF;


	END LOOP; --}

	-- Get column map for new Borders
	EXECUTE colMapExtractSQL
		USING colMapProviderParam, 'B', 'C'
		INTO colMapForNewBorder;
	IF colMapForNewBorder IS NULL
	THEN
		RAISE EXCEPTION '%: colMapProvider did not provide a map for new border typ=% and act=%',
			procName, 'B', 'C';
	END IF;
-- STRIP -- 	RAISE DEBUG 'colMapForNewBorder: %', colMapForNewBorder;


	-- Create a new Border for each edge in
	-- inputLineEdgeIds
	-- TODO: join edges togheter if they are not
	--       ending on inputLineNodeIds !
	FOR rec IN
		SELECT unnest(inputLineEdgeIds) edge_id
	LOOP

		typ := 'B';
		act := 'C';
		frm := null;

		-- Create the new Border TopoGeometry
		newBorder := topology.CreateTopoGeom(
			topo.name,
			2, -- lineal
			borderLayer.layer_id,
			topology.TopoElementArray_agg(ARRAY[rec.edge_id,2])
		)
		;
-- STRIP -- 		--RAISE DEBUG 'newBorder: %', newBorder;


		newBorderId := topo_update.insert_feature(
			newBorder,
			payloadProps,
			borderLayerTable,
			borderLayerGeomColumn,
			borderLayerIdColumn,
			colMapForNewBorder
		);

-- STRIP -- 		RAISE DEBUG '%: Border % created to cover input line edge %',
-- STRIP -- 			proc_name, newBorderId, rec.edge_id

		-- Return info about the created Border
		fid := newBorderId;
		RETURN NEXT;
	END LOOP;

	--------------------------------
	--
	-- Handling Surface split here
	--
	--------------------------------

	-- Fetch identifiers of new face created by adding the border
	sql := format(
		$$
SELECT array_agg(face_id)
FROM %I.face
WHERE face_id > %L
		$$,
		topo.name, maxFaceBefore
	);
-- STRIP -- 	RAISE DEBUG '%: sql: %', proc_name, sql;

	EXECUTE sql INTO newFaces;

	newFacesCount := COALESCE(array_upper(newFaces, 1), 0);

-- STRIP -- 	RAISE DEBUG '%: % new faces created by inserting border', proc_name, newFacesCount;


	-- Check that at least one face was split by the new edge
	IF newFacesCount = 0 THEN
		RAISE EXCEPTION '%: no face was split by border', proc_name;
	END IF;

	-- Check that the number of new faces is acceptable
	IF newFacesCount > maxNewSurfacesOrChangedAreaSurfaces THEN
		RAISE EXCEPTION '%: newFacesCount % is bigger than maxNewSurfacesOrChangedAreaSurfaces % when split by border', proc_name, newFacesCount, maxNewSurfacesOrChangedAreaSurfaces;
	END IF;



	-- Get column map for split Surface
	EXECUTE colMapExtractSQL
		USING colMapProviderParam, 'S', 'S'
		INTO colMapForSplitSurface;
	IF colMapForSplitSurface IS NULL
	THEN
		RAISE EXCEPTION '%: colMapProvider did not provide a map for split surface typ=% and act=%',
			procName, 'S', 'S';
	END IF;

-- STRIP -- 	RAISE DEBUG '%: split Surface ColMap: %', proc_name, colMapForSplitSurface;


	-- Get column map for modified Surface
	EXECUTE colMapExtractSQL
		USING colMapProviderParam, 'S', 'M'
		INTO colMapForModSurface;
	IF colMapForModSurface IS NULL
	THEN
		RAISE EXCEPTION '%: colMapProvider did not provide a map for modified surface typ=% and act=%',
			procName, 'S', 'M';
	END IF;

-- STRIP -- 	RAISE DEBUG '%: modified Surface ColMap: %', proc_name, colMapForModSurface;


	-- Build a column map for attributes-inheriting split Surface objects
	-- Write new surface mapping taking properties
	-- from payload when specified or from old surface
	-- when not specified
	inhSplitSurfaceColMap := topo_update._json_col_map_override(
		ARRAY[
			topo_update.json_col_map_from_pg(
				surfaceLayerTable,
				ARRAY[
					-- omit TopoGeometry column from mapping
					surfaceLayerGeomColumn::text,
					-- omit ID column from props
					surfaceLayerIdColumn::text
				]
			),
			colMapForSplitSurface
		]
	);
-- STRIP -- 	RAISE DEBUG '%: inheriting split Surface ColMap: %', proc_name, inhSplitSurfaceColMap;


	-- Find all Surface objects which were
	-- split by the new border, with their
	-- definition
	--
	-- $1 is newFaces
	--
	sql := format(
		$$
	SELECT
		DISTINCT ON (%1$I)
		%1$I::text id,
		%2$I tg,
		array_agg( r_to.element_id ) over (
			partition by %1$I
		) covered_new_faces,
		to_jsonb(fa_to) surface_record_jsonb
	FROM
		%3$s fa_to,
		%4$s.relation r_to
	WHERE
		r_to.layer_id = %5$s AND
		r_to.element_id = ANY($1) AND
		r_to.topogeo_id = id(fa_to.%2$s)
	ORDER BY %1$I
		$$,
		surfaceLayerIdColumn,   -- %1
		surfaceLayerGeomColumn, -- %2
		surfaceLayerTable,      -- %3
		topo.name,				-- %4
		layer_id(surfaceLayer)	-- %5
	);
-- STRIP -- 	RAISE DEBUG '%: sql: %', proc_name, sql;


	-- Iterate over all Surface objects which were
	-- split by the new border
	FOR rec IN EXECUTE sql
	USING newFaces
	LOOP --{
-- STRIP -- 		RAISE DEBUG 'Affected surface % covers new faces %',
-- STRIP -- 			rec.id, rec.covered_new_faces

		splitSurfaceCount := splitSurfaceCount + 1;
		IF splitSurfaceCount > maxAllowedSurfaceSplitCount THEN
			RAISE EXCEPTION 'Surface split count exceeded limit of %', maxAllowedSurfaceSplitCount;
		END IF;

		-- SANITY CHECK
		-- Check that the new faces covered by
		-- this surface were not previously found
		-- covered by another surface
		IF coveredNewFaces && rec.covered_new_faces -- overlap operator
		THEN
			-- This query could be improved by exposing a
			-- PointOnFace in PostGIS Topology:
			-- with: https://trac.osgeo.org/postgis/ticket/4861
			SELECT
				ST_Union(
					ST_PointOnSurface(
						topology.ST_GetFaceGeometry(
							topo.name,
							id
						)
					)
				)
			FROM unnest(rec.covered_new_faces) id
			INTO overlapPoints;
			RAISE EXCEPTION 'Surfaces overlap detected in %',
				ST_AsEWKT(overlapPoints);
		END IF;

		-- Extract properties of old surface
		oldSurfaceProps := rec.surface_record_jsonb
			- surfaceLayerGeomColumn -- drop TopoGeometry column from props
			- surfaceLayerIdColumn   -- drop ID column from props
		;
-- STRIP -- 		RAISE DEBUG 'Old Surface props: %', oldSurfaceProps;


		-- Create new surface props with
		-- old attributes in an 'old'-keyed field
		-- and payload attributes in a 'new'-keyed field
		newSurfaceProps := jsonb_build_object(
			'p0', oldSurfaceProps,
			'p1', payloadProps
		);
-- STRIP -- 		RAISE DEBUG 'New Surface props: %', newSurfaceProps;


		-- Update the set of new faces found covered
		coveredNewFaces := array(
			SELECT unnest(coveredNewFaces)
				UNION
			SELECT unnest(rec.covered_new_faces)
		);

-- STRIP -- --		RAISE DEBUG 'Surface TopoGeom BEFORE: id(%), elems(%)',
-- STRIP -- --			id(rec.tg),
-- STRIP -- --			topology.GetTopoGeomElementArray(rec.tg)

		-- Delete covered new faces from the
		-- split surface TopoGeometry object
		--
		-- FIXME: Single-part Surfaces defined by multiple faces may become
		--        multi-part when removing from them faces effectively
		--        splitting them. When multi-part Surfaces are not
		--        wanted we'll need to deal with this scenario.
		--        See https://gitlab.com/nibioopensource/pgtopo_update_sql/-/issues/263
		--
		--
		newSurface := rec.tg;
		sql := format(
			$$
DELETE FROM %1$I.relation
WHERE layer_id = %2$L
AND topogeo_id = %3$L
AND element_type = 3
AND element_id = ANY($1)
			$$,
			topo.name,
			layer_id(surfaceLayer),
			id(rec.tg)
		);
-- STRIP -- 		RAISE DEBUG '%: sql: %', proc_name, sql;

		EXECUTE sql USING rec.covered_new_faces;

-- STRIP -- --		RAISE DEBUG 'Surface TopoGeom AFTER: id(%), elems(%)',
-- STRIP -- --			id(rec.tg),
-- STRIP -- --			topology.GetTopoGeomElementArray(rec.tg)

		IF keepModifiedSurface
		THEN -- {

			rec2 := topo_update.update_feature(
				newSurface,
				payloadProps,
				surfaceLayerTable,
				surfaceLayerGeomColumn,
				surfaceLayerIdColumn,
				rec.id,
				colMapForModSurface
			);

-- STRIP -- 			RAISE DEBUG 'Surface % modified to drop faces %',
-- STRIP -- 				rec.id, rec.covered_new_faces

			-- Sanity check
			IF NOT (
				id(rec2.old_topogeom) = newSurface.id
			) THEN
				RAISE EXCEPTION 'topo_update.update_feature'
					' unexpectedly found the old TopoGeometry'
					' to be different from the new one (surface)';
			END IF;

			fid := rec.id;
			typ := 'S';
			act := 'M';
			frm := null;
			RETURN NEXT;
		ELSE -- }{

			-- DELETE old surface
			sql := format(
				$$
					DELETE FROM %1$s WHERE %2$I::text = $1
				$$,
				surfaceLayerTable,
				surfaceLayerIdColumn
			);
-- STRIP -- 			RAISE DEBUG '%: sql: %', proc_name, sql;

			EXECUTE sql USING rec.id;
			fid := rec.id;
			typ := 'S';
			act := 'D';
			frm := null;
			RETURN NEXT;

			-- CREATE new surface
			newSurfaceId := topo_update.insert_feature(
				newSurface,
				newSurfaceProps,
				surfaceLayerTable,
				surfaceLayerGeomColumn,
				surfaceLayerIdColumn,
				inhSplitSurfaceColMap
			);

-- STRIP -- 			RAISE DEBUG 'New Surface % created, with props %',
-- STRIP -- 				newSurfaceId, newSurfaceProps

			fid := newSurfaceId;
			typ := 'S';
			act := 'S';
			frm := rec.id;
			RETURN NEXT;

		END IF; --}


		-- Create a new surface TopoGeometry object
		-- covering each group of faces, from
		-- the set of the faces which we removed
		-- from the definition of the split surface
		-- ("rec.covered_new_faces"),
		-- that have at least one common edge not used
		-- by any Border feature

		-- Loop over every group of mergeable covered faces
		FOR tea IN
			SELECT topo_update._add_border_split_surface_mergeable_faces(
				topo,
				borderLayer,
				rec.covered_new_faces
			) tea
			ORDER BY tea
		LOOP --{

			newSurface := topology.CreateTopoGeom(
				topo.name,
				3, -- areal type
				layer_id(surfaceLayer), -- layer id
				tea -- topoelement_array
			);
-- STRIP -- 			--RAISE DEBUG 'TopoGeom covering faces eroded by split Surface: %',
-- STRIP -- 			--	ST_AsText(newSurface)


			-- Insert the new Surface feature with
			-- attribute values taken from the split surface
			-- and updated with values from the payload
			newSurfaceId := topo_update.insert_feature(
				newSurface,
				newSurfaceProps,
				surfaceLayerTable,
				surfaceLayerGeomColumn,
				surfaceLayerIdColumn,
				inhSplitSurfaceColMap
			);

-- STRIP -- 			RAISE DEBUG 'New Surface % created, with props %',
-- STRIP -- 				newSurfaceId, newSurfaceProps

			fid := newSurfaceId;
			typ := 'S';
			act := 'S';
			frm := rec.id;
			RETURN NEXT;

		END LOOP; --}


	END LOOP; --}

	uncoveredNewFaces := array(
		SELECT unnest(newFaces) face_id
			EXCEPT
		SELECT unnest(coveredNewFaces)
	);

-- STRIP -- 	RAISE DEBUG '%: for uncovered new faces are %',
-- STRIP -- 		proc_name, uncoveredNewFaces

	IF uncoveredNewFaces = '{}' THEN
		RETURN; -- nothing more to do here
	END IF;

	-- Get column map for new Surface
	EXECUTE colMapExtractSQL
		USING colMapProviderParam, 'S', 'C'
		INTO colMapForNewSurface;
	IF colMapForNewSurface IS NULL
	THEN
		RAISE EXCEPTION '%: colMapProvider did not provide a map for new surface typ=% and act=%',
			procName, 'S', 'C';
	END IF;
-- STRIP -- 	RAISE DEBUG '%: new Surface ColMap: %', proc_name, colMapForNewSurface;


	-- Build a column map for attributes-inheriting new Surface objects
	-- Write new surface mapping taking properties
	-- from payload when specified or from old surface
	-- when not specified
	inhNewSurfaceColMap := topo_update._json_col_map_override(
		ARRAY[
			topo_update.json_col_map_from_pg(
				surfaceLayerTable,
				ARRAY[
					-- omit TopoGeometry column from mapping
					surfaceLayerGeomColumn::text,
					-- omit ID column from props
					surfaceLayerIdColumn::text
				]
			),
			colMapForNewSurface
		]
	);
-- STRIP -- 	RAISE DEBUG '%: inheriting new Surface ColMap: %', proc_name, inhNewSurfaceColMap;


	-- Create a new surface TopoGeometry object
	-- covering each group of faces, from
	-- the set of the faces not previously covered
	-- by existing Srufaces ("uncoveredNewFaces"),
	-- that have at least one common edge not used
	-- by any Border feature
	FOR tea IN
		SELECT topo_update._add_border_split_surface_mergeable_faces(
			topo,
			borderLayer,
			uncoveredNewFaces
		) tea
		--ORDER BY tea -- TODO: order to make predictable ?
	LOOP
		newSurface := topology.CreateTopoGeom(
			topo.name,
			3, -- areal type
			layer_id(surfaceLayer), -- layer id
			tea -- topoelement_array
		);

-- STRIP -- 		RAISE DEBUG '%: new surface for uncovered new faces % is %',
-- STRIP -- 			proc_name, tea, newSurface

		-- Select a pre-existing Surface having the
		-- "most" adjacency to this new Surface
		SELECT bestSurfaceId, bestSurfaceProps
		FROM topo_update._most_adjacent_surface(
			topo,
			uncoveredNewFaces,
			surfaceLayer,
			surfaceLayerIdColumn -- needed ?
		)
		INTO rec;

		IF rec.bestSurfaceId IS NOT NULL
		THEN
-- STRIP -- 			RAISE DEBUG '%: most adjacent surface is %, with props %',
-- STRIP -- 				proc_name, rec.bestSurfaceId, rec.bestSurfaceProps
			newSurfaceProps := jsonb_build_object(
				'p0', rec.bestSurfaceProps,
				'p1', payloadProps
			);
			surfaceColMap := inhNewSurfaceColMap;
		ELSE
-- STRIP -- 			RAISE DEBUG '%: no adjacent surface found, not inheriting attributes',
-- STRIP -- 				proc_name
			newSurfaceProps := payloadProps;
			surfaceColMap := colMapForNewSurface;
		END IF;


		newSurfaceId := topo_update.insert_feature(
			newSurface,
			newSurfaceProps,
			surfaceLayerTable,
			surfaceLayerGeomColumn,
			surfaceLayerIdColumn,
			surfaceColMap
		);

-- STRIP -- 		RAISE DEBUG '%: new surface feature id is %',
-- STRIP -- 			proc_name, newSurfaceId

		-- Add new item to the returned JSONB for the created surface
		-- Return info about the created Surface
		fid := newSurfaceId;
		typ := 'S';
		act := 'C';
		frm := NULL;
		RETURN NEXT;

	END LOOP;

END;
$_$;



--
-- Name: add_path(jsonb, regclass, name, name, regproc, anyelement, double precision, double precision); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.add_path(feature jsonb, pathlayertable regclass, pathlayergeomcolumn name, pathlayeridcolumn name, colmapproviderfunc regproc, colmapproviderparam anyelement, tolerance double precision DEFAULT 0.0, mintoleratedpathlength double precision DEFAULT NULL::double precision) RETURNS TABLE(fid text, act character, frm text)
    LANGUAGE plpgsql
    AS $_$
DECLARE

	rec RECORD;
	rec2 RECORD;

	featureGeom JSONB;

	payloadProps JSONB;

	newPath topology.topogeometry;
	modPathGeom GEOMETRY;
	newPathId text;
	oldPathProps JSONB;
	newPathProps JSONB;

	-- holds dynamic sql
	sql text;

	proc_name text = 'topo_update.add_path';

	inputLine GEOMETRY;
	overlapPoints GEOMETRY;

	topo topology.topology;

	candidateInputLines GEOMETRY;
	dropInputLines INT[];

	inputLineEdgeIds INT[];
	inputLineNodeIds INT[];

	pathLayer topology.layer;

	-- Holds dynamic sql to execute
	-- by passing $1=colMapProviderParam,
	-- $2=act to extract the
	-- appropriate column mapping
	colMapExtractSQL TEXT;

	-- Column mapping file for modified paths
	-- as provided by colMapProvider
	colMapForModPath JSONB;

	-- Column mapping file for paths
	-- as provided by colMapProvider
	colMapForNewPath JSONB;

	-- Column mapping file for paths
	-- replacing space previously covered
	-- by existing paths as provided by
	-- colMapProvider
	colMapForSplitPath JSONB;

	-- Column mapping file for split paths
	-- inheriting attributes from existing Path
	inhSplitPathColMap JSONB;

	-- Path as split by incoming line
	splitPathGeom GEOMETRY;
	splitPathGeomComp GEOMETRY;
	splitPathStartPoint GEOMETRY;
	splitPathStartPointNodeDegree INT;
	splitPathMergeOnStartPoint BOOLEAN;

	-- Number of elements a path was split into
	splitPathCount INT;

	i INT;

	tea topology.TopoElementArray;

BEGIN

	-- Fetch topology and layer info from path layer references
	SELECT t topo, l layer
		FROM topology.layer l, topology.topology t, pg_class c, pg_namespace n
		WHERE l.schema_name = n.nspname
		AND l.table_name = c.relname
		AND c.oid = pathLayerTable
		AND c.relnamespace = n.oid
		AND l.feature_column = pathLayerGeomColumn
		AND l.topology_id = t.id
	--	FOR UPDATE, 2 problems, user needs SUPERUSER (can be fixed),
	--  ms used from 8601 -> 113606 for ((14.355156130507279 67.27980828078813, 14.354976710179235 67.28648792270606, 14.395077865039152 67.28664388346324, 14.395246132501715 67.27996419068565, 14.355156130507279 67.27980828078813))
		INTO rec;
	topo := rec.topo;
	pathLayer := rec.layer;

	--	RAISE NOTICE 'Lock on topology % obtained', topo.name;

	featureGeom = feature->'geometry';
	IF featureGeom IS NULL
	THEN
		RAISE EXCEPTION 'Input feature lacks a "geometry" element: %',
			feature;
	END IF;

	IF NOT featureGeom ? 'crs'
	THEN
		RAISE EXCEPTION 'Input feature geometry lacks a "crs" element: %',
			featureGeom;
	END IF;

	-- Read input line geometry from GeoJSON
	inputLine := ST_GeomFromGeoJSON(featureGeom);

	IF topo.srid != ST_Srid(inputLine) THEN
		inputLine := ST_Transform(inputLine, topo.srid);
-- STRIP -- 		--RAISE DEBUG 'REPROJECTED GEOM: %', ST_AsEWKT(geom);

	END IF;

-- STRIP -- 	RAISE DEBUG 'Input line: %', ST_AsText(inputLine);


	-- Write SQL to extract colMaps
	-- $1: usr
	-- $2: act
	colMapExtractSQL := format(
		'SELECT * FROM %s(usr => $1, act => $2)',
		colMapProviderFunc
	);

	payloadProps := feature -> 'properties';

	candidateInputLines := ST_ForceCollection(inputLine);

	-- We only tolerate paths having a length of at least
	-- the given amoun of topology units
	RAISE NOTICE 'Minimum tolerated path length: %', minToleratedPathLength;

	-- Insert candidate input lines and iterate if any of
	-- them has to be refused
	LOOP --{

-- STRIP -- 		--RAISE DEBUG 'Candidate input lines: %', ST_AsText(candidateInputLines);


		BEGIN --{

			-- Insert the inputLine to the topology
			-- and gather list of edges forming it
			SELECT array_agg(DISTINCT e)
			FROM ST_Dump(candidateInputLines) d,
			LATERAL topology.TopoGeo_addLineString(
					topo.name,
					d.geom,
					tolerance
				) e
			INTO inputLineEdgeIds;
-- STRIP -- 			RAISE DEBUG '%: input line edges: %',
-- STRIP -- 				proc_name, array_to_string(inputLineEdgeIds, ',')

			-- Remove any edge already used by existing paths
			-- from the the list of edges forming the new line
			sql := format(
				$$
		SELECT array_agg(x)
		FROM (
			SELECT x FROM (
				SELECT unnest($1) x
			) foo
			WHERE abs(x) NOT IN (
				SELECT abs(element_id)
				FROM %1$I.relation
				WHERE layer_id = %2$L
				AND element_type = 2 -- edge
			)
		) foo
				$$,
				topo.name,           -- %1
				pathLayer.layer_id -- %2
			);
-- STRIP -- 			RAISE DEBUG '%: sql: %', proc_name, sql;

			EXECUTE sql
			USING inputLineEdgeIds
			INTO inputLineEdgeIds;

-- STRIP -- 			RAISE DEBUG '%: input line edges not already used by existing paths: %',
-- STRIP -- 				proc_name, array_to_string(inputLineEdgeIds, ',')

			-- Check which new edges should be dropped
			dropInputLines := NULL;

			-- Remove edge below min tolerated length
			IF minToleratedPathLength > 0 THEN
				-- See https://gitlab.com/nibioopensource/pgtopo_update_sql/-/issues/261
				sql := format(
					$$
						SELECT array_agg(edge_id)
						FROM %1$I.edge_data
						WHERE edge_id = ANY($1)
						AND ST_Length(geom) < $2
					$$,
					topo.name
				);
				EXECUTE sql USING inputLineEdgeIds, minToleratedPathLength
				INTO dropInputLines;
				IF dropInputLines IS NOT NULL THEN
					RAISE NOTICE 'New edges % are shorter than tolerated, dropping', dropInputLines;
				END IF;

				IF dropInputLines IS NOT NULL
				THEN --{
					RAISE NOTICE 'All input lines edges: %', inputLineEdgeIds;
					RAISE NOTICE 'Dropped input lines edges: %', dropInputLines;
					SELECT array_agg(x) FROM (
						SELECT abs(unnest(inputLineEdgeIds)) x
							EXCEPT
						SELECT unnest(dropInputLines)
					) foo
					INTO inputLineEdgeIds;
					-- Re-write candidate input lines as the list
					-- of edges we keep
					sql := format(
						$$
							SELECT ST_Collect(e.geom ORDER BY e.edge_id)
							FROM
								%1$I.edge e
							WHERE edge_id = ANY($1)
						$$,
						topo.name
					);
					EXECUTE sql USING inputLineEdgeIds
					INTO candidateInputLines;
-- STRIP -- 					--RAISE DEBUG 'New candidate input lines num: %', ST_NumGeometries(candidateInputLines);


					IF candidateInputLines IS NULL THEN
						RAISE EXCEPTION 'No usable input lines found for inputline %' , ST_AsText(inputLine);
					END IF;

					-- Some input lines were refused,
					-- rollback the subtransaction
					RAISE USING ERRCODE = '22901'; -- custom error code
				END IF; --}

			END IF;

			EXIT; -- Exits the loop, no input lines were drop

		EXCEPTION WHEN SQLSTATE '22901' THEN --}{
			NULL; -- continue the loop
		END; --} exception handling transaction

	END LOOP; --}

-- STRIP -- 	RAISE DEBUG '%: nodes collecting phase start', proc_name;


	-- Collect all nodes covered by the inputLineEdgeIds
	-- Param $1 is the input line edge ids
	sql := format(
		$$
			WITH coveredNodes AS (
				SELECT start_node node_id
				FROM %1$I.edge_data
				WHERE edge_id = ANY($1)
					UNION
				SELECT end_node
				FROM %1$I.edge_data
				WHERE edge_id = ANY($1)
			)
			SELECT array_agg(node_id)
			FROM coveredNodes
		$$,
		topo.name
	);
-- STRIP -- 	RAISE DEBUG '%: sql: %', proc_name, sql;

	EXECUTE sql
		USING inputLineEdgeIds
		INTO inputLineNodeIds
	;
-- STRIP -- 	RAISE DEBUG '%: input line covers nodes %',
-- STRIP -- 		proc_name,
-- STRIP -- 		array_to_string(inputLineNodeIds, ',')
-- STRIP -- 	

	-- Query to extract Paths split by nodes
	-- covering edges forming the input line
	--
	-- Param $1 is the list of inputLineNodeIds
	--
	sql := format(
		$$
WITH pathSplit AS (
		SELECT
			DISTINCT
			b path_record,
			b.%1$I::text path_id,
			b.%4$I path_tg,
			n.node_id,
			e.edge_id,
			n.geom node_geom
		FROM
			%3$s b,
			%2$I.relation r,
			%2$I.edge_data e,
			%2$I.node n
		WHERE
			r.topogeo_id = id(b.%4$I)
			AND r.layer_id = layer_id(b.%4$I)
			AND r.element_type = 2 -- edge
			AND r.element_id IN ( e.edge_id, -e.edge_id )
			AND
			(
				(
					e.start_node = ANY($1)
					AND
					e.start_node = n.node_id
				)
				OR
				(
					e.end_node = ANY($1)
					AND
					e.end_node = n.node_id
				)
			)
)
SELECT
	path_record,
	path_id,
	ST_CollectionHomogenize(
			path_tg::geometry
	) path_geom,
	ST_Collect(node_geom) node_geoms,
	array_agg(node_id) node_ids
FROM pathSplit
GROUP BY path_record, path_id, path_tg
HAVING count(edge_id) > 1
		$$,
		pathLayerIdColumn,  -- %1
		topo.name,            -- %2
		pathLayerTable,     -- %3
		pathLayerGeomColumn -- %4
	);
-- STRIP -- 	RAISE DEBUG '%: sql: %', proc_name, sql;

	FOR rec IN
		EXECUTE sql
		USING inputLineNodeIds
	LOOP --{
-- STRIP -- 		RAISE DEBUG 'Path % was split on nodes %',
-- STRIP -- 			rec.path_id,
-- STRIP -- 			array_to_string(rec.node_ids, ',')
-- STRIP -- 		

-- STRIP -- 		RAISE DEBUG 'Path geom was: %',
-- STRIP -- 			ST_AsText(rec.path_geom)
-- STRIP -- 		

		splitPathStartPoint := ST_StartPoint(rec.path_geom);
		-- If the path is a closed path
		-- and its start/end point is not
		-- one of the "splitting nodes",
		-- then we will want to merge components
		-- of the split path that end on such
		-- point.
		splitPathMergeOnStartPoint := FALSE;
		IF ST_IsClosed(rec.path_geom)
		AND NOT ST_Intersects(
				splitPathStartPoint,
				rec.node_geoms
			)
		THEN
-- STRIP -- 			RAISE DEBUG 'Path is closed and its endpoint % is not a split node',
-- STRIP -- 				ST_AsText(splitPathStartPoint)
			-- Check if the node has degree > 2
			-- in which case we cannot merge back on it.
			-- TODO: only count edges taking part of the definition of
			--       other TopoGeometries in the Path layer
			-- See https://gitlab.com/nibioopensource/pgtopo_update_sql/-/issues/275
			sql := format(
				$SQL$
					SELECT count(e.edge_id)
					FROM %1$I.edge e, %1$I.node n
					WHERE ST_Equals(n.geom, $1)
					AND ( e.start_node = n.node_id OR e.end_node = n.node_id )
				$SQL$,
				topo.name
			);
			EXECUTE sql USING splitPathStartPoint INTO splitPathStartPointNodeDegree;
-- STRIP -- 			RAISE DEBUG 'Path endpoint node degree=%', splitPathStartPointNodeDegree;

			IF splitPathStartPointNodeDegree < 3 THEN
				splitPathMergeOnStartPoint := TRUE;
			END IF;
		END IF;

		-- Split the path geometry
		splitPathGeom := ST_Split(
			rec.path_geom,
			rec.node_geoms
		);
-- STRIP -- 		RAISE DEBUG 'Path was split to: %', ST_AsText(splitPathGeom);


		splitPathCount := ST_NumGeometries(splitPathGeom);

		-- (Sanity check: split path must have been split in at least 2 components.)
		-- The above is not true when we use snapTo because then we get the nodes from the server
		-- TODO do we need another sanity check her, or do we need this check at all ?
		IF splitPathCount < 1
		THEN
			RAISE EXCEPTION 'Path % (%) split by nodes % (%) is still a single geometry',
				ST_AsText(rec.path_geom),
				rec.path_id,
				ST_AsText(rec.node_geoms),
				array_to_string(rec.node_ids, ',')
			;
		END IF;

		-- Get column map for modified Paths
		IF colMapForModPath IS NULL
		THEN
			EXECUTE colMapExtractSQL
				USING colMapProviderParam, 'M'
				INTO colMapForModPath;
			IF colMapForModPath IS NULL
			THEN
				RAISE EXCEPTION '%: colMapProvider did not provide a map for modified path act=%',
					proc_name, 'M';
			END IF;
-- STRIP -- 			RAISE DEBUG 'colMapForModPath: %', colMapForModPath;

		END IF;

		-- Get column map for split Paths
		IF colMapForSplitPath IS NULL
		THEN
			EXECUTE colMapExtractSQL
				USING colMapProviderParam, 'S'
				INTO colMapForSplitPath;
			IF colMapForSplitPath IS NULL
			THEN
				RAISE EXCEPTION '%: colMapProvider did not provide a map for split path act=%',
					proc_name, 'S';
			END IF;
-- STRIP -- 			RAISE DEBUG 'colMapForSplitPath: %', colMapForSplitPath;


			-- Build a column map for attributes-inheriting split Path objects
			-- Write new path mapping taking properties
			-- from payload when specified or from old path
			-- when not specified
			inhSplitPathColMap := topo_update._json_col_map_override(
				ARRAY[
					topo_update.json_col_map_from_pg(
						pathLayerTable,
						ARRAY[
							-- omit TopoGeometry column from mapping
							pathLayerGeomColumn::text,
							-- omit ID column from props
							pathLayerIdColumn::text
						]
					),
					colMapForSplitPath
				]
			);
-- STRIP -- 			RAISE DEBUG '%: inheriting split Path ColMap: %', proc_name, inhSplitPathColMap;

		END IF;

		-- Create split paths for subsequent
		-- components of the splitted geometry

		-- Extract properties of old path
		oldPathProps := to_jsonb(rec.path_record)
			- pathLayerGeomColumn -- drop TopoGeometry column from props
			- pathLayerIdColumn   -- drop ID column from props
		;
-- STRIP -- 		RAISE DEBUG 'Old Path props: %', oldPathProps;


		-- Create new path props with
		-- old attributes in an 'old'-keyed field
		-- and payload attributes in a 'new'-keyed field
		newPathProps := jsonb_build_object(
			'p0', oldPathProps,
			'p1', payloadProps
		);
-- STRIP -- 		RAISE DEBUG 'New Path props: %', newPathProps;


		modPathGeom := NULL;
		FOR i IN 1 .. splitPathCount
		LOOP -- {
			splitPathGeomComp = ST_GeometryN(splitPathGeom, i);
-- STRIP -- 			RAISE DEBUG 'Split path geom component: %',
-- STRIP -- 				ST_AsText(splitPathGeomComp)

			IF NOT splitPathMergeOnStartPoint
			THEN --{

				-- If we don't need to merge components
				-- then we take component having the
				-- same start point as the original
				-- path as the one which will retain
				-- its path id
				IF modPathGeom IS NULL
				THEN
					IF ST_Equals(
						ST_StartPoint(splitPathGeomComp),
						splitPathStartPoint
					)
					THEN
-- STRIP -- 						RAISE DEBUG 'Component starts from  original path start point';

						modPathGeom := splitPathGeomComp;
						CONTINUE;
					END IF;
				END IF;

			ELSE -- }{

				-- If we do need to merge components
				-- then we take all components (2 expected)
				-- ending on the splitPathMergeOnStartPoint
				-- to build the new versino of the path
				-- which will retain its id
				IF ST_Equals(
						ST_StartPoint(splitPathGeomComp),
						splitPathStartPoint
					) OR
					ST_Equals(
						ST_EndPoint(splitPathGeomComp),
						splitPathStartPoint
					)
				THEN --{
-- STRIP -- 					RAISE DEBUG 'Component ends on original path endpoint';

					IF modPathGeom IS NULL
					THEN
						modPathGeom := splitPathGeomComp;
					ELSE
						modPathGeom := ST_LineMerge(
							ST_Collect(
								modPathGeom,
								splitPathGeomComp
							)
						);
					END IF;
					CONTINUE;

				END IF; --}

			END IF; --}

			rec2 := topo_update.insert_feature(
				splitPathGeomComp,
				newPathProps,
				pathLayerTable,
				pathLayerGeomColumn,
				pathLayerIdColumn,
				inhSplitPathColMap,
				-- use 0 tolerance as we're only using
				-- existing topological elements
				0.0 -- tolerance
			);

			fid := rec2.id;
			act := 'S';
			frm := rec.path_id;
-- STRIP -- 			RAISE DEBUG 'Path % split from % - returning %|%|%',
-- STRIP -- 				fid, frm, fid,act,frm
			RETURN NEXT;

		END LOOP; --}

		-- Update the modified path to only be composed
		-- by the first geometry returned by the split
-- STRIP -- 		RAISE DEBUG 'Modified path geom: %', ST_AsText(modPathGeom);


		fid := rec.path_id;
		act := 'M';
		frm := null;
-- STRIP -- 		RAISE DEBUG 'Path % modified - returning %|%|%',
-- STRIP -- 			fid, fid,act,frm
		RETURN NEXT;

		rec2 := topo_update.update_feature(
			modPathGeom,
			payloadProps,
			pathLayerTable,
			pathLayerGeomColumn,
			pathLayerIdColumn,
			fid,
			colMapForModPath,
			-- use 0 tolerance as we're only using
			-- existing topological elements
			0.0, -- tolerance
			true -- modify existing TopoGeometry
		);

		-- Sanity check
		IF NOT (
			id(rec2.old_topogeom) = newPath.id
		) THEN
			RAISE EXCEPTION 'topo_update.update_feature'
				' unexpectedly found the old TopoGeometry'
				' to be different from the new one (path)';
		END IF;


	END LOOP; --}

	-- Get column map for new Paths
	EXECUTE colMapExtractSQL
		USING colMapProviderParam, 'C'
		INTO colMapForNewPath;
	IF colMapForNewPath IS NULL
	THEN
		RAISE EXCEPTION '%: colMapProvider did not provide a map for new path act=%',
			proc_name, 'C';
	END IF;
-- STRIP -- 	RAISE DEBUG 'colMapForNewPath: %', colMapForNewPath;


	-- Create a new Path for each edge in
	-- inputLineEdgeIds
	-- TODO: join edges togheter if they are not
	--       ending on inputLineNodeIds !
	FOR rec IN
		SELECT unnest(inputLineEdgeIds) edge_id
	LOOP

		act := 'C';
		frm := null;

		-- Create the new Path TopoGeometry
		newPath := topology.CreateTopoGeom(
			topo.name,
			2, -- lineal
			pathLayer.layer_id,
			topology.TopoElementArray_agg(ARRAY[rec.edge_id,2])
		)
		;
-- STRIP -- 		--RAISE DEBUG 'newPath: %', newPath;


		newPathId := topo_update.insert_feature(
			newPath,
			payloadProps,
			pathLayerTable,
			pathLayerGeomColumn,
			pathLayerIdColumn,
			colMapForNewPath
		);

-- STRIP -- 		RAISE DEBUG '%: Path % created to cover input line edge %',
-- STRIP -- 			proc_name, newPathId, rec.edge_id

		-- Return info about the created Path
		fid := newPathId;
		RETURN NEXT;
	END LOOP;

END;
$_$;



--
-- Name: add_unique_topo_primitive_constraint(regclass, name, name, text); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.add_unique_topo_primitive_constraint(layertable regclass, layertopogeomcolumn name, layeridcolumn name, filtersql text DEFAULT NULL::text) RETURNS text
    LANGUAGE plpgsql
    AS $_$
DECLARE
	sql TEXT;
	rec RECORD;
	topo topology.topology;
	layer topology.layer;
	trigname TEXT;
BEGIN

	-- Fetch topology and layer info from layer references
	SELECT t topo, l layer
		FROM topology.layer l, topology.topology t, pg_class c, pg_namespace n
		WHERE l.schema_name = n.nspname
		AND l.table_name = c.relname
		AND c.oid = layerTable
		AND c.relnamespace = n.oid
		AND l.feature_column = layerTopoGeomColumn
		AND l.topology_id = t.id
	INTO rec;
	topo := rec.topo;
	layer := rec.layer;

	-- Check consitency upfront
	FOR rec IN SELECT * FROM topo_update.find_interiors_intersect(
			layerTable,
			layerTopoGeomColumn,
			layerIdColumn,
			filterSQL
		)
	LOOP
		IF rec.tgid1 != rec.tgid2 THEN
			RAISE EXCEPTION 'Features % and % in layer % (%) share %: %',
				rec.fid1, rec.fid2,
				layerTable, layerTopoGeomColumn,
				CASE
				WHEN rec.etyp = 1 THEN
					'nodes'
				WHEN rec.etyp = 2 THEN
					'edges'
				WHEN rec.etyp = 3 THEN
					'faces'
				END,
				array_to_string(rec.eids, ',') ;
		ELSE
			RAISE EXCEPTION 'Features % and % in layer % (%) have same TopoGeometry: %',
				rec.fid1, rec.fid2,
				layerTable, layerTopoGeomColumn,
				rec.tgid1;
		END IF;
	END LOOP;

	trigName := format('unique_primitives_in_layer_%s', layer.layer_id);

	sql := format(
		$$
CREATE TRIGGER %1$I
AFTER INSERT OR UPDATE
ON %2$s
FOR EACH STATEMENT
EXECUTE PROCEDURE
topo_update.check_unique_topo_primitive(%3$L, %4$L, %5$L)
		$$,
		trigName,              -- %1
		layerTable,            -- %2
		layerTopoGeomColumn,   -- %3
		layerIdColumn,         -- %4
		COALESCE(filterSQL,'') -- %5
	);

-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;


	EXECUTE sql;

	RETURN trigName;

END;
$_$;



--
-- Name: app_createschema(name, jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.app_createschema(appname name, appconfig jsonb) RETURNS void
    LANGUAGE plpgsql
    AS $_$ --{
DECLARE
	sql TEXT;
	topoconfig JSONB;
	rec RECORD;
	cur_search_path TEXT;
	new_search_path TEXT;
	topo_name TEXT;
	topo_id INT;
	appconfig_version TEXT;
BEGIN

	-- 0. Initialization

	-- 0.1. Get current search_path
	SELECT reset_val
	FROM pg_settings
	WHERE name = 'search_path'
	INTO cur_search_path;

	-- 0.3. Set topology name
	topo_name := appname || '_sysdata_webclient';

	-- 0.2. Validate appconfig
	PERFORM topo_update._app_validate_config(appconfig);

	-- 1. Create application topology schema
	topoconfig := appconfig -> 'topology';
	sql := format('SELECT topology.CreateTopology(%1$L, %2$L, %3$L)',
		topo_name,
		COALESCE((topoconfig ->> 'srid')::int, 0),
		COALESCE((topoconfig ->> 'snap_tolerance')::float8, 0)
	);
-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;

	EXECUTE sql INTO topo_id;
	IF topo_id IS NULL THEN
		RAISE EXCEPTION 'Could not create topology using sql %', sql;
	END IF;
	RAISE NOTICE 'Created topology % with id %', topo_name, topo_id;

	-- 2. Create application data tables schema

	-- 2.1. Create the schema

	sql := format('CREATE SCHEMA %I', appname);
-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;

	EXECUTE sql;

	-- 2.2. Set search_path to start with the just-created schema
	new_search_path := quote_ident(appname) || ',' || cur_search_path;
	EXECUTE format('SET search_path TO %s', new_search_path);

	-- 2.3. Ensure all required extension are created
	IF appconfig ? 'extensions' THEN --{
		FOR rec IN SELECT jsonb_array_elements( appconfig -> 'extensions' ) cfg
		LOOP --{
			sql := format('CREATE EXTENSION IF NOT EXISTS %I SCHEMA public', rec.cfg ->> 0);
-- STRIP -- 			RAISE DEBUG 'SQL: %', sql;

			EXECUTE sql;
		END LOOP; --}
	END IF; --}

	-- 2.4. Create all application domains
	-- TODO: give understandable error message if appconfig -> 'domains' is not an array
	FOR rec IN SELECT jsonb_array_elements( appconfig -> 'domains' ) cfg
	LOOP --{
		PERFORM topo_update._app_CreateSchema_domain(appname, rec.cfg);
	END LOOP; --}

	-- 2.5. Create all application tables
	-- TODO: give understandable error message if appconfig -> 'tables' is not an array
	FOR rec IN SELECT jsonb_array_elements( appconfig -> 'tables' ) cfg
	LOOP --{
		PERFORM topo_update._app_CreateSchema_table(appname, rec.cfg);
	END LOOP; --}

	-- 2.6. Create all application views
	-- TODO: give understandable error message if appconfig -> 'views' is not an array
	FOR rec IN SELECT jsonb_array_elements( appconfig -> 'views' ) cfg
	LOOP --{
		PERFORM topo_update._app_CreateSchema_view(appname, rec.cfg);
	END LOOP; --}

	-- 2.7. Reset search_path
	EXECUTE format('SET search_path TO %s', cur_search_path);

	-- 3. Create application functions

	-- TODO: decide where to store the functions
	--       (it could be in app schema)

	-- 3.1. Create the schema
	sql := format('CREATE SCHEMA %I', appname || '_sysdata_webclient_functions');
-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;

	EXECUTE sql;

	-- 3.2. Set search_path to start with the just-created schema
	new_search_path := quote_ident(appname || '_sysdata_webclient_functions') || ',' || cur_search_path;
	EXECUTE format('SET search_path TO %s', new_search_path);

	-- 3.3. Store app configuration in the schema
	CREATE TABLE app_config(cfg JSONB);
	INSERT INTO app_config(cfg) VALUES (appconfig);

	-- TODO: optionally generate wrapper functions ?

	-- 3.4. Reset search_path
	EXECUTE format('SET search_path TO %s', cur_search_path);

END;
$_$;



