--
-- Name: app_granteditorprivileges(text, name); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.app_granteditorprivileges(app_name text, editor_role_name name) RETURNS void
    LANGUAGE plpgsql STRICT
    AS $_$
BEGIN

  EXECUTE FORMAT(
    $$

GRANT SELECT, INSERT, UPDATE, DELETE
  ON ALL TABLES IN SCHEMA %1$I
  TO %2$I;

GRANT SELECT, INSERT, DELETE, UPDATE
  ON ALL TABLES IN SCHEMA %4$I
  TO %2$I;

GRANT USAGE
  ON SCHEMA %3$I
  TO %2$I;

GRANT SELECT
  ON TABLE %3$I.app_config
  TO %2$I;

GRANT USAGE
  ON SCHEMA topo_update
  TO %2$I;

GRANT USAGE
  ON SCHEMA %1$s
  TO %2$I;

GRANT USAGE
  ON SCHEMA %4$I
  TO %2$I;

GRANT USAGE
  ON ALL SEQUENCES IN SCHEMA %4$I
  TO %2$I;

GRANT USAGE
  ON ALL SEQUENCES IN SCHEMA %1$s
  TO %2$I;
    $$,
    app_name, -------------------------------------------- %1
    editor_role_name, ------------------------------------ %2
    format('%s_sysdata_webclient_functions', app_name), -- %3
    format('%s_sysdata_webclient', app_name) ------------- %4
  );

END
$_$;



--
-- Name: app_grantreaderprivileges(text, name); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.app_grantreaderprivileges(app_name text, editor_role_name name) RETURNS void
    LANGUAGE plpgsql STRICT
    AS $_X$
BEGIN

  EXECUTE FORMAT(
    $_GRANTS_$

GRANT SELECT
  ON ALL TABLES IN SCHEMA %1$I
  TO %2$I;

GRANT SELECT
  ON ALL TABLES IN SCHEMA %4$I
  TO %2$I;

GRANT USAGE
  ON SCHEMA %3$I
  TO %2$I;

GRANT SELECT
  ON TABLE %3$I.app_config
  TO %2$I;

GRANT USAGE
  ON SCHEMA topo_update
  TO %2$I;

GRANT USAGE
  ON SCHEMA %1$s
  TO %2$I;

GRANT USAGE
  ON SCHEMA %4$I
  TO %2$I;

    $_GRANTS_$,
    app_name, -------------------------------------------- %1
    editor_role_name, ------------------------------------ %2
    format('%s_sysdata_webclient_functions', app_name), -- %3
    format('%s_sysdata_webclient', app_name) ------------- %4
  );

END
$_X$;



--
-- Name: check_topo_primitives_all_used(); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.check_topo_primitives_all_used() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
	rec RECORD;
	layerTable REGCLASS;
	layerTopoGeomColumn NAME;
	sqlFilter TEXT;

BEGIN
-- STRIP -- 	RAISE DEBUG 'TG_ARGV: %', TG_ARGV;

-- STRIP -- 	RAISE DEBUG 'TG_RELID: %', TG_RELID;


	layerTable := TG_RELID;
	layerTopoGeomColumn := TG_ARGV[0];
	IF TG_ARGV[1] IS NOT NULL THEN
		sqlFilter := NULLIF(TG_ARGV[1], '');
	END IF;

	FOR rec IN SELECT * FROM topo_update.find_gaps(
			layerTable,
			layerTopoGeomColumn,
			sqlFilter
		)
	LOOP
		RAISE EXCEPTION 'No feature in layer % (%) uses % %',
				layerTable,
				layerTopoGeomColumn,
				CASE rec.etyp
				WHEN 1 THEN
					'node'
				WHEN 2 THEN
					'edge'
				WHEN 3 THEN
					'face'
				END,
				rec.eid;
	END LOOP;

	RETURN NULL;
END;
$$;



--
-- Name: check_unique_topo_primitive(); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.check_unique_topo_primitive() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
	rec RECORD;
	layerTable REGCLASS;
	layerTopoGeomColumn NAME;
	layerIdColumn NAME;
	sqlFilter TEXT;

BEGIN
-- STRIP -- 	RAISE DEBUG 'TG_ARGV: %', TG_ARGV;

-- STRIP -- 	RAISE DEBUG 'TG_RELID: %', TG_RELID;


	layerTable := TG_RELID;
	layerTopoGeomColumn := TG_ARGV[0];
	layerIdColumn := TG_ARGV[1];
	IF TG_ARGV[2] IS NOT NULL THEN
		sqlFilter := NULLIF(TG_ARGV[2], '');
	END IF;

	FOR rec IN SELECT * FROM topo_update.find_interiors_intersect(
			layerTable,
			layerTopoGeomColumn,
			layerIdColumn,
			sqlFilter
		)
	LOOP
		IF rec.tgid1 != rec.tgid2 THEN
			RAISE EXCEPTION 'Features % and % in layer % (%) share %: %',
				rec.fid1, rec.fid2,
				layerTable, layerTopoGeomColumn,
				CASE
				WHEN rec.etyp = 1 THEN
					'nodes'
				WHEN rec.etyp = 2 THEN
					'edges'
				WHEN rec.etyp = 3 THEN
					'faces'
				END,
				array_to_string(rec.eids, ',') ;
		ELSE
			RAISE EXCEPTION 'Features % and % in layer % (%) have same TopoGeometry: %',
				rec.fid1, rec.fid2,
				layerTable, layerTopoGeomColumn,
				rec.tgid1;
		END IF;
	END LOOP;

	RETURN NULL;
END;
$$;



--
-- Name: cleanup_topology(topology.topology, public.geometry); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.cleanup_topology(topo topology.topology, bbox public.geometry DEFAULT NULL::public.geometry) RETURNS integer
    LANGUAGE plpgsql
    AS $_$
DECLARE
  deletedNodes INT := 0;
  deletedEdges INT := 0;
  deletedNodesDeg2 INT := 0;
  sql TEXT;
  rec RECORD;
  edgeMap JSONB := '{}';
  edge1 INT;
  edge2 INT;
  removedNode INT;
  ok BOOLEAN;
  fixedLinks INT := 0;
  mergedFaces INT[];
  moreMergedFaces INT[];
BEGIN

  RAISE NOTICE 'Removing unused edges';

-- STRIP --   RAISE DEBUG 'Determining edges not referenced by linear TopoGeoms';

  -- Delete edges not used in non-hierarchical TopoGeometry
  -- from linear typed layers
  sql := format(
    $$
      CREATE TEMPORARY TABLE deleted_edges AS
      SELECT
        edge_id,
        next_right_edge,
        next_left_edge,
        left_face,
        right_face,
        start_node,
        end_node
      FROM %1$I.edge_data e
      WHERE ( $1 IS NULL OR ST_Intersects(geom, $1) )
      AND NOT EXISTS (
        SELECT 1
        FROM %1$I.relation r, topology.layer l
        WHERE r.layer_id = l.layer_id
        AND l.topology_id = $2
        AND l.child_id IS NULL
        AND l.feature_type IN (2, 4)
        AND r.element_id in ( e.edge_id, -e.edge_id )
      )
    $$,
    topo.name
  );
-- STRIP --   --RAISE DEBUG 'SQL: %', sql;

  EXECUTE sql USING bbox, topo.id;
  GET DIAGNOSTICS fixedLinks = ROW_COUNT;
-- STRIP --   RAISE DEBUG 'Found % edges not referenced by linear TopoGeoms', fixedLinks;


  -- remove from deleted_edges the edges binding
  -- faces that individually (not both) take part
  -- of the definition of an areal TopoGeometry
-- STRIP --   RAISE DEBUG 'Determining edges not binding areal TopoGeoms';

  sql := format(
    $$
      WITH breaking_merges AS (
        SELECT
          DISTINCT
          de.edge_id
          --, ARRAY[r.layer_id, r.topogeo_id] topogeo
          --, array_agg(r.element_id) faces
        FROM
          topology.layer l,
          %1$I.relation r,
          pg_temp.deleted_edges de
        WHERE l.topology_id = %2$L
        AND l.child_id IS NULL -- non-hierarchical layer
        AND l.feature_type IN (3, 4) -- areal or mixed layer
        AND r.layer_id = l.layer_id
        AND r.element_type = 3 -- face primitive
        AND de.left_face != de.right_face -- non-dangling edges
        AND ( r.element_id = de.left_face OR r.element_id = de.right_face )
        GROUP BY de.edge_id, r.layer_id, r.topogeo_id
        HAVING count(DISTINCT r.element_id) != 2
      )
      --SELECT * FROM breaking_merges
      DELETE FROM pg_temp.deleted_edges de
      WHERE edge_id IN (
        SELECT edge_id FROM breaking_merges
      )
    $$,
    topo.name,
    topo.id
  );
-- STRIP --   --RAISE DEBUG 'SQL: %', sql;

  EXECUTE sql;
  GET DIAGNOSTICS fixedLinks = ROW_COUNT;
-- STRIP --   RAISE DEBUG 'Retained % edges binding areal TopoGeoms', fixedLinks;

  --FOR rec IN EXECUTE sql LOOP
    --RAISE NOTICE 'Should retain edges % binding areal TopoGeom % in layer %', rec.edge_id, rec.topogeo_id, rec.layer_id;
  --END LOOP;


-- STRIP --   RAISE DEBUG 'Deleting unused edges';

  sql := format(
    $$
      DELETE FROM %1$I.edge_data e
      WHERE e.edge_id IN (
        SELECT edge_id FROM pg_temp.deleted_edges
      )
    $$,
    topo.name
  );
  EXECUTE sql;
  GET DIAGNOSTICS deletedEdges = ROW_COUNT;
-- STRIP --   RAISE DEBUG 'Deleted % unused edges', deletedEdges;



-- STRIP --   RAISE DEBUG 'Fixing broken next_right_edge links';

  sql := format(
    $$
      UPDATE %1$I.edge_data e
      SET
        next_right_edge =
          CASE
          WHEN e.next_right_edge = ne.edge_id THEN
            ne.next_right_edge
          ELSE
            ne.next_left_edge
          END,
        abs_next_right_edge =
          CASE
          WHEN e.next_right_edge = ne.edge_id THEN
            abs(ne.next_right_edge)
          ELSE
            abs(ne.next_left_edge)
          END
      FROM pg_temp.deleted_edges ne
      WHERE e.abs_next_right_edge = ne.edge_id
        AND e.next_right_edge !=
        CASE
        WHEN e.next_right_edge = ne.edge_id THEN
          ne.next_right_edge
        ELSE
          ne.next_left_edge
        END
      RETURNING e.*
    $$,
    topo.name
  );
-- STRIP --   --RAISE DEBUG 'SQL: %', sql;

  LOOP
    EXECUTE sql;
    GET DIAGNOSTICS fixedLinks = ROW_COUNT;
--    fixedLinks := 0;
--    FOR rec IN EXECUTE sql LOOP
--      fixedLinks := fixedLinks + 1;
-- STRIP -- --      RAISE DEBUG 'Updated next_right_edge link for edge %, now having next_right_edge=% and abs_next_right_edge=%', rec.edge_id, rec.next_right_edge, rec.abs_next_right_edge;

--    END LOOP;
    IF fixedLinks = 0 THEN
-- STRIP --       RAISE DEBUG 'No (more) broken next_right_edge links';

      EXIT;
    END IF;
-- STRIP --     RAISE DEBUG 'Updated % broken next_right_edge links', fixedLinks;

  END LOOP;

-- STRIP --   RAISE DEBUG 'Fixing broken next_left_edge links';

  sql := format(
    $$
      UPDATE %1$I.edge_data e
      SET
        next_left_edge =
          CASE
          WHEN e.next_left_edge = ne.edge_id THEN
            ne.next_right_edge
          ELSE
            ne.next_left_edge
          END,
        abs_next_left_edge =
          CASE
          WHEN e.next_left_edge = ne.edge_id THEN
            abs(ne.next_right_edge)
          ELSE
            abs(ne.next_left_edge)
          END
      FROM pg_temp.deleted_edges ne
      WHERE e.abs_next_left_edge = ne.edge_id
        -- Avoid updating records which do not need
        -- to be updated (alternatively we could DELETE
        -- those records from deleted_edges before next iteration)
        AND e.next_left_edge !=
        CASE
        WHEN e.next_left_edge = ne.edge_id THEN
          ne.next_right_edge
        ELSE
          ne.next_left_edge
        END
      RETURNING e.*
    $$,
    topo.name
  );
-- STRIP --   --RAISE DEBUG 'SQL: %', sql;

  LOOP
    EXECUTE sql;
    GET DIAGNOSTICS fixedLinks = ROW_COUNT;
--    fixedLinks := 0;
--    FOR rec IN EXECUTE sql LOOP
--      fixedLinks := fixedLinks + 1;
-- STRIP -- --      RAISE DEBUG 'Updated next_left_edge link for edge %, now having next_left_edge=% and abs_next_left_edge=%', rec.edge_id, rec.next_left_edge, rec.abs_next_left_edge;

--    END LOOP;
    IF fixedLinks = 0 THEN
-- STRIP --       RAISE DEBUG 'No (more) broken next_left_edge links found';

      EXIT;
    END IF;
-- STRIP --     RAISE DEBUG 'Updated % broken next_left_edge links', fixedLinks;

  END LOOP;

  --
  -- Build arrays of faces to be merged
  --

-- STRIP --   RAISE DEBUG 'Building face merge sets';


  CREATE TEMPORARY TABLE mergeable_faces AS
  WITH merges AS (
    SELECT
      DISTINCT
      ARRAY[
        LEAST(left_face, right_face),
        GREATEST(left_face, right_face)
      ] faceset
    FROM deleted_edges
    WHERE left_face != right_face
  )
  SELECT faceset
  FROM merges;

  CREATE TEMPORARY TABLE merged_faces (keep INT, merge INT[]);

  LOOP -- {

    -- Fetch next merge
    DELETE FROM mergeable_faces
    WHERE ctid = (SELECT ctid FROM mergeable_faces LIMIT 1)
    RETURNING faceset
    INTO mergedFaces;
    IF mergedFaces IS NULL THEN
      EXIT;
    END IF;

-- STRIP --     RAISE DEBUG 'Next merged faces start with: %', mergedFaces;


    LOOP --{
      WITH deleted AS (
        DELETE FROM mergeable_faces
        WHERE faceset && mergedFaces
        RETURNING faceset
      ), flood_faces AS (
        SELECT DISTINCT unnest(faceset) merged
        FROM deleted
      )
      SELECT array_agg(merged)
      FROM flood_faces
      INTO moreMergedFaces;

      IF moreMergedFaces IS NULL THEN
        EXIT;
      END IF;

-- STRIP --       RAISE DEBUG 'There is more merged faces: %', moreMergedFaces;

      SELECT array_agg(x) FROM (
        SELECT unnest(mergedFaces) x
          UNION
        SELECT unnest(moreMergedFaces)
      ) foo
      INTO mergedFaces;
-- STRIP --       RAISE DEBUG 'Merged faces grows to: %', mergedFaces;


    END LOOP; --}

    mergedFaces := array_agg(distinct x ORDER BY x) FROM unnest(mergedFaces) x;
-- STRIP --     RAISE DEBUG 'Storing merged faceset: %', mergedFaces;


    INSERT INTO pg_temp.merged_faces VALUES (
      mergedFaces[1],
      array_remove(mergedFaces, mergedFaces[1])
    );

  END LOOP; --}

  DROP TABLE pg_temp.mergeable_faces;

  --
  -- Fix face labels
  --

-- STRIP --   RAISE DEBUG 'Fixing broken left_face labels';

  sql := format(
    $$
      UPDATE %1$I.edge_data e
      SET left_face = mf.keep
      FROM pg_temp.merged_faces mf
      WHERE e.left_face != mf.keep
        AND e.left_face = ANY(mf.merge)
    $$,
    topo.name
  );
-- STRIP --   --RAISE DEBUG 'SQL: %', sql;

  EXECUTE sql;
  GET DIAGNOSTICS fixedLinks = ROW_COUNT;
-- STRIP --   RAISE DEBUG 'Updated % broken left_face links', fixedLinks;


-- STRIP --   RAISE DEBUG 'Fixing broken right_face labels';

  sql := format(
    $$
      UPDATE %1$I.edge_data e
      SET right_face = mf.keep
      FROM pg_temp.merged_faces mf
      WHERE e.right_face != mf.keep
        AND e.right_face = ANY(mf.merge)
    $$,
    topo.name
  );
-- STRIP --   --RAISE DEBUG 'SQL: %', sql;

  EXECUTE sql;
  GET DIAGNOSTICS fixedLinks = ROW_COUNT;
-- STRIP --   RAISE DEBUG 'Updated % broken right_face links', fixedLinks;



-- STRIP --   RAISE DEBUG 'Updating containing_face labels for merged faces';

  sql := format(
    $$
      UPDATE %1$I.node n
      SET containing_face = mf.keep
      FROM pg_temp.merged_faces mf
      WHERE n.containing_face != mf.keep
      AND n.containing_face = ANY(mf.merge)
    $$,
    topo.name
  );
-- STRIP --   --RAISE DEBUG 'SQL: %', sql;

  EXECUTE sql;
  GET DIAGNOSTICS fixedLinks = ROW_COUNT;
-- STRIP --   RAISE DEBUG 'Updated % containing_face labels for nodes', fixedLinks;


  --
  -- Fix face table (delete/update mbr)
  --

-- STRIP --   RAISE DEBUG 'Updating merged faces MBR';

  sql := format(
    $$
      WITH merged_mbr AS (
        SELECT
          mf.keep,
          ST_Envelope(
            ST_Collect(
              f.mbr
            )
          ) mbr
        FROM pg_temp.merged_faces mf
        JOIN %1$I.face f ON (
          f.face_id = mf.keep OR
          f.face_id = ANY( mf.merge )
        )
        WHERE mf.keep != 0
        GROUP by mf.keep
      )
      UPDATE %1$I.face f
      SET mbr = m.mbr
      FROM merged_mbr m
      WHERE f.face_id = m.keep
    $$,
    topo.name
  );
  EXECUTE sql;
  GET DIAGNOSTICS fixedLinks = ROW_COUNT;
-- STRIP --   RAISE DEBUG 'Updated % merged faces MBR', fixedLinks;


-- STRIP --   RAISE DEBUG 'Deleting removed faces';

  sql := format(
    $$
      DELETE FROM %1$I.face
      USING pg_temp.merged_faces mf
      WHERE face_id = ANY (mf.merge)
    $$,
    topo.name
  );
  EXECUTE sql;
  GET DIAGNOSTICS fixedLinks = ROW_COUNT;
-- STRIP --   RAISE DEBUG 'Deleted % merged faces', fixedLinks;


  --
  -- Fix TopoGeometry
  --

-- STRIP --   RAISE DEBUG 'Updating areal TopoGeometry definitions';

  -- We remove the merged faces from the definition
  -- of areal TopoGeometry objects
  sql := format(
    $$
      WITH deleted AS (
        DELETE FROM %1$I.relation r
        USING topology.layer l, pg_temp.merged_faces mf
        WHERE l.topology_id = %2$L
        AND l.feature_type IN (3, 4)
        AND l.child_id IS NULL
        AND r.layer_id = l.layer_id
        AND r.element_id = ANY (mf.merge)
        RETURNING
          r.topogeo_id,
          r.layer_id,
          l.schema_name,
          l.table_name,
          l.feature_column,
          mf.merge,
          mf.keep,
          r.element_id
      )
      SELECT
        topogeo_id,
        layer_id,
        schema_name,
        table_name,
        feature_column,
        merge,
        keep,
        array_agg(element_id) lost_faces
      FROM deleted
      GROUP BY 1,2,3,4,5,6,7
    $$,
    topo.name,
    topo.id
  );
  --RAISE NOTICE 'SQL: %', sql;
  FOR rec IN EXECUTE sql
  LOOP
-- STRIP --     RAISE DEBUG 'Areal TopoGeometry % in layer %.%.% '
-- STRIP --       'lost faces % (kept %) in its composition',
-- STRIP --       rec.topogeo_id, rec.schema_name,
-- STRIP --       rec.table_name, rec.feature_column,
-- STRIP --       rec.lost_faces, rec.keep
-- STRIP --     
  END LOOP;

  --
  -- Mark newly isolated nodes as such
  --

-- STRIP --   RAISE DEBUG 'Determining newly isolated nodes';

  sql := format(
    $$
      WITH unlinked_nodes AS (
        SELECT start_node node_id FROM pg_temp.deleted_edges
          UNION
        SELECT end_node FROM pg_temp.deleted_edges
      ), isolated AS (
        SELECT node_id FROM unlinked_nodes
        EXCEPT SELECT start_node FROM %1$I.edge_data
        EXCEPT  SELECT end_node FROM %1$I.edge_data
      ), incident_faces AS (
        SELECT
          node_id,
          array_agg(DISTINCT face_id) incident_faces
        FROM (
          SELECT DISTINCT node_id, unnest(face_id) face_id
          FROM (
            SELECT
              i.node_id,
              ARRAY[e.left_face, e.right_face] face_id
            FROM isolated i, deleted_edges e
            WHERE e.start_node = i.node_id
              UNION
            SELECT
              i.node_id,
              ARRAY[e.left_face, e.right_face] face_id
            FROM isolated i, deleted_edges e
            WHERE e.end_node = i.node_id
          ) foo
        ) bar
        GROUP BY node_id
      ), containing_faces AS (
        SELECT
          inc.node_id,
          COALESCE(mf.keep, incident_faces[1]) face_id
        FROM incident_faces inc
        LEFT JOIN pg_temp.merged_faces mf
          ON ( inc.incident_faces && mf.merge )
      )
      UPDATE %1$I.node n
      SET containing_face = cf.face_id
      FROM containing_faces cf
      WHERE n.node_id = cf.node_id
      AND n.containing_face IS DISTINCT FROM cf.face_id
    $$,
    topo.name
  );
-- STRIP --   --RAISE DEBUG 'SQL: %', sql;

  EXECUTE sql;
  GET DIAGNOSTICS fixedLinks = ROW_COUNT;
-- STRIP --   RAISE DEBUG 'Isolated % nodes', fixedLinks;


  RAISE NOTICE 'Removed % unused edges', deletedEdges;


  --
  -- Clean isolated nodes
  --

  -- Cleanup isolated nodes
  -- (non-isolated ones would have become isolated by now)
  sql := format(
    $$
      SELECT
        n.node_id
      FROM
        %1$I.node n
      WHERE ( $1 IS NULL OR ST_Intersects(n.geom, $1) )
      AND n.containing_face IS NOT NULL
      AND NOT EXISTS (
        SELECT 1
        FROM %1$I.relation r, topology.layer l
        WHERE r.layer_id = l.layer_id
        AND l.topology_id = $2
        AND l.child_id IS NULL
        AND l.feature_type = 1
        AND r.element_id = n.node_id
      )
    $$,
    topo.name
  );
  RAISE NOTICE 'Removing isolated nodes';
  FOR rec in EXECUTE sql USING bbox, topo.id
  LOOP --{
    BEGIN
      PERFORM topology.ST_RemIsoNode(topo.name, rec.node_id);
-- STRIP --       RAISE DEBUG 'Removed isolated node %', rec.node_id;

      deletedNodes := deletedNodes + 1;
    EXCEPTION WHEN OTHERS
    THEN
      RAISE WARNING 'Isolated node % could not be removed: %', rec.node_id, SQLERRM;
    END;
  END LOOP; --}
  RAISE NOTICE 'Removed % isolated nodes', deletedNodes;

  -- Remove nodes connecting only 2 edges if
  -- no lineal TopoGeometry exists that is defined
  -- by only one of them
  sql := format(
    $$
      WITH
      unused_connected_nodes_in_bbox AS (
        SELECT
          n.node_id
        FROM %1$I.node n
        WHERE
          ( $1 IS NULL OR ST_Intersects(n.geom, $1) )
          AND n.containing_face IS NULL

          EXCEPT

        SELECT r.element_id
        FROM %1$I.relation r
        JOIN topology.layer l ON ( r.layer_id = l.layer_id )
        WHERE l.child_id IS NULL
        AND l.topology_id = $2
        AND l.feature_type IN ( 1, 4 ) -- puntual or mixed layer
        AND r.element_type = 1 -- node primitive
      ),
      removable_nodes_of_degree_2_in_bbox AS (
        SELECT
          n.node_id,
          array_agg(e.edge_id) edges
        FROM
          unused_connected_nodes_in_bbox n,
          %1$I.edge e
        WHERE (
            n.node_id = e.start_node
            OR n.node_id = e.end_node
          )
        GROUP BY n.node_id
        HAVING count(e.edge_id) = 2
      ),
      breaking_heals AS (
        SELECT
          DISTINCT
          n.node_id
          -- , ARRAY[r.layer_id, r.topogeo_id]
          -- , array_agg(r.element_id) edges
        FROM
          removable_nodes_of_degree_2_in_bbox n,
          %1$I.relation r,
          topology.layer l
        WHERE l.topology_id = $2
          AND l.child_id IS NULL
          AND l.feature_type IN ( 2, 4 ) -- lineal or mixed layer
          AND r.layer_id = l.layer_id
          AND r.element_type = 2 -- edge primitive
          AND r.element_id IN (
            n.edges[1], -n.edges[1],
            n.edges[2], -n.edges[2]
          )
          GROUP BY n.node_id, r.layer_id, r.topogeo_id
          HAVING count(DISTINCT abs(r.element_id)) != 2
      )
      SELECT
        node_id,
        edges[1] edge1,
        edges[2] edge2
      FROM removable_nodes_of_degree_2_in_bbox
      WHERE node_id NOT IN (
        SELECT node_id FROM breaking_heals
      )
    $$,
    topo.name
  );
-- STRIP --   --RAISE DEBUG 'SQL: %', sql;

  RAISE NOTICE 'Removing unneeded nodes of degree 2';
  EXECUTE sql USING bbox, topo.id;
  FOR rec in EXECUTE sql USING bbox, topo.id
  LOOP --{
-- STRIP --     RAISE DEBUG 'edgeMap: %', edgeMap;

    -- Edges may have changed name
    edge1 := COALESCE( (edgeMap -> rec.edge1::text)::int, rec.edge1);
    edge2 := COALESCE( (edgeMap -> rec.edge2::text)::int, rec.edge2);

-- STRIP --     RAISE DEBUG 'Should heal edges % (now %) and % (now %) bound by node %',
-- STRIP --       rec.edge1, edge1, rec.edge2, edge2, rec.node_id

    IF edge1 = edge2 THEN
      -- Nothing to merge here, continue
      CONTINUE;
    END IF;
    ok := false;

    BEGIN
      -- TODO: replace ST_ModEdgeHeal loop with a faster direct deletion and healing
      removedNode := topology.ST_ModEdgeHeal(topo.name, edge1, edge2);
      IF rec.node_id != removedNode THEN
        RAISE EXCEPTION 'Healing of edges % and % was reported '
                        'to remove node % while we expected % instead',
                        edge1, edge2, removedNode, rec.node_id;
      END IF;
-- STRIP --       RAISE DEBUG 'Edge % merged into %, dropping node %', edge2, edge1, removedNode;

      ok := 1;
    EXCEPTION WHEN OTHERS
    THEN
      RAISE WARNING 'Edges % and % joined by node % could not be healed: %', edge1, edge2, rec.node_id, SQLERRM;
    END;
    IF ok THEN
      -- edge2 was now renamed to edge1, update map
      edgeMap := jsonb_set(edgeMap, ARRAY[edge2::text], to_jsonb(edge1));
      deletedNodesDeg2 := deletedNodesDeg2 + 1;
    END IF;
  END LOOP; --}
  RAISE NOTICE 'Removed % unneeded nodes of degree 2', deletedNodesDeg2;

  DROP TABLE pg_temp.deleted_edges;
  DROP TABLE pg_temp.merged_faces;

  RETURN deletedEdges + deletedNodes + deletedNodesDeg2;
END;
$_$;



--
-- Name: delete_unknown_features(regclass, name, name, public.geometry, text[]); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.delete_unknown_features(layertable regclass, layercolumn name, layeridcolumn name, bbox public.geometry, keepidvalues text[]) RETURNS integer
    LANGUAGE plpgsql
    AS $_$ -- {
DECLARE
	sql TEXT;
	delete_count INTEGER;
	proc_name TEXT = 'topo_update.delete_unknown_features';
	quoted_id TEXT;
	layer topology.layer;
	topo topology.topology;
	rec RECORD;
	intersecting_faces INT[];
BEGIN

	-- TODO: take these from caller
	SELECT t topo, l layer
		FROM topology.layer l, topology.topology t, pg_class c, pg_namespace n
		WHERE l.schema_name = n.nspname
		AND l.table_name = c.relname
		AND c.oid = layerTable
		AND c.relnamespace = n.oid
		AND l.feature_column = layerColumn
		AND l.topology_id = t.id
		INTO rec;
	topo := rec.topo;
	layer := rec.layer;

-- STRIP -- 	RAISE DEBUG 'layer.feature_type is %, child is %', layer.feature_type, layer.child_id;


	-- Optimize for non-hierarchical layers
	IF layer.child_id IS NULL
	THEN --{
		IF layer.feature_type = 2
		THEN --{ layer is lineal

			sql := format(
				$$
					WITH deleted AS
					(
						DELETE FROM %2$s
						WHERE %5$I IN (
							SELECT l.%5$I fid
							FROM
								%1$I.edge e,
								%1$I.relation r,
								%2$s l
							WHERE r.layer_id = %3$L
							AND ( NOT l.%5$I::text = ANY($2) )
							AND id(l.%4$I) = r.topogeo_id
							AND r.element_id IN ( e.edge_id, -e.edge_id )
							AND ST_Intersects(e.geom, $1)
						)
						RETURNING id(%4$I)
					)
					SELECT array_agg(id) did FROM deleted;
				$$,
				topo.name,       -- %1
				layerTable,      -- %2
				layer.layer_id,  -- %3
				layerColumn,     -- %4
				layerIDColumn    -- %5
			);
-- STRIP -- 			RAISE DEBUG 'SQL: %', sql;

			EXECUTE sql
			USING
				bbox, -- $1
				keepIDValues -- $2
			INTO rec
			;

			delete_count = COALESCE(array_upper(rec.did, 1), 0);
-- STRIP -- 			RAISE DEBUG 'DELETED: % linear features', delete_count;


			sql := format(
				$$
					DELETE FROM %1$I.relation
					WHERE layer_id = %2$L
					AND topogeo_id = ANY($1)
				$$,
				topo.name,
				layer.layer_id
			);
-- STRIP -- 			RAISE DEBUG 'SQL: %', sql;

			EXECUTE sql
			USING rec.did;

			RETURN delete_count;

		ELSIF layer.feature_type = 3
		THEN -- }{ layer is areal

			-- 1. Find all faces on the side
			--    of edges intersecting the bbox
			sql := format(
				$$
					WITH edges AS (
						SELECT e.edge_id, e.right_face, e.left_face
						FROM %1$I.edge e
						WHERE ST_Intersects(e.geom, $1)
					), edge_faces AS (
						SELECT edge_id, right_face face_id
						FROM edges
							UNION
						SELECT edge_id, left_face
						FROM edges
					)
					SELECT array_agg(distinct face_id)
					FROM edge_faces
				$$,
				topo.name
			);
-- STRIP -- 			RAISE DEBUG 'SQL: %', sql;

			EXECUTE sql USING bbox INTO intersecting_faces;

-- STRIP -- 			RAISE DEBUG 'Intersecting edge faces: %', intersecting_faces;


			IF intersecting_faces IS NULL THEN
-- STRIP -- 				RAISE DEBUG 'No edge intersects bbox %', ST_AsEWKT(bbox);

				SELECT ARRAY[topology.GetFaceByPoint(
					topo.name,
					ST_PointOnSurface(bbox),
					0
				)]
				INTO
				intersecting_faces;
-- STRIP -- 				RAISE DEBUG 'GetFaceByPoint returned face %', intersecting_faces;

			END IF;

			sql := format(
				$$
					WITH
					deleted AS
					(
						DELETE FROM %2$s
						WHERE ( NOT %5$I::text = ANY($2) )
						AND id(%4$I) IN (
							SELECT topogeo_id
							FROM %1$I.relation
							WHERE layer_id = %3$L
							AND element_id = ANY($1)
						)
						RETURNING id(%4$I)
					)
					SELECT array_agg(id) did FROM deleted;
				$$,
				topo.name,       -- %1
				layerTable,      -- %2
				layer.layer_id,  -- %3
				layerColumn,     -- %4
				layerIDColumn    -- %5
			);
-- STRIP -- 			RAISE DEBUG 'SQL: %', sql;

			EXECUTE sql
			USING
				intersecting_faces, -- $1
				keepIDValues -- $2
			INTO rec
			;

			delete_count = COALESCE(array_upper(rec.did, 1), 0);
-- STRIP -- 			RAISE DEBUG 'DELETED: % areal features', delete_count;


			sql := format(
				$$
					DELETE FROM %1$I.relation
					WHERE layer_id = %2$L
					AND topogeo_id = ANY($1)
				$$,
				topo.name,
				layer.layer_id
			);
-- STRIP -- 			RAISE DEBUG 'SQL: %', sql;

			EXECUTE sql
			USING rec.did;

			RETURN delete_count;

		END IF; --} layer is non-hierarchical and areal

	END IF; --} layer is non-hierarchical

	-- Compute ID name
	quoted_id := topo_update.__insert_to_update_identifier_syntax(layerIDColumn);

	-- Unoptimized query
	-- TODO: optimize for simple linear and simple areal cases
	-- TODO: optimize this upstream, see https://trac.osgeo.org/postgis/ticket/853
	sql := format(
		$$
WITH deleted AS (
	DELETE FROM %1$s
	WHERE ST_Intersects(%2$I, $1)
	AND NOT %3$s::text = ANY($2)
	RETURNING %2$I tg
) SELECT topology.clearTopoGeom(tg) FROM deleted
		$$,
		layerTable,   -- %1
		layerColumn,  -- %2
		quoted_id -- %3
	);

-- STRIP -- 	RAISE DEBUG '%: %', proc_name, sql;


	EXECUTE sql
	USING
		bbox, -- $1
		keepIDValues -- $2
	;

	GET DIAGNOSTICS delete_count = ROW_COUNT;

-- STRIP -- 	RAISE DEBUG 'Deleted % features in % layer', delete_count, layerTable::text;


	RETURN delete_count;

END;
$_$;



--
-- Name: extension_upgrade(); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.extension_upgrade() RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE
	oldversion text;
BEGIN
	UPDATE pg_catalog.pg_extension
	SET extversion = 'ANY'
	WHERE extname = 'topo_update'
	RETURNING extversion
	INTO oldversion;

	IF oldversion IS NOT NULL THEN
-- STRIP -- 		RAISE DEBUG 'Old version: %', oldversion;

		ALTER EXTENSION topo_update UPDATE;
	ELSE
		CREATE EXTENSION topo_update;
	END IF;

	RETURN 'topo_update extension is updated, run topo_update.version() for details';
END;
$$;



--
-- Name: features_as_geojson(regclass, name, name, text[], jsonb, regproc, anyelement, integer, integer); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.features_as_geojson(layertable regclass, layertopogeomcolumn name, layeridcolumn name, featureids text[], layercolmap jsonb DEFAULT NULL::jsonb, featurejsonmodifier regproc DEFAULT NULL::regproc, featurejsonmodifierarg anyelement DEFAULT NULL::integer, outsrid integer DEFAULT NULL::integer, maxdecimaldigits integer DEFAULT 9) RETURNS jsonb
    LANGUAGE plpgsql
    AS $_$ -- {
DECLARE
	rec RECORD;
	sql TEXT;
	crs TEXT;
	crsSRID INT;
	geojson JSONB;
	topo topology.topology;
	featureLayer topology.layer;
	featureProps JSONB;
	featureTopoGeom topology.TopoGeometry;
	featureGeom Geometry;
	featureJSON JSONB;
	geojsonFeatures JSONB[] = ARRAY[]::JSONB[];
	procName TEXT := 'topo_update.features_as_geojson';
BEGIN

	IF layerColMap IS NULL THEN
		layerColMap := topo_update.json_col_map_from_pg(layerTable, ARRAY[layerTopoGeomColumn]);
	END IF;

	sql := format(
		$$
			SELECT
			s::text as feature_record,
			s.%3$I as feature_topogeom,
			s.%2$I::TEXT AS feature_id
			FROM %1$s s
			WHERE %2$I::TEXT = ANY($1)
			ORDER BY %2$I
		$$,
		layerTable,
		layerIDColumn,
		layerTopoGeomColumn
	);
-- STRIP -- 	RAISE DEBUG '%: SQL": %', procName, sql;

	FOR rec IN EXECUTE sql USING featureIds
	LOOP --{

		IF topo IS NULL THEN
			-- Fetch topology info from the TopoGeometry
			SELECT *
				FROM topology.topology
				WHERE id = topology_id(rec.feature_topogeom)
				INTO topo;
			IF NOT FOUND THEN
				RAISE EXCEPTION
					'Cannot find topology (id=%) '
					'referenced by TopoGeometry of Feature % in layer %',
					topology_id(rec.feature_topogeom),
					rec.feature_id,
					layerTable
				;
			END IF;

			-- Fetch layer info from the TopoGeometry
			SELECT *
				FROM topology.layer
				WHERE topology_id = topo.id
				AND layer_id = layer_id(rec.feature_topogeom)
				INTO featureLayer;
			IF NOT FOUND THEN
				RAISE EXCEPTION
					'Cannot find layer (id=%) of topology % '
					'referenced by TopoGeometry of feature % in layer %',
					layer_id(rec.feature_topogeom),
					topo.name,
					rec.feature_id,
					layerTable
				;
			END IF;
		ELSE
			-- Sanity check: all Feature TopoGeometry objects are defined
			-- against the SAME topology
			IF topology_id(rec.feature_topogeom) != topo.id
			THEN
				RAISE EXCEPTION 'TopoGeometry of feature % in layer % is defined on'
					' Topology % instead of % (%)',
					rec.feature_id,
					layerTable,
					topology_id(rec.feature_topogeom),
					topo.id,
					topo.name
				;
			END IF;
			-- Sanity check: all TopoGeometry objects are defined
			-- against the SAME topology layer
			IF layer_id(rec.feature_topogeom) != featureLayer.layer_id
			THEN
				RAISE EXCEPTION 'TopoGeometry of Feature % is defined on'
					' layer % instead of % (%.%.%)',
					rec.feature_id,
					layer_id(rec.feature_topogeom),
					featureLayer.layer_id,
					featureLayer.schema_name,
					featureLayer.table_name,
					featureLayer.feature_column
				;
			END IF;
		END IF;

		-- Build properties of the Feature
		sql := format(
			$$
				SELECT topo_update.record_to_jsonb(
					%1$L::%2$s,
					%3$L
				);
			$$,
			rec.feature_record,
			layerTable::text,
			layerColMap
		);
		EXECUTE sql INTO featureProps;
		IF featureProps IS NULL THEN
			RAISE EXCEPTION 'Properties for feature % as extracted by colMap % are NULL',
				to_jsonb(rec.feature_record), layerColMap;
		END IF;

-- STRIP -- 		RAISE DEBUG '%: feature % has props %', procName, rec.feature_id, featureProps;


		-- Write the feature object
		featureGeom = ST_CollectionHomogenize(
			rec.feature_topogeom::geometry
		);

-- STRIP -- 		--RAISE DEBUG '%: homogenized feature: %', procName, ST_AsEWKT(featureGeom);


		IF outSRID IS NOT NULL
		THEN
			featureGeom := ST_Transform(featureGeom, outSRID);
		END IF;

		-- Remove points that will be seen as repeated
		-- when precision is reduced due to number of
		-- decimal digits
		-- TODO: featureGeom := ST_RemoveRepeatedPoints(featureGeom, prec);

-- STRIP -- 		--RAISE DEBUG '%: transformed feature geom: %', procName, ST_AsEWKT(featureGeom);


		featureJSON := jsonb_build_object(
			'type', 'Feature',
			'geometry', ST_AsGeoJSON(
				featureGeom,
				maxdecimaldigits => maxdecimaldigits,
				options => 0
			)::jsonb,
			'properties', featureProps
		);

-- STRIP -- 		--RAISE DEBUG '%: feature: %', procName, featureJSON;


		-- Append feature features to the global features array
		geojsonFeatures := geojsonFeatures || featureJSON;

	END LOOP; --}

	IF outSRID IS NOT NULL
	THEN
		IF outSRID = 0 THEN
			RAISE EXCEPTION 'If an output SRID is given, it cannot be 0';
		END IF;
		crsSRID = outSRID;
	ELSE
		crsSRID = topo.srid;
	END IF;

	-- Initialize geojson with CRS member, if SRID is known
	IF crsSRID = 0 THEN
		geojson := jsonb_build_object();
	ELSE
		SELECT auth_name || ':' || auth_srid
		FROM public.spatial_ref_sys
		WHERE srid = crsSRID
		INTO crs;

		IF FOUND THEN
			geojson := jsonb_build_object(
				'crs', jsonb_build_object(
					'properties', jsonb_build_object('name', crs),
					'type', 'name'
				)
			);
		ELSE
			RAISE EXCEPTION 'Could not found spatial_ref_sys entry for SRID %', crsSRID;
		END IF;
	END IF;

-- STRIP -- 	RAISE DEBUG '%: GeoJSON header: %', procName, geojson;


	-- Add features and type to the GsoJSON
	geojson := geojson || jsonb_build_object(
		'type', 'FeatureCollection',
		'features', to_jsonb(geojsonFeatures)
	);

-- STRIP -- 	RAISE DEBUG '%: GeoJSON being returned: %', procName, geojson;


	RETURN geojson;
END;
$_$;



--
-- Name: fill_surface_gaps(regclass, name, name, jsonb, jsonb, public.geometry); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.fill_surface_gaps(layertable regclass, layertopogeomcolumn name, layeridcolumn name, feature_properties jsonb, layercolmap jsonb, bbox public.geometry DEFAULT NULL::public.geometry) RETURNS TABLE(id text)
    LANGUAGE plpgsql
    AS $_$ -- {
DECLARE
	sql TEXT;
	layer topology.layer;
	topo topology.topology;
	rec RECORD;
	proc_name TEXT := 'topo_update.fill_surface_gaps';
	tg topology.TopoGeometry;
BEGIN

	layer := topology.findLayer(layerTable, layerTopoGeomColumn);
	IF layer.layer_id IS NULL THEN
		RAISE EXCEPTION 'No such topology layer registered: %.%', layerTable, layerTopoGeomColumn;
	END IF;

	topo := topology.findTopology(layer.topology_id);
	IF topo.id IS NULL THEN
		RAISE EXCEPTION 'Topology of topology layer %.% (%) is not registered',
			layerTable, layerTopoGeomColumn, layer.topology_id;
	END IF;

	IF layer.child_id IS NOT NULL THEN
		RAISE EXCEPTION '%: hierarchical layers are not supported',
			proc_name;
	END IF;

	IF layer.feature_type != 3 THEN
		RAISE EXCEPTION '%: only areal layers are supported',
			proc_name;
	END IF;

	-- TODO: merge adjacent faces not separated by borders ?
	-- See topo_update._add_border_split_surface_mergeable_faces
	sql := format(
		$$
SELECT g.eid face_id
FROM topo_update.find_gaps(%2$L, %3$L) g
JOIN %1$I.face f ON ( g.eid = f.face_id )
AND ( $1 IS NULL OR ST_Intersects(f.mbr, $1) )
		$$,
		topo.name,
		layerTable,
		layerTopoGeomColumn
	);

	FOR rec IN EXECUTE sql USING bbox
	LOOP
		tg := topology.CreateTopogeom(
			topo.name,
			layer.feature_type,
			layer.layer_id,
			ARRAY[ARRAY[rec.face_id, 3]]::topology.TopoElementArray
		);
		id := topo_update.insert_feature(
			tg,
			feature_properties,
			layerTable,
			layerTopoGeomColumn,
			layerIDColumn,
			layerColMap
		);

		RETURN NEXT;
	END LOOP;
END;
$_$;



--
-- Name: find_dangling_borders(regclass, name, name, regclass, name, public.geometry); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.find_dangling_borders(borderlayertable regclass, borderlayergeomcolumn name, borderlayeridcolumn name, surfacelayertable regclass, surfacelayergeomcolumn name, bbox public.geometry DEFAULT NULL::public.geometry) RETURNS SETOF text
    LANGUAGE plpgsql
    AS $_$ --{
DECLARE
	topo topology.topology;
	borderLayer topology.layer;
	surfaceLayer topology.layer;
	rec RECORD;
	sql TEXT;
BEGIN
	-- Fetch topology and layer info from border layer references
	SELECT t topo, l layer
		FROM topology.layer l, topology.topology t, pg_class c, pg_namespace n
		WHERE l.schema_name = n.nspname
		AND l.table_name = c.relname
		AND c.oid = borderLayerTable
		AND c.relnamespace = n.oid
		AND l.feature_column = borderLayerGeomColumn
		AND l.topology_id = t.id
		INTO rec;
	topo := rec.topo;
	borderLayer := rec.layer;

	-- Fetch topology and layer info from surface layer references
	SELECT t topo, l layer
		FROM topology.layer l, topology.topology t, pg_class c, pg_namespace n
		WHERE l.schema_name = n.nspname
		AND l.table_name = c.relname
		AND c.oid = surfaceLayerTable
		AND c.relnamespace = n.oid
		AND l.feature_column = surfaceLayerGeomColumn
		AND l.topology_id = t.id
		INTO rec;

	IF id(topo) != id(rec.topo) THEN
		RAISE EXCEPTION 'Surface and Border layers need to be in same topology';
	END IF;
	surfaceLayer := rec.layer;

	-- Find borders defined by dangling edges
	sql := format(
		$$
			WITH dangling_edges_in_bbox AS (
				SELECT
				  rb.topogeo_id tgid,
				  e.edge_id eid,
				  e.left_face fl,
				  e.right_face fr,
				  rsl.topogeo_id sl,
				  rsr.topogeo_id sr
				FROM %1$I.relation rb
				JOIN %1$I.edge_data e
					ON ( e.edge_id in ( rb.element_id, -rb.element_id ) )
				LEFT JOIN %1$I.relation rsl
					ON ( rsl.layer_id = %2$L AND rsl.element_id = e.left_face )
				LEFT OUTER JOIN %1$I.relation rsr
					ON ( rsr.layer_id = %2$L AND rsr.element_id = e.right_face )
				WHERE rb.layer_id = %3$L
				AND rsl.topogeo_id IS NOT DISTINCT FROM rsr.topogeo_id
				AND (
					%4$L is NULL
					OR
					e.geom && %4$L
				)
			)
			SELECT %5$I::text bid
			FROM %6$s
			WHERE id(%7$I) IN (
				SELECT tgid FROM dangling_edges_in_bbox
			)
		$$,
		topo.name,             -- %1
		surfaceLayer.layer_id, -- %2
		borderLayer.layer_id,  -- %3
		bbox,                  -- %4
		borderLayerIdColumn,   -- %5
		borderLayerTable,      -- %6
		borderLayerGeomColumn  -- %7
	);
-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;

	RETURN QUERY EXECUTE sql;
	--FOR rec IN EXECUTE sql LOOP
	--	RAISE WARNING 'Border % contains edges with same surface (or no surface) on both sides', rec.bid;
	--END LOOP;

	--RAISE EXCEPTION 'Not implemented yet';
END;
$_$;



--
-- Name: find_gaps(regclass, name, text); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.find_gaps(layertable regclass, layertopogeomcolumn name, sqlfilter text DEFAULT NULL::text) RETURNS TABLE(etyp integer, eid integer)
    LANGUAGE plpgsql
    AS $_$
DECLARE
	sql TEXT;
	rec RECORD;
	rec2 RECORD;
	featureFetchSQL TEXT;
	topo topology.topology;
	layer topology.layer;
	trigname TEXT;
	procName TEXT := 'topo_update.find_gaps';
	elemTypeName TEXT;
	cte TEXT;
BEGIN

	-- Fetch topology and layer info from layer references
	SELECT t topo, l layer
		FROM topology.layer l, topology.topology t, pg_class c, pg_namespace n
		WHERE l.schema_name = n.nspname
		AND l.table_name = c.relname
		AND c.oid = layerTable
		AND c.relnamespace = n.oid
		AND l.feature_column = layerTopoGeomColumn
		AND l.topology_id = t.id
		INTO rec;
	topo := rec.topo;
	layer := rec.layer;

	cte := format(
		$$
		WITH layer AS (
			SELECT %1$I tg FROM %2$s
			%3$s
		)
		$$,
		layerTopoGeomColumn,
		layerTable,
		CASE
		WHEN sqlFilter IS NULL THEN
			''
		ELSE
			format(' WHERE %s', sqlFilter)
		END
	);

	CASE layer.feature_type
	WHEN 1 THEN -- puntal
		elemTypeName := 'Node';
		sql := format(
			$$
				SELECT node_id eid
				FROM %1$I.node
			$$,
			topo.name
		);
	WHEN 2 THEN -- lineal
		elemTypeName := 'Edge';
		sql := format(
			$$
				SELECT edge_id eid
				FROM %1$I.edge
			$$,
			topo.name
		);
	WHEN 3 THEN -- areal
		elemTypeName := 'Face';
		sql := format(
			$$
				SELECT face_id eid
				FROM %1$I.face
				WHERE face_id > 0
			$$,
			topo.name
		);
	ELSE
		RAISE EXCEPTION '%: unsupported feature_type % for layer %',
			procName, layer.feature_type, layerTable;
	END CASE;

	-- Sanity check: this function does not support hierarchical layers
	IF layer.child_id IS NOT NULL THEN
		RAISE EXCEPTION '% function does not support hierarchical layers', procName;
	END IF;

	-- Exclude elements which are found in definition of
	-- TopoGeometry present in target layer
	--
	sql := format(
		$$
			%1$s
			%2$s
			EXCEPT
			SELECT DISTINCT abs(r.element_id)
			FROM %3$I.relation r, layer t
			WHERE r.element_type = $1
			AND r.layer_id = $2
			AND r.topogeo_id = id(tg)
		$$,
		cte,        -- %1
		sql,        -- %2
		topo.name  -- %3
	);
-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;


	FOR rec IN EXECUTE sql USING layer.feature_type, layer.layer_id
	LOOP
-- STRIP -- 		RAISE DEBUG '% % not covered by any TopoGeometry found in layer % (%)',
-- STRIP -- 			elemTypeName,
-- STRIP -- 			rec.eid,
-- STRIP -- 			layerTable, layerTopoGeomColumn
		etyp := layer.feature_type;
		eid := rec.eid;
		RETURN NEXT;
	END LOOP;


END;
$_$;



--
-- Name: find_interiors_intersect(regclass, name, name, text); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.find_interiors_intersect(layertable regclass, layertopogeomcolumn name, layeridcolumn name, sqlfilter text DEFAULT NULL::text) RETURNS TABLE(fid1 text, fid2 text, tgid1 integer, tgid2 integer, etyp integer, eids integer[])
    LANGUAGE plpgsql
    AS $_$
DECLARE
	sql TEXT;
	rec RECORD;
	rec2 RECORD;
	featureFetchSQL TEXT;
	topo topology.topology;
	layer topology.layer;
	trigname TEXT;
	procName TEXT := 'topo_update.find_interiors_intersect';
BEGIN

	-- Fetch topology and layer info from layer references
	SELECT t topo, l layer
		FROM topology.layer l, topology.topology t, pg_class c, pg_namespace n
		WHERE l.schema_name = n.nspname
		AND l.table_name = c.relname
		AND c.oid = layerTable
		AND c.relnamespace = n.oid
		AND l.feature_column = layerTopoGeomColumn
		AND l.topology_id = t.id
		INTO rec;
	topo := rec.topo;
	layer := rec.layer;

	-- Sanity check: this function does not support hierarchical layers
	IF layer.child_id IS NOT NULL THEN
		RAISE EXCEPTION '% function does not support hierarchical layers', procName;
	END IF;

	--
	-- Find TopoGeometry objects with common elements
	--
	sql := format(
		$$
			SELECT
				r1.topogeo_id id1,
				r2.topogeo_id id2,
				r2.element_type,
				array_agg(r2.element_id) elems
			FROM
				%1$I.relation r1,
				%1$I.relation r2
			WHERE r1.element_type = r2.element_type
			AND r1.layer_id = r2.layer_id
			AND r1.layer_id = %2$L
			AND r1.element_id = r2.element_id
			AND r1.topogeo_id < r2.topogeo_id
			GROUP BY r1.layer_id, id1, id2, r2.element_type
			ORDER BY id1, id2
		$$,
		topo.name,
		layer.layer_id
	);
-- STRIP -- 	--RAISE DEBUG 'SQL: %', sql;


	--
	-- Find TopoGeometry objects with common elements
	--
	FOR rec IN EXECUTE sql
	LOOP --{
-- STRIP -- 		RAISE DEBUG 'TopoGeoms % and % in layer % (%) share %: %',
-- STRIP -- 			rec.id1, rec.id2,
-- STRIP -- 			layerTable, layerTopoGeomColumn,
-- STRIP -- 			CASE
-- STRIP -- 			WHEN rec.element_type = 1 THEN
-- STRIP -- 				'nodes'
-- STRIP -- 			WHEN rec.element_type = 2 THEN
-- STRIP -- 				'edges'
-- STRIP -- 			WHEN rec.element_type = 3 THEN
-- STRIP -- 				'faces'
-- STRIP -- 			END,
-- STRIP -- 			array_to_string(rec.elems, ',')
-- STRIP -- 		

		--
		-- find records in layer table where TopoGeom id match
		-- the TopoGeom id of this overlapping pair ...
		--

		IF featureFetchSQL IS NULL
		THEN
			featureFetchSQL := format(
				$$
					WITH layer AS (
						SELECT * FROM %2$s
						%4$s
					)
					SELECT l1.%1$I id1, l2.%1$I id2
					FROM layer l1, layer l2
					WHERE id(l1.%3$I) = $1
					AND id(l2.%3$I) = $2
					ORDER BY id1, id2
				$$,
				layerIdColumn,
				layerTable,
				layerTopoGeomColumn,
				CASE
				WHEN sqlFilter IS NULL THEN
					''
				ELSE
					format(' WHERE %s', sqlFilter)
				END
			);
-- STRIP -- 			RAISE DEBUG 'SQL: %', sql;

		END IF;

		FOR rec2 IN EXECUTE featureFetchSQL USING rec.id1, rec.id2
		LOOP
-- STRIP -- 			RAISE DEBUG 'Features % and % in layer % (%) share %: %',
-- STRIP -- 				rec2.id1, rec2.id2,
-- STRIP -- 				layerTable, layerTopoGeomColumn,
-- STRIP -- 				CASE
-- STRIP -- 				WHEN rec.element_type = 1 THEN
-- STRIP -- 					'nodes'
-- STRIP -- 				WHEN rec.element_type = 2 THEN
-- STRIP -- 					'edges'
-- STRIP -- 				WHEN rec.element_type = 3 THEN
-- STRIP -- 					'faces'
-- STRIP -- 				END,
-- STRIP -- 				array_to_string(rec.elems, ',')
-- STRIP -- 			
			tgid1 := rec.id1;
			tgid2 := rec.id2;
			fid1 := rec2.id1;
			fid2 := rec2.id2;
			etyp := rec.element_type;
			eids := rec.elems;
			RETURN NEXT;
		END LOOP;

	END LOOP; --}

	-- Find records in layer having the same TopoGeometry
	sql := format(
		$$
			WITH layer AS (
				SELECT ctid, * FROM %2$s
				%4$s
				-- TODO: skip fids already checked in previous tests ?
			)
			SELECT
				id(l1.%3$I) tg_id,
				l1.%1$I fid1, l2.%1$I fid2
			FROM layer l1, layer l2
			WHERE l2.ctid > l1.ctid
			AND id(l1.%3$I) = id(l2.%3$I)
		$$,
		layerIdColumn,
		layerTable,
		layerTopoGeomColumn,
		CASE
		WHEN sqlFilter IS NULL THEN
			''
		ELSE
			format(' WHERE %s', sqlFilter)
		END
	);
	FOR rec IN EXECUTE sql
	LOOP
-- STRIP -- 		RAISE DEBUG 'Features % and % in layer % (%) have the same TopoGeometry %',
-- STRIP -- 			rec.fid1, rec.fid2,
-- STRIP -- 			layerTable, layerTopoGeomColumn,
-- STRIP -- 			rec.tg_id
		tgid1 := rec.tg_id;
		tgid2 := rec.tg_id;
		fid1 := rec.fid1;
		fid2 := rec.fid2;
		etyp := NULL;
		eids := NULL;
		RETURN NEXT;
	END LOOP;

	--
	-- If a layer is linear, find shared non-endpoint nodes
	--
	IF layer.feature_type = 2
	THEN
		-- Query to fetch info about non-boundary nodes
		-- shared between linel TopoGeometries in the same
		-- layer.
		--
		sql := format(
			$$
				-- Get all node ids and their count of connected
				-- edges (degree) for each border
				WITH layer AS (
					SELECT * FROM %4$s
					%5$s
				),
				feat_nodes AS (
					SELECT
						b.%1$I fid,
						b.%2$I tg,
						n.node_id nid,
						n.geom node_geom,
						ST_CollectionHomogenize(
							b.%2$I::geometry
						) feat_geom,
						count(e.edge_id) > 1 interior
					FROM
						%3$I.node n,
						%3$I.edge e,
						layer b,
						%3$I.relation r
					WHERE
						(
							n.node_id = e.start_node
							OR
							n.node_id = e.end_node
						)
						AND e.edge_id = abs(r.element_id)
						AND r.topogeo_id = id(%2$I)
						AND r.layer_id = layer_id(%2$I)
					GROUP by
						b.%1$I,
						b.%2$I,
						n.node_id
				)
				-- Get all TopoGeometry pairs sharing
				-- a node interior to either ones
				SELECT
					fn1.fid fid1,
					fn2.fid fid2,
					fn1.tg tg1,
					fn2.tg tg2,
					fn1.feat_geom feat_geom1,
					fn2.feat_geom feat_geom2,
					array_agg(fn1.nid) nids,
					array_agg(fn1.node_geom ORDER BY fn1.node_geom) ngeoms
				FROM
					feat_nodes fn1,
					feat_nodes fn2
				WHERE
					fn1.fid < fn2.fid
					AND fn1.nid = fn2.nid
					AND (
						fn1.interior
						OR
						fn2.interior
					)
				GROUP BY
					fid1, fid2, tg1, tg2, feat_geom1, feat_geom2
			$$,
			layerIdColumn,       -- %1
			layerTopoGeomColumn, -- %2
			topo.name,           -- %3
			layerTable,          -- %4
			CASE                 -- %5
			WHEN sqlFilter IS NULL THEN
				''
			ELSE
				format(' WHERE %s', sqlFilter)
			END
		);

-- STRIP -- 		--RAISE DEBUG 'sql: %', sql;


		FOR rec IN EXECUTE sql
		LOOP
			-- If there's only a single shared node check if it's
			-- the endpoint of a closed lineal topogeometry
			IF array_upper(rec.nids, 1) = 1
			THEN
				IF NOT ST_RelateMatch(
					ST_Relate(
						rec.feat_geom1,
						rec.ngeoms[1],
						2
					),
					'T********'
				)
				THEN
-- STRIP -- 					RAISE DEBUG 'Point % is on the boundary of feature 1: %',
-- STRIP -- 						ST_AsText(rec.ngeoms[1]),
-- STRIP -- 						ST_AsText(rec.feat_geom1)
-- STRIP -- 					
					-- This single shared node is on the endpoint of
					-- a closed ring in feature 1
					IF NOT ST_RelateMatch(
						ST_Relate(
							rec.feat_geom2,
							rec.ngeoms[1],
							2
						),
						'T********'
					)
					THEN
-- STRIP -- 						RAISE DEBUG 'Point % is on the boundary of feature 2: %',
-- STRIP -- 							ST_AsText(rec.ngeoms[1]),
-- STRIP -- 							ST_AsText(rec.feat_geom1)
-- STRIP -- 						
						-- This single shared node is on the endpoint of
						-- a closed ring in feature 2 as well, accepting it
						CONTINUE;
					END IF;
				END IF;
			END IF;

-- STRIP -- 			RAISE DEBUG 'Lineal features % and % in layer % (%) intersect on non-boundary node %',
-- STRIP -- 				rec.fid1, rec.fid2,
-- STRIP -- 				layerTable, layerTopoGeomColumn,
-- STRIP -- 				ST_AsEWKT(rec.ngeoms[1])
-- STRIP -- 			
			fid1 := rec.fid1;
			fid2 := rec.fid2;
			tgid1 := id(rec.tg1);
			tgid2 := id(rec.tg2);
			etyp := 1;
			eids := rec.nids;
			RETURN NEXT;
		END LOOP;

	END IF;


END;
$_$;



--
-- Name: find_surface_gaps(topology.topology, topology.layer, public.geometry); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.find_surface_gaps(topo topology.topology, surfacelayer topology.layer, bbox public.geometry DEFAULT NULL::public.geometry) RETURNS TABLE(err text, loc public.geometry)
    LANGUAGE plpgsql STABLE
    AS $_$
DECLARE
	rec RECORD;
	sql TEXT;
BEGIN
	-- Unused faces are invalid (gaps)
	sql := format(
		$$
SELECT f.face_id
FROM %1$I.face f
WHERE f.face_id != 0
AND ( $1 IS NULL OR f.mbr && $1 )
	EXCEPT
SELECT r.element_id FROM %1$I.relation r
WHERE r.layer_id = %2$L
		$$,
		topo.name,             -- %1
		surfaceLayer.layer_id  -- %2
	);

	err := 'Gap in Surface coverage';
	FOR rec iN EXECUTE sql USING bbox LOOP
		loc := ST_PointOnSurface(topology.ST_GetFaceGeometry(topo.name, rec.face_id));
		RETURN NEXT;
	END LOOP;
END;
$_$;



--
-- Name: find_surface_overlaps(topology.topology, topology.layer, public.geometry); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.find_surface_overlaps(topo topology.topology, surfacelayer topology.layer, bbox public.geometry DEFAULT NULL::public.geometry) RETURNS TABLE(err text, loc public.geometry)
    LANGUAGE plpgsql STABLE
    AS $_$
DECLARE
	rec RECORD;
	sql TEXT;
BEGIN
	-- Faces used by more than on Surface are invalid (overlaps)
	sql := format(
		$$
SELECT r.element_id face_id, count(r.topogeo_id)
FROM %1$I.relation r, %1$I.face f
WHERE r.layer_id = %2$L
AND f.face_id = r.element_id
AND ( $1 IS NULL OR f.mbr && $1 )
GROUP BY r.element_id
HAVING count(r.topogeo_id) > 1
		$$,
		topo.name,             -- %1
		surfaceLayer.layer_id  -- %2
	);

	err := 'Surface overlap';
	FOR rec iN EXECUTE sql USING bbox LOOP
		loc := ST_PointOnSurface(topology.ST_GetFaceGeometry(topo.name, rec.face_id));
		RETURN NEXT;
	END LOOP;
END;
$_$;



--
-- Name: get_border_split_info(regclass, name, name, regclass, name, name, regclass); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.get_border_split_info(surfacelayertable regclass, surfacelayergeomcolumn name, surfacelayeridcolumn name, borderlayertable regclass, borderlayergeomcolumn name, borderlayeridcolumn name, outputfrom_add_border_split_surface regclass) RETURNS TABLE(fid text, typ character, act character)
    LANGUAGE plpgsql
    AS $_$
DECLARE

	rec RECORD;
	sql text;
	topo topology.topology;
	surfaceLayer topology.layer;
	borderLayer topology.layer;

BEGIN

	-- TODO avoid using temp tables
	-- Create a temp table with last split data
	sql =  format('CREATE TEMP table old_split_border_result AS (SELECT s.fid, s.typ, s.act FROM %I s)', outputFrom_add_border_split_surface );
	EXECUTE sql;

	-- Create a temp table with new result
	DROP TABLE IF EXISTS pg_temp.temp_result_get_border_split_info;
	CREATE TEMP TABLE temp_result_get_border_split_info(fid text, typ char, act char);	
	
	-- Get info about topology
	SELECT t topo, l layer
	FROM topology.layer l, topology.topology t
	WHERE format('%I.%I', l.schema_name, l.table_name)::REGCLASS = surfaceLayerTable::REGCLASS
	AND l.feature_column = surfaceLayerGeomColumn
	AND l.topology_id = t.id
	INTO rec;

	topo := rec.topo;
	surfaceLayer := rec.layer;

	SELECT t topo, l layer
	FROM topology.layer l, topology.topology t
	WHERE format('%I.%I', l.schema_name, l.table_name)::REGCLASS = borderLayerTable::REGCLASS
	AND l.feature_column = borderLayerGeomColumn
	AND l.topology_id = t.id
	INTO rec;

	borderLayer := rec.layer;


	-- Find list of borders (T) used/touched by the changed surfaces in the input due to a split thats not already in the input list.	
	sql := format(
		$$
	CREATE TEMP TABLE result_add_used_borders AS (
		SELECT 
		DISTINCT ed_to.%8$s::TEXT AS fid
		FROM 
		%2$s fa_from,
		%1$s.relation r_from,
		%1$s.edge_data e_from,
		%1$s.relation r_to,
		%6$s ed_to,
		pg_temp.old_split_border_result tr
		WHERE tr.typ = 'S' AND fa_from.%4$I::TEXT = tr.fid AND
		(fa_from.%3$s).type = 3 AND
		(fa_from.%3$s).layer_id = %5$s AND
		(fa_from.%3$s).layer_id = r_from.layer_id AND
		(fa_from.%3$s).id = r_from.topogeo_id AND
		(r_from.element_id = e_from.right_face OR r_from.element_id = e_from.left_face) AND
		(e_from.edge_id = r_to.element_id OR e_from.edge_id = r_to.element_id) AND
		%9$s = r_to.layer_id AND
		(ed_to.%7$s).type = 2 AND
		(ed_to.%7$s).layer_id = %9$s AND
		(ed_to.%7$s).id = r_to.topogeo_id
	)
		$$,
		topo.name,
		surfaceLayerTable,
		surfaceLayerGeomColumn,
		surfaceLayerIdColumn,
		surfaceLayer.layer_id, -- 5
		borderLayerTable,
		borderLayerGeomColumn,
		borderLayerIdColumn,
		borderLayer.layer_id --9
	);
	EXECUTE sql;

	-- TODO, we may also need surfaces touhing changed surfaces
    -- Modify to add toching surface
	
	
	
	-- Find surfaces touching changed borderes
	sql := format(
		$$
	CREATE TEMP TABLE result_add_toched_affected_surfaces AS (
		SELECT 
		DISTINCT fa_from.%4$s::TEXT AS fid
		FROM 
		%2$s fa_from,
		%1$s.relation r_from,
		%1$s.edge_data e_from,
		%1$s.relation r_to,
		%6$s ed_to,
		pg_temp.old_split_border_result tr
		WHERE tr.typ = 'B' AND ed_to.%8$I::TEXT = tr.fid AND
		(fa_from.%3$s).type = 3 AND
		(fa_from.%3$s).layer_id = %5$s AND
		(fa_from.%3$s).layer_id = r_from.layer_id AND
		(fa_from.%3$s).id = r_from.topogeo_id AND
		(r_from.element_id = e_from.right_face OR r_from.element_id = e_from.left_face) AND
		(e_from.edge_id = r_to.element_id OR e_from.edge_id = r_to.element_id) AND
		%9$s = r_to.layer_id AND
		(ed_to.%7$s).type = 2 AND
		(ed_to.%7$s).layer_id = %9$s AND
		(ed_to.%7$s).id = r_to.topogeo_id
	)
		$$,
		topo.name,
		surfaceLayerTable,
		surfaceLayerGeomColumn,
		surfaceLayerIdColumn,
		surfaceLayer.layer_id, -- 5
		borderLayerTable,
		borderLayerGeomColumn,
		borderLayerIdColumn,
		borderLayer.layer_id --9
	);

	EXECUTE sql;

	-- Add list of used touched borderes
	INSERT INTO temp_result_get_border_split_info(fid,typ,act)
	SELECT s.fid, 'B', 'U' 
	FROM result_add_used_borders s 
	WHERE
    NOT EXISTS (
        SELECT 1 FROM pg_temp.old_split_border_result a WHERE a.fid = s.fid AND a.typ = 'B'
    );

	DROP TABLE IF EXISTS pg_temp.result_add_used_borders;

	-- Add surfaces touching changed borderes
	INSERT INTO temp_result_get_border_split_info(fid,typ,act)
	SELECT s.fid, 'S', 'T' 
	FROM result_add_toched_affected_surfaces s 
	WHERE
    NOT EXISTS (
        SELECT 1 FROM pg_temp.old_split_border_result a WHERE a.fid = s.fid AND a.typ = 'S'
    );
    
    DROP TABLE IF EXISTS pg_temp.result_add_toched_affected_surfaces;

    DROP TABLE IF EXISTS pg_temp.old_split_border_result;

	-- Return result
    
    RETURN QUERY SELECT s.fid, s.typ, s.act FROM temp_result_get_border_split_info s;


	

END;
$_$;



--
-- Name: get_surface_borders(topology.topology, topology.topogeometry, regclass, name, name); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.get_surface_borders(topo topology.topology, surfacetopogeom topology.topogeometry, borderlayertable regclass, borderlayertopogeomcolumn name, borderlayeridcolumn name) RETURNS TABLE(ringborders text[], signedringborders text[], ringbordergeoms public.geometry[])
    LANGUAGE plpgsql
    AS $_$
DECLARE
	cte TEXT;
	sql TEXT;
	procName TEXT := 'topo_update.get_surface_borders';
	rec RECORD;
	debug BOOLEAN := true;
	borderLayerID INT;
	surfaceGeom GEOMETRY;

BEGIN

	-- NOTE: we run this query to allow passing a view as
	--       the border table
	-- TODO: take borderLayerID as parameter
	sql := format(
		$$
			SELECT layer_id(%1$I)
			FROM %2$s
			WHERE %1$I IS NOT NULL
			LIMIT 1
		$$,
		borderLayerTopoGeomColumn,
		borderLayerTable
	);
	EXECUTE sql INTO borderLayerID;
	IF borderLayerID IS NULL THEN
		RAISE EXCEPTION 'No borders found in layer %.%', borderLayerTable, borderLayerTopoGeomColumn;
	END IF;

	-- Store list of border identifiers covering
	-- each Surface's boundary edges into a temporay
	-- sbe_borders table
	--
	-- Parameter $1 is the Surface TopoGeometry
	--
	sql := format(
		$$
			CREATE TEMPORARY TABLE
			sbe_borders AS
			-- Surface faces selection
			WITH surface_faces AS (
				SELECT topogeo_id, layer_id, array_agg(element_id) faces FROM %1$I.relation sf
				WHERE topogeo_id = id($1)
				AND element_type = 3 -- face
				AND layer_id = layer_id($1)
				GROUP BY topogeo_id, layer_id
			)
			SELECT
				b.%4$I::text border_id,
				b.%3$I border_tg,
				br.topogeo_id,
				sbe.geom sbe_geom,
				sbe.edge_id sbe_id,
				sbe.left_face = ANY (sf.faces) sbe_has_surface_on_left,
				br.element_id > 0 sbe_is_same_border_dir
			FROM
				-- surface faces
				surface_faces sf
				-- surface boundary edges
				JOIN %1$I.edge_data sbe ON (
					-- Pick only Surface boundary Borders
					(
						(
							sbe.left_face = ANY (sf.faces)
							AND NOT sbe.right_face = ANY(sf.faces)
						)
						OR
						(
							sbe.right_face = ANY (sf.faces)
							AND NOT sbe.left_face = ANY(sf.faces)
						)
					)
				)
				-- border relation
				LEFT JOIN %1$I.relation br ON (
				  br.layer_id = %5$L
				  AND br.element_id IN ( sbe.edge_id, -sbe.edge_id )
				)
				-- border table
				LEFT JOIN %2$s b ON (
					id(b.%3$I) = br.topogeo_id
--					EXISTS (
--						SELECT * FROM %1$I.relation r
--						WHERE r.layer_id = layer_id(b.%3$I)
--						AND r.topogeo_id = id(b.%3$I)
--						AND r.element_type = 2
--						AND r.element_id = sbe.edge_id
--					)
				)
		$$,
		topo.name,                 -- %1
		borderLayerTable::text,    -- %2
		borderLayerTopoGeomColumn, -- %3
		borderLayerIdColumn,       -- %4
		borderLayerID              -- %5
	);
-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;

	EXECUTE sql USING surfaceTopoGeom;

	-- DEBUG
	IF debug THEN
-- STRIP -- 		RAISE DEBUG 'Surface geom: %', ST_AsText(ST_CollectionHomogenize(surfaceTopoGeom));

-- STRIP -- 		RAISE DEBUG 'Surface boundary edges:';

		FOR rec IN SELECT * FROM sbe_borders ORDER BY sbe_id
		LOOP
-- STRIP -- 			RAISE DEBUG ' edge %', rec.sbe_id;

-- STRIP -- 			RAISE DEBUG '   geom: %', ST_AsText(rec.sbe_geom);

-- STRIP -- 			RAISE DEBUG '   covered by topogeom: %', rec.topogeo_id;

-- STRIP -- 			RAISE DEBUG '   covered by border: %', rec.border_id;

-- STRIP -- 			RAISE DEBUG '   has surface on the left ? %', rec.sbe_has_surface_on_left;

		END LOOP;
	END IF;

	-- Sanity check 0: verify that all Surface boundary edges
	-- are covered by at least one Border
	FOR rec IN
		SELECT sbe_id, sbe_geom, count(border_id)
		 FROM pg_temp.sbe_borders
		 GROUP BY sbe_id, sbe_geom
		 HAVING count(border_id) = 0
		ORDER BY sbe_id
	LOOP
		RAISE EXCEPTION 'No Border in layer %.% covers Surface boundary edge % at %',
			borderLayerTable,
			borderLayerTopoGeomColumn,
			rec.sbe_id,
			ST_AsText(
				ST_LineInterpolatePoint(
					rec.sbe_geom, 0.5
				)
			);
	END LOOP;

	-- Sanity check 1: verify that no borders share edges
	-- TODO: run the check in the same step as sanity check 0 ?
	FOR rec IN
		SELECT
			b1.border_id id1,
			b2.border_id id2,
			b1.sbe_id,
			b1.sbe_geom
		FROM
			pg_temp.sbe_borders b1,
			pg_temp.sbe_borders b2
		WHERE
			b1.border_id != b2.border_id
		AND
			b1.sbe_id = b2.sbe_id
		ORDER BY
			sbe_id

	LOOP
		RAISE EXCEPTION 'Borders % and % in layer %.% share edge % at %',
			rec.id1,
			rec.id2,
			borderLayerTable,
			borderLayerTopoGeomColumn,
			rec.sbe_id,
			ST_AsText(
				ST_LineInterpolatePoint(
					rec.sbe_geom, 0.5
				)
			);
	END LOOP;

	-- For each border in sbe_borders extract
	-- its geometry, the set of edges it covers
	-- and the side on which the surface is found
	--
	-- Store the result in a temporary surface_borders
	-- table
	--
	sql := format(
		$$
			CREATE TEMPORARY TABLE surface_borders AS
			WITH
			border_surface_coverage AS (
				SELECT
					sbeb.border_id,
					sbeb.border_tg,
					array_agg(
						sbeb.sbe_id
						ORDER BY sbeb.sbe_id
					) border_surface_edge_ids,
					array_agg(
						sbeb.sbe_geom
						ORDER BY sbeb.sbe_id
					) border_surface_edge_geoms,
					array_agg(
						sbeb.sbe_has_surface_on_left
						ORDER BY sbeb.sbe_id
					) border_surface_edge_surface_on_left
				FROM
					sbe_borders sbeb
				GROUP BY
					sbeb.border_id,
					sbeb.border_tg
			),
			border_composition AS (
				SELECT
					bsc.border_id,
					array_agg(
						abs(br.element_id)
						ORDER BY abs(br.element_id)
					) border_edge_ids,
					ST_Collect(
						CASE WHEN br.element_id = ed.edge_id THEN
							ed.geom
						ELSE
							ST_Reverse(ed.geom)
						END
						ORDER BY abs(br.element_id)
					) border_edge_geoms
				FROM
					border_surface_coverage bsc,
					%1$I.relation br,
					%1$I.edge_data ed
				WHERE
					br.topogeo_id = id(bsc.border_tg)
					AND br.layer_id = layer_id(bsc.border_tg)
					AND br.element_type = 2 -- edge
					AND ed.edge_id IN ( br.element_id, -br.element_id )
				GROUP BY bsc.border_id
			),
			border_info AS (
				SELECT
					bsc.*,
					bc.border_edge_ids,
					ST_LineMerge(
						bc.border_edge_geoms
					) as border_geom,
					ST_LineSubstring(
						ST_RemoveRepeatedPoints(
							bsc.border_surface_edge_geoms[1],
							0
						),
						0.1,
						0.2
					) as first_edge_sub,
					bsc.border_surface_edge_surface_on_left[1] as first_edge_has_surface_on_left
				FROM border_surface_coverage bsc
				JOIN border_composition bc ON (bsc.border_id = bc.border_id)
			),
			border_info_with_geomtype_multi AS (
				SELECT
					*,
					GeometryType(border_geom) LIKE 'MULTI%%' as border_geom_is_multi
				FROM border_info
			),
			border_info_with_first_edgeend_location AS (
				SELECT
					*,
					CASE WHEN border_geom_is_multi THEN
						NULL
					ELSE
						ST_LineLocatePoint(
							border_geom,
							ST_StartPoint(first_edge_sub)
						)
					END as first_edge_point1_loc,
					CASE WHEN border_geom_is_multi THEN
						NULL
					ELSE
						ST_LineLocatePoint(
							border_geom,
							ST_EndPoint(first_edge_sub)
						)
					END as first_edge_point2_loc
				FROM border_info_with_geomtype_multi
			)
			SELECT
				*,
				ST_StartPoint(border_geom) as start_point,
				ST_EndPoint(border_geom) as end_point,
				CASE WHEN
					first_edge_point1_loc < first_edge_point2_loc
				THEN
					-- border has face on the same
					-- side of the first edge composing it
					first_edge_has_surface_on_left
				ELSE
					-- border has face on the opposite
					-- side of the first edge composing it
					NOT first_edge_has_surface_on_left
				END as surface_on_left
			FROM border_info_with_first_edgeend_location
		$$,
		topo.name -- %1
	);
-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;

	EXECUTE sql;

	-- DEBUG
	IF debug THEN
-- STRIP -- 		RAISE DEBUG 'Surface boundary borders:';

		FOR rec IN
			SELECT * FROM pg_temp.surface_borders
			ORDER BY border_id
		LOOP
-- STRIP -- 			RAISE DEBUG ' Border %', rec.border_id;

-- STRIP -- 			RAISE DEBUG '   is multigeom ? %', rec.border_geom_is_multi;

-- STRIP -- 			RAISE DEBUG '   covers surface edges: %', rec.border_surface_edge_ids;

-- STRIP -- 			RAISE DEBUG '   composed by    edges: %', rec.border_edge_ids;

-- STRIP -- 			RAISE DEBUG '   starts on point: %', ST_AsText(rec.start_point);

-- STRIP -- 			RAISE DEBUG '   ends  on  point: %', ST_AsText(rec.end_point);

		END LOOP;
	END IF;

	-- Sanity check 2: verify that no borders covers more edges
	-- than the surface boundary ones
	sql := format(
		$$
			WITH extra_edges AS (
				SELECT
					border_id,
					border_surface_edge_ids,
					unnest(border_edge_ids) edge_id
				FROM pg_temp.surface_borders
					EXCEPT
				SELECT
					border_id,
					border_surface_edge_ids,
					unnest(border_surface_edge_ids) edge_id
				FROM pg_temp.surface_borders
			)
			SELECT ee.*, e.geom edge_geom
			FROM extra_edges ee, %1$I.edge_data e
			WHERE ee.edge_id = e.edge_id
		$$,
		topo.name
	);
-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;

	FOR rec IN EXECUTE sql
	LOOP
		RAISE EXCEPTION 'Border % in layer %.% covering surface boundary edges % also extends to edge % at %',
			rec.border_id,
			borderLayerTable,
			borderLayerTopoGeomColumn,
			array_to_string(rec.border_surface_edge_ids, ','),
			rec.edge_id,
			ST_AsText(
				ST_LineInterpolatePoint(
					rec.edge_geom, 0.5
				)
			)
		;
	END LOOP;

	-- Sanity check 3: verify that no borders are multi-line
	FOR rec IN
		SELECT * FROM pg_temp.surface_borders
		WHERE border_geom_is_multi
	LOOP
		RAISE EXCEPTION 'Border % in layer %.% is a multi-geometry: %',
			rec.border_id,
			borderLayerTable,
			borderLayerTopoGeomColumn,
			ST_AsText(
				rec.border_geom
			)
		;
	END LOOP;

	surfaceGeom := ST_BuildArea(ST_Collect(border_geom))
	FROM pg_temp.surface_borders;

	-- Create spatial indices?
	--CREATE INDEX ON pg_temp.surface_borders USING gist(start_point);
	--CREATE INDEX ON pg_temp.surface_borders USING gist(end_point);
	--CREATE INDEX ON pg_temp.surface_borders (ST_XMin(border_geom));
	--CREATE INDEX ON pg_temp.surface_borders (ST_YMin(border_geom));
	--CREATE INDEX ON pg_temp.surface_borders USING gist(border_geom);

	--ANALYZE pg_temp.surface_borders;

	-- Find all border rings
	FOR rec IN SELECT ST_Boundary(geom) surface_ring FROM ST_DumpRings(surfaceGeom)
	LOOP --{

-- STRIP -- 		RAISE DEBUG 'Next ring has % points', ST_NPoints(rec.surface_ring);


		-- Find next ring
		WITH RECURSIVE
		ring_covering_borders AS (
			SELECT *
			FROM pg_temp.surface_borders
			WHERE ST_Covers(rec.surface_ring, border_geom)
		),
		leftmost AS (
			SELECT
				border_id,
				border_geom,
				start_point,
				end_point
			FROM ring_covering_borders
			ORDER BY
				ST_XMin(border_geom),
				ST_YMin(border_geom),
				border_id
			LIMIT 1
		),
		ring AS (

			-- non-recursive term
			SELECT
				sb.border_id,
				sb.surface_on_left,
				sb.start_point,
				sb.end_point,
				sb.border_geom
			FROM ring_covering_borders sb, leftmost
			WHERE sb.border_id = leftmost.border_id

			UNION

			-- recursive term
			SELECT
				sb.border_id,
				sb.surface_on_left,
				sb.start_point,
				sb.end_point,
				sb.border_geom
			FROM ring_covering_borders sb, ring
			WHERE
				CASE WHEN ring.surface_on_left THEN
					-- Current border has surface on the left,
					-- so we want to travel it forward, thus
					-- finding a connection on its end_point
					CASE WHEN sb.surface_on_left THEN
						-- surface border also has surface on left side
						ring.end_point = sb.start_point
					ELSE
						-- surface border has surface on right side
						ring.end_point = sb.end_point
					END
				ELSE
					-- Current border has surface on the right,
					-- so we want to travel it backward, thus
					-- finding a connection on its start_point
					CASE WHEN sb.surface_on_left THEN
						-- surface border has surface on left side
						ring.start_point = sb.start_point
					ELSE
						-- surface border also has surface on right side
						ring.start_point = sb.end_point
					END
				END
		)
		SELECT
			array_agg(ring.border_id),
			array_agg(
				CASE WHEN ring.surface_on_left THEN
					ring.border_id
				ELSE
					'-' || ring.border_id
				END
			),
			array_agg(
				CASE WHEN ring.surface_on_left THEN
					ring.border_geom
				ELSE
					ST_Reverse(ring.border_geom)
				END
			)
		FROM ring
		INTO
			ringBorders,
			signedRingBorders,
			ringBorderGeoms
		;

		-- Exit if no more borders are found
		IF ringBorders IS NULL
		THEN
-- STRIP -- 			RAISE DEBUG '%: no more Surface rings to process', procName;

			EXIT;
		END IF;

-- STRIP -- 		RAISE DEBUG '%: next Surface ring is %', procName, signedRingBorders;


		-- Remove processed ring Borders from the temporary table
		DELETE FROM pg_temp.surface_borders
		WHERE border_id = ANY(ringBorders);

		RETURN NEXT;

	END LOOP; --}

	DROP TABLE pg_temp.surface_borders;
	DROP TABLE pg_temp.sbe_borders;
END;
$_$;



--
-- Name: insert_feature(topology.topogeometry, jsonb, regclass, name, name, jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.insert_feature(feature_topogeom topology.topogeometry, feature_properties jsonb, layertable regclass, layergeomcolumn name, layeridcolumn name, layercolmap jsonb, OUT id text) RETURNS text
    LANGUAGE plpgsql
    AS $$ -- {
DECLARE
	sql TEXT;
	colnames TEXT[];
	colvals TEXT[];
BEGIN

	SELECT c.colnames, c.colvals
	FROM topo_update.json_props_to_pg_cols(feature_properties, layerColMap) c
	INTO colnames, colvals;

-- STRIP -- 	RAISE DEBUG 'COMPUTED: colnames: %', colnames;

-- STRIP -- 	RAISE DEBUG 'COMPUTED: colvals: %', colvals;


	colnames := array_append(colnames, format('%I', layerGeomColumn));

	colvals := array_append(colvals, format('%L', feature_topogeom));

	sql := format('INSERT INTO %s (%s) VALUES(%s) RETURNING %I',
		layerTable,
		array_to_string(colnames, ','),
		array_to_string(colvals, ','),
		layerIDColumn
	);

-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;


	EXECUTE sql INTO id;

END;
$$;



--
-- Name: insert_feature(jsonb, integer, regclass, name, name, jsonb, double precision); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.insert_feature(feature jsonb, srid integer, layertable regclass, layergeomcolumn name, layeridcolumn name, layercolmap jsonb, tolerance double precision, OUT id text, OUT topogeom topology.topogeometry) RETURNS record
    LANGUAGE plpgsql
    AS $$ -- {
DECLARE
	sql TEXT;
	rec RECORD;
	geom GEOMETRY;
	props JSONB;
BEGIN

	props := feature -> 'properties';
	-- Will use the "crs" member in the GeoJSON, if any
	geom := ST_GeomFromGeoJSON(feature -> 'geometry');
-- STRIP -- 	--RAISE DEBUG 'GEOM: %', ST_AsEWKT(geom);


	-- Override SRID if given
-- STRIP -- 	RAISE DEBUG 'SRID: %', srid;

	IF srid IS NOT NULL THEN
		geom := ST_SetSRID(geom, srid);
	END IF;

	SELECT * FROM topo_update.insert_feature(
		geom,
		props,
		layerTable,
		layerGeomColumn,
		layerIDColumn,
		layerColMap,
		tolerance
	)
	INTO rec;

	id := rec.id;
	topogeom := rec.topogeom;

END;
$$;



--
-- Name: insert_feature(public.geometry, jsonb, regclass, name, name, jsonb, double precision); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.insert_feature(feature_geometry public.geometry, feature_properties jsonb, layertable regclass, layergeomcolumn name, layeridcolumn name, layercolmap jsonb, tolerance double precision, OUT id text, OUT topogeom topology.topogeometry) RETURNS record
    LANGUAGE plpgsql
    AS $$ -- {
DECLARE
	toponame TEXT;
	topo_srid INT;
	layer_id INT;
	sql TEXT;
	rec RECORD;
	procName TEXT := 'topo_update.insert_feature';
BEGIN

	-- TODO: do this one in the calling function and receive this
	--			 information pre-computed
	SELECT t.name, l.layer_id, t.srid
		FROM topology.layer l, topology.topology t, pg_class c, pg_namespace n
		WHERE l.schema_name = n.nspname
		AND l.table_name = c.relname
		AND c.oid = layerTable
		AND c.relnamespace = n.oid
		AND l.feature_column = layerGeomColumn
		AND l.topology_id = t.id
		INTO toponame, layer_id, topo_srid;

-- STRIP -- 	RAISE DEBUG '%: feature_geometry SRID: %', procName, ST_SRID(feature_geometry);

-- STRIP -- 	RAISE DEBUG '%: topo name: %', procName, toponame;

-- STRIP -- 	RAISE DEBUG '%: topo srid: %', procName, topo_srid;

-- STRIP -- 	RAISE DEBUG '%: layer_id: %', procName, layer_id;


	-- Reproject input geometry if needed
	IF ST_Srid(feature_geometry) != topo_srid
	THEN
-- STRIP -- 		RAISE DEBUG '%: feature srid (%) does not match topology srid (%), reprojecting',
-- STRIP -- 			procName,
-- STRIP -- 			ST_Srid(feature_geometry),
-- STRIP -- 			topo_srid
		feature_geometry := ST_Transform(feature_geometry, topo_srid);
	END IF;

	topogeom := topology.toTopoGeom(
		feature_geometry,
		toponame,
		layer_id,
		tolerance
	);

-- STRIP -- 	RAISE DEBUG '%: TopoGeom: % (srid: %)',
-- STRIP -- 		procName,
-- STRIP -- 		topogeom,
-- STRIP -- 		ST_SRID(topogeom)

	SELECT * FROM topo_update.insert_feature(
		topogeom,
		feature_properties,
		layerTable,
		layerGeomColumn,
		layerIDColumn,
		layerColMap
	)
	INTO id;

END;
$$;



--
-- Name: json_col_map_from_pg(regclass, text[]); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.json_col_map_from_pg(targettable regclass, excludecols text[] DEFAULT ARRAY[]::text[]) RETURNS jsonb
    LANGUAGE plpgsql STABLE
    AS $$ --{
DECLARE
	rec RECORD;
	subrec RECORD;
	map JSONB;
	maprec JSONB;
BEGIN

	map := '{}';

	<<pgkey>>
	FOR rec in
		SELECT unnest( topo_update._pg_col_names( targetTable ) ) pg_key
	LOOP
		FOR subrec IN SELECT unnest(excludeCols) x LOOP
			IF rec.pg_key = subrec.x
			   OR position(format('%s.', subrec.x) IN rec.pg_key) = 1 -- node exclude
			THEN
				CONTINUE pgkey;
			END IF;
		END LOOP;

		maprec := jsonb_build_object(rec.pg_key, string_to_array(rec.pg_key, '.'));
		map := map || maprec;
	END LOOP;

	RETURN map;
END;
$$;



--
-- Name: json_props_to_pg_cols(jsonb, jsonb, boolean); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.json_props_to_pg_cols(props jsonb, col_map jsonb, strict boolean DEFAULT false, OUT colnames text[], OUT colvals text[]) RETURNS record
    LANGUAGE plpgsql
    AS $$
DECLARE
	geom GEOMETRY;
	rec RECORD;
	nam TEXT;
	val TEXT;
	val_json JSONB;
	prop_array_json JSONB;
	prop_array TEXT[];
BEGIN

	FOR rec IN SELECT jsonb_object_keys( col_map ) k
	LOOP
		prop_array_json := col_map -> rec.k;
-- STRIP -- 		RAISE DEBUG 'prop_array_json: %', prop_array_json;


		-- Compute column value
		IF NOT jsonb_typeof(prop_array_json) = 'array' THEN
			RAISE EXCEPTION 'Invalid mapping: values should be arrays';
		END IF;

		-- TODO: improve performance of this
		prop_array := array_agg(x) from jsonb_array_elements_text( prop_array_json ) x;
-- STRIP -- 		RAISE DEBUG 'prop_array: %', prop_array;


		val_json := props #> prop_array;
		IF val_json IS NULL
		THEN
			IF strict THEN
				RAISE EXCEPTION 'Mapping file % references '
					'non-existent key % in properties object %',
					col_map, prop_array,
					props
				;
			END IF;
			CONTINUE;
		END IF;
		val := format('%L', props #>> prop_array);
		colvals := array_append(colvals, val);

		-- Compute column name
		nam = rec.k;
		IF nam LIKE '%.%' THEN
			-- Protect from SQL injection
			-- TODO: improve the checking !
			nam := regexp_replace(regexp_replace(nam, '(["\\])', '\\\1', 'g'), '([^.]+)', '"\1"', 'g');
		ELSE
			nam := format('%I', nam);
		END IF;
		colnames := array_append(colnames, nam);

	END LOOP;

	--RETURN ( colnames, colvals );
END;
$$;



--
-- Name: json_to_json_map(jsonb, jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.json_to_json_map(inp jsonb, map jsonb) RETURNS jsonb
    LANGUAGE plpgsql
    AS $$ --{
DECLARE
	ret JSONB;
	val JSONB;
	json_path TEXT[];
	rec RECORD;
	parent_path TEXT[];
	obj JSONB;
	i INT;
BEGIN

	ret := '{}'; -- start with empty object

	IF NOT jsonb_typeof( map ) = 'array' THEN
		RAISE EXCEPTION 'Invalid mapping: map should be an array';
	END IF;

	FOR rec IN SELECT jsonb_array_elements( map ) m
	LOOP

		-- Extract json value from source
		obj := rec.m -> 'from';
		IF obj IS NULL THEN
			RAISE EXCEPTION 'Invalid mapping: "from" key missing';
		END IF;
		IF NOT jsonb_typeof(obj) = 'array' THEN
			RAISE EXCEPTION 'Invalid mapping: "from" value should be array';
		END IF;
		json_path := array_agg(x) from jsonb_array_elements_text( obj ) x;
-- STRIP -- 		RAISE DEBUG 'from json_path: %', json_path;

		val := inp #> json_path;
		IF val IS NULL THEN
			RAISE EXCEPTION 'Unapplicable mapping: key % does not exist in input', json_path;
		END IF;
-- STRIP -- 		RAISE DEBUG 'value extracted from input json path: %', val;


		obj := rec.m -> 'to';
		IF obj IS NULL THEN
			RAISE EXCEPTION 'Invalid mapping: "to" key missing';
		END IF;
		IF NOT jsonb_typeof(obj) = 'array' THEN
			RAISE EXCEPTION 'Invalid mapping: "to" value should be array';
		END IF;
		json_path := array_agg(x) from jsonb_array_elements_text( obj ) x;
-- STRIP -- 		RAISE DEBUG 'to json_path: %', json_path;


		-- Ensure each element in the "to" array, other
		-- than the first, has an object in the returned
		-- JSONB for containing it
		FOR i IN 2..array_upper(json_path, 1)
		LOOP
			parent_path = json_path[1:i-1];
			obj = ret #> parent_path;
			IF obj IS NULL
			THEN
				ret := jsonb_set(ret, parent_path, '{}');
			ELSIF NOT jsonb_typeof(obj) = 'object'
			THEN
				RAISE EXCEPTION 'Invalid mapping: path in "to" exists as both object and non-object';
			END IF;
		END LOOP;

		-- Assign the value to the target
		ret := jsonb_set(ret, json_path, val);

	END LOOP;

	RETURN ret;
END;
$$;



--
-- Name: min_transformed_tolerance(public.geometry, double precision, integer); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.min_transformed_tolerance(location public.geometry, tolerance double precision, target_srid integer) RETURNS double precision
    LANGUAGE plpgsql
    AS $$ --{
DECLARE
	hull_input GEOMETRY;
	buff_hull_input GEOMETRY;
	trans_hull_input GEOMETRY;
	trans_buff_hull_input GEOMETRY;
BEGIN

	-- Short cut, if target srid == source srid, return
	-- the input tolerance
	IF ST_Srid(location) = target_srid THEN
		RETURN tolerance;
	END IF;

	-- Algorithm:
	--  1. Take the convex hull of the location
	--  2. Buffer the convex hull with the given
	--     tolerance.
	--  3. Transform both the hull and the buffer
	--     to target SRID
	--  4. Compute min distance between the
	--     facets of the transformed input
	--     and the facets of the transformed
	--     buffered input

	hull_input := ST_ConvexHull(location);
-- STRIP -- 	RAISE DEBUG 'Input hull: %', ST_AsText(hull_input);


	buff_hull_input := ST_ExteriorRing(
		ST_Buffer(
			hull_input,
			tolerance
		)
	);
-- STRIP -- 	RAISE DEBUG 'Buf input hull: %', ST_AsText(buff_hull_input);


	trans_hull_input := ST_Transform(
		hull_input,
		target_srid
	);
-- STRIP -- 	RAISE DEBUG 'Trans input hull: %', ST_AsText(trans_hull_input);


	IF ST_Dimension(trans_hull_input) > 1 THEN
		trans_hull_input := ST_ExteriorRing(
			trans_hull_input
		);
-- STRIP -- 		RAISE DEBUG 'Trans input hull exterior ring: %', ST_AsText(trans_hull_input);

	END IF;

	trans_buff_hull_input := ST_Transform(
		buff_hull_input,
		target_srid
	);
-- STRIP -- 	RAISE DEBUG 'Trans buf input hull: %', ST_AsText(trans_buff_hull_input);


	RETURN ST_Distance(
		trans_hull_input,
		trans_buff_hull_input
	);
END;
$$;



--
-- Name: prepare_split_border(public.geometry, text); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.prepare_split_border(line public.geometry, toponame text) RETURNS public.geometry
    LANGUAGE sql
    AS $_$
	SELECT topo_update.prepare_split_border(
		$1,
		(select t from topology.topology t WHERE name = $2)
	);
$_$;



--
-- Name: prepare_split_border(public.geometry, topology.topology, double precision); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.prepare_split_border(line public.geometry, topo topology.topology, tolerance double precision DEFAULT 0) RETURNS public.geometry
    LANGUAGE plpgsql
    AS $$ --{
DECLARE
	sql TEXT;
	num_edge_intersects INT;
	proc_name text = 'topo_update._prepare_split_border';
	input_line GEOMETRY =  line;
	closed_line GEOMETRY;
BEGIN

	IF NOT ST_IsSimple(line) THEN
		-- Non-simple line means there's a self-intersection.
		-- In this case we try to build a closed ring out of it,
		-- dropping loosing ends as we go.
		BEGIN
			closed_line := ST_BuildArea(ST_UnaryUnion(line))::geometry;
-- STRIP -- 			RAISE DEBUG '%: ST_BuildArea result is %',
-- STRIP -- 				proc_name, ST_AsEWKT(closed_line)
			IF closed_line IS NOT NULL THEN
				closed_line := ST_ExteriorRing(closed_line);
-- STRIP -- 				RAISE DEBUG '%: ST_ExteriorRing result is %',
-- STRIP -- 					proc_name, ST_AsEWKT(closed_line)
				line := closed_line;
			END IF;
		EXCEPTION WHEN others THEN
			RAISE EXCEPTION '%: BuildArea failed on non-simple input: % -> %',
				proc_name, ST_AsEWKT(input_line,13), SQLERRM;
		END;
	END IF;



	IF NOT ST_IsClosed(line) THEN
		-- If input line is not closed, split it by existing edges
		-- and pick all non-dangling components
		--
		-- Bail out if there are no non-dangling components
		--
		line := topo_update._select_split_component(
			line,
			topo,
			false, -- keep all components
			tolerance
		);

-- STRIP -- 		RAISE DEBUG '%: split components are %', proc_name, ST_AsText(line);


		IF line IS NULL THEN
			RAISE EXCEPTION 'Non closed linestring does not intersect at least twice with existing edges for input: % -> inputline: %, topo: %, tolerance: %',
				proc_name, ST_AsEWKT(input_line,13), topo.name, tolerance;
		END IF;
	END IF;

	RETURN line;
END; --}
$$;



--
-- Name: record_to_jsonb(anyelement, jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.record_to_jsonb(pgrec anyelement, col_map jsonb) RETURNS jsonb
    LANGUAGE plpgsql
    AS $$ -- }{
DECLARE
	ret JSONB;
	auto_json JSONB;
	k TEXT;
	v JSONB;
	rec RECORD;
	map_json_path JSONB;
	json_path TEXT[];
	parent_path TEXT[];
	obj JSONB;
	i INT;
	procName TEXT := 'topo_update.record_to_jsonb';
BEGIN

	auto_json := to_jsonb(pgrec);

-- STRIP -- 	RAISE DEBUG '%: REC(json): %', procName, auto_json;


	ret := '{}'; -- start with empty object

	FOR k IN SELECT jsonb_object_keys( col_map )
	LOOP
		map_json_path = col_map -> k;
-- STRIP -- 		RAISE DEBUG '%: K: % -- P: %', procName, k, map_json_path;


		json_path := array_agg(x) from jsonb_array_elements_text( map_json_path ) x;
-- STRIP -- 		RAISE DEBUG '%: json_path: %', procName, json_path;


		v := auto_json #> string_to_array(k, '.');
-- STRIP -- 		RAISE DEBUG '%: V from K: %', procName, v;


		IF v IS NULL THEN
			CONTINUE;
		END IF;

		-- Ensure each element in the "to" array, other
		-- than the first, has an object in the returned
		-- JSONB for containing it
		FOR i IN 2..array_upper(json_path, 1)
		LOOP
			parent_path := json_path[1:i-1];
			obj := ret #> parent_path;
			IF obj IS NULL
			THEN
				ret := jsonb_set(ret, parent_path, '{}');
			ELSIF NOT jsonb_typeof(obj) = 'object'
			THEN
				RAISE EXCEPTION 'Invalid mapping: json path exists as both object and simple value';
			END IF;
		END LOOP;

		-- Assign the value to the target
		ret := jsonb_set(
			ret,
			json_path,
			auto_json #> string_to_array(k, '.')
		);

-- STRIP -- 		--RAISE DEBUG '%: RET: %', procName, ret;


	END LOOP;
	RETURN ret;
END;
$$;



--
-- Name: remove_border_merge_surfaces(regclass, name, name, text, regclass, name, name, regproc, anyelement, boolean, boolean); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.remove_border_merge_surfaces(borderlayertable regclass, borderlayergeomcolumn name, borderlayeridcolumn name, borderid text, surfacelayertable regclass, surfacelayergeomcolumn name, surfacelayeridcolumn name, mergepolicyproviderfunc regproc, mergepolicyproviderparam anyelement, removeprimitives boolean DEFAULT false, removedanglingborders boolean DEFAULT false) RETURNS TABLE(fid text, typ character, act character, frm text[])
    LANGUAGE plpgsql
    AS $_$ --}{
DECLARE
	topo topology.topology;
	borderLayer topology.layer;
	surfaceLayer topology.layer;
	sql TEXT;
	rec RECORD;
	rec2 RECORD;
	borderTopoGeom topology.TopoGeometry;
	surfaceLeftId int;
	surfaceRightId int;
	surfaceLeftTopoGeom topology.TopoGeometry;
	surfaceRightTopoGeom topology.TopoGeometry;
	surfaceLeftKey TEXT;
	surfaceRightKey TEXT;
	surfaceLeftProps JSONB;
	surfaceRightProps JSONB;

	surfaceLayerColMap JSONB;
	mergedSurfaceProps JSONB;
	mergedSurfaceTopoGeom topology.TopoGeometry;
	tmpInt int;
	borderEdges int[];
	borderEdgeEndNodes int[];
	linkedEdges int[];

	procName TEXT := 'topo_update.remove_border_merge_surfaces';

BEGIN
	-- Fetch topology and layer info from border layer references
	SELECT t topo, l layer
		FROM topology.layer l, topology.topology t, pg_class c, pg_namespace n
		WHERE l.schema_name = n.nspname
		AND l.table_name = c.relname
		AND c.oid = borderLayerTable
		AND c.relnamespace = n.oid
		AND l.feature_column = borderLayerGeomColumn
		AND l.topology_id = t.id
		INTO rec;
	topo := rec.topo;
	borderLayer := rec.layer;

	-- Fetch topology and layer info from surface layer references
	SELECT t topo, l layer
		FROM topology.layer l, topology.topology t, pg_class c, pg_namespace n
		WHERE l.schema_name = n.nspname
		AND l.table_name = c.relname
		AND c.oid = surfaceLayerTable
		AND c.relnamespace = n.oid
		AND l.feature_column = surfaceLayerGeomColumn
		AND l.topology_id = t.id
		INTO rec;

	IF id(topo) != id(rec.topo) THEN
		RAISE EXCEPTION 'Surface and Border layers need to be in same topology';
	END IF;
	surfaceLayer := rec.layer;

	-- Fetch border
	sql := format(
		'SELECT %1$I tg FROM %2$s WHERE %3$I = %4$L',
		borderLayerGeomColumn,
		borderLayerTable,
		borderLayerIdColumn,
		borderId
	);
-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;

	EXECUTE sql
	INTO rec;

	IF rec IS NULL THEN
		RAISE EXCEPTION 'No Border with id % in table %', borderId, borderLayerTable;
	END IF;

	borderTopoGeom := rec.tg;

-- STRIP -- 	RAISE DEBUG 'Border % retrieved: %', borderId, borderTopoGeom;


	-- For each edge composing the border, find the surfaces covering
	-- the face on each side, and keep note of them.
	sql := format($$
		SELECT
			e.edge_id,
			e.start_node,
			e.end_node,
			r.element_id,
			e.left_face,
			e.right_face
		FROM %1$I.edge e, %1$I.relation r
		WHERE e.edge_id in (r.element_id, -r.element_id)
		AND r.layer_id = %2$L
		AND r.topogeo_id = $1
		AND r.element_type = 2
	$$, topo.name, borderLayer.layer_id);
-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;

	FOR rec IN EXECUTE sql USING borderTopoGeom.id
	LOOP --{
-- STRIP -- 		RAISE DEBUG 'Border % includes edge % having face % on the left and % on the right', borderId, rec.element_id, rec.left_face, rec.right_face;


		borderEdges := array_append(borderEdges, rec.edge_id);
		borderEdgeEndNodes := borderEdgeEndNodes || ARRAY[rec.start_node, rec.end_node];

		-- Swap left/right if edge_id was negated
		IF rec.element_id < 0 THEN
			tmpInt := rec.left_face;
			rec.left_face := rec.right_face;
			rec.right_face := tmpInt;
		END IF;
-- STRIP -- 		RAISE DEBUG 'Border % has face % on the left and % on the right', borderId, rec.left_face, rec.right_face;



		sql := format($$
			SELECT r.topogeo_id, r.element_id
			FROM %1$I.relation r
			WHERE r.layer_id = %2$L
			AND r.element_type = 3
			AND r.element_id IN ( %3$L, %4$L )
		$$, topo.name, surfaceLayer.layer_id,
			rec.left_face, rec.right_face );
-- STRIP -- 		RAISE DEBUG 'SQL: %', sql;

		FOR rec2 IN EXECUTE sql LOOP --{

			IF rec.left_face = rec2.element_id
			THEN --{
				-- Found one Surface on the left of the edge
-- STRIP -- 				RAISE DEBUG 'Border % at edge % has Surface % on the left', borderId, rec.edge_id, rec2.topogeo_id;

				IF surfaceLeftId IS NULL THEN
					surfaceLeftId := rec2.topogeo_id;
				ELSIF surfaceLeftId != rec2.topogeo_id THEN
					RAISE EXCEPTION
						'Border % at edge % has Surface % on the left but '
						'was previously found to have Surface % on the left',
						borderId, rec.edge_id, rec2.topogeo_id, surfaceLeftId;
				END IF;
			END IF; --}
			IF rec.right_face = rec2.element_id
			THEN --{
				-- Found one Surface on the right of the edge
-- STRIP -- 				RAISE DEBUG 'Border % at edge % has Surface % on the right', borderId, rec.edge_id, rec2.topogeo_id;

				IF surfaceRightId IS NULL THEN
					surfaceRightId := rec2.topogeo_id;
				ELSIF surfaceRightId != rec2.topogeo_id THEN
					RAISE EXCEPTION
						'Border % at edge % has Surface % on the right but '
						'was previously found to have Surface % on the right',
						borderId, rec.edge_id, rec2.topogeo_id, surfaceRightId;
				END IF;
			END IF; --}

		END LOOP; --} Loop over Surfaces composed by given (left/right) faces

	END LOOP; --} Loop over edges composing given Border

	RAISE NOTICE 'Border % has Surfaces % on the left and % on the right', borderId, surfaceLeftId, surfaceRightId;

	IF ( surfaceLeftId IS NULL ) != ( surfaceRightId IS NULL )
	THEN
		RAISE EXCEPTION
			'Only one Surface found defined by faces on either sides'
			' of edge %, included in definition of Border %'
			' (must be a peripherical Border which we cannot remove)',
			rec.edge_id, borderId;
	END IF;

	IF surfaceLeftId != surfaceRightId
	THEN --{

		-- find the surface identifiers and pass them to the policy callback
		sql := format(
			$$
				SELECT
					id(%2$I) i,
					r.%1$I k,
					r.%2$I g,
					to_jsonb(r) - %1$L - %2$L p
				FROM %3$s r
				WHERE id(%2$I) IN ( %4$L, %5$L )
			$$,
			surfaceLayerIdColumn, -- %1
			surfaceLayerGeomColumn, -- %2
			surfaceLayerTable, -- %3
			surfaceLeftId, -- %4
			surfaceRightId -- %5
		);
-- STRIP -- 		RAISE DEBUG 'SQL: %', sql;

		FOR rec IN EXECUTE sql
		LOOP
			IF rec.i = surfaceLeftId THEN
				surfaceLeftTopoGeom := rec.g;
				surfaceLeftKey := rec.k;
				surfaceLeftProps := rec.p;
			ELSE
				surfaceRightTopoGeom := rec.g;
				surfaceRightKey := rec.k;
				surfaceRightProps := rec.p;
			END IF;
		END LOOP;

-- STRIP -- 		RAISE DEBUG 'Border % has Surfaces % on the left and % on the right',
-- STRIP -- 			borderId,
-- STRIP -- 			surfaceLeftKey,
-- STRIP -- 			surfaceRightKey

-- STRIP -- 		RAISE DEBUG ' Properties of Left Surface: %', surfaceLeftProps;

-- STRIP -- 		RAISE DEBUG ' Properties of Right Surface: %', surfaceRightProps;


		-- Now pass surfaces and properties to the callback to return
		-- the properties of the new surface
		sql := format(
			$$
				SELECT * FROM %1$s(
					surfaceLeftId => %2$L,
					surfaceLeftTopoGeom => %3$L,
					surfaceLeftProps => %4$L,
					surfaceRightId => %5$L,
					surfaceRightTopoGeom => %6$L,
					surfaceRightProps => %7$L,
					usr => $1
				)
			$$,
			mergePolicyProviderFunc, -- %1
			surfaceLeftKey,          -- %2
			surfaceLeftTopoGeom,     -- %3
			surfaceLeftProps,        -- %4
			surfaceRightKey,         -- %5
			surfaceRightTopoGeom,    -- %6
			surfaceRightProps        -- %7
		);
-- STRIP -- 		RAISE DEBUG 'SQL: %', sql;

		EXECUTE sql
			USING mergePolicyProviderParam
			INTO mergedSurfaceProps;
		IF mergedSurfaceProps IS NULL
		THEN
-- STRIP -- 			RAISE DEBUG '%: mergePolicyProviderFunc returned NULL, not merging our surfaces', procName;

			RETURN;
		END IF;

-- STRIP -- 		RAISE DEBUG 'mergePolicyProviderFunc returned %', mergedSurfaceProps;


		-- Create a merged Surface TopoGeometry
		mergedSurfaceTopoGeom := topology.CreateTopoGeom(
			topo.name,
			3, -- area
			surfaceLayer.layer_id
		);
		mergedSurfaceTopoGeom := topology.TopoGeom_addTopoGeom(
			mergedSurfaceTopoGeom,
			surfaceLeftTopoGeom
		);
		mergedSurfaceTopoGeom := topology.TopoGeom_addTopoGeom(
			mergedSurfaceTopoGeom,
			surfaceRightTopoGeom
		);

-- STRIP -- 		RAISE DEBUG 'surfaceLeft TopoGeom: % -- area %', surfaceLeftTopoGeom, ST_Area(surfaceLeftTopoGeom);

-- STRIP -- 		RAISE DEBUG 'surfaceRight TopoGeom: % -- area %', surfaceRightTopoGeom, ST_Area(surfaceRightTopoGeom);

-- STRIP -- 		RAISE DEBUG 'MergedSurface TopoGeom: % -- area %', mergedSurfaceTopoGeom, ST_Area(mergedSurfaceTopoGeom);


		-- TODO: fetch from mergePolicy function ?
		surfaceLayerColMap := topo_update.json_col_map_from_pg(
			surfaceLayerTable,
			ARRAY[
				surfaceLayerGeomColumn::text
			]
		);
-- STRIP -- 		RAISE DEBUG 'surfaceLayerColMap: %', surfaceLayerColMap;


		-- Insert the new TopoGeometry
		fid := topo_update.insert_feature(
			mergedSurfaceTopoGeom,
			mergedSurfaceProps,
			surfaceLayerTable,
			surfaceLayerGeomColumn,
			surfaceLayerIdColumn,
			surfaceLayerColMap
		);
-- STRIP -- 		RAISE DEBUG 'Merge Surface % inserted', fid;

		typ := 'S';
		act := 'C';
		frm := ARRAY[surfaceLeftKey, surfaceRightKey];


		RETURN NEXT;

		-- Delete the two surface records
		sql := format(
			$$
				DELETE FROM %1$s WHERE %2$I IN (%3$L, %4$L)
				RETURNING %2$I as id
			$$,
			surfaceLayerTable,
			surfaceLayerIdColumn,
			surfaceLeftKey,
			surfaceRightKey
		);
-- STRIP -- 		RAISE DEBUG 'SQL: %', sql;

		FOR REC IN EXECUTE sql
		LOOP
			fid := rec.id;
			typ := 'S';
			act := 'D';
			frm := NULL;
			RETURN NEXT;
		END LOOP;

		-- Clear the two Surface object TopoGeometries
		PERFORM topology.clearTopoGeom(surfaceLeftTopoGeom);
		PERFORM topology.clearTopoGeom(surfaceRightTopoGeom);

-- STRIP -- 		RAISE DEBUG 'Old Surface objects % and % deleted and cleared',
-- STRIP -- 			surfaceLeftKey, surfaceRightKey

	END IF; --}

	-- Delete the border record
	sql := format(
		$$
			DELETE FROM %1$s WHERE %2$I = %3$L
		$$,
		borderLayerTable,
		borderLayerIdColumn,
		borderId
	);
-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;

	EXECUTE sql;
	fid := borderId;
	typ := 'B';
	act := 'D';
	frm := NULL;
	RETURN NEXT;

	-- Clear the Border object TopoGeometry
	PERFORM topology.clearTopoGeom(borderTopoGeom);

-- STRIP -- 	RAISE DEBUG 'Border object % deleted and cleared', borderId;


	-- Remove primitives, if requested
	IF removePrimitives THEN

		-- Remove edges used by the removed borderTopoGeom
-- STRIP -- 		RAISE DEBUG 'Removing border edges: %', borderEdges;

		FOR rec IN SELECT unnest(borderEdges) edge_id
		LOOP
			PERFORM topology.ST_RemEdgeModFace(topo.name, rec.edge_id);
		END LOOP;

		-- Remove removed edges' nodes which left isolated
		sql := format(
			$$
				SELECT n.node_id FROM %1$I.node n
				WHERE n.containing_face IS NOT NULL
				AND n.node_id = ANY ($1) -- $1 == borderEdgeEndNodes
			$$,
			topo.name
		);
-- STRIP -- 		RAISE DEBUG 'SQL: %', sql;

		FOR rec IN EXECUTE sql USING borderEdgeEndNodes
		LOOP
			PERFORM topology.ST_RemIsoNode(topo.name, rec.node_id);
		END LOOP;
	END IF;


	-- Remove dangling requested
	IF removeDanglingBorders THEN --{

		-- Find any dangling border defined by linked
		-- edges and remove them too
		sql := format(
			$$
				WITH dangling_edges AS (
					SELECT
					  rb.topogeo_id tgid,
					  e.edge_id eid,
					  e.left_face fl,
					  e.right_face fr,
					  rsl.topogeo_id sl,
					  rsr.topogeo_id sr
					FROM %1$I.relation rb -- relation for border
					JOIN %1$I.edge_data e
						ON ( e.edge_id in ( rb.element_id, -rb.element_id ) )
					LEFT JOIN %1$I.relation rsl -- relation for surface on the left
						ON ( rsl.layer_id = %2$L AND rsl.element_id = e.left_face )
					LEFT OUTER JOIN %1$I.relation rsr -- relation for surface on the right
						ON ( rsr.layer_id = %2$L AND rsr.element_id = e.right_face )
					WHERE rb.layer_id = %3$L
					AND rsl.topogeo_id IS NOT DISTINCT FROM rsr.topogeo_id
					AND rsl.topogeo_id = %4$L
				)
				SELECT %5$I bid
				FROM %6$s
				WHERE id(%7$I) IN (
					SELECT tgid FROM dangling_edges
				)
			$$,
			topo.name,                 -- %1
			surfaceLayer.layer_id,     -- %2
			borderLayer.layer_id,      -- %3
			-- Surface covering the space previously occupied
			-- by the removed border, which is either a new
			-- merged surface or (if the border was dangling)
			-- the Surface which was on both of its sides
			-- %4
			COALESCE(
				id(mergedSurfaceTopoGeom),
				surfaceLeftId
			),
			borderLayerIdColumn,       -- %5
			borderLayerTable,          -- %6
			borderLayerGeomColumn      -- %7
		);
-- STRIP -- 		RAISE DEBUG 'SQL: %', sql;

		FOR rec IN EXECUTE sql LOOP --{
-- STRIP -- 			RAISE DEBUG 'Found dangling border %', rec.bid;

			-- Recurse
			RETURN QUERY SELECT * FROM topo_update.remove_border_merge_surfaces(
				borderLayerTable,
				borderLayerGeomColumn,
				borderLayerIdColumn,
				rec.bid::text,
				surfaceLayerTable,
				surfaceLayerGeomColumn,
				surfaceLayerIdColumn,
				-- TODO: pass an function that would error out here,
				-- sinc we don't expect any further merge to occur ?
				mergePolicyProviderFunc,
				mergePolicyProviderParam,
				removePrimitives,
				removeDanglingBorders => false -- not needed recursively
			);
		END LOOP; --}


		-- TODO: remove isolated nodes if no surface was merged

	END IF; --}



END;
$_$;



--
-- Name: split_multiedge_borders(regclass, name, name, public.geometry); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.split_multiedge_borders(borderlayertable regclass, borderlayergeomcolumn name, borderlayeridcolumn name, bbox public.geometry DEFAULT NULL::public.geometry) RETURNS TABLE(bid text, act character, frm text)
    LANGUAGE plpgsql
    AS $_$
DECLARE
	rec RECORD;
	rec2 RECORD;
	sql TEXT;
	topo topology.topology;
	borderLayer topology.layer;
	newBorder topology.topogeometry;
	colMapForNewBorder JSONB;
	newBorderId text;
	oldBorderProps JSONB;
	newBorderProps JSONB;
BEGIN

	borderLayer := topology.findLayer(borderLayerTable, borderLayerGeomColumn);
	IF borderLayer IS NULL THEN
		RAISE EXCEPTION '%.% is not registered in topology.layer', borderLayerTable, borderLayerGeomColumn;
	END IF;

	topo := topology.findTopology(borderLayer.topology_id);
	IF topo IS NULL THEN
		RAISE EXCEPTION 'Border layer topology id % is not registered in topology.topology', borderLayer.topology_id;
	END IF;

	colMapForNewBorder := topo_update.json_col_map_from_pg(
		borderLayerTable,
		ARRAY[
			borderLayerIdColumn,
			borderLayerGeomColumn
		]
	);
-- STRIP -- 	RAISE DEBUG 'map for new border: %', jsonb_pretty(colMapForNewBorder);


	sql := format(
		$$
SELECT
	b.%5$I id,
	b.%3$I tg,
	to_jsonb(b) props,
	array_agg(r.element_id ORDER BY abs(r.element_id)) edges
FROM
	%1$I.relation r, %2$s b
WHERE r.layer_id = %4$L
AND r.topogeo_id = id(%3$I)
AND ( $1 IS NULL OR %3$I && $1 ) -- spatial filter, TODO: optimize
GROUP BY 1,2,3
HAVING count(r.element_id) > 1
		$$,
		topo.name,              -- %1
		borderLayerTable,       -- %2
		borderLayerGeomColumn,  -- %3
		borderLayer.layer_id,   -- %4
		borderLayerIdColumn     -- %5
	);
-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;

	FOR rec IN EXECUTE sql USING ( bbox )
	LOOP --{
-- STRIP -- 		RAISE DEBUG 'Will split Border % into % parts', rec.id, array_upper(rec.edges, 1);


		-- delete all components but first

		bid := rec.id;
		act := 'M';
		frm := null;
		RETURN NEXT;

		sql := format(
			$$
	DELETE FROM %1$I.relation
	WHERE layer_id = %2$L
	AND topogeo_id = %3$L
	AND element_id != %4$L
	RETURNING element_id
			$$,
			topo.name,
			borderLayer.layer_id,
			id(rec.tg),
			rec.edges[1]
		);

		FOR rec2 IN EXECUTE sql
		LOOP --{
			newBorder := topology.CreateTopoGeom(
				topo.name,
				2, -- lineal
				borderLayer.layer_id,
				topology.TopoElementArray_agg(ARRAY[rec2.element_id,2])
			)
			;
-- STRIP -- 			--RAISE DEBUG 'newBorder: %', newBorder;


			newBorderId := topo_update.insert_feature(
				newBorder,
				rec.props,
				borderLayerTable,
				borderLayerGeomColumn,
				borderLayerIdColumn,
				colMapForNewBorder
			);

			bid := newBorderId;
			act := 'C';
			frm := rec.id;
			RETURN NEXT;
		END LOOP; --}
	END LOOP; --}

END;
$_$;



--
-- Name: split_paths(jsonb, regclass, name, name, regproc, anyelement, double precision, integer); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.split_paths(feature jsonb, pathlayertable regclass, pathlayergeomcolumn name, pathlayeridcolumn name, colmapproviderfunc regproc, colmapproviderparam anyelement, tolerance double precision DEFAULT 0.0, maxsplits integer DEFAULT 0) RETURNS TABLE(fid text, act character, frm text)
    LANGUAGE plpgsql
    AS $_$
DECLARE

	rec RECORD;
	rec2 RECORD;

	featureGeom JSONB;

	payloadProps JSONB;

	newPath topology.topogeometry;
	modPathGeom GEOMETRY;
	newPathId text;
	oldPathProps JSONB;
	newPathProps JSONB;

	-- holds dynamic sql
	sql text;

	proc_name text = 'topo_update.split_paths';

	inputLine GEOMETRY;
	overlapPoints GEOMETRY;

	topo topology.topology;

	candidateInputLines GEOMETRY;
	dropInputLines INT[];

	inputLineEdgeIds INT[];
	inputLineNodeIds INT[];

	inputLineIsolatedNodeIds INT[];

	pathLayer topology.layer;

	-- Holds dynamic sql to execute
	-- by passing $1=colMapProviderParam,
	-- $2=act to extract the
	-- appropriate column mapping
	colMapExtractSQL TEXT;

	-- Column mapping file for modified paths
	-- as provided by colMapProvider
	colMapForModPath JSONB;

	-- Column mapping file for paths
	-- as provided by colMapProvider
	colMapForNewPath JSONB;

	-- Column mapping file for paths
	-- replacing space previously covered
	-- by existing paths as provided by
	-- colMapProvider
	colMapForSplitPath JSONB;

	-- Column mapping file for split paths
	-- inheriting attributes from existing Path
	inhSplitPathColMap JSONB;

	-- Path as split by incoming line
	splitPathGeom GEOMETRY;
	splitPathGeomComp GEOMETRY;
	splitPathStartPoint GEOMETRY;
	splitPathStartPointNodeDegree INT;
	splitPathMergeOnStartPoint BOOLEAN;

	-- Number of elements a path was split into
	splitPathCount INT;

	totalSplitsCount INT := 0;

	i INT;

	tea topology.TopoElementArray;

BEGIN

	-- Fetch topology and layer info from path layer references
	SELECT t topo, l layer
		FROM topology.layer l, topology.topology t, pg_class c, pg_namespace n
		WHERE l.schema_name = n.nspname
		AND l.table_name = c.relname
		AND c.oid = pathLayerTable
		AND c.relnamespace = n.oid
		AND l.feature_column = pathLayerGeomColumn
		AND l.topology_id = t.id
	--	FOR UPDATE, 2 problems, user needs SUPERUSER (can be fixed),
	--  ms used from 8601 -> 113606 for ((14.355156130507279 67.27980828078813, 14.354976710179235 67.28648792270606, 14.395077865039152 67.28664388346324, 14.395246132501715 67.27996419068565, 14.355156130507279 67.27980828078813))
		INTO rec;
	topo := rec.topo;
	pathLayer := rec.layer;

	--	RAISE NOTICE 'Lock on topology % obtained', topo.name;

	featureGeom = feature->'geometry';
	IF featureGeom IS NULL
	THEN
		RAISE EXCEPTION 'Input feature lacks a "geometry" element: %',
			feature;
	END IF;

	IF NOT featureGeom ? 'crs'
	THEN
		RAISE EXCEPTION 'Input feature geometry lacks a "crs" element: %',
			featureGeom;
	END IF;

	-- Read input line geometry from GeoJSON
	inputLine := ST_GeomFromGeoJSON(featureGeom);

	IF NOT ST_GeometryType(inputLine) IN ( 'ST_MultiLineString', 'ST_LineString' )
	THEN
		RAISE EXCEPTION '%: input geometry must be either LineString or MultiLineString, is % instead',
			proc_name, ST_GeometryType(inputLine);
	END IF;

	IF topo.srid != ST_Srid(inputLine) THEN
		inputLine := ST_Transform(inputLine, topo.srid);
-- STRIP -- 		--RAISE DEBUG 'REPROJECTED GEOM: %', ST_AsEWKT(geom);

	END IF;

-- STRIP -- 	RAISE DEBUG 'Input line: %', ST_AsText(inputLine);


	-- Write SQL to extract colMaps
	-- $1: usr
	-- $2: act
	colMapExtractSQL := format(
		'SELECT * FROM %s(usr => $1, act => $2)',
		colMapProviderFunc
	);

	payloadProps := feature -> 'properties';

	candidateInputLines := ST_ForceCollection(inputLine);

	-- Insert the inputLine to the topology
	-- and gather list of edges forming it
	SELECT array_agg(DISTINCT abs(e))
	FROM ST_Dump(candidateInputLines) d,
	LATERAL topology.TopoGeo_addLineString(
			topo.name,
			d.geom,
			tolerance
		) e
	INTO inputLineEdgeIds;
-- STRIP -- 	RAISE DEBUG '%: input line edges: %',
-- STRIP -- 		proc_name, array_to_string(inputLineEdgeIds, ',')

	-- Remove any edge already used by existing paths
	-- from the the list of edges forming the new line
	sql := format(
		$$
SELECT array_agg(x)
FROM (
	SELECT x FROM (
		SELECT unnest($1) x
	) foo
	WHERE abs(x) NOT IN (
		SELECT abs(element_id)
		FROM %1$I.relation
		WHERE layer_id = %2$L
		AND element_type = 2 -- edge
	)
) foo
		$$,
		topo.name,           -- %1
		pathLayer.layer_id -- %2
	);
-- STRIP -- 	RAISE DEBUG '%: sql: %', proc_name, sql;

	EXECUTE sql
	USING inputLineEdgeIds
	INTO inputLineEdgeIds;

	IF inputLineEdgeIds IS NULL
	THEN
		RAISE EXCEPTION 'Input geometry does not cross any Path';
	END IF;

-- STRIP -- 	RAISE DEBUG '%: input line edges not already used by existing paths: %',
-- STRIP -- 		proc_name, array_to_string(inputLineEdgeIds, ',')

-- STRIP -- 	RAISE DEBUG '%: nodes collecting phase start', proc_name;


	-- Collect all nodes covered by the inputLineEdgeIds
	-- Param $1 is the input line edge ids
	sql := format(
		$$
			WITH coveredNodes AS (
				SELECT start_node node_id
				FROM %1$I.edge_data
				WHERE edge_id = ANY($1)
					UNION
				SELECT end_node
				FROM %1$I.edge_data
				WHERE edge_id = ANY($1)
			)
			SELECT array_agg(node_id)
			FROM coveredNodes
		$$,
		topo.name
	);
-- STRIP -- 	RAISE DEBUG '%: sql: %', proc_name, sql;

	EXECUTE sql
		USING inputLineEdgeIds
		INTO inputLineNodeIds
	;
-- STRIP -- 	RAISE DEBUG '%: input line covers nodes %',
-- STRIP -- 		proc_name,
-- STRIP -- 		array_to_string(inputLineNodeIds, ',')
-- STRIP -- 	

	-- Query to extract Paths split by nodes
	-- covering edges forming the input line
	--
	-- Param $1 is the list of inputLineNodeIds
	--
	sql := format(
		$$
WITH pathSplit AS (
		SELECT
			DISTINCT
			b path_record,
			b.%1$I::text path_id,
			b.%4$I path_tg,
			n.node_id,
			e.edge_id,
			n.geom node_geom
		FROM
			%3$s b,
			%2$I.relation r,
			%2$I.edge_data e,
			%2$I.node n
		WHERE
			r.topogeo_id = id(b.%4$I)
			AND r.layer_id = layer_id(b.%4$I)
			AND r.element_type = 2 -- edge
			AND r.element_id IN ( e.edge_id, -e.edge_id )
			AND
			(
				(
					e.start_node = ANY($1)
					AND
					e.start_node = n.node_id
				)
				OR
				(
					e.end_node = ANY($1)
					AND
					e.end_node = n.node_id
				)
			)
)
SELECT
	path_record,
	path_id,
	ST_CollectionHomogenize(
			path_tg::geometry
	) path_geom,
	ST_Collect(node_geom) node_geoms,
	array_agg(node_id) node_ids
FROM pathSplit
GROUP BY path_record, path_id, path_tg
HAVING count(edge_id) > 1
		$$,
		pathLayerIdColumn,  -- %1
		topo.name,            -- %2
		pathLayerTable,     -- %3
		pathLayerGeomColumn -- %4
	);
-- STRIP -- 	RAISE DEBUG '%: sql: %', proc_name, sql;

	FOR rec IN
		EXECUTE sql
		USING inputLineNodeIds
	LOOP --{
-- STRIP -- 		RAISE DEBUG 'Path % was split on nodes %',
-- STRIP -- 			rec.path_id,
-- STRIP -- 			array_to_string(rec.node_ids, ',')
-- STRIP -- 		

-- STRIP -- 		RAISE DEBUG 'Path geom was: %',
-- STRIP -- 			ST_AsText(rec.path_geom)
-- STRIP -- 		

		splitPathStartPoint := ST_StartPoint(rec.path_geom);
		-- If the path is a closed path
		-- and its start/end point is not
		-- one of the "splitting nodes",
		-- then we will want to merge components
		-- of the split path that end on such
		-- point.
		splitPathMergeOnStartPoint := FALSE;
		IF ST_IsClosed(rec.path_geom)
		AND NOT ST_Intersects(
				splitPathStartPoint,
				rec.node_geoms
			)
		THEN
-- STRIP -- 			RAISE DEBUG 'Path is closed and its endpoint % is not a split node',
-- STRIP -- 				ST_AsText(splitPathStartPoint)
			-- Check if the node has degree > 2
			-- in which case we cannot merge back on it.
			-- TODO: only count edges taking part of the definition of
			--       other TopoGeometries in the Path layer
			-- See https://gitlab.com/nibioopensource/pgtopo_update_sql/-/issues/275
			sql := format(
				$SQL$
					SELECT count(e.edge_id)
					FROM %1$I.edge e, %1$I.node n
					WHERE ST_Equals(n.geom, $1)
					AND ( e.start_node = n.node_id OR e.end_node = n.node_id )
				$SQL$,
				topo.name
			);
			EXECUTE sql USING splitPathStartPoint INTO splitPathStartPointNodeDegree;
-- STRIP -- 			RAISE DEBUG 'Path endpoint node degree=%', splitPathStartPointNodeDegree;

			IF splitPathStartPointNodeDegree < 3 THEN
				splitPathMergeOnStartPoint := TRUE;
			END IF;
		END IF;

		-- Split the path geometry
		splitPathGeom := ST_Split(
			rec.path_geom,
			rec.node_geoms
		);
-- STRIP -- 		RAISE DEBUG 'Path was split to: %', ST_AsText(splitPathGeom);


		splitPathCount := ST_NumGeometries(splitPathGeom);

		-- (Sanity check: split path must have been split in at least 2 components.)
		-- The above is not true when we use snapTo because then we get the nodes from the server
		-- TODO do we need another sanity check her, or do we need this check at all ?
		IF splitPathCount < 1
		THEN
			RAISE EXCEPTION 'Path % (%) split by nodes % (%) is still a single geometry',
				ST_AsText(rec.path_geom),
				rec.path_id,
				ST_AsText(rec.node_geoms),
				array_to_string(rec.node_ids, ',')
			;
		END IF;

		-- Get column map for modified Paths
		IF colMapForModPath IS NULL
		THEN
			EXECUTE colMapExtractSQL
				USING colMapProviderParam, 'M'
				INTO colMapForModPath;
			IF colMapForModPath IS NULL
			THEN
				RAISE EXCEPTION '%: colMapProvider did not provide a map for modified path act=%',
					proc_name, 'M';
			END IF;
-- STRIP -- 			RAISE DEBUG 'colMapForModPath: %', colMapForModPath;

		END IF;

		-- Get column map for split Paths
		IF colMapForSplitPath IS NULL
		THEN
			EXECUTE colMapExtractSQL
				USING colMapProviderParam, 'S'
				INTO colMapForSplitPath;
			IF colMapForSplitPath IS NULL
			THEN
				RAISE EXCEPTION '%: colMapProvider did not provide a map for split path act=%',
					proc_name, 'S';
			END IF;
-- STRIP -- 			RAISE DEBUG 'colMapForSplitPath: %', colMapForSplitPath;


			-- Build a column map for attributes-inheriting split Path objects
			-- Write new path mapping taking properties
			-- from payload when specified or from old path
			-- when not specified
			inhSplitPathColMap := topo_update._json_col_map_override(
				ARRAY[
					topo_update.json_col_map_from_pg(
						pathLayerTable,
						ARRAY[
							-- omit TopoGeometry column from mapping
							pathLayerGeomColumn::text,
							-- omit ID column from props
							pathLayerIdColumn::text
						]
					),
					colMapForSplitPath
				]
			);
-- STRIP -- 			RAISE DEBUG '%: inheriting split Path ColMap: %', proc_name, inhSplitPathColMap;

		END IF;

		-- Create split paths for subsequent
		-- components of the splitted geometry

		-- Extract properties of old path
		oldPathProps := to_jsonb(rec.path_record)
			- pathLayerGeomColumn -- drop TopoGeometry column from props
			- pathLayerIdColumn   -- drop ID column from props
		;
-- STRIP -- 		RAISE DEBUG 'Old Path props: %', oldPathProps;


		-- Create new path props with
		-- old attributes in an 'old'-keyed field
		-- and payload attributes in a 'new'-keyed field
		newPathProps := jsonb_build_object(
			'p0', oldPathProps,
			'p1', payloadProps
		);
-- STRIP -- 		RAISE DEBUG 'New Path props: %', newPathProps;


		modPathGeom := NULL;
		FOR i IN 1 .. splitPathCount
		LOOP -- {
			splitPathGeomComp = ST_GeometryN(splitPathGeom, i);
-- STRIP -- 			RAISE DEBUG 'Split path geom component: %',
-- STRIP -- 				ST_AsText(splitPathGeomComp)

			IF NOT splitPathMergeOnStartPoint
			THEN --{

				-- If we don't need to merge components
				-- then we take component having the
				-- same start point as the original
				-- path as the one which will retain
				-- its path id
				IF modPathGeom IS NULL
				THEN
					IF ST_Equals(
						ST_StartPoint(splitPathGeomComp),
						splitPathStartPoint
					)
					THEN
-- STRIP -- 						RAISE DEBUG 'Component starts from  original path start point';

						modPathGeom := splitPathGeomComp;
						CONTINUE;
					END IF;
				END IF;

			ELSE -- }{

				-- If we do need to merge components
				-- then we take all components (2 expected)
				-- ending on the splitPathMergeOnStartPoint
				-- to build the new versino of the path
				-- which will retain its id
				IF ST_Equals(
						ST_StartPoint(splitPathGeomComp),
						splitPathStartPoint
					) OR
					ST_Equals(
						ST_EndPoint(splitPathGeomComp),
						splitPathStartPoint
					)
				THEN --{
-- STRIP -- 					RAISE DEBUG 'Component ends on original path endpoint';

					IF modPathGeom IS NULL
					THEN
						modPathGeom := splitPathGeomComp;
					ELSE
						modPathGeom := ST_LineMerge(
							ST_Collect(
								modPathGeom,
								splitPathGeomComp
							)
						);
					END IF;
					CONTINUE;

				END IF; --}

			END IF; --}

			rec2 := topo_update.insert_feature(
				splitPathGeomComp,
				newPathProps,
				pathLayerTable,
				pathLayerGeomColumn,
				pathLayerIdColumn,
				inhSplitPathColMap,
				-- use 0 tolerance as we're only using
				-- existing topological elements
				0.0 -- tolerance
			);

			fid := rec2.id;
			act := 'S';
			frm := rec.path_id;
-- STRIP -- 			RAISE DEBUG 'Path % split from % - returning %|%|%',
-- STRIP -- 				fid, frm, fid,act,frm
			RETURN NEXT;

			totalSplitsCount := totalSplitsCount + 1;

		END LOOP; --}

		-- Update the modified path to only be composed
		-- by the first geometry returned by the split
-- STRIP -- 		RAISE DEBUG 'Modified path geom: %', ST_AsText(modPathGeom);


		fid := rec.path_id;
		act := 'M';
		frm := null;
-- STRIP -- 		RAISE DEBUG 'Path % modified - returning %|%|%',
-- STRIP -- 			fid, fid,act,frm
		RETURN NEXT;

		rec2 := topo_update.update_feature(
			modPathGeom,
			payloadProps,
			pathLayerTable,
			pathLayerGeomColumn,
			pathLayerIdColumn,
			fid,
			colMapForModPath,
			-- use 0 tolerance as we're only using
			-- existing topological elements
			0.0, -- tolerance
			true -- modify existing TopoGeometry
		);

		-- Sanity check
		IF NOT (
			id(rec2.old_topogeom) = newPath.id
		) THEN
			RAISE EXCEPTION 'topo_update.update_feature'
				' unexpectedly found the old TopoGeometry'
				' to be different from the new one (path)';
		END IF;


	END LOOP; --}

	IF totalSplitsCount < 1
	THEN
		RAISE EXCEPTION 'Input geometry does not split any Path';
	END IF;

	IF maxSplits > 0 AND totalSplitsCount > maxSplits
	THEN
		RAISE EXCEPTION '%: input geometry introduces % splits but only up to % are allowed',
			proc_name, totalSplitsCount, maxSplits;
	END IF;

	-- Take note of nodes which would be left isolated upon
	-- edge removal
	sql := format(
		$$
WITH isoNodes AS (
	SELECT e.end_node n FROM
	%1$I.edge e
	WHERE e.edge_id = ANY($1)
	AND e.next_left_edge = -e.edge_id
		UNION ALL
	SELECT e.start_node FROM
	%1$I.edge e
	WHERE e.edge_id = ANY($1)
	AND e.next_right_edge = e.edge_id
) SELECT array_agg(DISTINCT n) FROM isoNodes
		$$,
		topo.name   -- %1
	);

-- STRIP -- 	RAISE DEBUG 'Query to fetch nodes about to be isolated: %', sql;

-- STRIP -- 	RAISE DEBUG 'innputLineEdgeIds: %', inputLineEdgeIds;


	EXECUTE sql
	USING inputLineEdgeIds
	INTO inputLineIsolatedNodeIds;

-- STRIP -- 	RAISE DEBUG 'Isolated node ids: %', inputLineIsolatedNodeIds;


	-- Drop all edges not already used by existing paths
	PERFORM topology.ST_RemEdgeModFace(topo.name, eid)
	FROM unnest(inputLineEdgeIds) eid;

	-- Drop isolated nodes
	-- TODO: drop from the list any node which is used
	--       in the definition of a pre-existing POI feature
	PERFORM topology.ST_RemIsoNode(topo.name, nid)
	FROM unnest(inputLineIsolatedNodeIds) nid;

END;
$_$;



--
-- Name: srid_to_json_crs(integer); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.srid_to_json_crs(srid integer) RETURNS jsonb
    LANGUAGE plpgsql
    AS $_$
DECLARE
	crs TEXT;
	p_srid INT = $1;
BEGIN
	SELECT auth_name || ':' || auth_srid
	FROM public.spatial_ref_sys s
	WHERE s.srid = p_srid
	INTO crs;

	IF FOUND THEN
		RETURN jsonb_build_object(
			'properties', jsonb_build_object('name', crs),
			'type', 'name'
		);
	ELSE
		RAISE EXCEPTION 'Could not found spatial_ref_sys entry for SRID %', srid;
	END IF;
END;
$_$;



--
-- Name: surfaces_as_geojson(regclass, name, name, jsonb, regclass, name, name, jsonb, text[], regproc, anyelement, integer, integer); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.surfaces_as_geojson(surfacelayertable regclass, surfacelayertopogeomcolumn name, surfacelayeridcolumn name, surfacelayercolmap jsonb, borderlayertable regclass, borderlayertopogeomcolumn name, borderlayeridcolumn name, borderlayercolmap jsonb, surfaceids text[], featurejsonmodifier regproc DEFAULT NULL::regproc, featurejsonmodifierarg anyelement DEFAULT NULL::integer, outsrid integer DEFAULT NULL::integer, maxdecimaldigits integer DEFAULT 9) RETURNS jsonb
    LANGUAGE plpgsql
    AS $_$ -- {
DECLARE
	rec RECORD;
	sql TEXT;
	crs TEXT;
	crsSRID INT;
	geojson JSONB;
	topo topology.topology;
	surfaceLayer topology.layer;
	surfaceProps JSONB;
	surfaceTopoGeo topology.TopoGeometry;
	surfaceFeatures JSONB[];
	geojsonFeatures JSONB[] = ARRAY[]::JSONB[];
	procName TEXT := 'topo_update.surfaces_as_geojson';
BEGIN

	-- Create a table to keep track of visited borders
	CREATE TEMPORARY TABLE visitedBorders(fid TEXT PRIMARY KEY);

	sql := format(
		$$
			SELECT
			s as surface_record,
			s.%3$I as surface_topogeom,
			s.%2$I::TEXT AS surface_id
			FROM %1$s s
			WHERE %2$I::TEXT = ANY($1)
			ORDER BY %2$I
		$$,
		surfaceLayerTable,
		surfaceLayerIDColumn,
		surfaceLayerTopoGeomColumn
	);
-- STRIP -- 	RAISE DEBUG '%: SQL": %', procName, sql;

	FOR rec IN EXECUTE sql USING surfaceIds
	LOOP --{

		IF topo IS NULL THEN
			-- Fetch topology info from Surface TopoGeometry
			SELECT *
				FROM topology.topology
				WHERE id = topology_id(rec.surface_topogeom)
				INTO topo;
			IF NOT FOUND THEN
				RAISE EXCEPTION
					'Cannot find topology (id=%) '
					'referenced by TopoGeometry of Surface %',
					topology_id(rec.surface_topogeom),
					rec.surface_id
				;
			END IF;

			-- Fetch layer info from Surface TopoGeometry
			SELECT *
				FROM topology.layer
				WHERE topology_id = topo.id
				AND layer_id = layer_id(rec.surface_topogeom)
				INTO surfaceLayer;
			IF NOT FOUND THEN
				RAISE EXCEPTION
					'Cannot find layer (id=%) of topology % '
					'referenced by TopoGeometry of Surface %',
					layer_id(rec.surface_topogeom),
					topo.name,
					rec.surface_id
				;
			END IF;
		ELSE
			-- Sanity check: all Surface TopoGeometry objects are defined
			-- against the SAME topology
			IF topology_id(rec.surface_topogeom) != topo.id
			THEN
				RAISE EXCEPTION 'TopoGeometry of Surface % is defined on'
					' Topology % instead of % (%)',
					rec.surface_id,
					topology_id(rec.surface_topogeom),
					topo.id,
					topo.name
				;
			END IF;
			-- Sanity check: all Surface TopoGeometry objects are defined
			-- against the SAME topology layer
			IF layer_id(rec.surface_topogeom) != surfaceLayer.layer_id
			THEN
				RAISE EXCEPTION 'TopoGeometry of Surface % is defined on'
					' layer % instead of % (%.%.%)',
					rec.surface_id,
					layer_id(rec.surface_topogeom),
					surfaceLayer.layer_id,
					surfaceLayer.schema_name,
					surfaceLayer.table_name,
					surfaceLayer.feature_column
				;
			END IF;
		END IF;

		-- Build properties of the Surface
		surfaceProps := topo_update.record_to_jsonb(
			rec.surface_record,
			surfaceLayerColMap
		);
		IF surfaceProps IS NULL THEN
			RAISE EXCEPTION 'Properties for surface % as extracted by colMap % are NULL',
				to_jsonb(rec.surface_record), surfaceLayerColMap;
		END IF;

-- STRIP -- 		RAISE DEBUG '%: surface % has props %', procName, rec.surface_id, surfaceProps;


		SELECT array_agg(f) FILTER (WHERE f IS NOT NULL)
		FROM topo_update._surface_as_geojson_features(
			topo,
			surfaceLayer,
			rec.surface_id,
			rec.surface_topogeom,
			surfaceProps,
			borderLayerTable,
			borderLayerTopoGeomColumn,
			borderLayerIdColumn,
			borderLayerColMap,
			'pg_temp.visitedBorders'::regclass,
			featureJsonModifier,
			featureJsonModifierArg,
			outSRID,
			maxdecimaldigits
		) f
		INTO surfaceFeatures;

-- STRIP -- 		RAISE DEBUG '%: surface features: %', procName, surfaceFeatures;


		-- Append surface features to the global features array
		geojsonFeatures := geojsonFeatures || surfaceFeatures;

	END LOOP; --}

	DROP TABLE pg_temp.visitedBorders;

	IF outSRID IS NOT NULL
	THEN
		IF outSRID = 0 THEN
			RAISE EXCEPTION 'If an output SRID is given, it cannot be 0';
		END IF;
		crsSRID = outSRID;
	ELSE
		crsSRID = topo.srid;
	END IF;

	-- Initialize geojson with CRS member, if SRID is known
	IF crsSRID = 0 THEN
		geojson := jsonb_build_object();
	ELSE
		SELECT auth_name || ':' || auth_srid
		FROM public.spatial_ref_sys
		WHERE srid = crsSRID
		INTO crs;

		IF FOUND THEN
			geojson := jsonb_build_object(
				'crs', jsonb_build_object(
					'properties', jsonb_build_object('name', crs),
					'type', 'name'
				)
			);
		ELSE
			RAISE EXCEPTION 'Could not found spatial_ref_sys entry for SRID %', crsSRID;
		END IF;
	END IF;

-- STRIP -- 	RAISE DEBUG '%: GeoJSON header: %', procName, geojson;


	-- Add features and type to the GsoJSON
	geojson := geojson || jsonb_build_object(
		'type', 'FeatureCollection',
		'features', to_jsonb(geojsonFeatures)
	);

-- STRIP -- 	RAISE DEBUG '%: GeoJSON being returned: %', procName, geojson;


	RETURN geojson;
END;
$_$;



--
-- Name: update_feature(topology.topoelementarray, jsonb, regclass, name, name, text, jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.update_feature(feature_topoelems topology.topoelementarray, feature_properties jsonb, layertable regclass, layergeomcolumn name, layeridcolumn name, id text, layercolmap jsonb, OUT updated boolean, OUT topogeom topology.topogeometry) RETURNS record
    LANGUAGE plpgsql
    AS $_$ -- {
DECLARE

	colnames TEXT[];
	colvals TEXT[];

	col_updates TEXT[];
	col_upd TEXT;

	sql TEXT;

	rec RECORD;

	topo topology.topology;

	procName TEXT := 'topo_update.update_feature';

	row_count INT;

BEGIN

	updated := FALSE;

	SELECT c.colnames, c.colvals
	FROM topo_update.json_props_to_pg_cols(feature_properties, layerColMap) c
	INTO colnames, colvals;

-- STRIP -- 	RAISE DEBUG 'COMPUTED: colnames: %', colnames;

-- STRIP -- 	RAISE DEBUG 'COMPUTED: colvals: %', colvals;


	-- Naive approach: always UPDATE, no matter what

	IF colnames IS NULL THEN
-- STRIP -- 		RAISE DEBUG 'NO VALID colnames found using layerColMap % in feature_properties % for layerTable %', layerColMap, feature_properties, layerTable;

		RAISE WARNING '%: no usable properties found, not updating feature % in layer %',
			procName, id, layerTable;
		RETURN;
	END IF;

	FOR i IN 1 .. array_upper(colnames, 1)
	LOOP
		col_upd := format('%s = %s', colnames[i], colvals[i]);
-- STRIP -- 		RAISE DEBUG 'col_upd: %', col_upd;

		col_updates := array_append(col_updates, col_upd);
	END LOOP;

-- STRIP -- 	RAISE DEBUG 'col_updates: %', col_updates;


	sql := format($$
UPDATE %1$s t
SET %2$s
FROM %1$s ot
WHERE ot.%3$I = t.%3$I
  AND ot.%3$I = %4$L
RETURNING (ot.%5$I) old_tg
		$$,
		layerTable,
		array_to_string(col_updates, ', '),
		layerIdColumn,
		id,
		layerGeomColumn
	);

	-- TODO: ADD more WHERE clauses to skip setting values which did not
	--			 change ?
-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;


	EXECUTE sql INTO rec;

	-- Early exit if no row was found
	GET DIAGNOSTICS row_count = ROW_COUNT;
	IF row_count = 0 THEN
		RETURN;
	END IF;

	topogeom := rec.old_tg;

	-- Fetch topology info
	SELECT t topo
		FROM topology.topology t
		WHERE t.id = topology_id(topogeom)
		INTO rec;
	topo := rec.topo;

	-- Query replacing components of topogeom ($2)
	-- with contents of feature_topoelems ($1)
	sql := format(
		$$
			WITH
			newElements AS (
				SELECT e[1][1] element_id, e[1][2] element_type
				FROM (
					SELECT ($1)[x:x][:] e
					FROM generate_series(1, array_upper($1, 1)) x
				) foo
			),
			oldElements AS (
				SELECT element_id, element_type
				FROM %1$I.relation
				WHERE topogeo_id = id($2)
				AND layer_id = layer_id($2)
			),
			insElements AS (
				INSERT INTO %1$I.relation (
					topogeo_id,
					layer_id,
					element_id,
					element_type
				)
				SELECT
					id($2),
					layer_id($2),
					element_id,
					element_type
				FROM newElements
				WHERE ( element_id, element_type )
					NOT IN
					(
						SELECT element_id, element_type
						FROM oldElements
					)
				RETURNING element_id, element_type
			)
			DELETE FROM %1$I.relation
			WHERE topogeo_id = id($2)
			AND layer_id = layer_id($2)
			AND ( element_id, element_type )
				NOT IN
				(
					SELECT element_id, element_type
					FROM newElements
				)
		$$,
		topo.name
	);

-- STRIP -- 	--RAISE DEBUG 'SQL: %', sql;


	EXECUTE sql USING feature_topoelems, topogeom;

	-- or shall we check if anything changed ?
	updated := true;

END;
$_$;



--
-- Name: update_feature(topology.topogeometry, jsonb, regclass, name, name, text, jsonb, boolean); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.update_feature(feature_topogeom topology.topogeometry, feature_properties jsonb, layertable regclass, layergeomcolumn name, layeridcolumn name, id text, layercolmap jsonb, modifyexistingtopogeom boolean DEFAULT true, OUT updated boolean, OUT old_topogeom topology.topogeometry) RETURNS record
    LANGUAGE plpgsql
    AS $_$ -- {
DECLARE

	colnames TEXT[];
	colvals TEXT[];

	col_updates TEXT[];
	col_upd TEXT;

	sql TEXT;

	rec RECORD;

	topo topology.topology;

	procName TEXT := 'topo_update.update_feature';

	row_count INT;

BEGIN

	-- Fetch topology info
	SELECT t topo
		FROM topology.topology t
		WHERE t.id = topology_id(feature_topogeom)
		INTO rec;
	topo := rec.topo;

	IF modifyExistingTopoGeom THEN
		SELECT * FROM topo_update.update_feature(
			topology.GetTopoGeomElementArray(
				topo.name,
				layer_id(feature_topogeom),
				id(feature_topogeom)
			),
			feature_properties,
			layerTable,
			layerGeomColumn,
			layerIdColumn,
			id,
			layerColMap
		) INTO rec;
		updated := rec.updated;
		old_topogeom := rec.topogeom;
		RETURN;
	END IF;

	SELECT c.colnames, c.colvals
	FROM topo_update.json_props_to_pg_cols(feature_properties, layerColMap) c
	INTO colnames, colvals;

	colnames := array_append(colnames, format('%I', layerGeomColumn));
	colvals := array_append(colvals, format('%L', feature_topogeom));


-- STRIP -- 	RAISE DEBUG 'COMPUTED: colnames: %', colnames;

-- STRIP -- 	RAISE DEBUG 'COMPUTED: colvals: %', colvals;


	-- Naive approach: always UPDATE, no matter what

	FOR i IN 1 .. array_upper(colnames, 1)
	LOOP
		col_upd := format('%s = %s', colnames[i], colvals[i]);
-- STRIP -- 		RAISE DEBUG 'col_upd: %', col_upd;

		col_updates := array_append(col_updates, col_upd);
	END LOOP;

-- STRIP -- 	RAISE DEBUG 'col_updates: %', col_updates;


	sql := format($$
UPDATE %1$s t
SET %2$s
FROM %1$s ot
WHERE ot.%3$I = t.%3$I
  AND ot.%3$I = %4$L
RETURNING (ot.%5$I) old_tg
		$$,
		layerTable,
		array_to_string(col_updates, ', '),
		layerIdColumn,
		id,
		layerGeomColumn
	);

	-- TODO: ADD more WHERE clauses to skip setting values which did not
	--			 change ?
-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;


	EXECUTE sql INTO rec;

	-- Early exit if no row was found
	GET DIAGNOSTICS row_count = ROW_COUNT;
	IF row_count = 0 THEN
		updated := FALSE;
		RETURN;
	END IF;

	updated := TRUE;
	old_topogeom := rec.old_tg;

END;
$_$;



--
-- Name: update_feature(jsonb, integer, regclass, name, name, text, jsonb, double precision, boolean); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.update_feature(feature jsonb, srid integer, layertable regclass, layergeomcolumn name, layeridcolumn name, id text, layercolmap jsonb, tolerance double precision, modifyexistingtopogeom boolean DEFAULT true, OUT updated boolean, OUT topogeom topology.topogeometry, OUT old_topogeom topology.topogeometry) RETURNS record
    LANGUAGE plpgsql
    AS $$ -- {
DECLARE
	topo_srid INT;
	geom GEOMETRY;
	rec RECORD;
BEGIN

	geom := ST_GeomFromGeoJSON(feature -> 'geometry');
-- STRIP -- 	--RAISE DEBUG 'GEOM: %', ST_AsEWKT(geom);


	-- TODO: do this one in the calling function and receive this
	--			 information pre-computed
	SELECT t.srid
		FROM topology.layer l, topology.topology t, pg_class c, pg_namespace n
		WHERE l.schema_name = n.nspname
		AND l.table_name = c.relname
		AND c.oid = layerTable
		AND c.relnamespace = n.oid
		AND l.feature_column = layerGeomColumn
		AND l.topology_id = t.id
		INTO topo_srid;

	-- TODO: use the deprecated "crs" member in GeoJSON, if found ?
-- STRIP -- 	RAISE DEBUG 'SRID: %', srid;

-- STRIP -- 	RAISE DEBUG 'TOPO_SRID: %', topo_srid;

	IF srid IS NOT NULL THEN
		geom := ST_SetSRID(geom, srid);
		IF topo_srid IS NOT NULL THEN
			geom := ST_Transform(geom, topo_srid);
		END IF;
-- STRIP -- 		RAISE DEBUG 'REPROJECTED GEOM: %', ST_AsEWKT(geom);

	END IF;

	SELECT * FROM topo_update.update_feature(
		geom,
		feature -> 'properties',
		layerTable,
		layerGeomColumn,
		layerIdColumn,
		id,
		layerColMap,
		tolerance,
		modifyExistingTopoGeom
	) INTO rec;

-- STRIP -- 	RAISE DEBUG 'update_feature(geom) returned rec: %', rec;


	updated := rec.updated;
	topogeom := rec.topogeom;
	old_topogeom := rec.old_topogeom;
END;
$$;



--
-- Name: update_feature(public.geometry, jsonb, regclass, name, name, text, jsonb, double precision, boolean, name); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.update_feature(feature_geometry public.geometry, feature_properties jsonb, layertable regclass, layergeomcolumn name, layeridcolumn name, id text, layercolmap jsonb, tolerance double precision, modifyexistingtopogeom boolean DEFAULT true, OUT updated boolean, OUT topogeom topology.topogeometry, OUT old_topogeom topology.topogeometry, layerversioncolumn name DEFAULT NULL::name) RETURNS record
    LANGUAGE plpgsql
    AS $_$ -- {
DECLARE
	toponame TEXT;
	topo_srid INT;
	layer_id INT;

	geom GEOMETRY;

	colnames TEXT[];
	colvals TEXT[];

	col_updates TEXT[];
	col_upd TEXT;

	quotedLayerVersionColumn TEXT;
	version_value TEXT;

	rec RECORD;
	sql TEXT;

	i INT;

	row_count INT;
BEGIN

	-- TODO: do this one in the calling function and receive this
	--			 information pre-computed
	SELECT t.name, l.layer_id, t.srid
		FROM topology.layer l, topology.topology t, pg_class c, pg_namespace n
		WHERE l.schema_name = n.nspname
		AND l.table_name = c.relname
		AND c.oid = layerTable
		AND c.relnamespace = n.oid
		AND l.feature_column = layerGeomColumn
		AND l.topology_id = t.id
		INTO toponame, layer_id, topo_srid;

-- STRIP -- 	RAISE DEBUG 'toponame: %', toponame;

-- STRIP -- 	RAISE DEBUG 'layer_id: %', layer_id;


	SELECT c.colnames, c.colvals
	FROM topo_update.json_props_to_pg_cols(feature_properties, layerColMap) c
	INTO colnames, colvals;

	colnames := array_append(colnames, format('%I', layerGeomColumn));

	geom := feature_geometry;
-- STRIP -- 	--RAISE DEBUG 'GEOM: %', ST_AsEWKT(geom);


	IF modifyExistingTopoGeom THEN
		colvals := array_append(
			colvals,
			format(
				'topology.toTopoGeom($1, topology.clearTopoGeom(t.%I), %L)',
				layerGeomColumn,
				tolerance
			)
		);
	ELSE
		colvals := array_append(
			colvals,
			format(
				'topology.toTopoGeom($1, %L, %L, %L)',
				toponame,
				layer_id,
				tolerance
			)
		);
	END IF;

-- STRIP -- 	RAISE DEBUG 'COMPUTED: colnames: %', colnames;

-- STRIP -- 	RAISE DEBUG 'COMPUTED: colvals: %', colvals;


	-- Naive approach: always UPDATE, no matter what

	quotedLayerVersionColumn = quote_ident(layerVersionColumn);
	FOR i IN 1 .. array_upper(colnames, 1)
	LOOP
		col_upd := format('%s = %s', colnames[i], colvals[i]);
-- STRIP -- 		RAISE DEBUG 'col_upd: %', col_upd;

		col_updates := array_append(col_updates, col_upd);
		IF quotedLayerVersionColumn = colnames[i] THEN
			version_value = colvals[i];
-- STRIP -- 			RAISE DEBUG 'VERSION VALUE: %', version_value;

		END IF;
	END LOOP;

-- STRIP -- 	RAISE DEBUG 'col_updates: %', col_updates;


	sql := format(
		$$
			UPDATE %1$s t
			SET %2$s
			FROM %1$s ot
			WHERE ot.%3$I = t.%3$I
			  AND ot.%3$I = %4$L
			  AND ( %6$s )
			RETURNING (ot.%5$I) old_tg, (t.%5$I) new_tg
		$$,
		layerTable,
		array_to_string(col_updates, ', '),
		layerIdColumn,
		id,
		layerGeomColumn,
		CASE
		WHEN layerVersionColumn IS NULL THEN
			'true'
		WHEN version_value IS NULL THEN
			format('ot.%1$I IS NOT NULL', layerVersionColumn)
		ELSE
			format('ot.%1$I IS NULL OR ot.%1$I != %2$s', layerVersionColumn, version_value)
		END
	);
	-- TODO: ADD more WHERE clauses to skip setting values which did not
	--			 change ?
-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;


	EXECUTE sql USING geom INTO rec;

	GET DIAGNOSTICS row_count = ROW_COUNT;
	IF row_count = 0 THEN
-- STRIP -- 		RAISE DEBUG 'Row for feature with id % was NOT updated', id;

		updated := FALSE;
	ELSE
		updated := TRUE;
	END IF;

	topogeom := rec.new_tg;
	old_topogeom := rec.old_tg;

END;
$_$;



--
-- Name: update_feature_attribute(jsonb, regclass, name, jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.update_feature_attribute(feature jsonb, layertable regclass, layeridcolumn name, layercolmap jsonb) RETURNS text
    LANGUAGE plpgsql
    AS $_$ -- {
DECLARE

	colnames TEXT[];
	colvals TEXT[];

	col_updates TEXT[];
	col_upd TEXT;

	sql TEXT;
	
	id_value TEXT;

	id_json_name TEXT;

	-- Counter for num update rows, used decide if to return true or false;
	v_cnt int;
	
	proc_name text = 'topo_update.update_feature_attribute';
	
	feature_properties JSONB;

BEGIN

	feature_properties = feature ->>  'properties';
	
	-- Get json name for primary key 
	id_json_name = (jsonb_array_elements_text( layerColMap -> layerIdColumn ));
	
	-- Get id
	id_value = feature_properties ->> id_json_name;
	
-- STRIP -- 	RAISE DEBUG 'id_value: %', id_value;


	IF id_value IS NULL THEN
	
		IF id_json_name IS NULL THEN
			RAISE EXCEPTION '%: % not found in % using %',
				proc_name,
				id_json_name,
				layerColMap,
				layerIdColumn
				;
		END IF;
			
		RAISE EXCEPTION '%: feature ID extracted from props %'
			' with mapping path % is using name % '
			', cannot proceed',
			proc_name,
			feature_properties,
			layerColMap,
			id_json_name
			;
	END IF;
	
	-- Remove primary key from update map
	layerColMap = layerColMap - layerIdColumn;


	SELECT c.colnames, c.colvals
	FROM topo_update.json_props_to_pg_cols(feature_properties, layerColMap) c
	INTO colnames, colvals;

-- STRIP -- 	RAISE DEBUG 'COMPUTED: colnames: %', colnames;

-- STRIP -- 	RAISE DEBUG 'COMPUTED: colvals: %', colvals;


	-- Naive approach: always UPDATE, no matter what

	

	
	
	FOR i IN 1 .. array_upper(colnames, 1)
	LOOP
		col_upd := format('%s = %s', colnames[i], colvals[i]);
-- STRIP -- 		RAISE DEBUG 'col_upd: %', col_upd;

		col_updates := array_append(col_updates, col_upd);
	END LOOP;

-- STRIP -- 	RAISE DEBUG 'col_updates: %', col_updates;


	sql := format($$
UPDATE %1$s t
SET %2$s
FROM %1$s ot
WHERE ot.%3$I = t.%3$I
  AND ot.%3$I = %4$L
		$$,
		layerTable,
		array_to_string(col_updates, ', '),
		layerIdColumn,
		id_value
	);

	-- TODO: ADD more WHERE clauses to skip setting values which did not
	--			 change ?
-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;


	EXECUTE sql;

	GET DIAGNOSTICS v_cnt = row_count;
	
	IF v_cnt = 0 THEN
		RETURN NULL;
	ELSE
		RETURN id_value;
	END IF;

END;
$_$;



--
-- Name: update_features(jsonb, regclass, name, name, jsonb, regclass, name, name, jsonb, double precision, public.geometry, regproc, regproc, regproc, name, name, public.geometry); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.update_features(featureset jsonb, areallayertable regclass, areallayercolumn name, areallayeridcolumn name, areallayercolmap jsonb, lineallayertable regclass, lineallayercolumn name, lineallayeridcolumn name, lineallayercolmap jsonb, tolerance double precision, deleteunknownfeaturesinbbox public.geometry DEFAULT NULL::public.geometry, roleandpropsextractor regproc DEFAULT NULL::regproc, resultingfeaturevalidator regproc DEFAULT NULL::regproc, payloadpreparation regproc DEFAULT NULL::regproc, lineallayerversioncolumn name DEFAULT NULL::name, areallayerversioncolumn name DEFAULT NULL::name, outerbarrierbboxforupsert public.geometry DEFAULT NULL::public.geometry) RETURNS void
    LANGUAGE plpgsql
    AS $_$ -- {
DECLARE
	rec RECORD;
	rec2 RECORD;
	feat JSONB;
	feat_id TEXT;
	feat_role CHAR;
	feat_prop JSONB;
	feat_geom GEOMETRY;
	geom_prop JSONB;
	ring_json JSONB;
	feat_crs TEXT;
	feat_srid INT;
	surface_features JSONB[];
	surface_geom GEOMETRY;
	hdist FLOAT8;
	surface_topoelems topology.TopoElementArray;
	ring GEOMETRY;
	exterior_ring GEOMETRY;
	interior_rings GEOMETRY[];
	affected_rows INT8;
	extractor REGPROC;
	extractSql TEXT;
	validateSql TEXT;
	sql TEXT;

	topo topology.topology;
	borderLayer topology.layer;
	borderLayerIDType name;
	borderLayerVersionType name;
	surfaceLayer topology.layer;
	surfaceLayerIDType name;
	surfaceLayerVersionType name;

	cleanupTopoPrimitives BOOLEAN := FALSE;

	procName TEXT := 'topo_update.update_features';

	json_prop_array TEXT[];

	payloadFeaturesCount INT;
	knownBorderFeaturesCount INT;
	knownSurfaceFeaturesCount INT;

	v_state text;
	v_msg text;
	v_detail text;
	v_hint text;
	v_context text;

	border_lines_removed int;
BEGIN


	IF payloadPreparation IS NOT NULL THEN
		sql := format($$
			SELECT * FROM %s(payload => $1, bbox => $2)
		$$, payloadPreparation);
		RAISE WARNING 'Preparation SQL: %', sql;
		EXECUTE sql USING featureset, deleteUnknownFeaturesInBbox
		INTO rec;
		featureset := rec.payload;
		deleteUnknownFeaturesInBbox := rec.bbox;

		IF featureset IS NULL THEN
			RAISE WARNING 'Payload preparation returned NULL payload, nothing to do';
			RETURN;
		END IF;
	END IF;

	-- Fetch topology and layer info from border layer references
	SELECT t topo, l layer
		FROM topology.layer l, topology.topology t, pg_class c, pg_namespace n
		WHERE l.schema_name = n.nspname
		AND l.table_name = c.relname
		AND c.oid = linealLayerTable
		AND c.relnamespace = n.oid
		AND l.feature_column = linealLayerColumn
		AND l.topology_id = t.id
	--	FOR UPDATE, 2 problems, user needs SUPERUSER (can be fixed),
	--  ms used from 8601 -> 113606 for ((14.355156130507279 67.27980828078813, 14.354976710179235 67.28648792270606, 14.395077865039152 67.28664388346324, 14.395246132501715 67.27996419068565, 14.355156130507279 67.27980828078813))
		INTO rec;
	topo := rec.topo;
	borderLayer := rec.layer;

	--	RAISE NOTICE 'Lock on topology % obtained', topo.name;

	-- Fetch topology and layer info from surface layer references
	SELECT t topo, l layer
		FROM topology.layer l, topology.topology t, pg_class c, pg_namespace n
		WHERE l.schema_name = n.nspname
		AND l.table_name = c.relname
		AND c.oid = arealLayerTable
		AND c.relnamespace = n.oid
		AND l.feature_column = arealLayerColumn
		AND l.topology_id = t.id
		INTO rec;

	IF id(topo) != id(rec.topo) THEN
		RAISE EXCEPTION '%: Lineal and Areal layers need to be in same topology',
			procName;
	END IF;
	surfaceLayer := rec.layer;

	-- Fetch border layer id column type
	SELECT t.typname FROM pg_type t, pg_attribute a
	WHERE a.attrelid = linealLayerTable
	AND a.attname = linealLayerIDColumn
	AND a.atttypid = t.oid
	INTO borderLayerIDType;

	-- Fetch border layer version column type
	IF linealLayerVersionColumn IS NOT NULL THEN
		IF NOT linealLayerColMap ? linealLayerVersionColumn THEN
			RAISE EXCEPTION 'Invalid linealLayerVersionColumn: % not found in linealLayerColMap %',
				linealLayerVersionColumn, linealLayerColMap;
		END IF;
		SELECT t.typname FROM pg_type t, pg_attribute a
		WHERE a.attrelid = linealLayerTable
		AND a.attname = linealLayerVersionColumn
		AND a.atttypid = t.oid
		INTO borderLayerVersionType;
	END IF;

	-- Fetch surface layer id column type
	SELECT t.typname FROM pg_type t, pg_attribute a
	WHERE a.attrelid = arealLayerTable
	AND a.attname = arealLayerIDColumn
	AND a.atttypid = t.oid
	INTO surfaceLayerIDType;

	-- Fetch surface layer version column type
	IF arealLayerVersionColumn IS NOT NULL THEN
		IF NOT arealLayerColMap ? arealLayerVersionColumn THEN
			RAISE EXCEPTION 'Invalid arealLayerVersionColumn: % not found in arealLayerColMap %',
				arealLayerVersionColumn, arealLayerColMap;
		END IF;
		SELECT t.typname FROM pg_type t, pg_attribute a
		WHERE a.attrelid = arealLayerTable
		AND a.attname = arealLayerVersionColumn
		AND a.atttypid = t.oid
		INTO surfaceLayerVersionType;
	END IF;

	IF roleAndPropsExtractor IS NOT NULL THEN
		extractor := roleAndPropsExtractor;
	ELSE
		extractor := 'topo_update._update_features_def_extractor'::regproc;
	END IF;

	extractSql := format(
		'SELECT role, prop FROM %s(feature => $1, feat_srid => $2, topo_srid => $3)',
		extractor::text
	);
-- STRIP -- 	RAISE DEBUG 'Extraction SQL: %', extractSql;


	-- Write validator SQL
	-- Parameters are:
	--	$1 role
	--	$2 fid
	--	$3 geom
	--	$4 tg
	--	$5 tolerance
	IF resultingFeatureValidator IS NOT NULL
	THEN
		validateSql := format(
			'SELECT %s( role => $1, fid => $2, geom => $3, tg => $4, tol => $5 )',
			resultingFeatureValidator::text
		);
-- STRIP -- 		RAISE DEBUG 'Validator SQL: %', validateSql;

	END IF;

	IF NOT featureset ? 'crs'
	THEN
		RAISE EXCEPTION 'Featureset lacks an explicit "crs" field';
	END IF;
	feat_crs := featureset -> 'crs' -> 'properties' ->> 'name';

-- STRIP -- 	RAISE DEBUG 'crs: %', feat_crs;


	SELECT s.srid
	FROM spatial_ref_sys s
	WHERE format('%s:%s', s.auth_name, s.auth_srid) = feat_crs
	INTO feat_srid;

	DROP TABLE IF EXISTS pg_temp.payload_features;

	sql := format(
		$$
	CREATE TEMP TABLE payload_features
	AS
	SELECT
		NULL::text AS id,
		NULL::text AS version,
		false::bool AS known,
		false::bool AS outside_outer_barrier_bbox_for_upsert,
		NULL::geometry AS geom,
		e.*,
		f -> 'geometry_properties' as geom_prop,
		f -> 'geometry' as geom_json
	FROM jsonb_array_elements($1 -> 'features') f,
		%1$s(feature => f, feat_srid => %3$L, topo_srid => %2$L) e
		$$,
		extractor::text, -- %1
		topo.srid, -- %2
		feat_srid, -- %3
		topo.srid  -- %4
	);
-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;

	EXECUTE sql USING featureset;
	GET DIAGNOSTICS payloadFeaturesCount = ROW_COUNT;
	RAISE NOTICE 'Features in payload: %', payloadFeaturesCount;

	-- Extract ID, Version and Geometry
	UPDATE payload_features SET
		id =
			CASE WHEN role = 'B' THEN
				prop #>> (
					SELECT array_agg(x) FROM
					jsonb_array_elements_text(
						linealLayerColMap -> linealLayerIdColumn
					) x
				)
			ELSE
				prop #>> (
					SELECT array_agg(x) FROM
					jsonb_array_elements_text(
						arealLayerColMap -> arealLayerIdColumn
					) x
				)
			END,
		version =
			CASE WHEN role = 'B' THEN
				prop #>> (
					SELECT array_agg(x) FROM
					jsonb_array_elements_text(
						linealLayerColMap -> linealLayerVersionColumn
					) x
				)
			ELSE
				prop #>> (
					SELECT array_agg(x) FROM
					jsonb_array_elements_text(
						arealLayerColMap -> arealLayerVersionColumn
					) x
				)
			END,
		geom =
			CASE WHEN role = 'B' THEN
				ST_Transform(
					ST_SetSRID(
						ST_Force2D(
							ST_GeomFromGeoJSON(geom_json)
						),
						feat_srid
					),
					topo.srid
				)
			ELSE
				NULL -- we will construct the Surface from Border refs
			END
	;

	BEGIN
		CREATE UNIQUE INDEX ON payload_features(id);
	EXCEPTION WHEN unique_violation THEN
	    GET STACKED DIAGNOSTICS v_state = RETURNED_SQLSTATE, v_msg = MESSAGE_TEXT, v_detail = PG_EXCEPTION_DETAIL, v_hint = PG_EXCEPTION_HINT, v_context = PG_EXCEPTION_CONTEXT;
		RAISE NOTICE 'Failed CREATE UNIQUE INDEX ON payload_features(id) at % state  : % message: % detail : % hint : % context: %',
		Timeofday(), v_state, v_msg, v_detail, v_hint, v_context;

		FOR rec IN
			SELECT id, count(role), array_agg(distinct role) roles
			FROM payload_features
			GROUP BY id
			HAVING count(*) > 1
		LOOP
			RAISE EXCEPTION '% with duplicate identifier % found in payload',
				CASE
					WHEN array_upper(rec.roles, 1) > 1 THEN
						'Features'
					WHEN rec.roles[1] = 'B' THEN
						'Borders'
					ELSE
						'Surfaces'
				END,
				rec.id;
		END LOOP;
	END;

	CREATE INDEX ON payload_features(role);

	-- Mark already known borders
	IF linealLayerVersionColumn IS NOT NULL THEN
		sql := format(
			$$
				UPDATE payload_features p
				SET known = true
				FROM %1$s l
				WHERE role = 'B'
				AND l.%2$I = p.id::%4$I
				AND (
					( l.%3$I IS NULL AND p.version IS NULL )
					OR
					( l.%3$I = p.version::%5$I )
				)
			$$,
			linealLayerTable,         -- %1
			linealLayerIDColumn,      -- %2
			linealLayerVersionColumn, -- %3
			borderLayerIDType,        -- %4
			borderLayerVersionType    -- %5
		);
-- STRIP -- 		RAISE DEBUG 'SQL: %', sql;

		EXECUTE sql;
		GET DIAGNOSTICS knownBorderFeaturesCount = ROW_COUNT;
		RAISE NOTICE 'Known Border features in payload: %', knownBorderFeaturesCount;
	END IF;

	-- Mark already known surfaces
	IF arealLayerVersionColumn IS NOT NULL THEN
		sql := format(
			$$
				UPDATE payload_features p
				SET known = true
				FROM %1$s l
				WHERE p.role = 'S'
				AND l.%2$I = p.id::%4$I
				AND (
					( l.%3$I IS NULL AND p.version IS NULL )
					OR
					( l.%3$I = p.version::%5$I )
				)
			$$,
			arealLayerTable,         -- %1
			arealLayerIDColumn,      -- %2
			arealLayerVersionColumn, -- %3
			surfaceLayerIDType,      -- %4
			surfaceLayerVersionType  -- %5
		);
-- STRIP -- 		RAISE DEBUG 'SQL: %', sql;

		EXECUTE sql;
		GET DIAGNOSTICS knownSurfaceFeaturesCount = ROW_COUNT;
		RAISE NOTICE 'Known Surface features in payload: %', knownSurfaceFeaturesCount;
	END IF;

	-- Delete any features intersecting the given area
	-- and not present in payload
	IF deleteUnknownFeaturesInBbox IS NOT NULL
	THEN --{

		IF ST_SRID(deleteUnknownFeaturesInBbox) != topo.srid
		THEN
			RAISE WARNING 'Bounding box passed to update_feature is not in the target topology CRS, transforming it';
			deleteUnknownFeaturesInBbox := ST_Transform(deleteUnknownFeaturesInBbox, topo.srid);
		END IF;

		affected_rows := topo_update.delete_unknown_features(
			arealLayerTable,
			arealLayerColumn,
			arealLayerIDColumn,
			deleteUnknownFeaturesInBbox,
			( SELECT COALESCE(array_agg(id),ARRAY[]::text[])
			  FROM payload_features
			  WHERE role = 'S'
			  AND known
			)
		);
		RAISE NOTICE 'Deleted % rows from areal layer', affected_rows;
		IF affected_rows > 0 THEN
			cleanupTopoPrimitives := TRUE;
		END IF;

		affected_rows := topo_update.delete_unknown_features(
			linealLayerTable,
			linealLayerColumn,
			linealLayerIDColumn,
			deleteUnknownFeaturesInBbox,
			( SELECT COALESCE(array_agg(id),ARRAY[]::text[])
			  FROM payload_features
			  WHERE role = 'B'
			  AND known
			)
		);
		RAISE NOTICE 'Deleted % rows from lineal layer', affected_rows;
		IF affected_rows > 0 THEN
			cleanupTopoPrimitives := TRUE;
		END IF;

		-- Clean up topology primitives if needed
		IF cleanupTopoPrimitives
		THEN --{
			affected_rows := topo_update.cleanup_topology(topo, deleteUnknownFeaturesInBbox);

			RAISE NOTICE 'Deleted % topology primitives', affected_rows;

		END IF; --}

	END IF; --}

	IF outerBarrierBboxForUpsert IS NOT NULL
	THEN
		CREATE INDEX ON payload_features USING GIST(geom);

		UPDATE payload_features p
		SET outside_outer_barrier_bbox_for_upsert = true
		WHERE role = 'B'
		AND NOT ST_Contains(outerBarrierBboxForUpsert,p.geom);

		GET DIAGNOSTICS border_lines_removed = ROW_COUNT;
		RAISE NOTICE 'for outerBarrierBboxForUpsert % , remove % because it touches edge_line_barrier ',
		outerBarrierBboxForUpsert, border_lines_removed;
	END IF;


	-- Upsert the borders
	PERFORM topo_update.upsert_feature(
		geom,
		prop,
		linealLayerTable,
		linealLayerColumn,
		linealLayerIDColumn,
		linealLayerColMap,
		tolerance,
		layerVersionColumn => linealLayerVersionColumn
	)
	FROM payload_features
	WHERE role = 'B'
	AND NOT known
	AND NOT outside_outer_barrier_bbox_for_upsert;

	GET DIAGNOSTICS affected_rows = ROW_COUNT;
	RAISE NOTICE 'Upserted % rows in lineal layer', affected_rows;
	IF affected_rows > 0 THEN
		--cleanupTopoPrimitives := TRUE;
	END IF;

	CREATE TEMP VIEW update_features_borders AS
	SELECT id, geom FROM payload_features
	WHERE role = 'B';

	-- Construct and insert surfaces
	affected_rows := 0;
	FOR rec IN
		SELECT *
		FROM payload_features
		WHERE role = 'S'
		AND NOT known
	LOOP --{

		feat_prop := rec.prop;
-- STRIP -- 		RAISE DEBUG 'Surface extracted_properties: %', feat_prop;


		geom_prop := rec.geom_prop;
		IF geom_prop IS NULL THEN
			RAISE EXCEPTION 'Surface lacks geometry_properties attribute: %', rec;
		END IF;
-- STRIP -- 		RAISE DEBUG 'Surface geometry_properties: %', feat_prop;


		-- Build external ring
		ring_json := geom_prop -> 'exterior';
-- STRIP -- 		RAISE DEBUG 'Surface exterior ring: %', ring_json;

		IF ring_json IS NULL THEN
			RAISE EXCEPTION 'Surface exterior ring attribute';
		END IF;
		WITH ring AS (
			SELECT
				row_number() OVER () seq,
				trim( leading '-' FROM e ) bid,
				e LIKE '-%' AS backward
			FROM
				jsonb_array_elements_text(ring_json) e
		)
		SELECT
			ST_MakeLine(
				CASE
				WHEN ring.backward THEN
					ST_Reverse(b.geom)
				ELSE
					b.geom
				END
				ORDER BY ring.seq
			)
		FROM
			update_features_borders b,
			ring
		WHERE
			b.id = ring.bid
		INTO exterior_ring;

		IF exterior_ring IS NULL THEN
			RAISE EXCEPTION $$
Not all borders referenced in surface exterior ring (%) are found in payload
				$$, ring_json;
		END IF;
-- STRIP -- 		RAISE DEBUG 'Exterior ring: % (SRID:%)', ST_Summary(exterior_ring), ST_SRID(exterior_ring);


		-- Check that exterior ring is closed
		-- TODO How will this check affect performance ??, (If the error print in ST_MakePolygon was better we should not need this check, no we onøy see this lwpoly_from_lwlines: shell must be closed)
		IF NOT ST_IsClosed(exterior_ring) THEN
-- STRIP -- 			RAISE DEBUG 'Exterior ring not closed run snap to grid with tolerance % : % (SRID:%)', tolerance, ST_Summary(exterior_ring), ST_SRID(exterior_ring);


			-- Check if this is a coodinate decimal problem run snap to grid an d chack again
			exterior_ring = ST_SnapToGrid(exterior_ring,tolerance);

			IF NOT ST_IsClosed(exterior_ring) THEN

				RAISE EXCEPTION 'Exterior ring is not closed for surface %  using this %',
					feat_prop #>> (
						SELECT array_agg(x)
						FROM
							jsonb_array_elements_text(
								arealLayerColMap -> arealLayerIDColumn
							) x
					),
					ST_AsEWKT(exterior_ring)
				;
			END IF;
		END IF;

		-- Check that the exterior ring is in CCW order
		IF NOT ST_IsPolygonCCW(ST_MakePolygon(exterior_ring)) THEN
			RAISE EXCEPTION 'Exterior ring of Surface % is not in CCW order, at or near %',
				feat_prop #>> (
					SELECT array_agg(x)
					FROM
						jsonb_array_elements_text(
							arealLayerColMap -> arealLayerIDColumn
						) x
				),
				ST_AsEWKT(ST_StartPoint(exterior_ring))
			;
		END IF;

		-- Build internal rings

		-- TODO we may get the same problems with internal rings yes

		ring_json := geom_prop -> 'interiors';

		WITH rings AS (
			SELECT row_number() OVER () ring_no, spec
			FROM (
				SELECT jsonb_array_elements(ring_json) spec
			) x
		),
		rings_with_signed_edges AS (
			SELECT
				ring_no,
				row_number() OVER (partition by ring_no) edge_no,
				signed_edge_id
			FROM (
				SELECT
					ring_no,
					jsonb_array_elements_text(spec) signed_edge_id
				FROM rings
			) x
		),
		rings_with_id_and_dir AS (
			SELECT
				ring_no,
				edge_no,
				trim( leading '-' FROM signed_edge_id ) bid,
				signed_edge_id LIKE '-%' AS backward
			FROM
				rings_with_signed_edges
		),
		rings_with_geom AS (
			SELECT
				ring.ring_no,
				ST_MakeLine(
						CASE
						WHEN ring.backward THEN
							ST_Reverse(b.geom)
						ELSE
							b.geom
						END
						ORDER BY ring.edge_no
					) geom
				FROM
					update_features_borders b,
					rings_with_id_and_dir ring
				WHERE
					b.id = ring.bid
				GROUP BY ring.ring_no
		)
		SELECT array_agg(geom ORDER BY ring_no) holes
		FROM rings_with_geom
		INTO interior_rings;

		IF interior_rings IS NOT NULL THEN
-- STRIP -- 			RAISE DEBUG 'Surface has % holes', array_upper(interior_rings, 1);

			surface_geom := ST_MakePolygon(exterior_ring, interior_rings);
		ELSE
			surface_geom := ST_MakePolygon(exterior_ring);
		END IF;


		IF outerBarrierBboxForUpsert IS NOT NULL AND NOT ST_Contains(outerBarrierBboxForUpsert,surface_geom) THEN
			RAISE NOTICE 'for outerBarrierBboxForUpsert % , removed surface at %',
			outerBarrierBboxForUpsert,
			ST_Centroid(surface_geom);
		ELSE

		rec2 := ST_IsValidDetail(surface_geom);
		IF NOT rec2.valid THEN
			RAISE EXCEPTION 'Geometry of Surface % is not valid: % at or near %',
				feat_prop #>> (
					SELECT array_agg(x)
					FROM jsonb_array_elements_text( arealLayerColMap -> arealLayerIDColumn ) x
				),
				-- NOTE: lower() gives us a nice output BUT it's
				--       really a workaround for some bug which
				--       seems to stop output from RAISE at the end
				--       of the string
				lower(rec2.reason),
				ST_AsEWKT(rec2.location)
				;
		END IF;

-- STRIP -- 		--RAISE DEBUG 'Surface Geom: %', ST_AsEWKT(surface_geom);


		-- Find all faces covered by the Surface geometry
		sql := format(
			$$
				SELECT
					topology.TopoElementArray_agg(
						ARRAY[f.face_id,3]::topology.TopoElement
					)
				FROM %1$I.face f
				WHERE f.mbr @ $1 -- face mbr is contained in surface's ($1) mbr
				-- TODO: check that face mbr is NOT contained in any surface's hole mbr ?
				AND ST_Covers(
					$1,
					topo_update._point_on_face(%1$L, f.face_id)
				)
			$$,
			topo.name
		);

-- STRIP -- 		RAISE DEBUG 'SQL: %', sql;

		EXECUTE sql
			USING surface_geom
			INTO surface_topoelems;

		-- Pass surface_topoelems to upsert_feature
		rec2 := topo_update.upsert_feature(
				surface_topoelems,
				feat_prop,
				arealLayerTable,
				arealLayerColumn,
				arealLayerIDColumn,
				arealLayerColMap
			);
		affected_rows := affected_rows + 1;

		-- Verify acceptability of new Surface object
		-- See https://gitlab.com/nibioopensource/pgtopo_update_sql/-/issues/104

		IF rec2.topogeom IS NULL
		THEN
			RAISE EXCEPTION
				'Input Surface % around % covers no topology'
				' face (too much snapping ?)',
				rec.id,
				ST_AsEWKT(ST_PointOnSurface(surface_geom))
			;
		END IF;


		-- Invoke external validator, if given

		IF validateSql IS NOT NULL
		THEN
			EXECUTE validateSql
			USING 'S', rec.id, surface_geom, rec2.topogeom, tolerance;
		END IF;
		END IF;

	END LOOP; --}
	RAISE NOTICE 'Upserted % rows in areal layer', affected_rows;
	IF affected_rows > 0 THEN
		--cleanupTopoPrimitives := TRUE;
	END IF;

	DROP VIEW pg_temp.update_features_borders;
	DROP TABLE pg_temp.payload_features;


END;
$_$;



--
-- Name: FUNCTION update_features(featureset jsonb, areallayertable regclass, areallayercolumn name, areallayeridcolumn name, areallayercolmap jsonb, lineallayertable regclass, lineallayercolumn name, lineallayeridcolumn name, lineallayercolmap jsonb, tolerance double precision, deleteunknownfeaturesinbbox public.geometry, roleandpropsextractor regproc, resultingfeaturevalidator regproc, payloadpreparation regproc, lineallayerversioncolumn name, areallayerversioncolumn name, outerbarrierbboxforupsert public.geometry); Type: COMMENT; Schema: topo_update; Owner: lop
--

COMMENT ON FUNCTION topo_update.update_features(featureset jsonb, areallayertable regclass, areallayercolumn name, areallayeridcolumn name, areallayercolmap jsonb, lineallayertable regclass, lineallayercolumn name, lineallayeridcolumn name, lineallayercolmap jsonb, tolerance double precision, deleteunknownfeaturesinbbox public.geometry, roleandpropsextractor regproc, resultingfeaturevalidator regproc, payloadpreparation regproc, lineallayerversioncolumn name, areallayerversioncolumn name, outerbarrierbboxforupsert public.geometry) IS '
feature - JSON payload with format specified by http://skjema.geonorge.no/SOSI/produktspesifikasjon/FKB-Ar5/4.6/FKB-Ar546.xsd
';


--
-- Name: upsert_feature(topology.topoelementarray, jsonb, regclass, name, name, jsonb); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.upsert_feature(feature_topoelems topology.topoelementarray, feature_properties jsonb, layertable regclass, layertopogeomcolumn name, layeridcolumn name, layercolmap jsonb, OUT id text, OUT topogeom topology.topogeometry) RETURNS record
    LANGUAGE plpgsql
    AS $_$ -- {
DECLARE
	props JSONB;
	geom GEOMETRY;
	json_prop_array TEXT[];
	sql TEXT;
	rec RECORD;
	known bool;
	topo topology.topology;
	layer topology.layer;
	proc_name TEXT := 'topo_update.upsert_feature';
BEGIN
	props := feature_properties;

	json_prop_array := array_agg(x) FROM
		jsonb_array_elements_text( layerColMap -> layerIdColumn ) x;

	id := props #>> json_prop_array;
	IF id IS NULL THEN
		RAISE EXCEPTION '%: feature ID extracted from props %'
			' with mapping path % is null'
			', cannot proceed',
			proc_name,
			props,
			json_prop_array
			;
	END IF;

-- STRIP -- 	RAISE DEBUG 'Feature % has elems %', id, feature_topoelems;

-- STRIP -- 	RAISE DEBUG 'Target table is %', layerTable;

-- STRIP -- 	RAISE DEBUG 'Target table spatial column is %', layerTopoGeomColumn;

-- STRIP -- 	RAISE DEBUG 'Target table id column is %', layerIdColumn;


	sql := format('SELECT %1$I FROM %2$s WHERE %1$I = %3$L LIMIT 2',
		layerIdColumn, layerTable, id);
-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;

	known := false;
	FOR rec IN EXECUTE sql
	LOOP
		IF known THEN
			RAISE EXCEPTION 'Multiple features in table % have ID %', layerTable, id;
		ELSE
			known := true;
		END IF;
	END LOOP;

	IF known THEN
-- STRIP -- 		RAISE DEBUG 'Feature with id % exists in table %, will UPDATE if needed',id, layerTable;

		rec := topo_update.update_feature(
			feature_topoelems,
			feature_properties,
			layerTable,
			layerTopoGeomColumn,
			layerIdColumn,
			id::text,
			layerColMap
		);

		topogeom := rec.topogeom;
	ELSE
-- STRIP -- 		RAISE DEBUG 'Feature with id % does not exist in table %, will INSERT',id, layerTable;


		-- Fetch topology and layer info from layer references
		SELECT t topo, l layer
			FROM topology.layer l, topology.topology t, pg_class c, pg_namespace n
			WHERE l.schema_name = n.nspname
			AND l.table_name = c.relname
			AND c.oid = layerTable
			AND c.relnamespace = n.oid
			AND l.feature_column = layerTopoGeomColumn
			AND l.topology_id = t.id
			INTO rec;
		topo := rec.topo;
		layer := rec.layer;

		topogeom := topology.CreateTopoGeom(
			topo.name,
			layer.feature_type,
			layer.layer_id,
			feature_topoelems
		);

-- STRIP -- 		RAISE DEBUG 'New feature will have TopoGeom: %', topogeom;


		id := topo_update.insert_feature(
			topogeom,
			feature_properties,
			layerTable,
			layerTopoGeomColumn,
			layerIdColumn,
			layerColMap
		);

	END IF;
END;
$_$;



--
-- Name: upsert_feature(jsonb, integer, regclass, name, name, jsonb, double precision, boolean); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.upsert_feature(feature jsonb, srid integer, layertable regclass, layergeomcolumn name, layeridcolumn name, layercolmap jsonb, tolerance double precision, modifyexistingtopogeom boolean DEFAULT true, OUT id text, OUT topogeom topology.topogeometry, OUT old_topogeom topology.topogeometry) RETURNS record
    LANGUAGE plpgsql
    AS $$ -- {
DECLARE
	props JSONB;
	geom GEOMETRY;
	rec RECORD;
BEGIN
	props := feature -> 'properties';
	geom := ST_GeomFromGeoJSON(feature -> 'geometry');

	-- TODO: use the deprecated "crs" member in GeoJSON, if found ?
-- STRIP -- 	RAISE DEBUG 'SRID: %', srid;

	IF srid IS NOT NULL THEN
		geom := ST_SetSRID(geom, srid);
	END IF;

	SELECT *
	FROM topo_update.upsert_feature(
			geom,
			props,
			layerTable,
			layerGeomColumn,
			layerIdColumn,
			layerColMap,
			tolerance,
			modifyExistingTopoGeom
		)
	INTO rec; -- id, topogeom;

	id := rec.id;
	topogeom := rec.topogeom;
	old_topogeom := rec.old_topogeom;
END;
$$;



--
-- Name: upsert_feature(public.geometry, jsonb, regclass, name, name, jsonb, double precision, boolean, name); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.upsert_feature(feature_geometry public.geometry, feature_properties jsonb, layertable regclass, layergeomcolumn name, layeridcolumn name, layercolmap jsonb, tolerance double precision, modifyexistingtopogeom boolean DEFAULT true, OUT id text, OUT topogeom topology.topogeometry, OUT old_topogeom topology.topogeometry, layerversioncolumn name DEFAULT NULL::name) RETURNS record
    LANGUAGE plpgsql
    AS $_$ -- {
DECLARE
	props JSONB;
	geom GEOMETRY;
	json_prop_array TEXT[];
	sql TEXT;
	rec RECORD;
	known bool;
	proc_name TEXT := 'topo_update.upsert_feature';
BEGIN
	props := feature_properties;

	json_prop_array := array_agg(x) FROM
		jsonb_array_elements_text( layerColMap -> layerIdColumn ) x;

	id := props #>> json_prop_array;
	IF id IS NULL THEN
		RAISE EXCEPTION '%: feature ID extracted from props %'
			' with mapping path % is null'
			', cannot proceed',
			proc_name,
			props,
			json_prop_array
			;
	END IF;

	geom := feature_geometry;

-- STRIP -- 	RAISE DEBUG 'Feature % is a %  and has area % and length % with srid %', id, ST_GeometryType(geom), ST_Area(geom), ST_Length(geom), ST_SRID(geom);

-- STRIP -- 	RAISE DEBUG 'Target table is %', layerTable;

-- STRIP -- 	RAISE DEBUG 'Target table spatial column is %', layerGeomColumn;

-- STRIP -- 	RAISE DEBUG 'Target table id column is %', layerIdColumn;

-- STRIP -- 	RAISE DEBUG 'Tolerance is %', tolerance;


	sql := format('SELECT %1$I FROM %2$s WHERE %1$I = %3$L LIMIT 2',
								layerIdColumn, layerTable, id);
-- STRIP -- 	RAISE DEBUG 'SQL: %', sql;

	known := false;
	FOR rec IN EXECUTE sql
	LOOP
		IF known THEN
			RAISE EXCEPTION 'Multiple features in table % have ID %', layerTable, id;
		ELSE
			known := true;
		END IF;
	END LOOP;

	IF known THEN
-- STRIP -- 		RAISE DEBUG 'Feature with id % exists in table %, will UPDATE if needed',id, layerTable;

		rec := topo_update.update_feature(
			feature_geometry,
			feature_properties,
			layerTable,
			layerGeomColumn,
			layerIdColumn,
			id::text,
			layerColMap,
			tolerance,
			modifyExistingTopoGeom,
			layerVersionColumn
		);

		topogeom := rec.topogeom;
		old_topogeom := rec.old_topogeom;
	ELSE
-- STRIP -- 		RAISE DEBUG 'Feature with id % does not exist in table %, will INSERT',id, layerTable;

		rec := topo_update.insert_feature(
			feature_geometry,
			feature_properties,
			layerTable,
			layerGeomColumn,
			layerIdColumn,
			layerColMap,
			tolerance
		);

		topogeom := rec.topogeom;
		id := rec.id;
	END IF;
END;
$_$;



--
-- Name: validate_surface_borders(topology.topology, topology.layer, topology.layer, public.geometry); Type: FUNCTION; Schema: topo_update; Owner: lop
--

CREATE FUNCTION topo_update.validate_surface_borders(topo topology.topology, surfacelayer topology.layer, borderlayer topology.layer, bbox public.geometry DEFAULT NULL::public.geometry) RETURNS TABLE(err text, loc public.geometry)
    LANGUAGE plpgsql STABLE
    AS $_$
DECLARE
	rec RECORD;
	sql TEXT;
BEGIN

	-- All Surface boundaries should be covered by Borders
	-- ( find Surface Boundary gaps )
	sql := format(
		$$
WITH edgeSurfaces AS (
	SELECT
		e.edge_id,
		array_agg(rl.topogeo_id ORDER BY rl.topogeo_id) left_surfaces,
		array_agg(rr.topogeo_id ORDER BY rr.topogeo_id) right_surfaces
	FROM %1$I.edge e
	LEFT OUTER JOIN %1$I.relation rl
		ON ( rl.layer_id = %2$L AND rl.element_id = e.left_face )
	LEFT OUTER JOIN %1$I.relation rr
		ON ( rr.layer_id = %2$L AND rr.element_id = e.right_face )
	WHERE ( $1 IS NULL OR e.geom && $1 )
	GROUP BY e.edge_id
),
surfaceBoundaryEdges AS (
	SELECT * FROM edgeSurfaces
	WHERE left_surfaces != right_surfaces
)
SELECT sbe.edge_id, e.geom
FROM surfaceBoundaryEdges sbe
JOIN  %1$I.edge e ON ( sbe.edge_id = e.edge_id )
WHERE sbe.edge_id NOT IN (
	SELECT element_id FROM %1$I.relation
	WHERE layer_id = %3$L
)
		$$,
		topo.name,              -- %1
		surfaceLayer.layer_id,  -- %2
		borderLayer.layer_id    -- %3
	);
	err := 'Boundary edge not covered by any Border';
	FOR rec IN EXECUTE sql USING ( bbox )
	LOOP
		loc := rec.geom;
		RETURN NEXT;
	END LOOP;

	-- Border should only use Surface boundary edges
	-- ( find non-boundary Borders )
	sql := format(
		$$
WITH edgeSurfaces AS (
	SELECT
		e.edge_id,
		array_agg(rl.topogeo_id ORDER BY rl.topogeo_id) left_surfaces,
		array_agg(rr.topogeo_id ORDER BY rr.topogeo_id) right_surfaces
	FROM %1$I.edge e
	LEFT OUTER JOIN %1$I.relation rl
		ON ( rl.layer_id = %2$L AND rl.element_id = e.left_face )
	LEFT OUTER JOIN %1$I.relation rr
		ON ( rr.layer_id = %2$L AND rr.element_id = e.right_face )
	WHERE ( $1 IS NULL OR e.geom && $1 )
	GROUP BY e.edge_id
),
surfaceBoundaryEdges AS (
	SELECT * FROM edgeSurfaces
	WHERE left_surfaces != right_surfaces
)
SELECT br.element_id, e.geom
FROM %1$I.relation br
JOIN  %1$I.edge e ON ( br.element_id = e.edge_id )
WHERE br.layer_id = %3$L
AND ( $1 IS NULL OR e.geom && $1 )
AND br.element_id NOT IN (
	SELECT edge_id FROM surfaceBoundaryEdges
)
		$$,
		topo.name,              -- %1
		surfaceLayer.layer_id,  -- %2
		borderLayer.layer_id    -- %3
	);
	err := 'Border on non-Boundary edge';
	FOR rec IN EXECUTE sql USING ( bbox )
	LOOP
		loc := rec.geom;
		RETURN NEXT;
	END LOOP;

	-- not two Borders should use the same edge
	-- ( find Borders overlap )
	sql := format(
		$$
WITH reusedEdge AS (
	SELECT array_agg(br.topogeo_id), br.element_id
	FROM %1$I.relation br
	WHERE br.layer_id = %2$L
	GROUP BY br.element_id
	HAVING count(br.topogeo_id) > 1
)
SELECT e.edge_id, e.geom FROM
%1$I.edge e JOIN reusedEdge re ON ( e.edge_id = re.element_id )
WHERE ( $1 IS NULL OR e.geom && $1 )
		$$,
		topo.name,              -- %1
		borderLayer.layer_id    -- %2
	);
	err := 'Border overlap';
	FOR rec IN EXECUTE sql USING ( bbox )
	LOOP
		loc := rec.geom;
		RETURN NEXT;
	END LOOP;

	-- Borders covering a Surface boundary should not extend past the boundary
	-- ( find multi-boundary Borders )
	sql := format(
		$$
WITH edgeSurfaces AS (
	SELECT
		e.edge_id,
		array_agg(rl.topogeo_id ORDER BY rl.topogeo_id) left_surfaces,
		array_agg(rr.topogeo_id ORDER BY rr.topogeo_id) right_surfaces
	FROM %1$I.edge e
	LEFT OUTER JOIN %1$I.relation rl
		ON ( rl.layer_id = %2$L AND rl.element_id = e.left_face )
	LEFT OUTER JOIN %1$I.relation rr
		ON ( rr.layer_id = %2$L AND rr.element_id = e.right_face )
	WHERE ( $1 IS NULL OR e.geom && $1 )
	GROUP BY e.edge_id
),
surfaceBoundaryEdges AS (
	SELECT * FROM edgeSurfaces
	WHERE left_surfaces != right_surfaces
),
borderEdge AS (
	SELECT
		br.topogeo_id,
		sbe.edge_id,
		ARRAY[
			least(sbe.left_surfaces, sbe.right_surfaces),
			greatest(sbe.left_surfaces, sbe.right_surfaces)
		] side_surfaces
	FROM %1$I.relation br,
	surfaceBoundaryEdges sbe
	WHERE br.layer_id = %3$L
	AND br.element_id = sbe.edge_id
)
SELECT
	DISTINCT be1.topogeo_id
FROM
	borderEdge be1,
	borderEdge be2
WHERE be1.side_surfaces != be2.side_surfaces -- different side surfaces
AND be1.topogeo_id = be2.topogeo_id -- same border
		$$,
		topo.name,              -- %1
		surfaceLayer.layer_id,  -- %2
		borderLayer.layer_id    -- %3
	);
	err := 'Border binds multiple Surfaces';
	FOR rec IN EXECUTE sql USING ( bbox )
	LOOP
		loc := ST_CollectionHomogenize((topo.id,borderLayer.layer_id,rec.topogeo_id, 2)::topology.topogeometry::geometry);
		RETURN NEXT;
	END LOOP;

END;
$_$;



